fn getHash(s: []const u8) u64 {
    return std.hash.Wyhash.hash(0, s);
}

const CssTokKind = enum { word, punct };

const CssTok = struct {
    kind: CssTokKind,
    start: usize,
    end: usize,
    full_start: usize,
    has_leading_whitespace: bool = false,
};

// starts immediately before /*
fn scanCssComment(css: []const u8, pos: usize) usize {
    var i = pos+2;
    while (i + 1 < css.len and !(css[i] == '*' and css[i + 1] == '/')) i += 1;
    if (i + 1 < css.len) i += 2;
    return i;
}

fn scanCssString(css: []const u8, pos: usize) usize {
    const q = css[pos];
    var i = pos+1;
    while (i < css.len and css[i] != q) {
        if (css[i] == '\\') i = scanCssEscape(css, i)
        else i += 1;
    }
    if (i < css.len) i += 1;
    return i;
}

fn scanCssEscape(css: []const u8, pos: usize) usize {
    if (pos + 1 >= css.len) return css.len;
    var i = pos + 1;
    var hex_count: u32 = 0;
    while (i < css.len) {
        switch (css[i]) {
            '0'...'9', 'a'...'f', 'A'...'F' => {
                i += 1;
                hex_count += 1;
                if (hex_count == 6) break;
            },
            else => break,
        }
    }
    if (hex_count == 0 or (i < css.len and std.ascii.isWhitespace(css[i]))) {
        i += 1;
    }
    return i;
}

fn scanCssBlockLike(css: []const u8, pos: usize) usize {
    const closer: u8 = switch (css[pos]) {
        '(' => ')',
        '[' => ']',
        '{' => '}',
        else => unreachable,
    };
    var i = pos + 1;
    while (i < css.len) {
        switch (css[i]) {
            '/' => {
                if (i + 1 < css.len and css[i + 1] == '*') i = scanCssComment(css, i)
                else i += 1;
            },
            '\\' => i = scanCssEscape(css, i),
            '"', '\'' => i = scanCssString(css, i),
            '(', '[', '{' => i = scanCssBlockLike(css, i),
            ')', ']', '}' => {
                if (css[i] == closer) return i + 1;
                i += 1;
            },
            else => i += 1,
        }
    }
    return i;
}

// TODO: technically, you are supposed to preprocess the text to normalize \r, \r\n, \f to \n
fn cssNext(css: []const u8, pos: usize) ?CssTok {
    var i = pos;
    var has_leading_whitespace = false;

    while (i < css.len) {
        if (std.ascii.isWhitespace(css[i])) {
            i += 1;
            has_leading_whitespace = true;
        } else if (i + 1 < css.len and css[i] == '/' and css[i + 1] == '*') {
            i = scanCssComment(css, i);
        } else break;
    }

    if (i >= css.len) return null;

    const start = i;
    var is_punctuation = false;

    while (i < css.len) {
        switch (css[i]) {
            '&', ':', ',', ';', '>', '+', '~', '{', '}' => {
                if (i == start) {
                    i += 1;
                    is_punctuation = true;
                }
                break;
            },
            '(', '[' => {
                if (i == start) i = scanCssBlockLike(css, i);
                break;
            },
            '/' => {
                if (i + 1 < css.len and css[i + 1] == '*') i = scanCssComment(css, i)
                else i += 1;
            },
            '\\' => i = scanCssEscape(css, i),
            '"', '\'' => i = scanCssString(css, i),
            ' ', '\t', '\n', '\r' => break,
            else => i += 1,
        }
    }

    std.debug.assert(i != start);

    return .{
        .kind = if (is_punctuation) .punct else .word,
        .start = start,
        .full_start = pos,
        .end = i,
        .has_leading_whitespace = has_leading_whitespace,
    };
}

fn transformCssSelectorList(
    css: []const u8,
    attr: []const u8,
    sub_attrs: []const []const u8,
    comp_entries: []const CompSelectorEntry,
    scope_subject: bool,
    out: *std.ArrayList(u8)
) !void {
    var i: usize = 0;
    var is_first = true;
    while (cssNext(css, i)) |token| {
        try out.appendSlice(css[i..token.start]); // prints leading trivia
        i = token.start;
        if (token.kind == .word or css[token.start] == ':' or css[token.start] == '&') {
            const did_emit = try transformCssCompoundSelector(css, &i, attr, sub_attrs, comp_entries, is_first, scope_subject, out);
            is_first = is_first and !did_emit;
        } else {
            try out.appendSlice(css[token.start..token.end]);
            if (css[token.start] == ',') is_first = true;
            i = token.end;
        }
    }
    try out.appendSlice(css[i..]);
}

fn transformCssCompoundSelector(
    css: []const u8,
    pos: *usize,
    attr: []const u8,
    sub_attrs: []const []const u8,
    comp_entries: []const CompSelectorEntry,
    is_first: bool,
    scope_subject: bool,
    out: *std.ArrayList(u8)
) anyerror!bool {
    const full_start = pos.*;
    var i = full_start;
    var print_cursor = i;
    var needs_suffix = false;
    var skip_suffix = false;
    var did_emit = false;
    while (cssNext(css, i)) |token| {
        if (token.has_leading_whitespace and i != full_start) break;
        if (token.kind == .punct) {
            switch (css[token.start]) {
                '>', '+', '~', ',', '{', '}', ';' => break,
                else => {}
            }
        }
        i = token.end;
        if (token.kind == .word) {
            const word = css[token.start..token.end];
            if (word.len > 0 and word[0] >= 'A' and word[0] <= 'Z') {
                for (comp_entries) |e| {
                    if (std.mem.eql(u8, e.name, word)) {
                        try out.appendSlice(css[print_cursor..token.start]);
                        try out.append('[');
                        try out.appendSlice(e.attr);
                        try out.append(']');
                        print_cursor = token.end;
                        did_emit = true;
                        break;
                    }
                }
                if (!did_emit) needs_suffix = true;
            } else {
                needs_suffix = true;
            }
            continue;
        }
        switch (css[token.start]) {
            '&' => {
                skip_suffix = true;
            },
            ':' => {
                if (cssNext(css, token.end)) |name| {
                    if (name.has_leading_whitespace) break;
                    i = name.end;
                    if (name.kind == .punct and css[name.start] == ':') {
                        // pseudo element, scope attr must come before it
                        if (scope_subject and needs_suffix and !skip_suffix) {
                            try out.appendSlice(css[print_cursor..token.full_start]);
                            print_cursor = token.full_start;
                            try appendScopeAttr(out, attr, sub_attrs, is_first);
                            did_emit = true;
                        }
                        skip_suffix = true;
                        continue;
                    }
                    // TODO: `nth-*` child pseudo classes have a special "of" syntax
                    const args = cssNext(css, i) orelse break;
                    // the spec normally tokenizes the ident with the open paren, so we replicate that here
                    if (args.start != name.end) continue;
                    if (css[args.start] != '(') continue;
                    if (std.mem.eql(u8, css[name.start..name.end], "unscoped")) {
                        try out.appendSlice(css[print_cursor..token.start]);
                        try out.appendSlice(css[args.start+1..args.end-1]);
                        i = args.end;
                        print_cursor = i;
                        continue;
                    }
                    const pseudo_fns = [_][]const u8{ "has", "is", "not", "where" };
                    var matched_pseudo: ?[]const u8 = null;
                    for (pseudo_fns) |p| {
                        if (std.mem.eql(u8, css[name.start..name.end], p)) {
                            matched_pseudo = p;
                            break;
                        }
                    }
                    if (matched_pseudo != null) {
                        if (scope_subject and !skip_suffix and !did_emit) {
                            try out.appendSlice(css[print_cursor..token.full_start]);
                            print_cursor = token.full_start;
                            try appendScopeAttr(out, attr, sub_attrs, is_first);
                            did_emit = true;
                        }
                        const is_has = std.mem.eql(u8, matched_pseudo.?, "has");
                        try out.appendSlice(css[print_cursor..args.start+1]);
                        const inner = css[args.start+1..args.end-1];
                        // only :has scopes its args
                        try transformCssSelectorList(inner, attr, sub_attrs, comp_entries, is_has, out);
                        i = args.end;
                        print_cursor = args.end-1;
                    }
                }
            },
            else => {},
        }
    }
    try out.appendSlice(css[print_cursor..i]);
    if (scope_subject and needs_suffix and !skip_suffix and !did_emit) {
        try appendScopeAttr(out, attr, sub_attrs, is_first);
        did_emit = true;
    }
    pos.* = i;
    return did_emit;
}

fn cssSkipBlock(css: []const u8, pos: usize) usize {
    var p = pos;
    while (cssNext(css, p)) |tok| {
        p = tok.end;
        if (tok.kind == .punct) {
            switch (css[tok.start]) {
                '{' => p = cssSkipBlock(css, p),
                '}' => return p,
                else => {},
            }
        }
    }
    return css.len;
}

const ScannedCssDeclaration = struct {
    const Kind = enum {
        invalid,
        property,
        rule,
        at_rule,
        at_rule_statement, // e.g. `@foo;`
    };
    kind: Kind,
    start: usize,
    end: usize,
    // for rules, this is before the open brace
    // for properties, this is before the colon
    value_start: usize,
};

fn cssScanDeclaration(css: []const u8, pos: usize) ?ScannedCssDeclaration {
    const first = cssNext(css, pos) orelse return null;
    const start = first.start;
    // --hover {}color:red; is parsed as a nested rule + property decl
    // this does treat `--:foo;` as a property, but that's fine
    const is_custom_property = std.mem.startsWith(u8, css[first.start..first.end], "--");
    var i = start;
    var value_start = i;
    var kind: ScannedCssDeclaration.Kind = .invalid;    
    while (cssNext(css, i)) |x| {
        i = x.end;
        if (x.kind == .punct) {
            switch (css[x.start]) {
                '}' => break,
                ';' => {
                    if (value_start != start) kind = .property;
                    break;
                },
                '{' => {
                    // TODO: if a colon follows the simple block, browsers don't treat it as a rule 
                    if (!(is_custom_property and kind == .property)) {
                        value_start = x.start;
                        kind = .rule;
                    }
                    i = cssSkipBlock(css, i);
                    if (kind == .rule) break;
                },
                ':' => {
                    if (value_start == start) {
                        value_start = x.start;
                        kind = .property;
                    }
                },
                else => {},
            }
        }
    }
    if (css[start] == '@' and (kind == .rule or kind == .invalid)) {
        if (value_start == start) value_start = first.end;
        kind = if (kind == .rule) .at_rule else .at_rule_statement;
    }

    return .{
        .kind = kind,
        .start = start,
        .end = i,
        .value_start = value_start,
    };
}

const KeyframeEntry = struct {
    original: []const u8,
    scoped: []const u8,
};

const CompSelectorEntry = struct {
    name: []const u8,
    attr: []const u8,
};

fn collectKeyframes(css: []const u8, entries: *std.ArrayList(KeyframeEntry)) !void {
    var pos: usize = 0;
    while (cssScanDeclaration(css, pos)) |decl| {
        pos = decl.end;
        var should_recurse = false;
        switch (decl.kind) {
            .rule => {
                // @keyframes inside of rules is (currently) inert
            },
            .at_rule => {
                const kw_token = cssNext(css, decl.start) orelse continue;
                const kw = css[kw_token.start..kw_token.end];
                if (std.mem.eql(u8, kw, "@keyframes")) {
                    // TODO: name can be a string, you need to normalize w/ escapes
                    const name_token = cssNext(css, kw_token.end) orelse continue;
                    const name = css[name_token.start..name_token.end];
                    const hash = getHash(css[decl.value_start+1..decl.end-1]);
                    var buf: [StyleVisitor.hash_suffix_buf_size]u8 = undefined;
                    const scoped = try std.fmt.allocPrint(getAllocator(), "{s}{s}", .{ name, StyleVisitor.makeBase36Suffix(hash, &buf) });
                    try entries.append(.{ .original = name, .scoped = scoped });
                    continue;
                }
                const recurse_into = [_][]const u8{ "@media", "@supports", "@layer", "@container", "@scope" };
                for (recurse_into) |x| {
                    if (std.mem.eql(u8, kw, x)) {
                        should_recurse = true;
                        break;
                    }
                }
            },
            else => {},
        }
        if (should_recurse) {
            try collectKeyframes(css[decl.value_start+1..decl.end-1], entries);
        }
    }
}

fn collectComponentSelectors(css: []const u8, root_attr: []const u8, entries: *std.ArrayList(CompSelectorEntry)) !void {
    var pos: usize = 0;
    while (cssScanDeclaration(css, pos)) |decl| {
        pos = decl.end;
        var should_recurse = false;
        switch (decl.kind) {
            .rule => {
                const selector = css[decl.start..decl.value_start];
                var i: usize = 0;
                while (cssNext(selector, i)) |tok| {
                    i = tok.end;
                    if (tok.kind != .word) continue;
                    const word = selector[tok.start..tok.end];
                    if (word.len == 0 or word[0] < 'A' or word[0] > 'Z') continue;
                    var found = false;
                    for (entries.items) |e| {
                        if (std.mem.eql(u8, e.name, word)) { found = true; break; }
                    }
                    if (!found) {
                        var h = std.hash.Wyhash.init(0);
                        h.update(root_attr);
                        h.update(word);
                        var buf: [StyleVisitor.hash_suffix_buf_size]u8 = undefined;
                        const suffix = StyleVisitor.makeBase36Suffix(h.final(), &buf);
                        const attr = try std.fmt.allocPrint(getAllocator(), "_comp{s}", .{suffix});
                        try entries.append(.{ .name = try getAllocator().dupe(u8, word), .attr = attr });
                    }
                }
                should_recurse = true;
            },
            .at_rule => {
                const kw_token = cssNext(css, decl.start) orelse continue;
                const kw = css[kw_token.start..kw_token.end];
                const recurse_into = [_][]const u8{ "@media", "@supports", "@layer", "@container", "@scope", "@starting-style" };
                for (recurse_into) |x| {
                    if (std.mem.eql(u8, kw, x)) { should_recurse = true; break; }
                }
            },
            else => {},
        }
        if (should_recurse) {
            try collectComponentSelectors(css[decl.value_start+1..decl.end-1], root_attr, entries);
        }
    }
}

fn cssTsAddUnique(out: *std.ArrayList([]const u8), word: []const u8) !void {
    for (out.items) |e| if (std.mem.eql(u8, e, word)) return;
    try out.append(try getAllocator().dupe(u8, word));
}

fn collectTypeSelectorsFromCompound(css: []const u8, pos: *usize, out: *std.ArrayList([]const u8)) anyerror!void {
    const full_start = pos.*;
    var at_start = true;
    var has_type_selector = false;
    var ignore = false;

    var i = full_start;
    while (cssNext(css, i)) |tok| {
        if (tok.has_leading_whitespace and i != full_start) break;
        if (tok.kind == .punct) {
            switch (css[tok.start]) {
                '>', '+', '~', ',', '{', '}', ';' => break,
                '&' => {
                    i = tok.end;
                    ignore = true;
                    at_start = false;
                },
                ':' => {
                    at_start = false;
                    i = tok.end;
                    const name_tok = cssNext(css, i) orelse break;
                    if (name_tok.has_leading_whitespace) break;
                    i = name_tok.end;
                    if (name_tok.kind == .punct) continue; // ::pseudo-element
                    const name_text = css[name_tok.start..name_tok.end];
                    const paren = std.mem.indexOfScalar(u8, name_text, '(') orelse continue;
                    const fn_name = name_text[0..paren];
                    if (!ignore and (std.mem.eql(u8, fn_name, "is") or std.mem.eql(u8, fn_name, "where"))) {
                        const inner = name_text[paren + 1 .. name_text.len - 1];
                        const prev_len = out.items.len;
                        try collectTypeSelectorsFromSelectorList(inner, out);
                        if (out.items.len > prev_len) has_type_selector = true;
                    }
                },
                else => {
                    at_start = false;
                    i = tok.end;
                },
            }
        } else {
            const word = css[tok.start..tok.end];
            if (!ignore and at_start) {
                if (std.mem.eql(u8, word, "*")) {
                    try cssTsAddUnique(out, "*");
                    has_type_selector = true;
                } else if (word[0] != '.' and word[0] != '#' and word[0] != '[') {
                    var end: usize = 0;
                    while (end < word.len) {
                        switch (word[end]) {
                            '.', '#' => break,
                            else => {},
                        }
                        end += 1;
                    }
                    try cssTsAddUnique(out, word[0..end]);
                    has_type_selector = true;
                }
            }
            at_start = false;
            i = tok.end;
        }
    }

    pos.* = i;
    if (!ignore and !has_type_selector) {
        try cssTsAddUnique(out, "*");
    }
}

fn collectTypeSelectorsFromSelectorList(css: []const u8, out: *std.ArrayList([]const u8)) anyerror!void {
    var i: usize = 0;
    while (cssNext(css, i)) |tok| {
        if (tok.kind == .punct) {
            switch (css[tok.start]) {
                ',', '>', '+', '~' => { i = tok.end; },
                '{', '}', ';' => break,
                '&', ':' => try collectTypeSelectorsFromCompound(css, &i, out),
                else => { i = tok.end; },
            }
        } else {
            try collectTypeSelectorsFromCompound(css, &i, out);
        }
        for (out.items) |t| if (std.mem.eql(u8, t, "*")) return;
    }
}

fn collectPossibleTypeSelectorsFromCss(css: []const u8, out: *std.ArrayList([]const u8)) !void {
    var pos: usize = 0;
    while (cssScanDeclaration(css, pos)) |decl| {
        pos = decl.end;
        var should_recurse = false;
        switch (decl.kind) {
            .rule => {
                try collectTypeSelectorsFromSelectorList(css[decl.start..decl.value_start], out);
                for (out.items) |t| if (std.mem.eql(u8, t, "*")) return;
                should_recurse = true;
            },
            .at_rule => {
                const kw_token = cssNext(css, decl.start) orelse continue;
                const kw = css[kw_token.start..kw_token.end];
                const recurse_into = [_][]const u8{ "@media", "@supports", "@layer", "@container", "@scope", "@starting-style" };
                for (recurse_into) |x| {
                    if (std.mem.eql(u8, kw, x)) { should_recurse = true; break; }
                }
            },
            else => {},
        }
        if (should_recurse) {
            try collectPossibleTypeSelectorsFromCss(css[decl.value_start + 1 .. decl.end - 1], out);
            for (out.items) |t| if (std.mem.eql(u8, t, "*")) return;
        }
    }
}

fn replaceKeyframeNamesInValue(value: []const u8, keyframes: []const KeyframeEntry, out: *std.ArrayList(u8)) !void {
    var i: usize = 0;
    var s = i;
    outer: while (cssNext(value, i)) |t| {
        i = t.end;
        if (t.kind == .punct) continue;
        for (keyframes) |kf| {
            const n = kf.original;
            // TODO: we should compare normalized token values, not verbatim
            if (t.end-t.start != n.len or !std.mem.eql(u8, value[t.start..t.end], n)) continue;
            try out.appendSlice(value[s..t.start]);
            s = i;
            try out.appendSlice(kf.scoped);
            continue :outer;
        }
    }
    try out.appendSlice(value[s..]);
}

fn replaceAnimKeyframes(
    css: []const u8, 
    decl: ScannedCssDeclaration,
    keyframes: []const KeyframeEntry, 
    out: *std.ArrayList(u8)
) !void {
    std.debug.assert(decl.kind == .property);

    const props = [_][]const u8{ "animation-name", "animation" };
    const name = std.mem.trimRight(u8, css[decl.start..decl.value_start], " \t\n\r");

    var matched = false;
    for (props) |prop| {
        if (std.ascii.eqlIgnoreCase(name, prop)) { matched = true; break; }
    }
    if (!matched) {
        try out.appendSlice(css[decl.start..decl.end]);
        return;        
    }

    try out.appendSlice(css[decl.start..decl.value_start+1]);
    try replaceKeyframeNamesInValue(css[decl.value_start+1..decl.end], keyframes, out);
}

fn transformCssRuleBody(css: []const u8, attr: []const u8, sub_attrs: []const []const u8, comp_entries: []const CompSelectorEntry, keyframes: []const KeyframeEntry, out: *std.ArrayList(u8)) anyerror!void {
    var i: usize = 0;
    var s = i;
    while (cssScanDeclaration(css, i)) |decl| {
        i = decl.end;
        var should_recurse = false;
        switch (decl.kind) {
            .property => {
                try out.appendSlice(css[s..decl.start]);
                try replaceAnimKeyframes(css, decl, keyframes, out);
                s = decl.end;
            },
            .rule => {
                try out.appendSlice(css[s..decl.start]);
                try transformCssSelectorList(css[decl.start..decl.value_start], attr, sub_attrs, comp_entries, true, out);
                s = decl.value_start;
                should_recurse = true;
            },
            .at_rule => {
                const kw_token = cssNext(css, decl.start) orelse continue;
                const kw = css[kw_token.start..kw_token.end];
                if (std.mem.eql(u8, kw, "@unscoped")) {
                    try out.appendSlice(css[s..decl.start]);
                    try transformCssRuleBody(css[decl.value_start+1..decl.end-1], "", &.{}, comp_entries, keyframes, out);
                    s = decl.end;
                    continue;
                }
                if (std.mem.eql(u8, kw, "@scope")) {
                    var j: usize = 0;
                    while (cssNext(css[decl.start..decl.value_start], j)) |t| {
                        j = t.end;
                        if (t.kind == .punct) continue;
                        if (css[decl.start+t.start] != '(') continue;
                        try out.appendSlice(css[s..decl.start+t.start+1]);
                        try transformCssSelectorList(css[decl.start+t.start+1..decl.start+t.end-1], attr, sub_attrs, comp_entries, true, out);
                        s = decl.start+t.end-1;
                    }
                    try out.appendSlice(css[s..decl.value_start+1]);
                    try transformCssRuleBody(css[decl.value_start+1..decl.end-1], attr, sub_attrs, comp_entries, keyframes, out);
                    s = decl.end-1;
                    continue;
                }
                if (std.mem.eql(u8, kw, "@keyframes")) {
                    try out.appendSlice(css[s..decl.start]);
                    const block_start = decl.value_start+1;
                    try replaceKeyframeNamesInValue(css[decl.start..block_start], keyframes, out);
                    s = block_start;
                    continue;
                }

                const recurse_into = [_][]const u8{ "@media", "@supports", "@layer", "@container", "@starting-style" };
                for (recurse_into) |x| {
                    if (std.mem.eql(u8, kw, x)) {
                        should_recurse = true;
                        break;
                    }
                }
            },
            else => {},
        }
        if (should_recurse) {
            try out.appendSlice(css[s..decl.value_start+1]);
            try transformCssRuleBody(css[decl.value_start+1..decl.end-1], attr, sub_attrs, comp_entries, keyframes, out);
            s = decl.end-1;
        }
    }
    try out.appendSlice(css[s..]);
}

/// First compound selector in each complex selector gets `[attr]`,
/// subsequent compounds get `:where([attr])`.
fn transformCssSelectors(css: []const u8, attr: []const u8, sub_attrs: []const []const u8, comp_entries_out: *std.ArrayList(CompSelectorEntry), out: *std.ArrayList(u8)) !void {
    var kf_list = std.ArrayList(KeyframeEntry).init(getAllocator());
    defer kf_list.deinit();
    try collectKeyframes(css, &kf_list);
    try collectComponentSelectors(css, attr, comp_entries_out);
    try transformCssRuleBody(css, attr, sub_attrs, comp_entries_out.items, kf_list.items, out);
}

fn appendScopeAttr(out: *std.ArrayList(u8), attr: []const u8, sub_attrs: []const []const u8, is_first: bool) !void {
    if (attr.len == 0) return;
    if (is_first) {
        try out.append('[');
        try out.appendSlice(attr);
        try out.append(']');
        if (sub_attrs.len > 0) {
            try out.appendSlice(":where(");
            for (sub_attrs) |sa| { try out.append('['); try out.appendSlice(sa); try out.append(']'); }
            try out.append(')');
        }
    } else {
        try out.appendSlice(":where([");
        try out.appendSlice(attr);
        try out.append(']');
        for (sub_attrs) |sa| { try out.append('['); try out.appendSlice(sa); try out.append(']'); }
        try out.append(')');
    }
}

// TODO: emit css using `insertRule`, possibly with a single global synthetic stylesheet
// this would have to take into account @import rules which need to be inserted (positionally) before other rules

// * all #style directives in a single immediate scope are merged
// * the hash of a root style is derived from the text of all children scoped styles
const StyleVisitor = struct {
    const RootScope = struct {
        attr: []const u8 = &.{},
        hash_acc: std.hash.Wyhash,
        scopes: std.ArrayListUnmanaged(*ScopeInfo) = .{},
    };
    pub const ScopeInfo = struct {
        root: *RootScope,
        subscopes: std.ArrayListUnmanaged([]const u8) = .{},
        merged_css: []const u8 = &.{},
        needs_attr_value: bool = false,
        comp_selectors: []const CompSelectorEntry = &.{},
        possible_type_selectors: ?[]const []const u8 = null,

        did_transform: bool = false, // updates `merged_css`

        // mutated during final pass
        did_emit: bool = false,
    };

    nodes: *const BumpAllocator(AstNode) = undefined,
    node_ptr_to_scope_map: std.AutoArrayHashMapUnmanaged(*const AstNode, *ScopeInfo) = .{},

    merging: bool = false,
    text_acc: std.ArrayListUnmanaged(u8) = .{},
    current_scope: ?*ScopeInfo = null,
    skipped_block_scope: NodeRef = 0,

    fn makeSubAttr(_: *@This(), count: usize) ![]const u8 {
        return std.fmt.allocPrint(getAllocator(), "_s-{d}", .{count});
    }

    const total_digits = 8;
    const attr_prefix = "_";
    pub const hash_suffix_buf_size = total_digits+attr_prefix.len;
    pub fn makeBase36Suffix(hash: u64, buf: *[hash_suffix_buf_size]u8) []u8 {
        const chars = "0123456789abcdefghijklmnopqrstuvwxyz";
        var digits: [total_digits]u8 = undefined;
        var n_digits: usize = 0;
        var v = hash;
        while (v > 0 and n_digits < total_digits) {
            digits[n_digits] = chars[v % 36];
            v /= 36;
            n_digits += 1;
        }
        if (n_digits == 0) { digits[0] = '0'; n_digits = 1; }
        for (0..attr_prefix.len) |k| buf[k] = attr_prefix[k];
        for (0..n_digits) |k| buf[attr_prefix.len + k] = digits[n_digits - 1 - k];
        return buf[0..attr_prefix.len + n_digits];
    }

    fn transformCss(_: *@This(), s: *ScopeInfo) !void {
        std.debug.assert(!s.did_transform);
        std.debug.assert(s.root.attr.len != 0);
        std.debug.assert(s.merged_css.len != 0);
        s.did_transform = true;
        var type_sel_list = std.ArrayList([]const u8).init(getAllocator());
        try collectPossibleTypeSelectorsFromCss(s.merged_css, &type_sel_list);
        s.possible_type_selectors = try type_sel_list.toOwnedSlice();
        var scoped = std.ArrayList(u8).init(getAllocator());
        var comp_list = std.ArrayList(CompSelectorEntry).init(getAllocator());
        try transformCssSelectors(s.merged_css, s.root.attr, s.subscopes.items, &comp_list, &scoped);
        s.comp_selectors = try comp_list.toOwnedSlice();
        getAllocator().free(s.merged_css);
        // TODO: avoid this extra allocation by escaping as we emit
        var fixed = try std.ArrayListUnmanaged(u8).initCapacity(getAllocator(), scoped.items.len);
        for (scoped.items) |c| {
            if (c == '\\' or c == '`') {
                try fixed.append(getAllocator(), '\\');
            }
            try fixed.append(getAllocator(), c);
        }
        // scoped.shrinkAndFree(scoped.items.len);
        // s.merged_css = scoped.items;
        s.merged_css = fixed.items;
        scoped.deinit();
    }

    fn getRootScope(self: *@This()) !*RootScope {
        if (self.current_scope) |s| return s.root;
        const root = try getAllocator().create(RootScope);
        root.* = .{ .hash_acc = std.hash.Wyhash.init(0) };
        return root;
    }

    fn mergeImmediateStyles(self: *@This(), n: *const AstNode) ![]const u8 {
        defer self.text_acc = .{};
        self.merging = true;
        defer self.merging = false;
        if (n.kind == .jsx_component and self.skipped_block_scope != 0) {
            try parser.forEachChild(self.nodes, self.nodes.at(self.skipped_block_scope), self);
        }
        try parser.forEachChild(self.nodes, n, self);
        self.text_acc.shrinkAndFree(getAllocator(), self.text_acc.items.len);
        return self.text_acc.items;
    }

    fn maybeSetNeedsAttrValue(s: *ScopeInfo) !void {
        // naive check
        if (std.mem.indexOf(u8, s.merged_css, "@scope")) |i| {
            var j = i;
            while (j < s.merged_css.len) {
                switch (s.merged_css[j]) {
                    '(', ')', '}', => break,
                    '{' => {
                        s.needs_attr_value = true;
                        break;
                    },
                    else => {},
                }
                j += 1;
            }
        }
    }

    pub fn visit(self: *@This(), n: *const AstNode, ref: NodeRef) anyerror!void {
        if (self.merging) {
            if (n.kind == .jsx_style_directive) {
                const txt_ref = getPackedData(n).right;
                if (txt_ref != 0) {
                    try self.text_acc.appendSlice(getAllocator(), getSlice(self.nodes.at(txt_ref), u8));
                }
            }
            return;
        }

        switch (n.kind) {
            .block => {
                if (self.skipped_block_scope == ref) {
                    return try parser.forEachChild(self.nodes, n, self);
                }
            },
            .jsx_component => {
                // we treat the init body and the top-level children as being apart of the same style scope
                const fn_exp = self.nodes.at(getPackedData(n).left);
                self.skipped_block_scope = fn_exp.len;
            },
            .jsx_element, .jsx_self_closing_element, .jsx_style_directive => {
                if (self.current_scope) |s| {
                    try self.node_ptr_to_scope_map.put(getAllocator(), n, s);
                }
            },
            else => {},
        }

        switch (n.kind) {
            .jsx_element, .jsx_if_directive, .jsx_else_directive, 
            .jsx_fragment, .jsx_component,
            .source_file, .block => {
                const merged = try self.mergeImmediateStyles(n);
                if (merged.len == 0) {
                    return try parser.forEachChild(self.nodes, n, self);
                }
                const is_root = self.current_scope == null;
                const root_scope = try self.getRootScope();
                const save_current_scope = self.current_scope;
                defer self.current_scope = save_current_scope;
                const scope = try getAllocator().create(ScopeInfo);
                scope.* = .{ .root = root_scope, .merged_css = merged };
                // try maybeSetNeedsAttrValue(scope);
                root_scope.hash_acc.update(merged);
                if (!is_root) {
                    const subscope_attr = try self.makeSubAttr(root_scope.scopes.items.len);
                    scope.subscopes = try save_current_scope.?.subscopes.clone(getAllocator());
                    try scope.subscopes.append(getAllocator(), subscope_attr);
                }
                try root_scope.scopes.append(getAllocator(), scope);
                self.current_scope = scope;
                try parser.forEachChild(self.nodes, n, self);
                if (is_root) {
                    const hash = root_scope.hash_acc.final();
                    var buf: [hash_suffix_buf_size]u8 = undefined;
                    root_scope.attr = try getAllocator().dupe(u8, makeBase36Suffix(hash, &buf));
                    for (root_scope.scopes.items) |s| {
                        try self.transformCss(s);
                    }
                    root_scope.scopes.shrinkAndFree(getAllocator(), 0);
                }
            },
            else => {
                try parser.forEachChild(self.nodes, n, self);
            },
        }
    }
};

inline fn getKeywordHash(keyword: parser.SyntaxKind) !u64 {
    return switch (keyword) {
        .this_keyword => comptime getHash("this"),
        .super_keyword => comptime getHash("super"),
        .null_keyword => comptime getHash("null"),
        .undefined_keyword => comptime getHash("undefined"),
        .number_keyword => comptime getHash("number"),
        .string_keyword => comptime getHash("string"),
        .boolean_keyword => comptime getHash("boolean"),
        .true_keyword => comptime getHash("true"),
        .false_keyword => comptime getHash("false"),
        else => error.InvalidKeyword,
    };
}

const ModuleResolver = struct {
    arena: std.heap.ArenaAllocator,
    working_dir: []const u8,

    pub fn initDefault() !@This() {
        const arena = std.heap.ArenaAllocator.init(getAllocator());
        var this = @This(){
            .arena = arena,
            .working_dir = &.{},
        };

        this.working_dir = try std.process.getCwdAlloc(this.arena.allocator());

        return this;
    }

    fn getResolveDir(this: *@This(), file_name: []const u8) !struct { should_free: bool = false, dir: []const u8 } {
        const dir = std.fs.path.dirname(file_name) orelse return .{ .dir = this.working_dir };
        if (std.fs.path.isAbsolute(dir)) return .{ .dir = dir };

        const resolved = try std.fs.path.resolve(this.arena.allocator(), &.{ this.working_dir, dir });

        return .{ .should_free = true, .dir = resolved };
    }

    fn findNodeModules(this: *@This(), origin: []const u8) anyerror!?[]const u8 {
        const resolve_dir = try this.getResolveDir(origin);
        defer if (resolve_dir.should_free) this.arena.allocator().free(resolve_dir.dir);

        return this._findNodeModules(resolve_dir.dir);
    }

    fn _findNodeModules(this: *@This(), dir: []const u8) anyerror!?[]const u8 {
        var found = false;
        const resolved = try std.fs.path.resolve(this.arena.allocator(), &.{ dir, "node_modules" });
        defer if (!found) this.arena.allocator().free(resolved);

        std.fs.accessAbsolute(resolved, .{}) catch |e| {
            if (e != std.fs.Dir.AccessError.FileNotFound) {
                return e;
            }

            return this._findNodeModules(std.fs.path.dirname(dir) orelse return null);
        };

        found = true;
        return resolved;
    }

    pub fn resolveTypesDirective(this: *@This(), origin: []const u8, name: []const u8) anyerror!?[]const u8 {
        const start = try this.findNodeModules(origin) orelse return null;

        var found = false;
        const resolved = try std.fs.path.resolve(this.arena.allocator(), &.{ start, "@types", name });
        defer if (!found) this.arena.allocator().free(resolved);

        std.fs.accessAbsolute(resolved, .{}) catch |e| {
            if (e != std.fs.Dir.AccessError.FileNotFound) {
                return e;
            }

            return this.resolveTypesDirective(std.fs.path.dirname(start) orelse return null, name);
        };

        found = true;
        return resolved;
    }

    pub fn resolveSpecifier(this: *@This(), origin: []const u8, spec: []const u8) ![]const u8 {
        if (std.fs.path.isAbsolute(spec)) return error.TODO;
        if (spec.len > 0 and spec[0] != '.') return error.TODO_bare_spec;

        const resolve_dir = try this.getResolveDir(origin);
        defer if (resolve_dir.should_free) this.arena.allocator().free(resolve_dir.dir);

        const ext = std.fs.path.extension(spec);
        const resolved = try std.fs.path.resolve(this.arena.allocator(), &.{ resolve_dir.dir, spec });
        if (strings.eqlComptime(ext, ".ts")) {
            return resolved;
        }

        const origin_ext = if (strings.endsWithComptime(origin, ".syn")) ".syn" else ".ts";

        defer this.arena.allocator().free(resolved);

        var stack_buf: [4096]u8 = undefined;
        const with_ext = try std.fmt.bufPrint(&stack_buf, "{s}{s}", .{resolved,origin_ext});

        const buf = try this.arena.allocator().alloc(u8, with_ext.len);
        @memcpy(buf, with_ext);

        return buf;
    }
};

const FileDiagnostic = struct {
    node_ref: NodeRef,
    message: []const u8,
};

pub const AsyncProgramLoader = struct {
    const HostFns = @import("./api.zig").CompilerHostFns;

    host_fns: *HostFns,
    program: *Program,
    file_requests: std.AutoArrayHashMap(u64, FileRef),
    completed: u32 = 0,

    on_done_ctx: ?*anyopaque = null,
    on_done: ?*const fn (ctx: ?*anyopaque) anyerror!void = null,

    mu: std.Thread.Mutex = std.Thread.Mutex{},

    pub fn init(program: *Program, host_fns: *HostFns) !@This() {
        return .{
            .program = program,
            .host_fns = host_fns,
            .file_requests = std.AutoArrayHashMap(u64, FileRef).init(program.allocator),
        };
    }

    pub fn loadFiles(this: *@This(), ctx: ?*anyopaque, on_done: *const fn (ctx: ?*anyopaque) anyerror!void) !void {
        this.program.did_load_async = true;

        this.on_done_ctx = ctx;
        this.on_done = on_done;

        for (this.program.options.default_libs) |f| {
            const resolved = try this.host_fns.callResolveFilePath(.lib, f, null);
            _ = try this.requestFile(resolved, true);
        }

        for (this.program.options.types) |f| {
            const resolved = try this.host_fns.callResolveFilePath(.types, f, null);
            const id = try this.requestFile(resolved, false);
            // XXX: need to clean this up
            const directive = try this.file_requests.allocator.create(parser.TripleSlashDirective);
            const name = try this.file_requests.allocator.alloc(u8, f.len);
            @memcpy(name, f);
            directive.* = .{
                .kind = .types,
                .value = name,
            };
            try this.program.associated_directives.put(id, directive);
        }

        this.program.did_load_default_libs = true;

        for (this.program.root_files) |f| {
            _ = try this.requestFile(f, false);
        }
    }

    fn onParsedFile(this: *@This(), parsed: *ParsedFile) !void {
        const n = parsed.source_name orelse return error.MissingName;
        const key = getHash(n);
        const ref = this.file_requests.get(key) orelse return error.MissingFileRef;

        try this.program.putFileData(key, ref, parsed);

        try this.evaluateDirectives(ref);

        if (!parsed.is_lib) {
            try this.resolveImports(this.program.getFileData(ref));
            try this.program.resolveAndBindModules(this.program.getFileData(ref));
        } else {
            try this.program.bindLibForAsync(this.program.getFileData(ref));
        }

        this.completed += 1;
        if (this.completed == this.file_requests.count()) {
            defer this.file_requests.deinit();

            if (this.on_done) |cb| {
                try cb(this.on_done_ctx);
            }
        }
    }

    pub fn requestFile(this: *@This(), name: []const u8, is_lib: bool) !FileRef {
        // this.mu.lock();
        // defer this.mu.unlock();

        const key = getHash(name);
        if (this.file_requests.get(key)) |ref| return ref;

        const id: FileRef = @intCast(this.program.files.items.len);
        const data = try this.program.allocator.create(ParsedFileData);
        // data.linkage = try this.program.allocator.create(ModuleLinkage);
        // data.linkage.* = ModuleLinkage{};

        try this.program.files.append(data);
        try this.file_requests.put(key, id);

        try this.host_fns.callRequestSourceFile(@This(), this, @This().onParsedFile, name, is_lib);

        return id;
    }

    fn resolveImports(this: *@This(), file: *ParsedFileData) anyerror!void {
        const origin_id = file.id;
        const origin = file.file_name orelse return error.MissingOrigin;

        var iter = file.binder.imports.iterator();
        while (iter.next()) |entry| {
            const resolved = this.host_fns.callResolveFilePath(.module, entry.value_ptr.spec, origin) catch {
                try this.program.getFileData(origin_id).unresolved_imports.append(entry.key_ptr.*);
                continue;
            };

            const id = try this.requestFile(resolved, false);
            try this.program.getFileData(origin_id).import_map.put(entry.key_ptr.*, id);
        }

        for (file.binder.exports.aliased_exports.items) |item| {
            const resolved = this.host_fns.callResolveFilePath(.module, item.spec, origin) catch |err| {
                if (err == error.FileNotFound) continue;
                return err;
            };
            _ = try this.requestFile(resolved, false);
        }
    }

    fn evaluateDirectives(this: *@This(), origin_id: u32) !void {
        const file = this.program.getFileData(origin_id);
        const origin = file.file_name orelse return error.MissingOrigin;
        const directives = file.ast.triple_slash_directives;
        for (directives) |*directive| {
            switch (directive.kind) {
                .lib => {
                    const resolved = try this.host_fns.callResolveFilePath(.lib, directive.value, origin);
                    _ = try this.requestFile(resolved, true);
                },
                .path => {
                    const resolved = try this.host_fns.callResolveFilePath(.path, directive.value, origin);
                    const id = try this.requestFile(resolved, false);
                    try this.program.associated_directives.put(id, this.program.associated_directives.get(origin_id) orelse directive);
                },
                .types => {
                    const resolved = try this.host_fns.callResolveFilePath(.types, directive.value, origin);
                    const id = try this.requestFile(resolved, false);
                    try this.program.associated_directives.put(id, directive);
                },
                .no_default_lib => {},
                else => return error.TODO,
            }
        }
    }
};

fn printSymbol(file: *ParsedFileData, sym_ref: SymbolRef) void {
    const ident = getIdentFromSymbol(file.binder, sym_ref) orelse return;

    const s = getSlice(ident, u8);
    if (parser.getLoc(&file.ast.nodes, ident)) |loc| {
        const file_name = file.file_name orelse "<unknown>";
        const cwd = std.fs.cwd().realpathAlloc(getAllocator(), ".") catch "";
        defer getAllocator().free(cwd);
        var did_alloc = true;
        const rel = std.fs.path.relative(getAllocator(), cwd, file_name) catch blk: {
            did_alloc = false;
            break :blk file_name;
        };
        defer if (did_alloc) getAllocator().free(rel);
        std.debug.print("{s} at {s}:{}:{}\n", .{ s, rel, loc.line + 1, loc.col + 1 });
    } else {
        std.debug.print("{s}\n", .{s});
    }
}

fn printNameWithLocation(f: *ParsedFileData, ref: NodeRef) !void {
    const n = f.ast.nodes.at(ref);
    const name = getSlice(n, u8);
    const loc = parser.getLoc(&f.ast.nodes, n) orelse {
        std.debug.print("{?}\n",.{n.kind});
        return error.MissingLocation;
    };
    const file_name = f.file_name orelse return error.MissingFileName;
    std.debug.print("{s} at {s}:{}:{}\n", .{ name, file_name, loc.line + 1, loc.col + 1 });
}

const ProgramOptions = struct {
    default_libs: []const []const u8 = &.{},
    types: []const []const u8 = &.{},
};

// Roughly based off `tsc`
pub const Program = struct {
    allocator: std.mem.Allocator,

    options: ProgramOptions = .{},
    lib_dir: []const u8,
    root_files: []const []const u8,

    resolver: ModuleResolver,

    libs: std.AutoArrayHashMap(u64, FileRef),
    files: std.ArrayList(*ParsedFileData),
    parsed_files: std.AutoArrayHashMap(u64, ParsedPair),

    import_map: std.AutoArrayHashMapUnmanaged(u64, FileRef) = std.AutoArrayHashMapUnmanaged(u64, FileRef){},

    // Used for re-emits
    associated_directives: std.AutoArrayHashMap(FileRef, *const parser.TripleSlashDirective),

    ambient: Ambient,

    analyzer: ?*Analyzer = null,

    did_load_default_libs: bool = false,
    did_load_async: bool = false,

    // for testing
    virtual_files: std.AutoArrayHashMapUnmanaged(u64, []const u8) = std.AutoArrayHashMapUnmanaged(u64, []const u8){},

    loader: ?*anyopaque = null,

    pub fn init(
        allocator: std.mem.Allocator,
        root_files: []const []const u8,
        lib_dir: []const u8,
    ) !@This() {
        return .{
            .allocator = allocator,
            .root_files = root_files,
            .lib_dir = lib_dir,
            .ambient = Ambient.init(allocator),
            .resolver = try ModuleResolver.initDefault(),
            .libs = std.AutoArrayHashMap(u64, FileRef).init(allocator),
            .files = std.ArrayList(*ParsedFileData).init(allocator),
            .parsed_files = std.AutoArrayHashMap(u64, ParsedPair).init(allocator),
            .associated_directives = std.AutoArrayHashMap(FileRef, *const parser.TripleSlashDirective).init(allocator),
        };
    }

    // for testing
    pub fn addVirtualFile(this: *@This(), file_name: []const u8, data: []const u8) !void {
        try this.virtual_files.put(this.allocator, getHash(file_name), data);
    }

    pub fn getAnalyzer(this: *@This()) !*Analyzer {
        if (this.analyzer) |p| return p;

        const p = try this.allocator.create(Analyzer);
        p.* = try Analyzer.init(this);
        this.analyzer = p;

        return p;
    }

    pub fn putFileData(this: *@This(), hash: u64, id: FileRef, parsed: *ParsedFile) !void {
        if (parsed.source_program == null) parsed.source_program = this;
        const linkage = this.files.items[id].linkage;
        this.files.items[id].* = ParsedFileData.initFromParsedFile(parsed, linkage);
        this.files.items[id].id = id;
        try this.parsed_files.put(hash, .{ parsed, id });
    }

    fn parseFile(this: *@This(), file_name: []const u8, is_lib: bool, is_declaration: bool) !FileRef {
        const hash = getHash(file_name);
        if (this.parsed_files.get(hash)) |pair| {
            return pair[1];
        }

        var parsed: *ParsedFile = undefined;

        if (this.virtual_files.get(hash)) |data| {
            parsed = try ParsedFile.createFromBuffer(data, file_name, is_lib, null);
        } else {
            parsed = try ParsedFile.createFromPath(file_name, is_lib);
        }

        const id: u32 = @intCast(this.files.items.len);
        var data = try this.allocator.create(ParsedFileData);
        // data.linkage = try this.allocator.create(ModuleLinkage);
        // data.linkage.* = ModuleLinkage{};
        try this.files.append(data);
        try this.putFileData(hash, id, parsed);
        data.is_declaration = is_declaration;

        return id;
    }

    pub fn getLib(this: *@This(), name: []const u8) !*ParsedFileData {
        const hash = getHash(name);
        if (this.libs.get(hash)) |ref| {
            return this.getFileData(ref);
        }

        const basename = try std.fmt.allocPrint(this.allocator, "lib.{s}.d.ts", .{name});
        defer this.allocator.free(basename);

        const resolved = try std.fs.path.resolve(this.allocator, &.{ this.lib_dir, basename });
        const id = try this.parseFile(resolved, true, true);

        try this.libs.put(hash, id);

        return this.getFileData(id);
    }

    fn bindMapToGlobals(this: *@This(), file: *ParsedFileData, m: *parser.Binder.SymbolTable, comptime is_type: bool) !void {
        var dst = switch (is_type) {
            true => &this.ambient.global_types,
            false => &this.ambient.globals,
        };

        // TODO: dedupe w/ `bindLibMap`
        var iter = m.iterator();
        while (iter.next()) |entry| {
            const r = try dst.getOrPut(entry.key_ptr.*);
            var id: Ambient.GlobalRef = undefined;
            if (r.found_existing) {
                id = r.value_ptr.*;
            } else {
                id = try this.ambient.globals_allocator.push(.{});
                r.value_ptr.* = id;
            }

            try this.ambient.globals_allocator.at(id).symbols.append(
                this.ambient.globals.allocator,
                .{ .file_id = file.id, .ref = entry.value_ptr.* },
            );
        }
    }

    const BindLibMode = enum { globals, types, modules };

    pub fn bindLibMap(this: *@This(), file: *ParsedFileData, comptime mode: BindLibMode) !void {
        const m = switch (mode) {
            .globals => &file.binder.exports.symbols,
            .types => &file.binder.exports.type_symbols,
            .modules => &file.binder.ambient_modules,
        };

        var dst = switch (mode) {
            .globals => &this.ambient.globals,
            .types => &this.ambient.global_types,
            .modules => &this.ambient.modules,
        };

        var iter = m.iterator();
        while (iter.next()) |entry| {
            const r = try dst.getOrPut(entry.key_ptr.*);
            var id: Ambient.GlobalRef = undefined;
            if (r.found_existing) {
                id = r.value_ptr.*;
            } else {
                id = try this.ambient.globals_allocator.push(.{});
                r.value_ptr.* = id;
            }

            try this.ambient.globals_allocator.at(id).symbols.append(
                this.ambient.globals.allocator,
                .{ .file_id = file.id, .ref = entry.value_ptr.* },
            );

            // we only handle `types` because `declare var x: Foo` is 
            // pointless because you cannot change the type
            if (comptime mode == .types) {
                var sym = file.binder.symbols.at(entry.value_ptr.*);
                // std.debug.assert(sym.hasFlag(.global));
                std.debug.assert(sym.binding == 0);
                sym.binding = id;
            }
        }
    }

    fn maybeBindGlobalNamespace(this: *@This(), file: *ParsedFileData) !void {
        const global_ns = blk: {
            for (file.binder.namespaces.items) |*ns| {
                if (ns.is_global) {
                    break :blk ns;
                }
            }

            return;
        };

        try this.bindMapToGlobals(file, &global_ns.symbols, false);
        try this.bindMapToGlobals(file, &global_ns.type_symbols, true);
    }

    inline fn _bindLib(this: *@This(), f: *ParsedFileData) anyerror!void {
        try this.bindLibMap(f, .globals);
        try this.bindLibMap(f, .types);
        try this.bindLibMap(f, .modules);

        try this.bindGlobals(f);
    }

    fn bindLib(this: *@This(), f: *ParsedFileData) anyerror!void {
        if (f.did_analyze) return;

        f.did_analyze = true;

        try this.evaluateDirectives(f.id);

        try this._bindLib(f);
    }

    pub fn bindLibForAsync(this: *@This(), f: *ParsedFileData) anyerror!void {
        if (f.did_analyze) return;

        f.did_analyze = true;

        try this.maybeBindGlobalNamespace(f);

        try this._bindLib(f);
    }

    fn resolveImports(this: *@This(), file: *ParsedFileData) anyerror!void {
        const origin_id = file.id;
        const origin = file.file_name orelse return error.MissingFileName; 

        var iter = file.binder.imports.iterator();
        while (iter.next()) |entry| {
            const resolved = this.resolver.resolveSpecifier(origin, entry.value_ptr.spec) catch {
                try this.getFileData(origin_id).unresolved_imports.append(entry.key_ptr.*);
                continue;
            };

            const module_id = try this.getResolvedModule(resolved);
            try this.getFileData(origin_id).import_map.put(entry.key_ptr.*, module_id);
        }
    }

    fn getResolvedModule(this: *@This(), resolved: []const u8) !FileRef {
        const hash = std.hash.Wyhash.hash(0, resolved);
        if (this.parsed_files.get(hash)) |tuple| {
            return tuple[1];
        }

        return try this.loadModule(resolved, hash);
    }

    pub inline fn getFileData(this: *const @This(), id: FileRef) *ParsedFileData {
        return this.files.items[id];
    }

    fn evaluateDirectives(this: *@This(), origin_id: u32) !void {
        for (this.getFileData(origin_id).ast.triple_slash_directives) |*directive| {
            switch (directive.kind) {
                .lib => {
                    const lib = try this.getLib(directive.value);
                    try this.bindLib(lib);
                },
                .path => {
                    const resolved = blk: {
                        if (std.fs.path.isAbsolute(directive.value)) break :blk directive.value;

                        const p = this.getFileData(origin_id).file_name orelse return error.MissingImporterFileName;
                        if (std.fs.path.dirname(p)) |dir| {
                            break :blk try std.fs.path.resolve(this.allocator, &.{ dir, directive.value });
                        }
                        break :blk try std.fs.path.resolve(this.allocator, &.{ this.resolver.working_dir, directive.value });
                    };
                    const id = try this.parseFile(resolved, false, true); // d.ts file

                    try this.associated_directives.put(id, this.associated_directives.get(origin_id) orelse directive);

                    try this.maybeBindGlobalNamespace(this.getFileData(id));
                    try this.bindLib(this.getFileData(id));
                },
                .types => {
                    const origin = this.getFileData(origin_id).file_name orelse return error.MissingImporterFileName;
                    const resolved = try this.resolver.resolveTypesDirective(origin, directive.value) orelse return error.MissingTypesDirective;

                    // TODO: this has to read from `package.json`
                    std.debug.print("types dir {s} -> {s}", .{ directive.value, resolved });

                    // TODO: associate directive w/ file
                },
                .no_default_lib => {},
                else => return error.TODO,
            }
        }
    }

    fn loadDefaultLibs(this: *@This()) !void {
        if (this.did_load_default_libs) return;
        this.did_load_default_libs = true;

        for (this.options.default_libs) |name| {
            try this.bindLib(try this.getLib(name));
        }
    }

    fn bindToGlobalSymbol(this: *@This(), f: *ParsedFileData, sym_hash: NodeSymbolHash, sym_ref: SymbolRef, comptime is_type: bool) !void {
        const m = if (comptime is_type) &this.ambient.global_types else &this.ambient.globals;
        var sym = f.binder.symbols.at(sym_ref);

        const global_ref = m.get(sym_hash) orelse blk: {
            if (!comptime is_type) {
                const global_this_hash: u32 = comptime @truncate(std.hash.Wyhash.hash(0, "globalThis"));
                if (sym_hash == global_this_hash) {
                    break :blk std.math.maxInt(u32);
                }
            }

            if (!f.is_lib) {
                // try printNameWithLocation(f, sym.binding);
                const name = getSlice(f.ast.nodes.at(sym.binding), u8);
                // XXX: long name will error here
                var buf: [128]u8 = undefined;
                if (comptime is_type) {
                    const message = try std.fmt.bufPrint(&buf, "Cannot find type '{s}'", .{name});
                    try f.emitError(sym.binding, message);
                } else {
                    const message = try std.fmt.bufPrint(&buf, "Cannot find name '{s}'", .{name});
                    try f.emitError(sym.binding, message);
                }
            }

            // We'll bind early (without a decl) for lib files
            // FIXME: `global` augmentations should only be applied when importing a module that declares it
            const id = try this.ambient.globals_allocator.push(.{});
            try m.put(sym_hash, id);
            break :blk id;
        };

        sym.declaration = global_ref;
    }

    fn getNamespaceFromSymbol(this: *const @This(), absolute_symbol: AbsoluteSymbolRef) Binder.Namespace {
        const b = this.getFileData(absolute_symbol.file_id).binder;
        const ns_sym = b.symbols.at(absolute_symbol.ref);
        
        return b.namespaces.items[ns_sym.binding];
    }

    fn followAliasedExports(this: *@This(), imported_sym: *parser.Symbol, target_hash: u32, sym: *parser.Symbol) !void {
        if (imported_sym.next == std.math.maxInt(u32)) {
            // non-ambient export
            const f = this.getFileData(imported_sym.getOrdinal());

            // FIXME: type exports are ignored 
            const maybe = f.binder.exports.symbols.get(target_hash) orelse {
                return error.AliasedExportError;
            };

            const maybe_sym = f.binder.symbols.at(maybe);
            if (maybe_sym.hasFlag(.aliased_module)) {
                return this.followAliasedExports(maybe_sym, target_hash, sym);
            }
            
            sym.addFlag(.local);
            sym.declaration = maybe;
            sym.ordinal |= @as(u16, @intCast(imported_sym.getOrdinal()));
            return;
        }

        const items = this.ambient.globals_allocator.at(imported_sym.next).symbols.items;
        for (items) |g| {
            const b2 = this.getFileData(g.file_id).binder;
            const ns_sym2 = b2.symbols.at(g.ref);
            const ns2 = b2.namespaces.items[ns_sym2.binding];
            const maybe = ns2.exports.?.symbols.get(target_hash) orelse continue;

            const maybe_sym = b2.symbols.at(maybe);
            if (maybe_sym.hasFlag(.aliased_module)) {
                return this.followAliasedExports(maybe_sym, target_hash, sym);
            }

            sym.addFlag(.local);
            sym.declaration = maybe;
            sym.ordinal |= @as(u16, @intCast(g.file_id));
        }

        return error.MissingAliasedExportedSymbolModule;
    }

    // fn searchAliasedExports(this: *@This(), exports: *parser.Exports, sym_hash: u32) !void {

    // }

    fn bindImports(this: *@This(), f: *ParsedFileData) !void {
        var iter = f.binder.imports.iterator();
        while (iter.next()) |entry| {
            const imported_id = f.import_map.get(entry.key_ptr.*) orelse return error.MissingImport;
            // ambient module
            if (imported_id >> 31 == 1) {
                const global_ref = @as(u31, @truncate(imported_id));
                var sym_iter = entry.value_ptr.bindings.iterator();
                while (sym_iter.next()) |sym_entry| {
                    const symbols = this.ambient.globals_allocator.at(global_ref).symbols;
                    if (symbols.items.len != 1) {
                        return error.TODO_multiple_ambient_module_decls;
                    }

                    const imported_file = this.getFileData(symbols.items[0].file_id);
                    try this.processAliasedExports(imported_file);

                    const b = imported_file.binder;
                    const ns_sym = b.symbols.at(symbols.items[0].ref);
                    const ns = b.namespaces.items[ns_sym.binding];

                    const exports = ns.exports orelse return error.MissingModuleExports;


                    const imported_sym = exports.symbols.get(sym_entry.key_ptr.*) orelse exports.type_symbols.get(sym_entry.key_ptr.*) orelse {
                        printSymbol(f, sym_entry.value_ptr.*);
                        return error.MissingImportedSymbolModule;
                    };

                    var sym = f.binder.symbols.at(sym_entry.value_ptr.*);

                    const imported_sym2 = b.symbols.at(imported_sym);
                    if (imported_sym2.hasFlag(.aliased_module)) {
                        try this.followAliasedExports(imported_sym2, sym_entry.key_ptr.*, sym);
                        continue;
                    }

                    sym.declaration = imported_sym;
                    sym.ordinal |= @as(u16, @intCast(symbols.items[0].file_id));
                }

                // star imports
                var next: SymbolRef = entry.value_ptr.namespace_binding orelse 0;
                while (next != 0) {
                    var sym = f.binder.symbols.at(next);
                    next = sym.next;
                    sym.declaration = global_ref;
                    sym.ordinal |= (@as(u32, @intFromEnum(SymbolFlags.late_bound)) << 16);
                }
                continue;
            }

            const imported_file = this.getFileData(imported_id);
            try this.processAliasedExports(imported_file); // TODO: we could do this lazily if we cannot find symbols normally

            const b = imported_file.binder;

            // std.debug.print("exported symbol count -> {} [id: {}]\n", .{ imported_file.binder.exports.keys().len, imported_id });

            var sym_iter = entry.value_ptr.bindings.iterator();
            while (sym_iter.next()) |sym_entry| {
                const imported_sym = b.exports.symbols.get(sym_entry.key_ptr.*) orelse b.exports.type_symbols.get(sym_entry.key_ptr.*) orelse {
                    printSymbol(f, sym_entry.value_ptr.*);
                    return error.MissingImportedSymbol;
                };

                var sym = f.binder.symbols.at(sym_entry.value_ptr.*);

                const imported_sym2 = b.symbols.at(imported_sym);
                if (imported_sym2.hasFlag(.aliased_module)) {
                    try this.followAliasedExports(imported_sym2, sym_entry.key_ptr.*, sym);
                    continue;
                }

                sym.declaration = imported_sym;
                sym.ordinal |= @as(u16, @intCast(imported_id));
            }

            // star imports
            var next: SymbolRef = entry.value_ptr.namespace_binding orelse 0;
            while (next != 0) {
                var sym = f.binder.symbols.at(next);
                sym.ordinal |= @as(u16, @intCast(imported_id));
                next = sym.next;
            }

            // default imports
            next = entry.value_ptr.default_binding orelse 0;
            while (next != 0) {
                const imported_node = imported_file.binder.default_export orelse return error.MissingDefaultExport;
                var sym = f.binder.symbols.at(next);
                sym.declaration = (1 << 30) | imported_node; // node ref
                sym.ordinal |= @as(u16, @intCast(imported_id));
                next = sym.next;
            }
        }
    }

    fn bindGlobals(this: *@This(), f: *ParsedFileData) !void {
        {
            var iter = f.binder.unbound_symbols.iterator();
            while (iter.next()) |entry| {
                try this.bindToGlobalSymbol(f, entry.key_ptr.*, entry.value_ptr.*, false);
            }
        }
        {
            var iter = f.binder.unbound_type_symbols.iterator();
            while (iter.next()) |entry| {
                try this.bindToGlobalSymbol(f, entry.key_ptr.*, entry.value_ptr.*, true);
            }
        }
    }

    pub fn bindModule(this: *@This(), f: *ParsedFileData) !void {
        try this.resolveAndBindModules(f);

        if (f.did_bind_imports) return;
        f.did_bind_imports = true;

        if (!this.did_load_async) {
            try this.loadDefaultLibs();
            try this.evaluateDirectives(f.id);
        }

        // Finalize modules
        for (f.unresolved_imports.items) |hash| {
            const global_ref = this.ambient.modules.get(hash) orelse {
                const import = f.binder.imports.get(hash) orelse @panic("Missing import spec");
                std.debug.print("missing {s}\n", .{import.spec});
                return error.MissingModule;
            };
            try f.import_map.put(hash, (1 << 31) | global_ref);
        }

        try this.bindGlobals(f);
        try this.bindImports(f);
    }

    fn doTopLevelCfa(this: *@This(), f: *ParsedFileData, start: NodeRef) !void {
        if (!f.did_top_level_cfa) {
            f.did_top_level_cfa = true;
            if (f.is_declaration) return;

            const analyzer = try this.getAnalyzer();
            const first_statement = maybeUnwrapRef(f.ast.nodes.at(start)) orelse 0;

            if (first_statement != 0) {
                std.debug.assert(f.flow == null);
                f.flow = try analyzer.allocator().create(Analyzer.FlowTyper);
                f.flow.?.* = Analyzer.FlowTyper.init(analyzer, f);
                try f.flow.?.visitModule(first_statement);
            }
        }
    }

    fn processAliasedExports(this: *@This(), f: *ParsedFileData) anyerror!void {
        if (f.did_bind_aliased_exports) return;

        f.did_bind_aliased_exports = true;

        const origin = f.file_name orelse return error.MissingFileName;
        const exports2 = &f.binder.exports;
        for (exports2.aliased_exports.items) |item| {
            const resolved = try this.resolver.resolveSpecifier(origin, item.spec);
            const file_id = try this.getResolvedModule(resolved);
            if (!this.did_load_async) {
                try this.bindModule(this.getFileData(file_id));
            }
            try this.processAliasedExports(this.getFileData(file_id));

            var sym2 = f.binder.symbols.at(item.sym);
            sym2.ordinal |= @as(u16, @intCast(file_id));

            if (item.target == 0) {
                if (item.binding == 0) {
                    // export * from 'y'
                    var iter = this.getFileData(file_id).binder.exports.symbols.iterator();

                    sym2.next = std.math.maxInt(u32);

                    while (iter.next()) |item2| {
                        try @constCast(exports2).symbols.put(f.binder.allocator, item2.key_ptr.*, item.sym);
                    }
                } else {
                    // export * as y from 'y'
                    std.debug.assert(sym2.hasFlag(.namespace));
                    try @constCast(exports2).symbols.put(f.binder.allocator, getHashFromNode(f.ast.nodes.at(sym2.binding)), item.sym);
                }
            } else {
                const sym_hash = getHashFromNode(f.ast.nodes.at(sym2.declaration));

                sym2.declaration = this.getFileData(file_id).binder.exports.symbols.get(sym_hash) 
                    orelse return error.MissingAliasedExport;

                if (item.binding == 0) {
                    // export { x } from 'y'
                    try @constCast(exports2).symbols.put(f.binder.allocator, sym_hash, item.sym);
                } else {
                    // export { x as y } from 'y'
                    const aliased_hash = getHashFromNode(f.ast.nodes.at(sym2.binding));
                    try @constCast(exports2).symbols.put(f.binder.allocator, aliased_hash, item.sym);
                }
            }
        }

        // ambient modules cannot use relative specifiers
        var module_iter = f.binder.ambient_modules.iterator();
        while (module_iter.next()) |module_entry| {
            const sym = f.binder.symbols.at(module_entry.value_ptr.*);
            std.debug.assert(sym.hasFlag(.namespace));
            const ns = f.binder.namespaces.items[sym.binding];
            // std.debug.print("re-exports {s} -> {s}\n", .{f.file_name orelse "", ns.module_specifier orelse ""});

            var exports3 = ns.exports orelse return error.MissingModuleExports;
            for (exports3.aliased_exports.items) |item| {
                const global_ref = this.ambient.modules.get(getHash(item.spec)) orelse {
                    std.debug.print("missing re-exported module '{s}'\n", .{item.spec});
                    continue;
                };

                if (item.target == 0) {
                    if (item.binding == 0) {
                        const symbols = this.ambient.globals_allocator.at(global_ref).symbols.items;
                        const x = this.getNamespaceFromSymbol(symbols[0]);
                        var iter = x.exports.?.symbols.iterator();

                        var sym2 = f.binder.symbols.at(item.sym);
                        sym2.ordinal |= @as(u16, @intCast(symbols[0].file_id));
                        sym2.next = global_ref;

                        while (iter.next()) |item2| {
                            try exports3.symbols.put(f.binder.allocator, item2.key_ptr.*, item.sym);
                        }
                    } else {
                        // exports2.symbols.put(f.binder.scopes.allocator, getHashFromNode(), );
                    }
                } else {

                }
            }
        }
    }

    pub fn resolveAndBindModules(this: *@This(), f: *ParsedFileData) !void {
        if (f.did_resolve_imports) return;
        f.did_resolve_imports = true;

        if (!this.did_load_async) {
            try this.resolveImports(f);
        }

        // We need to bind module augmentation early
        try this.bindLibMap(f, .modules);
        try this.maybeBindGlobalNamespace(f); // TODO: only do this in ambient contexts
    }

    fn loadModule(this: *@This(), file_name: []const u8, hash: u64) anyerror!FileRef {
        _ = hash; // TODO: don't compute hash twice
        const id = try this.parseFile(file_name, false, false);
        try this.resolveAndBindModules(this.getFileData(id));

        return id;
    }

    pub fn getBoundFile(this: *@This(), id: FileRef) !*ParsedFileData {
        const f = this.getFileData(id);
        if (!f.is_lib) {
            try this.bindModule(f);
        }

        return this.getFileData(id);
    }

    pub fn getFileByPath(this: *@This(), file_name: []const u8) !?*ParsedFile {
        const hash = getHash(file_name);
        if (this.parsed_files.get(hash)) |pair| return pair[0];
        return null;
    }

    pub fn getFileIdByPath(this: *@This(), file_name: []const u8) !FileRef {
        const hash = getHash(file_name);
        if (this.parsed_files.get(hash)) |pair| {
            return pair[1];
        }
        for (this.root_files) |f| {
            if (strings.eql(f, file_name)) {
                return this.parseFile(f, false, false);
            }
        }

        // for testing
        if (this.virtual_files.get(hash) != null) {
            return this.parseFile(file_name, false, false);
        }

        return error.MissingFile;
    }

    pub fn transformSyn(this: *@This(), file_id: u32, start: NodeRef) !std.AutoArrayHashMap(NodeRef, NodeRef) {
        const f = this.getFileData(file_id);
        std.debug.assert(f.ast.nodes.at(start).kind == .source_file);

        try this.bindModule(f);

        // synth_helper.debugPrintCaptures(f.binder, &f.ast) catch |err| {
        //     std.debug.print("synth_helper debug dump failed: {any}\n", .{err});
        // };

        try this.doTopLevelCfa(f, start);

        const Visitor = struct {
            const Kind = Analyzer.Kind;
            const TypeRef = Analyzer.TypeRef;

            const Helper = enum { style, template, set_attribute, spread_attributes, update_symbol, spread_comp, splice_at, replace, set_slot, set_slot_spread, swap_tree };
            const helper_code = struct {
                const style = "var __style = (c => s => c[s]||=(document.head.insertAdjacentHTML('beforeend', `<style>${s}</style>`),1))({})";
                const sheet = 
                    \\var __sheet = (x,a=document.adoptedStyleSheets) => {
                    \\  for (x of a) if (x._syn) return x
                    \\  a.push(x = new CSSStyleSheet())
                    \\  x._syn = 1
                    \\  return x
                    \\}
                ;
                const style_sectioned = 
                    \\var __style = ((p,c) => (s,q,x=0) => {
                    \\  if (c[s]) return c[s]
                    \\  q = __sheet()
                    \\  while (p.match(s)) q.insertRule(s.slice(x,(x=p.lastIndex)-4),q.cssRules.length)
                    \\  return c[s] = 1
                    \\})(/^---$/gm,{})
                ;

                // const template =
                //     \\var __template = ((c,p) => s => {
                //     \\  c[0] ||= setTimeout(() => c={})
                //     \\  return s in c ? (c[s][1] ||= p(s)).cloneNode(1) : (c[s] = [p(s)])[0]
                //     \\})({}, (s,t=document.createElement('template')) => (t.innerHTML = s, t.content.firstChild))
                // ;
                // fragment variant, should be emitted instead of the normal `__template` when a fragment is needed
                const template =
                    \\var __template = ((c,p) => (s,b) => {
                    \\  c[0] ||= setTimeout(() => c={})
                    \\  return s in c ? (c[s][1] ||= p(s,b)).cloneNode(1) : (c[s] = [p(s,b)])[0]
                    \\})({}, (s,b,t=document.createElement('template')) => {
                    \\  t.innerHTML = s
                    \\  return b ? t.content : t.content.firstChild
                    \\})
                ;
                const set_attribute =
                    \\var __attr = (x,k,v) => v == null ? x.removeAttribute(k) : x.setAttribute(k,v)
                ;
                const spread_attributes =
                    \\var __attr_s = (f => (x, v, c = {}, t, k) => {
                    \\  for (k in c) k in v || f(x, k, null, t)
                    \\  for (k in v) f(x, k, v[k], t)
                    \\  return v
                    \\})((x, k, v, t, u = t?.[k] ?? k) => !u ? __attr(x,k,v) : x[u] = v)
                ;
                const update_symbol = "var __sym_upd = Symbol.update ||= Symbol.for('update')";
                const spread_comp =
                    \\var __comp_s = function(a=this._b) {
                    \\  return this.root._sc(a),a
                    \\}
                ;
                const splice_at = "var __splice_at = (c,i,v,d,l=c.length) => (c.splice(i,d,...v), c.length-l+d)";
                const replace = 
                    \\var __replace_end = (t,v,o=0,i=0) => {
                    \\  for (t[o+i++] of v);
                    \\  t.length = i+o
                    \\}
                ;
                const set_slot =
                    \\var __slot = (a,c,v) => {
                    \\  const q = c?.nextSibling === a
                    // \\  if (c && !q && c.parentNode === a.parentNode) throw Error('Invalid DOM state: prior node or anchor moved')
                    \\  if (typeof v !== 'object') {
                    // weird that browsers seem to not optimize the setter _that_ much for setting the same val
                    // \\    if (q && c.nodeType === 3) { c.nodeValue = v; return c }
                    \\    if (q && c.nodeType === 3) { c.data != v && (c.data = v); return c }
                    \\    v = new Text(v)
                    \\  }
                    \\  q ? c !== v && c.replaceWith(v) : a.parentNode?.insertBefore(v,a)
                    \\  return v
                    \\}
                ;
                const set_slot_spread =
                    \\var __slot_s = (a,b,v) => {
                    \\  let p, n = a.nextSibling
                    \\  for (p of v) n === p ? n=n.nextSibling : n.before(p)
                    \\  while (p = n, n = p.nextSibling, p !== b) p.remove()
                    \\}
                ;
                // TODO: use this for #if regions
                const swap_tree =
                    \\var __swap_tree = (a,b,v,u=[]) => {
                    \\  let p, n = a.nextSibling
                    \\  while (p = n, n = p.nextSibling, p !== b) (u[u.length] = p).remove()
                    \\  a.after(...v)
                    \\  v.length = 0
                    \\}
                ;
            };

            // empty string = no property exists, always use DOM attr
            // null return = use the attr name as the prop name (1:1)
            const html_global_attr_aliases = std.StaticStringMap([]const u8).initComptime(.{
                .{ "accesskey",       "accessKey" },
                .{ "autocapitalize",  "autoCapitalize" },
                .{ "autocorrect",     "autoCorrect" },
                .{ "autofocus",       "autoFocus" },
                .{ "class",           "className" },
                .{ "contenteditable", "contentEditable" },
                .{ "elementtiming",   "elementTiming" },
                .{ "inputmode",       "inputMode" },
                .{ "tabindex",        "tabIndex" },
                .{ "itemid",          "" },
                .{ "itemprop",        "" },
                .{ "itemref",         "" },
                .{ "itemscope",       "" },
                .{ "itemtype",        "" },
                // TODO: do these even work if they're dynamically added via `setAttribute` ?
                // .{ "is",        "" },
                // .{ "exportparts",        "" },
            });

            fn htmlTagAttrAlias(tag: []const u8, attr: []const u8) ?[]const u8 {
                if (std.mem.eql(u8, tag, "a") or std.mem.eql(u8, tag, "area")) {
                    const m = std.StaticStringMap([]const u8).initComptime(.{
                        .{ "hreflang",        "hrefLang" },
                        .{ "referrerpolicy",  "referrerPolicy" },
                    });
                    return m.get(attr);
                }
                if (std.mem.eql(u8, tag, "audio") or std.mem.eql(u8, tag, "video")) {
                    const m = std.StaticStringMap([]const u8).initComptime(.{
                        .{ "autoplay",               "autoPlay" },
                        .{ "controlslist",           "controlsList" },
                        .{ "crossorigin",            "crossOrigin" },
                        .{ "disableremoteplayback",  "disableRemotePlayback" },
                    });
                    return m.get(attr);
                }
                if (std.mem.eql(u8, tag, "button")) {
                    const m = std.StaticStringMap([]const u8).initComptime(.{
                        .{ "commandfor",           "commandFor" },
                        .{ "formaction",           "formAction" },
                        .{ "formenctype",          "formEncType" },
                        .{ "formmethod",           "formMethod" },
                        .{ "formnovalidate",       "formNoValidate" },
                        .{ "formtarget",           "formTarget" },
                        .{ "popovertarget",        "popoverTarget" },
                        .{ "popovertargetaction",  "popoverTargetAction" },
                    });
                    return m.get(attr);
                }
                if (std.mem.eql(u8, tag, "del") or std.mem.eql(u8, tag, "ins") or std.mem.eql(u8, tag, "time")) {
                    const m = std.StaticStringMap([]const u8).initComptime(.{
                        .{ "datetime", "dateTime" },
                    });
                    return m.get(attr);
                }
                if (std.mem.eql(u8, tag, "dialog")) {
                    const m = std.StaticStringMap([]const u8).initComptime(.{
                        .{ "closedby", "closedBy" },
                    });
                    return m.get(attr);
                }
                if (std.mem.eql(u8, tag, "form")) {
                    const m = std.StaticStringMap([]const u8).initComptime(.{
                        .{ "accept-charset", "acceptCharset" },
                        .{ "autocomplete",   "autoComplete" },
                        .{ "novalidate",     "noValidate" },
                    });
                    return m.get(attr);
                }
                if (std.mem.eql(u8, tag, "iframe")) {
                    const m = std.StaticStringMap([]const u8).initComptime(.{
                        .{ "frameborder",     "frameBorder" },
                        .{ "referrerpolicy",  "referrerPolicy" },
                        .{ "srcdoc",          "srcDoc" },
                    });
                    return m.get(attr);
                }
                if (std.mem.eql(u8, tag, "img")) {
                    const m = std.StaticStringMap([]const u8).initComptime(.{
                        .{ "crossorigin",    "crossOrigin" },
                        .{ "fetchpriority",  "fetchPriority" },
                        .{ "referrerpolicy", "referrerPolicy" },
                        .{ "srcset",         "srcSet" },
                        .{ "usemap",         "useMap" },
                    });
                    return m.get(attr);
                }
                if (std.mem.eql(u8, tag, "input")) {
                    const m = std.StaticStringMap([]const u8).initComptime(.{
                        .{ "autocomplete",   "autoComplete" },
                        .{ "formaction",     "formAction" },
                        .{ "formenctype",    "formEncType" },
                        .{ "formmethod",     "formMethod" },
                        .{ "formnovalidate", "formNoValidate" },
                        .{ "formtarget",     "formTarget" },
                        .{ "maxlength",      "maxLength" },
                        .{ "minlength",      "minLength" },
                        .{ "readonly",       "readOnly" },
                    });
                    return m.get(attr);
                }
                if (std.mem.eql(u8, tag, "label") or std.mem.eql(u8, tag, "output")) {
                    const m = std.StaticStringMap([]const u8).initComptime(.{
                        .{ "for", "htmlFor" },
                    });
                    return m.get(attr);
                }
                if (std.mem.eql(u8, tag, "link")) {
                    const m = std.StaticStringMap([]const u8).initComptime(.{
                        .{ "charset",        "charSet" },
                        .{ "crossorigin",    "crossOrigin" },
                        .{ "fetchpriority",  "fetchPriority" },
                        .{ "hreflang",       "hrefLang" },
                        .{ "imagesrcset",    "imageSrcset" },
                        .{ "referrerpolicy", "referrerPolicy" },
                    });
                    return m.get(attr);
                }
                if (std.mem.eql(u8, tag, "meta")) {
                    const m = std.StaticStringMap([]const u8).initComptime(.{
                        .{ "charset",    "charSet" },
                        .{ "http-equiv", "httpEquiv" },
                    });
                    return m.get(attr);
                }
                if (std.mem.eql(u8, tag, "object")) {
                    const m = std.StaticStringMap([]const u8).initComptime(.{
                        .{ "usemap", "useMap" },
                    });
                    return m.get(attr);
                }
                if (std.mem.eql(u8, tag, "script")) {
                    const m = std.StaticStringMap([]const u8).initComptime(.{
                        .{ "charset",        "charSet" },
                        .{ "crossorigin",    "crossOrigin" },
                        .{ "nomodule",       "noModule" },
                        .{ "referrerpolicy", "referrerPolicy" },
                    });
                    return m.get(attr);
                }
                if (std.mem.eql(u8, tag, "select")) {
                    const m = std.StaticStringMap([]const u8).initComptime(.{
                        .{ "autocomplete", "autoComplete" },
                    });
                    return m.get(attr);
                }
                if (std.mem.eql(u8, tag, "source")) {
                    const m = std.StaticStringMap([]const u8).initComptime(.{
                        .{ "srcset", "srcSet" },
                    });
                    return m.get(attr);
                }
                if (std.mem.eql(u8, tag, "td") or std.mem.eql(u8, tag, "th")) {
                    const m = std.StaticStringMap([]const u8).initComptime(.{
                        .{ "colspan", "colSpan" },
                        .{ "rowspan", "rowSpan" },
                    });
                    return m.get(attr);
                }
                if (std.mem.eql(u8, tag, "textarea")) {
                    const m = std.StaticStringMap([]const u8).initComptime(.{
                        .{ "autocomplete", "autoComplete" },
                        .{ "maxlength",    "maxLength" },
                        .{ "minlength",    "minLength" },
                        .{ "readonly",     "readOnly" },
                    });
                    return m.get(attr);
                }
                if (std.mem.eql(u8, tag, "track")) {
                    const m = std.StaticStringMap([]const u8).initComptime(.{
                        .{ "srclang", "srcLang" },
                    });
                    return m.get(attr);
                }
                return null;
            }

            fn isCamelCase(s: []const u8) bool {
                for (s) |c| if (c >= 'A' and c <= 'Z') return true;
                return false;
            }

            // only meaningful for HTML elements, null = use setAttribute
            fn htmlResolvePropName(tag: []const u8, key: []const u8) ?[]const u8 {
                if (strings.startsWith(key, "data-") or strings.startsWith(key, "aria-")) return null;
                if (isCamelCase(key)) return key;
                if (htmlTagAttrAlias(tag, key)) |alias| return if (alias.len == 0) null else alias;
                if (html_global_attr_aliases.get(key)) |alias| return if (alias.len == 0) null else alias;
                // assume attr name == prop name 
                return key;
            }

            fn isHtmlIntrinsic(tag: []const u8) bool {
                const svg_math = std.StaticStringMap(void).initComptime(.{
                    .{ "svg",            {} }, .{ "path",          {} }, .{ "circle",   {} },
                    .{ "rect",           {} }, .{ "ellipse",       {} }, .{ "line",     {} },
                    .{ "polyline",       {} }, .{ "polygon",       {} }, .{ "g",        {} },
                    .{ "use",            {} }, .{ "defs",          {} }, .{ "symbol",   {} },
                    .{ "clipPath",       {} }, .{ "mask",          {} }, .{ "filter",   {} },
                    .{ "text",           {} }, .{ "tspan",         {} }, .{ "textPath", {} },
                    .{ "foreignObject",  {} }, .{ "linearGradient",{} }, .{ "radialGradient", {} },
                    .{ "stop",           {} }, .{ "pattern",       {} }, .{ "marker",   {} },
                    .{ "animate",        {} }, .{ "set",           {} },
                    .{ "math",           {} }, .{ "mi",            {} }, .{ "mo",       {} },
                    .{ "mn",             {} }, .{ "mrow",          {} }, .{ "mfrac",    {} },
                    .{ "msub",           {} }, .{ "msup",          {} },
                });
                return !svg_math.has(tag);
            }

            file: *ParsedFileData,
            nodes: *BumpAllocator(AstNode),
            factory: *parser.Factory,
            analyzer: *Analyzer,
            replacements: *std.AutoArrayHashMap(NodeRef, NodeRef),
            is_async_ctx: bool = true, // we start in a module
            should_use_parens: bool = false,
            as_type_node: ?*const AstNode = null,
            run_directive_symbols: std.AutoHashMapUnmanaged(u32, void) = .{},
            symbol_replacements: std.AutoHashMapUnmanaged(u32, NodeRef) = .{},
            proxied_symbol_replacements: std.AutoHashMapUnmanaged(u32, NodeRef) = .{},
            jsx_emit_state: ?*InlineEmitState = null,

            style_visitor: StyleVisitor = .{},

            helpers: std.EnumSet(Helper) = std.EnumSet(Helper).initEmpty(),

            type_helpers: std.AutoArrayHashMapUnmanaged(TypeRef, []const u8) = .{},

            fn requireHelper(self: *@This(), comptime h: Helper) []const u8 {
                self.helpers.insert(h);
                // some helpers depend on other helpers
                if (h == .spread_attributes) self.helpers.insert(.set_attribute);
                //if (h == .set_slot_spread) self.helpers.insert(.set_slot);
                return switch (h) {
                    .style => "__style",
                    .template => "__template",
                    .set_attribute => "__attr",
                    .spread_attributes => "__attr_s",
                    .update_symbol => "__sym_upd",
                    .spread_comp => "__comp_s",
                    .splice_at => "__splice_at",
                    .replace => "__replace",
                    .set_slot => "__slot",
                    .set_slot_spread => "__slot_s",
                    .swap_tree => "__swap_tree",
                };
            }

            fn typeofExp(self: *@This(), subject: NodeRef, comptime s: []const u8) !NodeRef {
                const lhs = try self.factory.createTypeofExpression(subject);
                const rhs = try self.factory.createStringLiteral(s);
                return self.factory.createBinaryExpression(lhs, .equals_equals_equals_token, rhs);
            }

            fn maybeAddLogicalParens(self: *@This(), ref: NodeRef, comptime operator: SyntaxKind) !NodeRef { 
                const n = self.nodes.at(ref);
                if (n.kind != .binary_expression) return ref;
                
                switch (@as(SyntaxKind, @enumFromInt(n.len))) {
                    .bar_bar_token,
                    .question_question_token,
                    .ampersand_ampersand_token => |other| {
                        if (other == operator) {
                            return ref;
                        }
                        return self.factory.createParenthesizedExpression(ref);
                    },
                    else => return ref,
                }
            }

            fn binaryExpWithParens(self: *@This(), left: NodeRef, comptime operator: SyntaxKind, right: NodeRef) !NodeRef {
                return self.factory.createBinaryExpression(
                    try self.maybeAddLogicalParens(left, operator),
                    operator,
                    try self.maybeAddLogicalParens(right, operator),
                );
            }

            fn appendEscapedRegex(_: *@This(), pattern: *std.ArrayList(u8), text: []const u8) !void {
                for (text) |c| {
                    switch (c) {
                        '.', '*', '+', '?', '^', '$', '{', '}', '[', ']', '|', '(', ')', '\\' => {
                            try pattern.append('\\');
                            try pattern.append(c);
                        },
                        else => try pattern.append(c),
                    }
                }
            }

            fn createHelper(self: *@This(), ty: TypeRef, decl_ref: NodeRef, followed: TypeRef) ![]const u8 {
                const name = try std.fmt.allocPrint(getAllocator(), "__is{d}", .{self.type_helpers.count()});

                try self.type_helpers.put(getAllocator(), ty, name);

                const param_ident = try self.factory.createIdentifier("x");
                const check = try self.generateIsExpression(param_ident, followed);
                const fn_name = try self.factory.createIdentifierAllocated(name);
                const param = try self.factory.createParameter(param_ident, 0);
                const helper_ref = try self.factory.createFunctionDeclaration(fn_name, param, &.{
                    try self.factory.createReturnStatement(check)
                });

                const decl = self.file.ast.nodes.at(decl_ref);
                const clone_ref = try self.factory.cloneNode(decl);

                self.file.ast.nodes.at(helper_ref).next = decl.next;
                self.file.ast.nodes.at(clone_ref).next = helper_ref;

                try self.replacements.put(decl_ref, clone_ref);

                return name;
            }

            fn callHelper(self: *@This(), helper_name: []const u8, subject: u32) !u32 {
                const fn_ident = try self.factory.createIdentifier(helper_name);
                return self.factory.createCallExpression(fn_ident, subject);
            }

            fn addReplacement(self: *@This(), ref: NodeRef, new_ref: NodeRef) !void {
                if (self.replacements.get(ref)) |existing_ref| {
                    const orig = self.nodes.at(ref);
                    if (orig.next != 0) {
                        return error.ReplacementConflict;
                    }
                    const existing = self.nodes.at(existing_ref);
                    self.nodes.at(new_ref).next = existing.next;
                }
                try self.replacements.put(ref, new_ref);
            }

            fn prependStatements(self: *@This(), head: NodeRef, tail: NodeRef) !void {
                const s = unwrapRef(self.nodes.at(start));
                if (self.replacements.get(s)) |r| {
                    self.nodes.at(tail).next = r;
                } else {
                    self.nodes.at(tail).next = s;
                }
                try self.replacements.put(s, head);
            }

            // use in lists dealing with re-used references
            fn cloneIfNeeded(self: *@This(), ref: NodeRef) !NodeRef {
                const n = self.nodes.at(ref);
                if (n.kind != .identifier) return ref;
                const symbol_id = n.extra_data;
                if (symbol_id == 0) return ref;
                const t = self.symbol_replacements.get(symbol_id) orelse return ref;
                return try self.factory.cloneNodeRef(t);
            }

            // focused on unary
            // e.g. `!! x > y` --> `!!(x > y)`
            fn addParensIfNeeded(self: *@This(), exp: NodeRef) !NodeRef {
                return switch (self.nodes.at(exp).kind) {
                    .prefix_unary_expression,
                    .postfix_unary_expression,
                    .no_substitution_template_literal,
                    .string_literal, .numeric_literal,
                    .identifier, .property_access_expression, 
                    .element_access_expression, 
                    .call_expression, .parenthesized_expression,
                    .true_keyword, .false_keyword, .undefined_keyword, .null_keyword => exp,
                    else => try self.factory.createParenthesizedExpression(exp),
                };
            }

            // e.g. `foo()` -> `!!foo()`
            // if the exp guarantees boolean, the exp is returned unchanged
            fn normalizeExpToBoolean(self: *@This(), exp: NodeRef) !NodeRef {
                const n = self.nodes.at(exp);
                switch (n.kind) {
                    .true_keyword, .false_keyword, .is_expression => return exp,
                    .prefix_unary_expression => {
                        switch (@as(SyntaxKind, @enumFromInt(getPackedData(n).left))) {
                            .exclamation_token => {
                                return exp;
                            },
                            else => {},
                        }  
                    },
                    .binary_expression => {
                        switch (@as(SyntaxKind, @enumFromInt(n.len))) {
                            .in_keyword, .instanceof_keyword,
                            .equals_equals_token, .equals_equals_equals_token,
                            .exclamation_equals_token, .exclamation_equals_equals_token,
                            .less_than_token, .less_than_equals_token, 
                            .greater_than_token, .greater_than_equals_token => {
                                return exp;
                            },
                            .ampersand_ampersand_token, .bar_bar_token => {
                                const d = getPackedData(n);
                                if (try self.normalizeExpToBoolean(d.left) == d.left) {
                                    if (try self.normalizeExpToBoolean(d.right) == d.right) {
                                        return exp;
                                    }
                                }
                            },
                            else => {},
                        }
                    },
                    .parenthesized_expression => {
                        const inner = unwrapRef(n);
                        if (try self.normalizeExpToBoolean(inner) == inner) return exp;
                    },
                    .identifier => {
                        const sym_id = n.extra_data;
                        if (sym_id != 0) {
                            const sym = self.file.binder.symbols.at(sym_id);
                            if (sym.hasFlag(.@"const") and !sym.hasFlag(.late_bound) and !sym.hasFlag(.imported) and sym.declaration != 0) {
                                const decl = self.nodes.at(sym.declaration);
                                if (decl.kind == .variable_declaration) {
                                    const initializer = getPackedData(decl).right;
                                    if (try self.normalizeExpToBoolean(initializer) == initializer) {
                                        return exp;
                                    }
                                }
                            }
                        }
                    },
                    // todo: type-assisted emit (would be opt-in at first)
                    else => {},
                }
                return try self.factory.createPrefixUnaryExpression(.exclamation_token,
                    try self.factory.createPrefixUnaryExpression(.exclamation_token,
                    try self.addParensIfNeeded(exp)));
            }

            fn getDeclarationForAlias(self: *@This(), ty: TypeRef) ?NodeRef {
                if (ty >= @intFromEnum(Kind.false)) return null;

                const t = self.analyzer.types.at(ty);
                if (t.getKind() != .alias) return null;

                const alias_file_id = t.slot3;
                const sym_ref = t.slot4;

                if (alias_file_id != self.file.id) return null;

                const sym = self.file.binder.symbols.at(sym_ref);
                return sym.declaration;
            }

            fn getOrCreateHelperForType(self: *@This(), ty: TypeRef) !?[]const u8 {
                if (self.type_helpers.get(ty)) |name| {
                    return name;
                }

                const decl_ref = self.getDeclarationForAlias(ty) orelse return null;

                const followed = try self.analyzer.evaluateType(ty, (1 << 0) | @intFromEnum(Analyzer.EvaluationFlags.no_instance_aliases));
                if (self.analyzer.getKindOfRef(followed) != .object_literal) {
                    return null;
                }

                return try self.createHelper(ty, decl_ref, followed);
            }

            fn generateUnionCheck(self: *@This(), subject: NodeRef, elements: []const TypeRef) !NodeRef {
                // TODO: unions need to be sorted
                // we should check tuples -> array -> objects


                var lhs: u32 = try self.generateIsExpression(subject, elements[0]);

                for (1..elements.len) |i| {
                    const n = try self.generateIsExpression(subject, elements[i]);
                    lhs = try self.binaryExpWithParens(lhs, .bar_bar_token, n);
                }

                return lhs;
            }

            fn generateObjectCheck(self: *@This(), subject: NodeRef, members: []Analyzer.ObjectLiteralMember) !NodeRef {
                var lhs: NodeRef = 0;

                for (members) |*u| {
                    if (u.kind != .property and u.kind != .method) continue; // TODO

                    if (self.analyzer.getKindOfRef(u.name) == .symbol_literal) continue; // TODO

                    const name = self.analyzer.getSliceFromLiteral(u.name);
                    const sub = try self.factory.createPropertyAccessExpression(subject, name);
                    var ty = try u.getType(self.analyzer);
                    if (u.hasFlag(NodeFlags.optional)) {
                        ty = try self.analyzer.toUnion(&.{ty, @intFromEnum(Kind.undefined)});
                    }

                    const q = try self.generateIsExpression(sub, ty);

                    if (lhs == 0) {
                        lhs = q;
                    } else {
                        lhs = try self.binaryExpWithParens(lhs, .ampersand_ampersand_token, q);
                    }
                }

                return lhs;
            }

            fn generateIsExpression(self: *@This(), subject: u32, ty: u32) anyerror!u32 {
                const getSlice2 = Analyzer.getSlice2;

                if (self.analyzer.isParameterizedRef(ty)) {
                    if (ty < @intFromEnum(Kind.false)) {
                        // const inner = self.analyzer.types.at(ty);
                        // if (self.analyzer.getKindOfRef(inner.slot3) == .function_literal) {
                        //     return try self.typeofExp(subject, "function");
                        // }
                    } else {
                        self.analyzer.printTypeInfo(ty);
                        return error.TODO_parameterized;
                    }
                }

                if (ty >= @intFromEnum(Kind.false)) {
                    if (ty == @intFromEnum(Kind.false)) {
                        const rhs = try self.factory.createFalse();
                        return self.factory.createBinaryExpression(subject, .equals_equals_equals_token, rhs);
                    }
                    if (ty == @intFromEnum(Kind.true)) {
                        const rhs = try self.factory.createTrue();
                        return self.factory.createBinaryExpression(subject, .equals_equals_equals_token, rhs);
                    }
                    if (ty == @intFromEnum(Kind.undefined)) {
                        const rhs = try self.factory.createUndefined();
                        return self.factory.createBinaryExpression(subject, .equals_equals_equals_token, rhs);
                    }
                    if (ty == @intFromEnum(Kind.null)) {
                        const rhs = try self.factory.createNull();
                        return self.factory.createBinaryExpression(subject, .equals_equals_equals_token, rhs);
                    }

                    // if (ty == @intFromEnum(Kind.void)) {
                    //     return try this.getIntrinsic("Void");
                    // }

                    if (ty == @intFromEnum(Kind.any)) {
                        return self.factory.createTrue();
                    }
                    if (ty == @intFromEnum(Kind.unknown)) {
                        return self.factory.createTrue();
                    }
                    if (ty == @intFromEnum(Kind.never)) {
                        return self.factory.createFalse();
                    }

                    if (ty == @intFromEnum(Kind.string)) {
                        return self.typeofExp(subject, "string");
                    }
                    if (ty == @intFromEnum(Kind.number)) {
                        return self.typeofExp(subject, "number");
                    }
                    if (ty == @intFromEnum(Kind.boolean)) {
                        return self.typeofExp(subject, "boolean");
                    }
                    if (ty == @intFromEnum(Kind.object)) {
                        return self.typeofExp(subject, "object");
                    }
                    if (ty == @intFromEnum(Kind.symbol)) {
                        return self.typeofExp(subject, "symbol");
                    }

                    if (ty == @intFromEnum(Kind.empty_string)) {
                        const rhs = try self.factory.createStringLiteral("");
                        return self.factory.createBinaryExpression(subject, .equals_equals_equals_token, rhs);
                    } else if (ty == @intFromEnum(Kind.empty_object)) {
                    //    return try this.createShape("__Object");
                    } else if (ty == @intFromEnum(Kind.empty_tuple)) {
                    //    return try this.createShape("__Tuple");
                    }

                    // empty_element -> undefined ?

                    if (ty >= @intFromEnum(Kind.zero)) {
                        const v = self.analyzer.getDoubleFromType(ty);
                        const rhs = try self.factory.createNumericLiteral(v);
                        return self.factory.createBinaryExpression(subject, .equals_equals_equals_token, rhs);
                    }

                    self.analyzer.printTypeInfo(ty);
                    return error.TODO_unhandled_primitve_type;
                }

                const t = self.analyzer.types.at(ty);
                switch (t.getKind()) {
                    .alias => {
                        if (t.hasFlag(.instance_alias)) {
                            const alias_file_id = t.slot3;
                            const sym_ref = t.slot4;

                            // only handle symbols in the same file (TODO: handle more)
                            if (alias_file_id != self.file.id) {
                                return error.InstanceOfCrossFileNotSupported;
                            }

                            const sym = self.file.binder.symbols.at(sym_ref);
                            const decl = self.file.ast.nodes.at(sym.declaration);
                            const ident_ref = getPackedData(decl).left;
                            const ident = self.file.ast.nodes.at(ident_ref);
                            const name = getSlice(ident, u8);

                            const class_ident = try self.factory.createIdentifier(name);
                            return self.factory.createBinaryExpression(subject, .instanceof_keyword, class_ident);
                        }
                        if (t.hasFlag(.enum_alias)) {
                            const o_ref =  try self.analyzer.maybeResolveAlias(ty);
                            const o = self.analyzer.types.at(o_ref);
                            const members = getSlice2(o, Analyzer.ObjectLiteralMember);
                            var vals = std.ArrayListUnmanaged(TypeRef){};
                            defer vals.deinit(self.analyzer.allocator());
                            try vals.ensureTotalCapacity(self.analyzer.allocator(), members.len);
                            for (members) |*m| {
                                const v = try m.getType(self.analyzer);
                                vals.appendAssumeCapacity(v);
                            }
                            return try self.generateUnionCheck(subject, vals.items);
                        }

                        if (t.hasFlag(.global)) {
                            if (try self.analyzer.getGlobalType("Error", .{})) |error_type| {
                                if (ty == error_type) {
                                    // TODO: use Error.isError, or add `DOMException`
                                    const error_ident = try self.factory.createIdentifier("Error");
                                    return self.factory.createBinaryExpression(subject, .instanceof_keyword, error_ident);
                                }
                            }
                        }

                        if (try self.getOrCreateHelperForType(ty)) |helper_name| {
                            return try self.callHelper(helper_name, subject);
                        }

                        const followed = try self.analyzer.evaluateType(ty, (1 << 0) | @intFromEnum(Analyzer.EvaluationFlags.no_instance_aliases) | @intFromEnum(Analyzer.EvaluationFlags.no_enum_aliases));
                        if (ty == followed) {
                            self.analyzer.printTypeInfo(ty);
                            return error.RecursiveAlias;
                        }

                        const result = try self.generateIsExpression(subject, followed);

                        return result;
                    },
                    .conditional, .indexed, .keyof, .query, .mapped, .intersection => {
                        const followed = try self.analyzer.evaluateType(ty, 1 << 0 | 1 << 30);
                        if (ty == followed) {
                            self.analyzer.printTypeInfo(ty);
                            return error.Recursive;
                        }

                        return try self.generateIsExpression(subject, followed);
                    },
                    .array => {
                        const is_array = try self.factory.createPropertyAccessExpression(
                            try self.factory.createIdentifier("Array"),
                            "isArray"
                        );
                        const lhs: u32 = try self.factory.createCallExpression(is_array, subject);

                        const fn_subject = try self.factory.createIdentifier("el");
                        const inner = try self.generateIsExpression(fn_subject, t.slot0);
                        if (self.nodes.at(inner).kind == .false_keyword or self.nodes.at(inner).kind == .true_keyword) {
                            return lhs;
                        }

                        const param = try self.factory.createParameter(fn_subject, 0);
                        const predicate = try self.factory.createSingleParamArrowFunction(param, inner, 0);

                        const every_access = try self.factory.createPropertyAccessExpression(subject, "every");
                        const every = try self.factory.createCallExpression(every_access, predicate);
                        return self.factory.createBinaryExpression(lhs, .ampersand_ampersand_token, every);
                    },
                    .tuple => {
                        const is_array = try self.factory.createPropertyAccessExpression(
                            try self.factory.createIdentifier("Array"),
                            "isArray"
                        );
                        var lhs: u32 = try self.factory.createCallExpression(is_array, subject);

                        const elements = getSlice2(t, TypeRef);
                        const has_spread = elements.len > 0 and
                            elements[elements.len - 1] < @intFromEnum(Kind.false) and
                            self.analyzer.types.at(elements[elements.len - 1]).hasFlag(.spread);

                        if (elements.len > 0) {
                            const len_access = try self.factory.createPropertyAccessExpression(subject, "length");
                            const min_len = if (has_spread) elements.len - 1 else elements.len;
                            const len = try self.factory.createNumericLiteral(min_len);
                            const cmp = if (has_spread)
                                try self.factory.createBinaryExpression(len_access, .greater_than_equals_token, len)
                            else
                                try self.factory.createBinaryExpression(len_access, .equals_equals_equals_token, len);
                            lhs = try self.factory.createBinaryExpression(lhs, .ampersand_ampersand_token, cmp);
                        }

                        for (elements, 0..) |el, i| {
                            if (el < @intFromEnum(Kind.false) and self.analyzer.types.at(el).hasFlag(.spread)) {
                                if (i != elements.len - 1) {
                                    return error.TODO_non_terminal_rest_tuple;
                                }

                                const spread_type = self.analyzer.types.at(el);
                                const array_type = self.analyzer.types.at(spread_type.slot1);
                                const element_type: TypeRef = array_type.slot0;

                                if (element_type == @intFromEnum(Kind.any)) break;

                                const fn_subject = try self.factory.createIdentifier("el");
                                const inner = try self.generateIsExpression(fn_subject, element_type);

                                if (self.nodes.at(inner).kind != .false_keyword and self.nodes.at(inner).kind != .true_keyword) {
                                    const param = try self.factory.createParameter(fn_subject, 0);
                                    const predicate = try self.factory.createSingleParamArrowFunction(param, inner, 0);

                                    const slice_access = try self.factory.createPropertyAccessExpression(subject, "slice");
                                    const sliced = try self.factory.createCallExpression(slice_access, try self.factory.createNumericLiteral(i));
                                    const every_access = try self.factory.createPropertyAccessExpression(sliced, "every");
                                    const every = try self.factory.createCallExpression(every_access, predicate);

                                    lhs = try self.factory.createBinaryExpression(lhs, .ampersand_ampersand_token, every);
                                }

                                break;
                            }

                            const elem_access = try self.factory.createElementAccessExpression(subject, i);
                            const pred = try self.generateIsExpression(elem_access, el);

                            lhs = try self.factory.createBinaryExpression(lhs, .ampersand_ampersand_token, pred);
                        }

                        return lhs;
                    },
                    .tuple_element => {
                        return try self.generateIsExpression(subject, t.slot1);
                    },
                    .@"union" => {
                        const elements = getSlice2(t, TypeRef);
                        return try self.generateUnionCheck(subject, elements);
                    },
                    .string_literal => {
                        const s = self.analyzer.getSliceFromLiteral(ty);
                        const rhs = try self.factory.createStringLiteral(s);
                        return self.factory.createBinaryExpression(subject, .equals_equals_equals_token, rhs);
                    },
                    .number_literal => {
                        const v = self.analyzer.getDoubleFromType(ty);
                        const rhs = try self.factory.createNumericLiteral(v);
                        return self.factory.createBinaryExpression(subject, .equals_equals_equals_token, rhs);
                    },
                    .object_literal => {
                        // check proto first
                        var lhs: u32 = if (t.slot3 != 0)
                            try self.generateIsExpression(subject, t.slot3)
                        else blk: {
                            const typeof_check = try self.typeofExp(subject, "object");
                            const null_check = try self.factory.createBinaryExpression(subject, .exclamation_equals_equals_token, try self.factory.createNull());
                            break :blk try self.factory.createBinaryExpression(typeof_check, .ampersand_ampersand_token, null_check);
                        };

                        const members = getSlice2(t, Analyzer.ObjectLiteralMember);
                        const rhs = try self.generateObjectCheck(subject, members);
                        if (rhs != 0) {
                            lhs = try self.binaryExpWithParens(lhs, .ampersand_ampersand_token, rhs);
                        }

                        return lhs;
                    },
                    .parameterized => {
                        return try self.typeofExp(subject, "function");
                    },
                    .function_literal => {
                        return try self.typeofExp(subject, "function");
                    },
                    .class => {
                        // slot6 contains the instance_alias for the class
                        if (t.slot6 != 0) {
                            return try self.generateIsExpression(subject, t.slot6);
                        }
                        return error.ClassWithoutInstanceAlias;
                    },
                    .template_literal => {
                        const slice = getSlice2(t, TypeRef);

                        var pattern = std.ArrayList(u8).init(getAllocator());
                        try pattern.append('/');
                        try pattern.append('^');

                        if (slice.len > 0) {
                            const head_text = self.analyzer.getSliceFromLiteral(slice[0]);
                            try self.appendEscapedRegex(&pattern, head_text);
                        }

                        var i: u32 = 1;
                        while (i < slice.len) : (i += 2) {
                            const exp_type = slice[i];

                            try self.appendRegExpPattern(&pattern, exp_type);

                            if (i + 1 < slice.len) {
                                const text = self.analyzer.getSliceFromLiteral(slice[i + 1]);
                                try self.appendEscapedRegex(&pattern, text);
                            }
                        }

                        try pattern.append('$');
                        try pattern.append('/');

                        const typeof_check = try self.typeofExp(subject, "string");

                        const regex_node = try self.nodes.push(.{
                            .kind = .regular_expression_literal,
                            .data = pattern.items.ptr,
                            .len = @intCast(pattern.items.len),
                        });

                        const test_access = try self.factory.createPropertyAccessExpression(regex_node, "test");
                        const test_call = try self.factory.createCallExpression(test_access, subject);

                        return self.factory.createBinaryExpression(typeof_check, .ampersand_ampersand_token, test_call);
                    },
                    else => {},
                    // module_namespace
                    // symbol_literal (only well-known symbols)
                }

                self.analyzer.printTypeInfo(ty);
                return error.TODO_unhandled_allocated_type;
            }
    
            fn generateNarrowedIsExpression(self: *@This(), subject: NodeRef, ty: TypeRef, subject_type: TypeRef) anyerror!u32 {
                if (ty == subject_type) {
                    return self.factory.createTrue();
                }

                if (subject_type == @intFromEnum(Kind.any) or subject_type == @intFromEnum(Kind.unknown)) {
                    return self.generateIsExpression(subject, ty);
                }

                if (!try self.analyzer.isAssignableTo(ty, subject_type)) {
                    return self.factory.createFalse();
                }

                const et = try self.analyzer.evaluateType(ty, @intFromEnum(Analyzer.EvaluationFlags.no_objects));
                if (et >= @intFromEnum(Kind.false)) {
                    return self.generateIsExpression(subject, et);
                }
                
                const st = try self.analyzer.evaluateType(subject_type, @intFromEnum(Analyzer.EvaluationFlags.no_objects));
                if (st >= @intFromEnum(Kind.false) or self.analyzer.getKindOfRef(st) != .@"union") {
                    return self.generateIsExpression(subject, et);
                }

                const nt = try self.analyzer.excludeType(st, et);

                // no overlap
                if (nt == st) {
                    return self.factory.createFalse();
                }

                if (nt >= @intFromEnum(Kind.false) or self.analyzer.getKindOfRef(nt) != .@"union") {
                    if (et < @intFromEnum(Kind.false) and self.analyzer.getKindOfRef(et) == .object_literal) {
                        if (try self.analyzer.findBestObjectDiscriminant(&.{nt}, et)) |disc| {
                            const s = self.analyzer.getSliceFromLiteral(disc.key);
                            const prop_node = try self.factory.createPropertyAccessExpression(subject, s);
                            return self.generateIsExpression(prop_node, disc.value);
                        }
                    }

                    // TODO: add complexity heuristic for complex non-union type, as not all negations are simple

                    const n2 = try self.generateIsExpression(subject, nt);
                    const n3 = try self.factory.createParenthesizedExpression(n2);
                    return self.factory.createPrefixUnaryExpression(.exclamation_token, n3);
                }


                // first determine what sorts of elements we have in `nt`
                // we want to get the typeof for `et`, then see if elements of `nt` match or not
                // if no elements match, we can return a simple `typeof` check
                const et_typeof = self.analyzer.typeofRef(et) orelse {
                    return self.generateIsExpression(subject, et);
                };


                const nt_elements = Analyzer.getSlice2(self.analyzer.types.at(nt), TypeRef);

                var any_match = false;
                for (nt_elements) |elem| {
                    const x = try self.analyzer.maybeResolveAlias(elem);
                    const elem_typeof = self.analyzer.typeofRef(x);
                    if (elem_typeof == null or elem_typeof == et_typeof) {
                        any_match = true;
                        break;
                    }
                }
                if (!any_match) {
                    return self.generateIsExpression(subject, @intFromEnum(et_typeof));
                }

                // when `nt` contains only objects, we first search for common properties shared by `nt` and `et`
                // that can be used to uniquely isolate `et` from `nt`. If none exist, we look for extraneous
                // properties on `et` that nothing in `nt` has. If that fails, we skip optimizations.
                const et_kind = self.analyzer.getKindOfRef(et);
                if (et_kind == .object_literal) {
                    var all_objects = true;
                    for (nt_elements) |elem| {
                        const x = try self.analyzer.maybeResolveAlias(elem);
                        const elem_kind = self.analyzer.getKindOfRef(x);
                        if (elem_kind != .object_literal) {
                            all_objects = false;
                            break;
                        }
                    }

                    if (all_objects) {
                        if (try self.analyzer.findBestObjectDiscriminant(nt_elements, et)) |disc| {
                            const s = self.analyzer.getSliceFromLiteral(disc.key);
                            const prop_node = try self.factory.createPropertyAccessExpression(subject, s);
                            return self.generateIsExpression(prop_node, disc.value);
                        }
                    }
                }

                // when `nt` contains only arrays and `et` is an array, check if the arr is empty or that the
                // first element matches the array type
                // TODO: implement array discrimination

                // Fallback: generate full is expression
                return self.generateIsExpression(subject, et);
            }

            fn appendRegExpPattern(self: *@This(), pattern: *std.ArrayList(u8), exp_type: TypeRef) anyerror!void {
                if (exp_type >= @intFromEnum(Kind.zero)) {
                    const val = self.analyzer.getDoubleFromType(exp_type);
                    var buf: [64]u8 = undefined;
                    return pattern.appendSlice(try std.fmt.bufPrint(&buf, "{d}", .{val}));
                }
                
                try switch (self.analyzer.getKindOfRef(exp_type)) {
                    .string => pattern.appendSlice(".*"),
                    .number => pattern.appendSlice("-?[0-9]+\\.?[0-9]*"),
                    .true => pattern.appendSlice("true"),
                    .false => pattern.appendSlice("false"),
                    .string_literal => {
                        const s = self.analyzer.getSliceFromLiteral(exp_type);
                        return self.appendEscapedRegex(pattern, s);
                    },
                    .number_literal => {
                        const val = self.analyzer.getDoubleFromType(exp_type);
                        var buf: [64]u8 = undefined;
                        return self.appendEscapedRegex(pattern, try std.fmt.bufPrint(&buf, "{d}", .{val}));
                    },
                    .@"union" => {
                        try pattern.appendSlice("(?:");
                        const slice = Analyzer.getSlice2(self.analyzer.types.at(exp_type), TypeRef);
                        for (slice, 0..) |el, i| {
                            try self.appendRegExpPattern(pattern, el);
                            if (i != slice.len-1) try pattern.append('|');
                        }
                        try pattern.append(')');
                    },
                    .alias => {
                        const followed = try self.analyzer.evaluateType(exp_type, 1 << 0);
                        if (followed == exp_type) {
                            return pattern.appendSlice(".*");
                        }
                        return self.appendRegExpPattern(pattern, followed);
                    },
                    // nested template literal?
                    else => pattern.appendSlice(".*"),
                };
            }

            fn transformCaseBody(self: *@This(), stmts_head: NodeRef) !NodeRef {
                if (stmts_head == 0) {
                    return self.factory.createBreakStatement();
                }

                const first_stmt = self.nodes.at(stmts_head);
                const is_single_block = first_stmt.kind == .block and first_stmt.next == 0;

                if (is_single_block) {
                    const block_stmts_head = maybeUnwrapRef(first_stmt) orelse 0;
                    if (block_stmts_head == 0) {
                        return self.factory.createBlock(try self.factory.createBreakStatement());
                    }

                    var last_stmt_ref: NodeRef = block_stmts_head;
                    if (block_stmts_head != 0) {
                        var stmt_iter = NodeIterator.init(self.nodes, block_stmts_head);
                        while (stmt_iter.nextRef()) |stmt_ref| {
                            last_stmt_ref = stmt_ref;
                        }
                    }

                    const needs_break = if (block_stmts_head == 0) true else switch (self.nodes.at(last_stmt_ref).kind) {
                        .break_statement, .return_statement, .throw_statement, .continue_statement => false,
                        else => true,
                    };

                    if (needs_break) {
                        const break_stmt = try self.factory.createBreakStatement();
                        const last_copy = try self.factory.cloneNode(self.nodes.at(last_stmt_ref));
                        self.nodes.at(last_copy).next = break_stmt;
                        try self.addReplacement(last_stmt_ref, last_copy);
                    }
                    return stmts_head;
                }

                var last_stmt_ref: NodeRef = stmts_head;
                var stmt_iter = NodeIterator.init(self.nodes, stmts_head);
                while (stmt_iter.nextRef()) |stmt_ref| {
                    last_stmt_ref = stmt_ref;
                }

                const last_stmt = self.nodes.at(last_stmt_ref);
                const needs_break = switch (last_stmt.kind) {
                    .break_statement, .return_statement, .throw_statement, .continue_statement => false,
                    else => true,
                };

                if (!needs_break and last_stmt_ref == stmts_head) {
                    return stmts_head;
                }

                if (needs_break) {
                    const break_stmt = try self.factory.createBreakStatement();
                    const last_copy = try self.factory.cloneNode(last_stmt);
                    self.nodes.at(last_copy).next = break_stmt;
                    try self.addReplacement(last_stmt_ref, last_copy);
                }
                return self.factory.createBlock(stmts_head);
            }

            fn unwrapSubject(self: *@This(), ref: NodeRef) NodeRef {
                const n = self.nodes.at(ref);
                return switch (n.kind) {
                    .parenthesized_expression => self.unwrapSubject(unwrapRef(n)),
                    .as_expression, .satisfies_expression => self.unwrapSubject(getPackedData(n).left),
                    else => ref,
                };
            }

            // --- JSX Transform Helpers ---

            fn isIntrinsicTag(self: *const @This(), tag_ref: NodeRef) bool {
                if (tag_ref == 0) return false;
                const tag = self.nodes.at(tag_ref);
                if (tag.kind != .identifier) return false;
                const name = getSlice(tag, u8);
                return name.len > 0 and name[0] >= 'a' and name[0] <= 'z';
            }

            fn isIntrinsicElement(self: *const @This(), ref: NodeRef) bool {
                switch (self.nodes.at(ref).kind) {
                    .jsx_element, .jsx_self_closing_element => {
                        return self.isIntrinsicTag(self.getJsxTagRef(self.nodes.at(ref)));
                    },
                    else => return false,
                }
            }

            // we're only checking same-file refs
            // IMPORTANT: `throw` is not considered an effect for this analysis
            // TODO: should be in `Analyzer` ?
            fn isSimplePureFn(self: *const @This(), ref: NodeRef) bool {
                std.debug.assert(ref != 0);
                const n = self.nodes.at(ref);
                std.debug.assert(n.kind == .function_declaration or n.kind == .function_expression); // TODO: other decls
                if (n.len == 0) return false;

                const d = getPackedData(n);

                // check all param init, if any
                var params_iter = NodeIterator.init(self.nodes, d.right);
                while (params_iter.nextRef()) |param_ref| {
                    const p = getPackedData(self.nodes.at(param_ref));
                    if (p.right != 0 and self._dependsOnEffects(p.right)) {
                        // TODO: some allocations can be treated as semantically pure e.g.
                        //      `function foo(x: any[] = []) { return x[0] }`
                        // We should only do this if the type annotation is "typical"
                        return false;
                    }
                }

                return !self._dependsOnEffects(n.len);
            }

            inline fn _dependsOnEffects(self: *const @This(), inner: NodeRef) bool {
                return self.dependsOnEffects(inner, self.nodes.at(inner));
            }

            // TODO: move to Analyzer alongside `isSimplePureFn`
            // this is pessimistic!
            //
            // FIXME: we need to separate "hasEffects" with "dependsOnEffects".
            // Optimizing JSX expressions needs to understand what cannot possibly change, which
            // is related to `hasEffects` but not the same. 
            fn dependsOnEffects(self: *const @This(), inner: NodeRef, inner_node: *const AstNode) bool {
                switch (inner_node.kind) {
                    .identifier => {
                        if (self.file.binder.getSymbol(inner)) |sym_ref| {
                            if (self.run_directive_symbols.contains(sym_ref)) return true;
                            const sym = self.file.binder.symbols.at(sym_ref);
                            if (sym.hasFlag(.@"const")) {
                                return false;
                            }
                            // TODO: treat all imported symbols as const
                            if (!sym.hasFlag(.late_bound) and !sym.hasFlag(.imported) and sym.declaration != 0) {
                                const decl = self.nodes.at(sym.declaration);
                                if (decl.kind == .function_declaration or decl.kind == .class_declaration) {
                                    return false;
                                }
                            }
                        }
                        return true;
                    },
                    .call_expression => {
                        const d = getPackedData(inner_node);
                        if (self._dependsOnEffects(d.left)) return true;

                        var args = NodeIterator.init(self.nodes, d.right);
                        while (args.nextRef()) |arg_ref| {
                            if (self._dependsOnEffects(arg_ref)) return true;
                        }

                        if (self.file.binder.getSymbol(d.left)) |sym_ref| {
                            const sym = self.file.binder.symbols.at(sym_ref);
                            if (!sym.hasFlag(.late_bound) and !sym.hasFlag(.imported) and sym.declaration != 0) {
                                const decl = self.nodes.at(sym.declaration);
                                if (decl.kind == .function_declaration and self.isSimplePureFn(sym.declaration)) {
                                    return false;
                                }
                            }
                        }

                        return true;
                    },
                    .parenthesized_expression => {
                        return self._dependsOnEffects(unwrapRef(inner_node));
                    },
                    // note: we treat `instanceof` as pure currently
                    .binary_expression => {
                        const d = getPackedData(inner_node);
                        switch (@as(SyntaxKind, @enumFromInt(inner_node.len))) {
                            // any assignment = effects
                            // TODO: for fn analysis, we should only treat these as impure if they
                            // affect symbols declared outside of the current fn boundary
                            .equals_token,
                            .minus_equals_token,
                            .plus_equals_token,

                            .bar_equals_token,
                            .ampersand_equals_token,
                            .caret_equals_token,

                            .question_question_equals_token,
                            .bar_bar_equals_token,
                            .ampersand_ampersand_equals_token,

                            .asterisk_equals_token,
                            .asterisk_asterisk_equals_token,
                            .percent_equals_token,
                            .slash_equals_token => {
                                return true;
                            },
                            else => {},
                        }
                        return self._dependsOnEffects(d.left) or self._dependsOnEffects(d.right);
                    },
                    .prefix_unary_expression => {
                        const d = getPackedData(inner_node);
                        switch (@as(SyntaxKind, @enumFromInt(d.left))) {
                            .plus_plus_token,
                            .minus_minus_token => {
                                return true;
                            },
                            // technically, some unary operators can have effects via user methods
                            // But we are treating such expressions as semantically pure until we add
                            // in type analysis.
                            else => {},
                        }
                        return self._dependsOnEffects(d.right);
                    },
                    .conditional_expression => {
                        // TODO: could technically be "partially thunked", this should use a new tag
                        const d = getPackedData(inner_node);
                        return self._dependsOnEffects(d.left) or self._dependsOnEffects(d.right) or self._dependsOnEffects(inner_node.len);
                    },
                    .typeof_expression,
                    .void_expression => {
                        return self._dependsOnEffects(unwrapRef(inner_node));
                    },
                    .numeric_literal, .string_literal, .no_substitution_template_literal,
                    .true_keyword, .false_keyword, .null_keyword, .undefined_keyword,
                    .arrow_function, .function_expression => {
                        return false;
                    },
                    // template_expression
                    // class expressions are treated as effectively declarations, much like fn expressions
                    // so, static blocks + static field initializers run in source order. 
                    // We never thunk class expressions, even if they contain effectful static blocks.
                    .class_expression => {
                        return false;
                    },
                    .is_expression => {
                        const d = getPackedData(inner_node);
                        return self._dependsOnEffects(d.left);
                    },

                    // statements
                    .defer_statement,
                    .throw_statement,
                    .expression_statement => {
                        return self._dependsOnEffects(unwrapRef(inner_node));
                    },
                    .return_statement => {
                        if (maybeUnwrapRef(inner_node)) |r| {
                            return self._dependsOnEffects(r);
                        }
                        return false;
                    },
                    .block => {
                        var statements_iter = NodeIterator.init(self.nodes, maybeUnwrapRef(inner_node) orelse 0);
                        while (statements_iter.nextRef()) |s_ref| {
                            if (self._dependsOnEffects(s_ref)) return true;
                        }
                        return false;
                    },
                    .if_statement => {
                        const d = getPackedData(inner_node);
                        if (self._dependsOnEffects(d.left)) return true;
                        if (self._dependsOnEffects(d.right)) return true;
                        if (inner_node.len != 0 and self._dependsOnEffects(inner_node.len)) return true;
                        return false;
                    },
                    // should we even support `do...while` in Syn?
                    .while_statement => {
                        const d = getPackedData(inner_node);
                        return self._dependsOnEffects(d.left) or self._dependsOnEffects(d.right);
                    },
                    .for_statement => {
                        const d = getPackedData(inner_node);
                        if (d.left != 0 and self._dependsOnEffects(d.left)) return true;
                        if (d.right != 0 and self._dependsOnEffects(d.right)) return true;
                        if (inner_node.len != 0 and self._dependsOnEffects(inner_node.len)) return true;
                        return self._dependsOnEffects(inner_node.extra_data);
                    },
                    .for_of_statement => {
                        const d = getPackedData(inner_node);
                        // FIXME: we don't need to check `d.left` for Syn ?
                        return self._dependsOnEffects(d.left) or self._dependsOnEffects(d.right) or self._dependsOnEffects(inner_node.len);
                    },
                    .case_clause, .default_clause => {
                        if (inner_node.data) |d| {
                            if (inner_node.hasFlag(.declare)) {
                                // case is
                                return false;
                            } else {
                                if (self._dependsOnEffects(@intCast(@intFromPtr(d)))) return true;
                            }
                        }
                        var iter = NodeIterator.init(self.nodes, inner_node.len);
                        while (iter.nextRef()) |s_ref| {
                            if (self._dependsOnEffects(s_ref)) return true;
                        }
                        return false;
                    },
                    .switch_statement => {
                        const d = getPackedData(inner_node);
                        if (self._dependsOnEffects(d.left)) return true;
                        var iter = NodeIterator.init(self.nodes, d.right);
                        while (iter.nextRef()) |case_ref| {
                            if (self._dependsOnEffects(case_ref)) return true;
                        }
                        return false;
                    },
                    .break_statement, .continue_statement => return false,
                    .variable_declaration => {
                        const d = getPackedData(inner_node);
                        if (d.right != 0) {
                            return self._dependsOnEffects(d.right);
                        }
                        return false;
                    },
                    .variable_statement => {
                        var decls = NodeIterator.init(self.nodes, unwrapRef(inner_node));
                        while (decls.nextRef()) |d_ref| {
                            if (self._dependsOnEffects(d_ref)) return true;
                        }
                        return false;
                    },
                    else => return true, // assume effects by default  
                }
            }

            //  FIXME: 3rd param of .map (or ...rest param) should count as aliasing
            //  FIXME: we don't handle various parens cases (and comma) e.g. return (foo) 
            fn childrenParamMutatesOrEscapes(self: *@This(), param_ident: NodeRef, body_ref: NodeRef) !bool {
                const V = struct {
                    sym: u32,
                    nodes: *const BumpAllocator(AstNode),
                    mutates: bool = false,
                    in_lhs: bool = false,

                    pub fn visit(s: *@This(), n: *const AstNode, ref: NodeRef) anyerror!void {
                        _ = n;
                        s.mutates = try s._visit(ref);
                    }

                    fn _visit(s: *@This(), ref: NodeRef) !bool {
                        if (s.mutates) return true;
                        if (ref == 0) return false;
                        const in_lhs = s.in_lhs;
                        s.in_lhs = false;
                        const n = s.nodes.at(ref);
                        switch (n.kind) {
                            .identifier => {
                                if (!in_lhs) return false;
                                return n.extra_data == s.sym;
                            },
                            .element_access_expression => {
                                const d = getPackedData(n);
                                if (in_lhs) {
                                    s.in_lhs = true;
                                    if (try s._visit(d.left)) return true;
                                    return s._visit(d.right);
                                }
                            },
                            .property_access_expression => {
                                const d = getPackedData(n);
                                if (in_lhs) {
                                    s.in_lhs = true;
                                    if (try s._visit(d.left)) return true;
                                    return false;
                                }
                            },
                            .property_assignment => {
                                const d = getPackedData(n);
                                if (in_lhs) {
                                    s.in_lhs = true;
                                    if (try s._visit(d.left)) return true;
                                }
                            },
                            .binary_expression => {
                                const d = getPackedData(n);
                                switch (@as(SyntaxKind, @enumFromInt(n.len))) {
                                    .equals_token,
                                    .plus_equals_token, .minus_equals_token,
                                    .asterisk_equals_token, .asterisk_asterisk_equals_token,
                                    .slash_equals_token, .percent_equals_token,
                                    .bar_equals_token, .ampersand_equals_token, .caret_equals_token,
                                    .question_question_equals_token, .bar_bar_equals_token,
                                    .ampersand_ampersand_equals_token => {
                                        s.in_lhs = true;
                                        if (try s._visit(d.left)) return true;
                                        return try s._visit(d.right);
                                    },
                                    .equals_equals_equals_token, .equals_equals_token, 
                                    .exclamation_equals_equals_token, .exclamation_equals_token => {
                                        // we treat reference checks as escaping
                                        if (s.nodes.at(d.left).kind == .identifier) {
                                            if (s.nodes.at(d.left).extra_data == s.sym) return true;
                                        }
                                        if (s.nodes.at(d.right).kind == .identifier) {
                                            if (s.nodes.at(d.right).extra_data == s.sym) return true;
                                        }
                                    },
                                    else => {},
                                }
                            },
                            .prefix_unary_expression => {
                                const d = getPackedData(n);
                                const is_mutating = switch (@as(SyntaxKind, @enumFromInt(d.left))) {
                                    .plus_plus_token, .minus_minus_token => true,
                                    else => false,
                                };
                                s.in_lhs = is_mutating;
                            },
                            // TODO: jsx shorthand attr
                            .postfix_unary_expression, .shorthand_property_assignment => {
                                s.in_lhs = true;
                            },
                            .call_expression => {
                                const d = getPackedData(n);
                                const callee = s.nodes.at(d.left);
                                if (callee.kind == .property_access_expression) {
                                    const cd = getPackedData(callee);
                                    const obj = s.nodes.at(cd.left);
                                    if (obj.kind == .identifier and obj.extra_data == s.sym) {
                                        const method = s.nodes.at(cd.right);
                                        const method_name = getSlice(method, u8);
                                        const copies = for ([_][]const u8{
                                            "slice", "map", "filter", "find", "findIndex",
                                            "indexOf", "lastIndexOf", "some", "every",
                                            "reduce", "reduceRight", "forEach", "includes",
                                            "join", "flat", "flatMap", "at", "entries",
                                            "keys", "values", "concat",
                                        }) |sm| {
                                            if (std.mem.eql(u8, method_name, sm)) break true;
                                        } else false;
                                        if (!copies) return true;
                                        var args = NodeIterator.init(s.nodes, d.right);
                                        while (args.nextRef()) |arg_ref| {
                                            if (try s._visit(arg_ref)) return true;
                                        }
                                        return false;
                                    }
                                } else if (callee.kind == .element_access_expression) {
                                    const cd = getPackedData(callee);
                                    const obj = s.nodes.at(cd.left);
                                    if (obj.kind == .identifier and obj.extra_data == s.sym) {
                                        return true; // treat it as escaped
                                    }
                                }
                                var args = NodeIterator.init(s.nodes, d.right);
                                while (args.nextRef()) |arg_ref| {
                                    const arg = s.nodes.at(arg_ref);
                                    if (arg.kind == .identifier and arg.extra_data == s.sym) return true;
                                    if (try s._visit(arg_ref)) return true;
                                }
                                return false;
                            },
                            .variable_declaration => {
                                const d = getPackedData(n);
                                if (d.right != 0) {
                                    const rhs = s.nodes.at(d.right);
                                    if (rhs.kind == .identifier and rhs.extra_data == s.sym) return true;
                                }
                            },
                            .parenthesized_expression => {
                                s.in_lhs = in_lhs;
                            },
                            .return_statement => {
                                if (maybeUnwrapRef(n)) |r| {
                                    const ret = s.nodes.at(r);
                                    if (ret.kind == .identifier and ret.extra_data == s.sym) return true;
                                }
                                return false;
                            },
                            else => {},
                        }
                        try parser.forEachChild(s.nodes, n, s);
                        return s.mutates;
                    }
                };

                var v = V{
                    .nodes = self.nodes,
                    .sym = self.nodes.at(param_ident).extra_data,
                };

                try v.visit(self.nodes.at(body_ref), body_ref);

                return v.mutates;
            }

            // FIXME: scanner should track this with a flag `all_whitespace`
            fn isJsxTextAllWhitespace(_: *const @This(), child: *const AstNode) bool {
                var i: usize = 0;
                var has_newline = false;
                const text = getSlice(child, u8);
                while (i < text.len) {
                    if (std.mem.indexOfScalar(u8, " \t\n\r", text[i]) == null) break;
                    if (text[i] == '\n') has_newline = true;
                    i += 1;
                }
                // all whitespace on 1 line is treated as being visible
                return i == text.len and has_newline;
            }

            fn collapseJsxText(self: *const @This(), child: *const AstNode) ![]const u8 {
                const follows_open_tag = child.hasFlag(.abstract);
                const precedes_close_tag = child.next == 0 or (self.nodes.at(child.next).kind == .jsx_closing_element or self.nodes.at(child.next).kind == .jsx_closing_fragment);
                const text = getSlice(child, u8);

                var i: usize = 0;
                var maybe_interior = false;
                var newline_count: u32 = 0;
                var text_start: ?usize = null;
                var whitespace_start: ?usize = null;
                var result = std.ArrayList(u8).init(getAllocator()); // TODO: needs arena
                while (i < text.len) {
                    // we are only concerned with ascii whitespace
                    const ch = text[i];
                    switch (ch) {
                        ' ', '\t', '\n', '\r' => {
                            if (text_start) |x| {
                                try result.appendSlice(text[x..i]);
                                text_start = null;
                                maybe_interior = true;
                                newline_count = 0;
                            }
                            if (whitespace_start == null) {
                                whitespace_start = i;
                            }
                            if (ch == '\n') {
                                newline_count += 1;
                            }
                        },
                        else => {
                            if (whitespace_start) |x| {
                                if (newline_count > 0) {
                                    if (follows_open_tag and result.items.len == 0) 
                                        newline_count -= 1;
                                    while (newline_count > 0) {
                                        newline_count -= 1;
                                        try result.append('\n');
                                    }
                                } else {
                                    try result.appendSlice(text[x..i]);
                                }
                                whitespace_start = null;
                                maybe_interior = false;
                            }
                            if (text_start == null) {
                                text_start = i;
                            }
                        },
                    }
                    i += 1;
                }

                if (whitespace_start) |x| {
                    if (newline_count > 0) {
                        if (precedes_close_tag) newline_count -= 1;
                        while (newline_count > 0) {
                            newline_count -= 1;
                            try result.append('\n');
                        }
                    } else {
                        if (result.items.len == 0) return text;
                        try result.appendSlice(text[x..]);
                    }
                }

                if (text_start) |x| {
                    if (result.items.len == 0) return text;
                    try result.appendSlice(text[x..]);
                }

                result.shrinkAndFree(result.items.len);
                return result.items;
            }

            fn jsxTextToString(self: *@This(), child: *const AstNode) !?NodeRef {
                const trimmed = try self.collapseJsxText(child);
                if (trimmed.len == 0) return null;
                var i: usize = 0;
                const text = getSlice(child, u8);
                while (i < text.len) {
                    if (std.mem.indexOfScalar(u8, "\"\n", text[i]) != null) {
                        if (text[i] != '"' or i == 0 or text[i-1] != '\\') {
                            break;
                        }
                    }
                    i += 1;
                }
                const needs_template_str = i != text.len;
                if (!needs_template_str) {
                    return try self.factory.createStringLiteral(trimmed);
                }
                return try self.factory.createNoSubstitutionTemplateLiteralAllocated(
                    try getAllocator().dupe(u8, trimmed)
                );
            }

            fn templateIsVoidElement(tag: []const u8) bool {
                const voids = [_][]const u8{ "area", "base", "br", "col", "embed", "hr", "img", "input", "link", "meta", "param", "source", "track", "wbr" };
                for (voids) |v| if (std.mem.eql(u8, tag, v)) return true;
                return false;
            }

            fn templateHasSpreadAttr(self: *@This(), attrs_ref: NodeRef) bool {
                if (attrs_ref == 0) return false;
                const attrs = self.nodes.at(attrs_ref);
                if (attrs.kind != .jsx_attributes) return false;
                var iter = NodeIterator.init(self.nodes, unwrapRef(attrs));
                while (iter.next()) |attr| {
                    if (attr.kind == .jsx_spread_attribute) return true;
                }
                return false;
            }

            fn getJsxTagRef(self: *const @This(), node: *const AstNode) NodeRef {
                return switch (node.kind) {
                    .jsx_self_closing_element => getPackedData(node).left,
                    .jsx_element => blk: {
                        const or_ = maybeUnwrapRef(node) orelse break :blk 0;
                        break :blk getPackedData(self.nodes.at(or_)).left;
                    },
                    else => 0,
                };
            }

            fn jsxRecursiveMaxChildCount(self: *@This(), opening_ref: NodeRef) u32 {
                var iter = NodeIterator.init(self.nodes, opening_ref);
                var child_count: u32 = 0;
                while (iter.next()) |child| {
                    switch (child.kind) {
                        .jsx_text => {
                            if (!self.isJsxTextAllWhitespace(child)) {
                                child_count += 1;
                            }
                        },
                        .jsx_element, .jsx_self_closing_element => {
                            const child_tag_ref = self.getJsxTagRef(child);
                            if (child_tag_ref != 0) {
                                child_count += 1;
                            }
                        },
                        .jsx_if_directive, .jsx_fragment => {
                            var q = self.jsxRecursiveMaxChildCount(getPackedData(child).right);
                            if (child.kind == .jsx_if_directive and child.next != 0 and self.nodes.at(child.next).kind == .jsx_else_directive) {
                                const k = self.jsxRecursiveMaxChildCount(getPackedData(self.nodes.at(child.next)).right);
                                q = @max(q, k);
                            }
                            child_count += q;
                        },
                        else => {},
                    }
                }
                return child_count;
            }

            fn jsxGetChildrenStartRef(_: *@This(), n: *const AstNode) NodeRef {
                switch (n.kind) {
                    .jsx_if_directive, .jsx_else_directive, .jsx_component => return getPackedData(n).right,
                    .jsx_element, .jsx_fragment => return unwrapRef(n),
                    else => return 0,
                }
            }

            fn jsxRealChildCount(self: *@This(), opening_ref: NodeRef, skip_text: bool, skip_comps: bool) u32 {
                var iter = NodeIterator.init(self.nodes, opening_ref);
                var child_count: u32 = 0;
                while (iter.next()) |child| {
                    switch (child.kind) {
                        .jsx_text => {
                            if (skip_text) continue;
                            if (!self.isJsxTextAllWhitespace(child)) {
                                child_count += 1;
                            }
                        },
                        .jsx_element, .jsx_self_closing_element => {
                            const child_tag_ref = self.getJsxTagRef(child);
                            if (!skip_comps) {
                                child_count += 1;
                                continue;
                            }
                            if (child_tag_ref != 0 and self.isIntrinsicTag(child_tag_ref)) {
                                child_count += 1;
                            }
                        },
                        else => {},
                    }
                }
                return child_count;
            }

            // returns null if the length of the array would not be constant
            fn jsxStableArrayLength(self: *@This(), opening_ref: NodeRef) ?u32 {
                var count: u32 = 0;
                var iter = NodeIterator.init(self.nodes, opening_ref);
                while (iter.next()) |child| {
                    switch (child.kind) {
                        .jsx_style_directive,
                        .jsx_run_directive, .jsx_component,
                        .jsx_opening_element, .jsx_closing_element, 
                        .jsx_closing_fragment, .jsx_text_all_white_spaces => {},
                        .jsx_text => {
                            if (!self.isJsxTextAllWhitespace(child)) {
                                count += 1;
                            }
                        },
                        .jsx_expression,  .jsx_element, .jsx_self_closing_element => {
                            if (child.hasFlag(.generator)) return null;
                            count += 1;
                        },
                        .jsx_fragment => {
                            count += self.jsxStableArrayLength(self.jsxGetChildrenStartRef(child)) 
                                orelse return null;
                        },
                        .jsx_if_directive => {
                            const c = self.jsxStableArrayLength(self.jsxGetChildrenStartRef(child))
                                orelse return null;
                            if (child.next != 0) {
                                const maybe_else = self.nodes.at(child.next);
                                if (maybe_else.kind == .jsx_else_directive) {
                                    const c2 = self.jsxStableArrayLength(self.jsxGetChildrenStartRef(child))
                                        orelse return null;
                                    if (c != c2) return null;
                                }
                            }
                            count += c;
                        },
                        else => return null,
                    }
                }
                return count;
            }

            fn jsxNodeHasManyChildren(self: *@This(), node: *const AstNode) bool {
                switch (node.kind) {
                    .jsx_self_closing_element, .jsx_component,
                    .jsx_if_directive, .jsx_else_directive => {
                        return self.jsxHasManyChildren(getPackedData(node).right);
                    },
                    .jsx_fragment, .jsx_element => {
                        return self.jsxHasManyChildren(maybeUnwrapRef(node) orelse 0);
                    },
                    else => unreachable,
                }
            }

            fn jsxHasManyChildren(self: *@This(), opening_ref: NodeRef) bool {
                var iter = NodeIterator.init(self.nodes, opening_ref);
                var child_count: u32 = 0;
                while (iter.next()) |child| {
                    switch (child.kind) {
                        .jsx_style_directive,
                        .jsx_run_directive, .jsx_component,
                        .jsx_opening_element, .jsx_closing_element, .jsx_text_all_white_spaces => {},
                        .jsx_text => {
                            if (!self.isJsxTextAllWhitespace(child)) {
                                child_count += 1;
                                if (child_count > 1) return true;
                            }
                        },
                        else => {
                            child_count += 1;
                            if (child_count > 1) return true;
                        }
                    }
                }
                return false;
            }

            fn nextIntrinsicSiblingTag(self: *@This(), node: *const AstNode) ?[]const u8 {
                var iter = NodeIterator.init(self.nodes, node.next);
                while (iter.next()) |n| {
                    switch (n.kind) {
                        .jsx_text_all_white_spaces, .jsx_opening_element, .jsx_closing_element => {},
                        .jsx_element => {
                            const od = getPackedData(self.nodes.at(unwrapRef(n)));
                            if (!self.isIntrinsicTag(od.left)) return null;
                            return getSlice(self.nodes.at(od.left), u8);
                        },
                        .jsx_self_closing_element => {
                            const d = getPackedData(n);
                            if (!self.isIntrinsicTag(d.left)) return null;
                            return getSlice(self.nodes.at(d.left), u8);
                        },
                        else => return null,
                    }
                }
                return null;
            }

            fn templateCanOmitEndTag(tag: []const u8, next: []const u8) bool {
                const eql = std.ascii.eqlIgnoreCase;
                if (eql(tag, "li"))
                    return eql(next, "li");
                if (eql(tag, "p"))
                    // could also include ol / section / ul / h1-h6 / dialog and a some others
                    return eql(next, "p") or eql(next, "div");
                if (eql(tag, "dd") or eql(tag, "dt"))
                    return eql(next, "dd") or eql(next, "dt");
                if (eql(tag, "rt") or eql(tag, "rp"))
                    return eql(next, "rt") or eql(next, "rp");
                if (eql(tag, "optgroup"))
                    return eql(next, "optgroup") or eql(next, "hr");
                if (eql(tag, "option"))
                    return eql(next, "option") or eql(next, "optgroup") or eql(next, "hr");
                if (eql(tag, "thead"))
                    return eql(next, "tbody") or eql(next, "tfoot");
                if (eql(tag, "tbody"))
                    return eql(next, "tbody") or eql(next, "tfoot");
                if (eql(tag, "tr"))
                    return eql(next, "tr");
                if (eql(tag, "td") or eql(tag, "th"))
                    return eql(next, "td") or eql(next, "th");
                return false;
            }

            fn templateWriteHtmlChildren(self: *@This(), opening_ref: NodeRef, out: *std.ArrayList(u8), comptime for_component: bool) anyerror!void {
                var has_preceding_text: bool = false;
                var iter = NodeIterator.init(self.nodes, opening_ref);
                var nodes = std.ArrayList(*TreeNodeInfo).init(getAllocator());
                defer nodes.deinit();
                while (iter.nextRef()) |child_ref| {
                    const child = self.nodes.at(child_ref);
                    const child_info: ?*TreeNodeInfo = blk: {
                        const s = self.jsx_emit_state orelse break :blk null;
                        break :blk s.node_info.get(child_ref);
                    };
                    switch (child.kind) {
                        .jsx_opening_element, .jsx_closing_element, .jsx_text_all_white_spaces => {},
                        .jsx_text => {
                            // if (for_component) continue;
                            if (self.isJsxTextAllWhitespace(child)) continue;
                            if (for_component and has_preceding_text) continue;

                            const trimmed = try self.collapseJsxText(child);
                            if (trimmed.len == 0) continue;

                            has_preceding_text = true;
 
                            for (trimmed) |c| switch (c) {
                                '<' => try out.appendSlice("&lt;"),
                                '>' => try out.appendSlice("&gt;"),
                                '&' => try out.appendSlice("&amp;"),
                                else => try out.append(c),
                            };
                        },
                        .jsx_expression => {
                            if (for_component) continue;

                            try out.appendSlice("<!>");
                            if (child.hasFlag(.generator) and !child.hasFlag(.static)) {
                                try out.appendSlice("<!>");
                            }
                        },
                        .jsx_element, .jsx_self_closing_element => {
                            const child_tag_ref = self.getJsxTagRef(child);
                            if (self.isIntrinsicTag(child_tag_ref)) {
                                has_preceding_text = false;
                                try self.templateWriteHtml(child_ref, out, false);
                            } else {
                                if (for_component) continue;
                                try out.appendSlice("<!>"); 
                            }
                        },
                        .jsx_if_directive => {
                            if (for_component) continue;
                            try out.appendSlice("<!>");
                            try out.appendSlice("<!>");
                        },
                        .jsx_fragment => {
                            const children_ref = maybeUnwrapRef(child) orelse continue;
                            try self.templateWriteHtmlChildren(children_ref, out, for_component);
                            continue;
                        },
                        else => {},
                    }
                    if (child_info) |info| try nodes.append(info);
                }

                var needs_nav = false;
                var i: usize = nodes.items.len;
                var nav_count: u32 = 0;
                while (i > 0) {
                    i -= 1;
                    if (!needs_nav) {
                        needs_nav = switch (nodes.items[i].kind) {
                            .if_directive, .expression,
                            .component_instance, .intrinsic_dynamic => true,
                            .intrinsic_static => self.inlineMaybeGetElementBinding(nodes.items[i].node_ptr) != null,
                            else => false,
                        };
                    }
                    if (!needs_nav) continue;
                    var can_release: bool = false;
                    nav_count += 1;
                    switch (nodes.items[i].kind) {
                        .text_static => {
                            can_release = true;
                        },
                        else => {},
                    }
                    nodes.items[i].needs_nav = true;
                    nodes.items[i].nav_info = .{
                        .can_release_name = can_release,
                        .prior_nav_node = if (i > 0) nodes.items[i-1] else null,
                        .is_comment_node = switch (nodes.items[i].kind) {
                            .text_static, .intrinsic_dynamic, .intrinsic_static => false,
                            else => true,
                        },
                        .is_two_nodes = nodes.items[i].is_spread,
                    };
                }

                if (nav_count == 1 and for_component) {
                    for (nodes.items) |info| {
                        if (info.needs_nav) {
                            info.nav_info.?.amount = 0;
                        }
                    }
                }
            }

            fn templateWriteHtmlScopeAttrs(self: *@This(), node: *const AstNode, tag: []const u8, out: *std.ArrayList(u8)) !void {
                const s = self.style_visitor.node_ptr_to_scope_map.get(node) orelse return;
                if (s.possible_type_selectors) |pts| {
                    var matched = false;
                    for (pts) |t| {
                        if (std.mem.eql(u8, t, "*") or std.mem.eql(u8, t, tag)) { matched = true; break; }
                    }
                    if (!matched) return;
                }
                try out.append(' ');
                try out.appendSlice(s.root.attr);
                // if (s.needs_attr_value) {
                //     if (s.subscopes.items.len == 0) {
                //         try out.appendSlice("=\"root\"");
                //     } else {
                //         try out.appendSlice("=\"");
                //         try out.appendSlice(s.subscopes.items[s.subscopes.items.len-1]);
                //         try out.append('"');
                //     }
                // }
                for (s.subscopes.items) |sa| {
                    try out.append(' ');
                    try out.appendSlice(sa);
                }
            }

            fn templateWriteEndTagIfNeeded(self: *@This(), node: *const AstNode, tag: []const u8, out: *std.ArrayList(u8)) anyerror!void {
                if (templateIsVoidElement(tag)) {
                    if (node.kind == .jsx_element and self.jsxRecursiveMaxChildCount(unwrapRef(node)) > 0) {
                        try self.file.emitError(unwrapRef(node), "HTML void elements cannot have any HTML children");
                    }
                    return;
                }
                const next_tag = if (out.items.len == 0) null else self.nextIntrinsicSiblingTag(node);
                const omit = next_tag != null and templateCanOmitEndTag(tag, next_tag.?);
                if (!omit) {
                    try out.appendSlice("</");
                    try out.appendSlice(tag);
                    try out.appendSlice(">");
                }
            }

            // TODO: <html>/<head>/<body> are ignored by <template> tags, these should be emitted w/o using templates
            fn templateWriteHtml(self: *@This(), node_ref: NodeRef, out: *std.ArrayList(u8), comptime for_component: bool) anyerror!void {
                const node = self.nodes.at(node_ref);
                switch (node.kind) {
                    .jsx_self_closing_element => {
                        const d = getPackedData(node);
                        const tag = getSlice(self.nodes.at(d.left), u8);
                        try out.appendSlice("<");
                        try out.appendSlice(tag);
                        try self.templateWriteHtmlScopeAttrs(node, tag, out);
                        try self.templateWriteHtmlAttrs(d.right, out);
                        try out.appendSlice(">");
                        try self.templateWriteEndTagIfNeeded(node, tag, out);
                    },
                    .jsx_element => {
                        const opening_ref = unwrapRef(node);
                        const opening = self.nodes.at(opening_ref);
                        const od = getPackedData(opening);
                        if (!self.isIntrinsicTag(od.left)) {
                            // try out.appendSlice("<a>");
                            try self.templateWriteHtmlChildren(opening_ref, out, true);
                            // try out.appendSlice("</a>");
                            return;
                        }

                        const tag = getSlice(self.nodes.at(od.left), u8);
                        try out.appendSlice("<");
                        try out.appendSlice(tag);
                        try self.templateWriteHtmlScopeAttrs(node, tag, out);
                        try self.templateWriteHtmlAttrs(od.right, out);
                        try out.appendSlice(">");

                        try self.templateWriteHtmlChildren(opening_ref, out, false);
                        try self.templateWriteEndTagIfNeeded(node, tag, out);
                    },
                    .jsx_if_directive, .jsx_else_directive, .jsx_component => {
                        const d = getPackedData(node);
                        if (d.right == 0) return;

                        // const has_many = self.jsxHasManyChildren(d.right);
                        //if (has_many) try out.appendSlice("<a>");
                        if (node.kind == .jsx_component) {
                            try self.templateWriteHtmlChildren(d.right, out, true);
                        } else {
                            try self.templateWriteHtmlChildren(d.right, out, for_component);
                        }
                        // if (has_many) try out.appendSlice("</a>");
                    },
                    .jsx_fragment => {
                        const children_ref = maybeUnwrapRef(node) orelse return;
                        // try out.appendSlice("<a>");
                        try self.templateWriteHtmlChildren(children_ref, out, for_component);
                        // try out.appendSlice("</a>");
                    },
                    else => {},
                }
            }

            // Excludes dynamic attrs 
            fn templateWriteHtmlAttrs(self: *@This(), attrs_ref: NodeRef, out: *std.ArrayList(u8)) !void {
                if (attrs_ref == 0) return;
                const attrs = self.nodes.at(attrs_ref);
                if (attrs.kind != .jsx_attributes) return;
                const has_spread = self.hasSpreadAttr(attrs);
                if (has_spread) return;
                var iter = NodeIterator.init(self.nodes, unwrapRef(attrs));
                while (iter.next()) |attr| {
                    if (attr.kind == .jsx_class_attribute) {
                        const d = getPackedData(attr);
                        if (d.right != 0) continue; // conditional, handled in update body
                        try out.appendSlice(" class=\"");
                        var ni = NodeIterator.init(self.nodes, d.left);
                        var first_name = true;
                        while (ni.next()) |name_node| {
                            if (!first_name) try out.append(' ');
                            try out.appendSlice(getSlice(name_node, u8));
                            first_name = false;
                        }
                        try out.append('"');
                        continue;
                    }
                    if (attr.kind == .jsx_class_list) {
                        if (attr.data == null) continue;
                        const list_ref: NodeRef = @truncate(@intFromPtr(attr.data.?));
                        var li = NodeIterator.init(self.nodes, list_ref);
                        while (li.next()) |ca| {
                            if (ca.kind != .jsx_class_attribute) continue;
                            const d = getPackedData(ca);
                            if (d.right != 0) continue;
                            try out.appendSlice(" class=\"");
                            var ni = NodeIterator.init(self.nodes, d.left);
                            var first_name = true;
                            while (ni.next()) |name_node| {
                                if (!first_name) try out.append(' ');
                                try out.appendSlice(getSlice(name_node, u8));
                                first_name = false;
                            }
                            try out.append('"');
                        }
                        continue;
                    }
                    if (attr.kind != .jsx_attribute) continue;
                    const ad = getPackedData(attr);
                    const name = getSlice(self.nodes.at(ad.left), u8);
                    if (isCamelCase(name)) continue; // emitted as prop assignment
                    if (ad.right == 0 or self.nodes.at(ad.right).kind == .true_keyword) {
                        // bool attr: <input disabled>
                        try out.appendSlice(" ");
                        try out.appendSlice(name);
                        continue;
                    }
                    const val = self.nodes.at(ad.right);
                    if (val.kind == .false_keyword) continue;
                    if (val.kind == .jsx_expression) continue;
                    if (val.kind == .numeric_literal) {
                        try out.appendSlice(" ");
                        try out.appendSlice(name);
                        try out.appendSlice("=");
                        if (val.data) |d| {
                            // FIXME: dedupe
                            const val2: u64 = @intFromPtr(d);
                            const f2: f64 = @bitCast(val2);
                            var buf: [64]u8 = undefined;
                            try out.appendSlice(try std.fmt.bufPrint(&buf, "{d}", .{f2}));
                        } else {
                            try out.appendSlice("0");
                        }
                        continue;
                    }
                    const lit = getSlice(val, u8);
                    try out.appendSlice(" ");
                    try out.appendSlice(name);
                    try out.appendSlice("=\"");
                    for (lit) |c| switch (c) {
                        '"' => try out.appendSlice("&quot;"),
                        '&' => try out.appendSlice("&amp;"),
                        else => try out.append(c),
                    };
                    try out.appendSlice("\"");
                }
            }

            const HtmlPrinter = struct {
                const Attr = struct {
                    name: []const u8,
                    value: ?[]const u8 = null,
                    value_needs_quotes: bool = true,
                };
                const Node = union(enum) {
                    text: TextNode,
                    comment: CommentNode,
                    element: ElementNode,
                };
                const TextNode = struct {
                    text: []const u8,
                    parent: ?*ElementNode = null,
                };
                const CommentNode = struct {
                    text: []const u8 = &.{},
                    parent: ?*ElementNode = null,
                };
                const ElementNode = struct {
                    tag: []const u8,
                    children: std.ArrayListUnmanaged(*Node) = .{},
                    attributes: std.ArrayListUnmanaged(*Attr) = .{},
                    parent: ?*ElementNode = null,
                };

                fn _printAttr(attr: *Attr, out: *std.ArrayList(u8)) !void {
                    try out.appendSlice(attr.name);
                    if (attr.value) |v| {
                        try out.append("=");
                        if (attr.value_needs_quotes) try out.append('"');
                        for (v) |c| switch (c) {
                            '"' => try out.appendSlice("&quot;"),
                            '&' => try out.appendSlice("&amp;"),
                            else => try out.append(c),
                        };
                        if (attr.value_needs_quotes) try out.append('"');
                    }
                }

                fn _printChild(node: *Node, out: *std.ArrayList(u8)) !void {
                    switch (node) {
                        .comment => |n| {
                            if (n.text.len == 0) {
                                try out.appendSlice("<!>");
                            } else {
                                try out.appendSlice("<!--");
                                try out.appendSlice(n.text);
                                try out.appendSlice("-->");
                            }
                        },
                        .text => |n| {
                            for (n.text) |c| switch (c) {
                                '<' => try out.appendSlice("&lt;"),
                                '>' => try out.appendSlice("&gt;"),
                                '&' => try out.appendSlice("&amp;"),
                                else => try out.append(c),
                            };
                        },
                        .element => |n| {
                            try _printElement(n, out);
                        },
                    }
                }

                fn _printElement(node: *ElementNode, out: *std.ArrayList(u8)) !void {
                    const is_fragment = node.tag.len == 0;
                    const is_void = templateIsVoidElement(node.tag);
                    if (is_fragment) {
                        std.debug.assert(node.attributes.items.len == 0);
                    } else {
                        try out.append('<');
                        try out.appendSlice(node.tag);
                        for (node.attributes.items) |attr| {
                            try out.append(' ');
                            try _printAttr(attr, out);
                        }
                        try out.append('>');
                    }
                    if (is_void) {
                        try out.append('>');
                        std.debug.assert(node.children.items.len == 0);
                        return;
                    } 
                    for (node.children.items) |c| {
                        try _printChild(c, out);
                    }
                    if (!is_fragment) {
                        try out.appendSlice("</");
                        try out.appendSlice(node.tag);
                        try out.append('>');
                    }
                }

                pub fn print(node: *ElementNode) !std.ArrayList(u8) {
                    var out = std.ArrayList(u8).init(getAllocator());
                    try _printElement(node, &out);
                    return out;
                }

                pub fn createElement(tag: []const u8) !*ElementNode {
                    const el = try getAllocator().create(ElementNode);
                    el.* = .{ .tag = tag };
                    return el;
                }

                pub fn appendElement(el: *ElementNode, child: *ElementNode) !void {
                    child.parent = el;
                    try el.children.append(getAllocator(), child);
                }

                pub fn appendNewElement(el: *ElementNode, tag: []const u8) !*ElementNode {
                    const n = try createElement(tag);
                    try appendElement(el, n);
                    return n;
                }

                pub fn appendNewAttribute(el: *ElementNode, name: []const u8, value: ?[]const u8) !*Attr {
                    const attr = try getAllocator().create(Attr);
                    attr.* = .{ .name = name, .value = value };
                    try el.attributes.append(getAllocator(), attr);
                    return attr;
                }

                pub fn appendNewAnchor(el: *ElementNode) !*CommentNode {
                    const n = try getAllocator().create(CommentNode);
                    n.* = .{ .parent = el };
                    try el.children.append(getAllocator(), n);
                    return n;
                }

                pub fn appendNewText(el: *ElementNode, text: []const u8) !*TextNode {
                    const n = try getAllocator().create(TextNode);
                    n.* = .{ .text = text, .parent = el };
                    try el.children.append(getAllocator(), n);
                    return n;
                }
            };

            // used for gating `static` code regions with one binding e.g.
            //
            // let _v0 = 0x2
            //  ...
            //    if (_v0) { _v0 >>= 1; ... }
            //  ...
            //    if (_v0) { _v0 >>= 1; ... }
            //
            // cannot share with conditional regions
            const PackedStaticGate = struct {
                name: []const u8,
                count: u5 = 0,
            };

            fn emitStaticGateInit(self: *@This(), state: *InlineEmitState) !void {
                const gate = state.static_gate orelse return;
                const v = try self.factory.createNumericLiteral((@as(i32, 1) << gate.count) - 1);
                self.nodes.at(v).flags |= @intFromEnum(NodeFlags.let); // hex
                const decl = try self.factory.createLetVariable(try self.factory.createIdentifier(gate.name), v);
                try state.stmts.insert(0, decl);
                state.static_gate = null;
            }

            fn emitStaticStatements(self: *@This(), state: *InlineEmitState, statements: []const NodeRef) !NodeRef {
                if (state.static_gate == null) {
                    state.static_gate = .{
                        .name = try state.nextName(),
                    };
                }
                var gate = &state.static_gate.?;
                const block = try self.factory.createBlock(statements);
                const assign = try self.factory.createExpressionStatement(
                    try self.factory.createBinaryExpression(
                        try self.factory.createIdentifier(gate.name),
                        .greater_than_greater_than_equals_token,
                        try self.factory.createNumericLiteral(@as(i64,1)),
                    )
                );
                const l = unwrapRef(self.nodes.at(block));
                self.nodes.at(block).data = @ptrFromInt(assign);
                self.nodes.at(assign).next = l;
                const branch = try self.factory.createIfStatement(try self.factory.createIdentifier(gate.name), block, 0);

                gate.count += 1;
                if (gate.count == 31) {
                    try self.emitStaticGateInit(state);
                }

                return branch;
            }

            const TreeScope = struct {
                const AllocatedName = struct {
                    name: []const u8,
                    scope: *TreeScope,

                    pub fn release(s: @This()) void {
                        s.scope.released_names.append(s.name) catch unreachable;
                    }
                };
                
                is_static_scope: bool = false,
                body: std.ArrayList(NodeRef),
                state: *InlineEmitState,
                released_names: std.ArrayList([]const u8),
                parent_scope: ?*TreeScope = null,
                tree_static_scope: ?*TreeScope = null,

                fn getName(s: *@This()) !AllocatedName {
                    return .{
                        .name = s.released_names.popOrNull() orelse try s.state.nextName(),
                        .scope = s,
                    };
                }

                pub fn getUpdateScopedName(s: *@This()) !AllocatedName {
                    if (s.released_names.items.len > 0) {
                        return s.getName();
                    }
                    if (s.parent_scope) |parent| {
                        return parent.getUpdateScopedName();
                    }
                    return s.getName();
                }

                pub fn getStaticScopedName(s: *@This()) !AllocatedName {
                    if (s.released_names.items.len > 0) {
                        return s.getName();
                    }
                    if (s.tree_static_scope) |parent| {
                        return parent.getStaticScopedName();
                    }
                    return s.getName();
                }

                pub fn appendStatement(s: *@This(), ref: NodeRef) !void {
                    if (!s.is_static_scope) {
                        try s.body.append(ref);
                    } else {
                        try s.parent_scope.?.appendStatement(ref);
                    }
                }

                pub fn appendStaticStatement(s: *@This(), ref: NodeRef) !void {
                    if (s.is_static_scope) {
                        try s.body.append(ref);
                    } else {
                        try s.parent_scope.?.appendStaticStatement(ref);
                    }
                }

                fn initScope(state: *InlineEmitState, comptime is_static: bool) *@This() {
                    var t = @This(){
                        .state = state,
                        .body = std.ArrayList(NodeRef).init(getAllocator()),
                        .released_names = std.ArrayList([]const u8).init(getAllocator()),
                        .is_static_scope = is_static,
                    };
                    t.parent_scope = state.tree_scope;
                    if (state.tree_scope) |x| { 
                        if (x.is_static_scope) {
                            t.tree_static_scope = x;
                        } else {
                            t.tree_static_scope = x.tree_static_scope;
                        }
                    }
                    state.tree_scope = try getAllocator().create(@This());
                    state.tree_scope.* = t;
                    return state.tree_scope.?;
                }

                pub fn initStaticScope(state: *InlineEmitState) *@This() {
                    return @This().initScope(state, true);
                }

                pub fn initUpdateScope(state: *InlineEmitState) *@This() {
                    return @This().initScope(state, false);
                }

                pub fn deinit(s: *@This()) void {
                    defer getAllocator().destroy(s);
                    if (s.body.items.len > 0) {
                        std.debug.assert(!s.is_static_scope);
                        std.debug.assert(s.parent_scope != null);
                        std.debug.assert(!s.parent_scope.?.is_static_scope);
                        s.parent_scope.?.body.appendSlice(s.body.items) catch unreachable;
                    }
                    s.body.deinit();
                    s.released_names.deinit();
                    s.state.tree_scope = s.parent_scope;
                }
            };

            const InlineEmitState = struct {
                pub const Ctx = enum {
                    templated,
                    component,
                };

                counter: u32 = 0,
                ctx: Ctx = .templated,
                stmts: std.ArrayList(NodeRef),
                // used by inlineArrayChildren
                offset_counter_name: NodeRef = 0,
                children_exp: NodeRef = 0,
                children_init_ref: NodeRef = 0,
                emit_internal_fragment: bool = false,
                containing_element_is_fragment_like: bool = false,
                // some vars can be re-used, those go here
                // must _not_ be used if you need uninitialized state
                released_vars: std.ArrayListUnmanaged([]const u8) = .{},
                tree_scope: ?*TreeScope = null,

                bridged_declarations: ?*std.AutoHashMapUnmanaged(SymbolRef, NodeRef) = null,
                hoistables: ?*std.AutoHashMapUnmanaged(NodeRef, void) = null,
                hoistable_symbols: ?*std.AutoHashMapUnmanaged(SymbolRef, bool) = null,
                static_nonnull: ?*std.AutoHashMapUnmanaged(SymbolRef, void) = null,
                did_prepass_for_bridges: bool = false,
                borrowed_bridged_declarations: bool = false,

                current_node_ref: NodeRef = 0,
                skip_attributes: bool = false, // XXX
                
                current_component_decl: NodeRef = 0,
                node_info: std.AutoHashMapUnmanaged(NodeRef, *TreeNodeInfo) = .{},
                tree_classification: ?*TreeClassification = null,
                consumer_getters: std.AutoHashMapUnmanaged(SymbolRef, NodeRef) = .{},
                consumer_setters: std.AutoHashMapUnmanaged(SymbolRef, NodeRef) = .{},

                static_gate: ?PackedStaticGate = null,

                fn nextName(s: *@This()) ![]const u8 {
                    const name = try std.fmt.allocPrint(getAllocator(), "_v{d}", .{s.counter});
                    s.counter += 1;
                    return name;
                }

                pub fn getUpdateScopedName(s: *@This()) !TreeScope.AllocatedName {
                    std.debug.assert(s.tree_scope != null);
                    return s.tree_scope.?.getUpdateScopedName();
                }

                pub fn getStaticScopedName(s: *@This()) !TreeScope.AllocatedName {
                    std.debug.assert(s.tree_scope != null);
                    return s.tree_scope.?.getStaticScopedName();
                }

                fn addStmt(s: *@This(), stmt: NodeRef) !void {
                    try s.stmts.append(stmt);
                }

                fn maybeReuseName(s: *@This()) ?[]const u8 {
                    return s.released_vars.popOrNull();
                }

                fn releaseName(s: *@This(), name: []const u8) !void {
                    try s.released_vars.append(getAllocator(), name);
                }

                fn createTreeNodeInfo(s: *@This(), ref: NodeRef, node: *const AstNode) !*TreeNodeInfo {
                    const ptr = try getAllocator().create(TreeNodeInfo);
                    ptr.* = .{
                        .kind = switch (node.kind) {
                            .jsx_element, .jsx_self_closing_element => .intrinsic_static, // placeholder!
                            .jsx_if_directive, .jsx_else_directive => .if_directive,
                            .jsx_run_directive => .run_directive,
                            .jsx_component => .component_directive,
                            .jsx_style_directive => .style_directive,
                            .jsx_text => .text_static,
                            .jsx_expression => .expression,
                            else => unreachable,
                        },
                        .node_ref = ref,
                        .node_ptr = node,
                        .is_spread = node.hasFlag(.generator) or node.kind == .jsx_if_directive or node.kind == .jsx_else_directive,
                    };
                    try s.node_info.put(getAllocator(), ref, ptr);
                    return ptr;
                }

                fn getOrPutTreeNodeInfo(s: *@This(), ref: NodeRef, node: *const AstNode) !struct { found: bool, info: *TreeNodeInfo } {
                    const entry = try s.node_info.getOrPut(getAllocator(), ref);
                    if (entry.found_existing) {
                        return .{ .found = true, .info = entry.value_ptr.* };
                    }
                    const ptr = try s.createTreeNodeInfo(ref, node);
                    entry.value_ptr.* = ptr;
                    return .{ .found = false, .info = ptr };
                }

                fn deinit(s: *@This()) void {
                    s.stmts.deinit();
                    if (!s.borrowed_bridged_declarations) {
                        if (s.bridged_declarations) |m| m.deinit(getAllocator());
                        if (s.tree_classification) |tc| {
                            tc.deinit();
                            getAllocator().destroy(tc);
                        }
                        defer s.node_info.deinit(getAllocator());
                        var iter = s.node_info.valueIterator();
                        while (iter.next()) |ptr| {
                            ptr.*.children.deinit(getAllocator());
                            getAllocator().destroy(ptr.*);
                        }
                    }
                    if (s.hoistables) |m| m.deinit(getAllocator());
                    if (s.hoistable_symbols) |m| m.deinit(getAllocator());
                    if (s.static_nonnull) |m| m.deinit(getAllocator());

                    s.consumer_getters.deinit(getAllocator());
                    s.consumer_setters.deinit(getAllocator());
                }
            };

            fn inlineEmitSymbolUpdateFull(
                self: *@This(),
                state: *InlineEmitState,
                el_name: []const u8,
                own_ops: []const NodeRef,
            ) !bool {
                if (own_ops.len == 0) return state.ctx == .component;
                const lhs = blk: {
                    if (state.ctx == .component) {
                        break :blk try self.factory.createPropertyAccessExpression(
                            try self.factory.createIdentifier(el_name), "_u");
                    }
                    break :blk try self.accessUpdateSymbol(try self.factory.createIdentifier(el_name));
                };
                if (own_ops.len == 1 and self.nodes.at(own_ops[0]).kind == .expression_statement) {
                    const n = self.nodes.at(unwrapRef(self.nodes.at(own_ops[0])));
                    if (n.kind == .call_expression) {
                        const d = getPackedData(n);
                        const inner = self.nodes.at(d.left);
                        if (
                            d.right == 0 and
                            inner.kind == .element_access_expression and
                            self.nodes.at(getPackedData(inner).right).kind == .identifier and
                            strings.eql(getSlice(self.nodes.at(getPackedData(inner).right), u8), "__sym_upd")
                        ) {
                            // TODO: we don't need to bind intrinsics
                            const bind = try self.factory.createCallExpression(try self.factory.createPropertyAccessExpression(d.left, "bind"), &.{
                                getPackedData(inner).left
                            });
                            const assign = try self.factory.createBinaryExpression(lhs, .equals_token, bind);
                            try state.addStmt(try self.factory.createExpressionStatement(assign));
                            return true;
                        }
                        if (d.right == 0 and inner.kind == .identifier) {
                            const assign = try self.factory.createBinaryExpression(lhs, .equals_token, d.left);
                            try state.addStmt(try self.factory.createExpressionStatement(assign));
                            return true;   
                        }
                    }
                }
                const body_block = try self.factory.createBlock(own_ops);
                const arrow = try self.factory.createArrowFunction(0, body_block, 0);
                const assign = try self.factory.createBinaryExpression(lhs, .equals_token, arrow);
                try state.addStmt(try self.factory.createExpressionStatement(assign));
                return true;
            }

            fn createKeyedAccess(self: *@This(), subject: NodeRef, key: []const u8) !NodeRef {
                const is_ident = @import("lexer.zig").isIdentifier(key);
                if (is_ident) {
                    return self.factory.createPropertyAccessExpression(subject, key);
                }
                return self.factory.createElementAccessExpression(subject, key);
            }

            fn accessUpdateSymbol(self: *@This(), op: NodeRef) !NodeRef {
                const sym = try self.factory.createIdentifier(self.requireHelper(.update_symbol));
                return try self.factory.createElementAccessExpression(op, sym);
            }

            fn accessUpdateSymbolDirect(self: *@This(), op: NodeRef) !NodeRef {
                // load the update_symbol helper so Symbol.update is polyfilled
                _ = self.requireHelper(.update_symbol);
                const sym = try self.factory.createPropertyAccessExpression(
                    try self.factory.createIdentifier("Symbol"), "update");
                return try self.factory.createElementAccessExpression(op, sym);
            }

            fn isFragmentLike(_: *@This(), n: *const AstNode) bool {
                return n.kind == .jsx_fragment or n.kind == .jsx_component or
                    n.kind == .jsx_if_directive or n.kind == .jsx_else_directive;
            }

            fn inlineCallSymbolUpdate(self: *@This(), el_name: []const u8) !NodeRef {
                return self.factory.createExpressionStatement(
                    try self.factory.createCallExpression(try self.accessUpdateSymbol(try self.factory.createIdentifier(el_name)), &.{}));
            }

            fn maybeEmitCompAttr(self: *@This(), state: *InlineEmitState, binding_name: []const u8, node: *const AstNode) !void {
                const tag_ref = self.getJsxTagRef(node);
                if (tag_ref == 0) return;
                const tag_node = self.nodes.at(tag_ref);
                if (tag_node.kind != .identifier) return;
                const tag_name = getSlice(tag_node, u8);
                const scope = self.style_visitor.node_ptr_to_scope_map.get(node) orelse return;
                for (scope.comp_selectors) |e| {
                    if (std.mem.eql(u8, e.name, tag_name)) {
                        const a_lhs = try self.factory.createPropertyAccessExpression(
                            try self.factory.createIdentifier(binding_name), "_a");
                        const a_rhs = try self.factory.createStringLiteral(e.attr);
                        try state.addStmt(try self.factory.createExpressionStatement(
                            try self.factory.createBinaryExpression(a_lhs, .equals_token, a_rhs)));
                        return;
                    }
                }
            }

            fn createSpliceAtStatement(self: *@This(), offset_counter_name: NodeRef, len_name: NodeRef, children_exp: NodeRef, inner_ref: NodeRef, arr_pos: u32) !NodeRef {
                if (offset_counter_name == 0) {
                    const assign_len = try self.factory.createBinaryExpression(
                        len_name, 
                        .equals_token,
                        try self.factory.createCallExpression(try self.factory.createIdentifier(self.requireHelper(.splice_at)), &.{
                            try self.factory.cloneNodeRef(children_exp),
                            try self.factory.createNumericLiteral(arr_pos),
                            try self.cloneIfNeeded(inner_ref),
                            try self.factory.cloneNodeRef(len_name),
                        })
                    );
                    return try self.factory.createExpressionStatement(assign_len);
                }
                const index_exp = if (arr_pos == 0) 
                    try self.factory.cloneNodeRef(offset_counter_name)
                else
                    try self.factory.createBinaryExpression(try self.factory.createNumericLiteral(arr_pos), .plus_token, offset_counter_name);
                const assign_len = try self.factory.createBinaryExpression(
                    len_name, 
                    .equals_token,
                    try self.factory.createCallExpression(try self.factory.createIdentifier(self.requireHelper(.splice_at)), &.{
                        try self.factory.cloneNodeRef(children_exp),
                        index_exp,
                        try self.cloneIfNeeded(inner_ref),
                        try self.factory.cloneNodeRef(len_name),
                    })
                );
                const update_offset = try self.factory.createBinaryExpression(
                    offset_counter_name,
                    .plus_equals_token,
                    try self.factory.createParenthesizedExpression(assign_len),
                );
                return try self.factory.createExpressionStatement(update_offset);
            }

            fn inlineSetAttrStmt(self: *@This(), ctx: InlineEmitState.Ctx, el_name: []const u8, tag: []const u8, key: []const u8, val_ref: NodeRef) !NodeRef {
                const el_id = try self.factory.createIdentifier(el_name);
                if (ctx == .component and !isHtmlIntrinsic(tag)) {
                    const lhs = try self.createKeyedAccess(el_id, key);
                    const assign = try self.factory.createBinaryExpression(lhs, .equals_token, val_ref);
                    return self.factory.createExpressionStatement(assign);
                }
                if (strings.startsWith(key, "attr:")) {
                    const set_fn = try self.factory.createIdentifier(self.requireHelper(.set_attribute));
                    const key_str = try self.factory.createStringLiteral(key);
                    return self.factory.createExpressionStatement(
                        try self.factory.createCallExpression(set_fn, &.{ el_id, key_str, val_ref }));
                }
                if (strings.startsWith(key, "on:")) {
                    const set_fn = try self.factory.createPropertyAccessExpression(
                        try self.factory.createIdentifier(el_name), try self.factory.createIdentifier("addEventListener"));
                    const key_str = try self.factory.createStringLiteral(key[3..]);
                    return self.factory.createExpressionStatement(
                        try self.factory.createCallExpression(set_fn, &.{ key_str, val_ref }));
                }
                if (strings.startsWith(key, "style:")) {
                    const style_access = try self.factory.createPropertyAccessExpression(el_id, "style");
                    const set_fn = try self.factory.createPropertyAccessExpression(style_access, "setProperty");
                    const prop_str = try self.factory.createStringLiteral(key[6..]);
                    return self.factory.createExpressionStatement(
                        try self.factory.createCallExpression(set_fn, &.{ prop_str, val_ref }));
                }
                if (tag.len > 0 and isHtmlIntrinsic(tag)) {
                    if (htmlResolvePropName(tag, key)) |prop| {
                        const lhs = try self.factory.createPropertyAccessExpression(el_id, prop);
                        const assign = try self.factory.createBinaryExpression(lhs, .equals_token, val_ref);
                        return self.factory.createExpressionStatement(assign);
                    }
                }
                const can_call_direct = switch (self.nodes.at(val_ref).kind) {
                    .string_literal, .template_expression, 
                    .no_substitution_template_literal, .numeric_literal => true,
                    else => false,
                };
                if (can_call_direct) {
                    const set_fn = try self.factory.createPropertyAccessExpression(
                        try self.factory.createIdentifier(el_name), try self.factory.createIdentifier("setAttribute"));
                    const key_str = try self.factory.createStringLiteral(key);
                    return self.factory.createExpressionStatement(
                        try self.factory.createCallExpression(set_fn, &.{ key_str, val_ref }));
                }
                const set_fn = try self.factory.createIdentifier(self.requireHelper(.set_attribute));
                const key_str = try self.factory.createStringLiteral(key);
                return self.factory.createExpressionStatement(
                    try self.factory.createCallExpression(set_fn, &.{ el_id, key_str, val_ref }));
            }

            fn hasSpreadAttr(self: *@This(), attrs: *const AstNode) bool {
                std.debug.assert(attrs.kind == .jsx_attributes);
                const ref = maybeUnwrapRef(attrs) orelse return false;
                var iter = NodeIterator.init(self.nodes, ref);
                while (iter.next()) |n| {
                    if (n.kind == .jsx_spread_attribute) return true;
                }
                return false;
            }

            fn inlineEmitClassToggle(
                self: *@This(),
                state: *InlineEmitState,
                upd_body: *std.ArrayList(NodeRef),
                el_name: []const u8,
                class_attr: *const AstNode,
            ) !void {
                const d = getPackedData(class_attr);
                if (d.right == 0) return;
                const cond_inner = unwrapRef(self.nodes.at(d.right));
                try self.visit(self.nodes.at(cond_inner), cond_inner);

                var name_count: u32 = 0;
                var ni = NodeIterator.init(self.nodes, d.left);
                while (ni.next()) |_| name_count += 1;

                if (name_count == 1) {
                    const name = getSlice(self.nodes.at(d.left), u8);
                    const cl = try self.factory.createPropertyAccessExpression(
                        try self.factory.createIdentifier(el_name), "classList");
                    const toggle = try self.factory.createPropertyAccessExpression(cl, "toggle");
                    const call = try self.factory.createCallExpression(toggle,
                        &.{ try self.factory.createStringLiteral(name), cond_inner });
                    try upd_body.append(try self.factory.createExpressionStatement(call));
                } else {
                    var block_stmts = std.ArrayList(NodeRef).init(getAllocator());
                    defer block_stmts.deinit();
                    const cond_id = try self.factory.createIdentifier(try state.nextName());
                    try block_stmts.append(try self.factory.createConstVariable(cond_id, cond_inner));
                    ni = NodeIterator.init(self.nodes, d.left);
                    while (ni.next()) |name_node| {
                        const name = getSlice(name_node, u8);
                        const cl = try self.factory.createPropertyAccessExpression(
                            try self.factory.createIdentifier(el_name), "classList");
                        const toggle = try self.factory.createPropertyAccessExpression(cl, "toggle");
                        const call = try self.factory.createCallExpression(toggle,
                            &.{ try self.factory.createStringLiteral(name), cond_id });
                        try block_stmts.append(try self.factory.createExpressionStatement(call));
                    }
                    try upd_body.append(try self.factory.createBlock(block_stmts.items));
                }
            }

            fn forEachChildInlineBridge(
                self: *@This(),
                state: *InlineEmitState,
                bridged_symbols: *std.AutoHashMapUnmanaged(SymbolRef, NodeRef),
                deopt: *bool,
                start_ref: NodeRef
            ) !void {
                if (start_ref == 0) return;
                const Self = *@This();
                const V = struct {
                    s: Self,
                    deopt: *bool,
                    state: *InlineEmitState,
                    bridged_symbols: *std.AutoHashMapUnmanaged(SymbolRef, NodeRef),
                    pub fn visit(v: *@This(), n: *const AstNode, ref: NodeRef) anyerror!void {
                        if (v.deopt.* == true) return;
                        switch (n.kind) {
                            .identifier => {
                                try v.s.inlineBridgeStaticAnonymousFnVisitor(v.state, v.bridged_symbols, ref, v.deopt);
                            },
                            .parameter => {
                                const init_ref = getPackedData(n).right;
                                if (init_ref != 0) {
                                    try parser.forEachChild(v.s.nodes, v.s.nodes.at(init_ref), v);
                                }
                            },
                            else => {
                                try parser.forEachChild(v.s.nodes, n, v);
                            }
                        }
                    }
                };

                var v = V{
                    .s = self,
                    .state = state,
                    .deopt = deopt,
                    .bridged_symbols = bridged_symbols,
                };
                try parser.forEachChild(self.nodes, self.nodes.at(start_ref), &v);
            }

            fn markNonNull(self: *@This(), ref: NodeRef, candidates: *std.AutoHashMapUnmanaged(SymbolRef, ?bool), is_nonnull: bool) void {
                const n = self.nodes.at(ref);
                if (n.kind != .identifier) return;
                const sym = self.file.binder.getSymbol(ref) orelse return;
                if (candidates.getEntry(sym)) |entry| {
                    if (entry.value_ptr.* == null) {
                        entry.value_ptr.* = is_nonnull;
                    }
                }
            }

            fn markNonNullFromExp(self: *@This(), expr_ref: NodeRef, candidates: *std.AutoHashMapUnmanaged(SymbolRef, ?bool)) void {
                if (expr_ref == 0) return;
                const n = self.nodes.at(expr_ref);
                switch (n.kind) {
                    .call_expression, .new_expression => {
                        if (n.hasFlag(NodeFlags.optional)) return self.markNonNullFromExp(getPackedData(n).left, candidates);
                        self.findNonNullProofOrIdent(getPackedData(n).left, candidates);
                        var iter = NodeIterator.init(self.nodes, getPackedData(n).right);
                        while (iter.nextRef()) |arg_ref| self.markNonNullFromExp(arg_ref, candidates);
                    },
                    .property_access_expression, .element_access_expression => {
                        if (n.hasFlag(NodeFlags.optional)) return self.markNonNullFromExp(getPackedData(n).left, candidates);
                        self.findNonNullProofOrIdent(getPackedData(n).left, candidates);
                        if (n.kind == .element_access_expression) {
                            self.markNonNullFromExp(getPackedData(n).right, candidates);
                        }
                    },
                    .binary_expression => {
                        self.markNonNullFromExp(getPackedData(n).left, candidates);
                        // we can't always check right due to short circuiting
                        // if (self.getNonnullProof(getPackedData(n).right, candidates)) |s| return s;
                        if (n.len != @intFromEnum(SyntaxKind.in_keyword)) return;
                        return self.findNonNullProofOrIdent(getPackedData(n).right, candidates);
                    },
                    .keyword_unary_expression => {
                        if (n.len != @intFromEnum(SyntaxKind.update_keyword)) return;
                        return self.findNonNullProofOrIdent(unwrapRef(n), candidates);
                    },
                    .parenthesized_expression, .await_expression => return self.markNonNullFromExp(unwrapRef(n), candidates),
                    else => {},
                }
            }

            fn findNonNullProofOrMarkEscaped(self: *@This(), expr_ref: NodeRef, candidates: *std.AutoHashMapUnmanaged(SymbolRef, ?bool)) void {
                const n = self.nodes.at(expr_ref);
                return switch (n.kind) {
                    .identifier => self.markNonNull(expr_ref, candidates, false),
                    .parenthesized_expression, .await_expression => self.findNonNullProofOrMarkEscaped(unwrapRef(n), candidates),
                    else => self.markNonNullFromExp(expr_ref, candidates),
                };
            }

            fn findNonNullProofOrIdent(self: *@This(), expr_ref: NodeRef, candidates: *std.AutoHashMapUnmanaged(SymbolRef, ?bool)) void {
                const n = self.nodes.at(expr_ref);
                return switch (n.kind) {
                    .identifier => self.markNonNull(expr_ref, candidates, true),
                    .parenthesized_expression, .await_expression => self.findNonNullProofOrIdent(unwrapRef(n), candidates),
                    else => self.markNonNullFromExp(expr_ref, candidates),
                };
            }

            fn markNonNullCandidatesStatements(self: *@This(), stmts_head: NodeRef, candidates: *std.AutoHashMapUnmanaged(SymbolRef, ?bool)) void {
                var iter = NodeIterator.init(self.nodes, stmts_head);
                while (iter.nextRef()) |stmt_ref| {
                    const stmt = self.nodes.at(stmt_ref);
                    switch (stmt.kind) {
                        .expression_statement => {
                            self.markNonNullFromExp(unwrapRef(stmt), candidates);
                        },
                        .for_of_statement => {
                            self.findNonNullProofOrIdent(getPackedData(stmt).right, candidates);
                        },
                        .update_statement => {
                            var op_iter = NodeIterator.init(self.nodes, getPackedData(stmt).left);
                            while (op_iter.nextRef()) |op_ref| {
                                self.findNonNullProofOrIdent(op_ref, candidates);
                            }
                            self.markNonNullCandidatesStatements(getPackedData(stmt).right, candidates);
                        },
                        .block => {
                            self.markNonNullCandidatesStatements(maybeUnwrapRef(stmt) orelse 0, candidates);
                        },
                        .variable_statement => {
                            const decl = unwrapRef(stmt);
                            const binding = getPackedData(self.nodes.at(decl)).left;
                            const initializer = getPackedData(self.nodes.at(decl)).right;
                            if (self.nodes.at(binding).kind != .identifier) {
                                // destructuring
                                self.findNonNullProofOrIdent(initializer, candidates);
                            } else {
                                self.markNonNullFromExp(initializer, candidates);
                            }
                        },
                        .if_statement, .while_statement, .switch_statement => {
                            const exp = getPackedData(stmt).left;
                            self.markNonNullFromExp(exp, candidates);
                            if (stmt.kind != .switch_statement and self.nodes.at(exp).kind == .true_keyword) {
                                const r = getPackedData(stmt).right;
                                if (r != 0) self.markNonNullCandidatesStatements(r, candidates);
                            }
                        },
                        else => {},
                    }
                }
            }

            fn inlineMarkNonNullCandidates(
                self: *@This(),
                state: *InlineEmitState,
                stmts_head: NodeRef,
                candidates: *std.AutoHashMapUnmanaged(SymbolRef, ?bool),
            ) !void {
                self.markNonNullCandidatesStatements(stmts_head, candidates);
                var m_iter = candidates.iterator();
                while (m_iter.next()) |entry| {
                    if (entry.value_ptr.* != true) continue;
                    if (state.static_nonnull == null) {
                        state.static_nonnull = try getAllocator().create(std.AutoHashMapUnmanaged(SymbolRef, void));
                        state.static_nonnull.?.* = .{};
                    }
                    try state.static_nonnull.?.put(getAllocator(), entry.key_ptr.*, {});       
                }
            }

            fn _inlineBridgeStaticAnonymousFns(
                self: *@This(),
                state: *InlineEmitState,
                children_start: NodeRef,
            ) !void {
                try self.inlineCollectDynamicRunSymbols(children_start);

                var iter = NodeIterator.init(self.nodes, children_start);
                while (iter.nextRef()) |ref| {
                    const n = self.nodes.at(ref);
                    switch (n.kind) {
                        .jsx_run_directive => {
                            const stmts_head = getPackedData(n).right;
                            if (stmts_head == 0) continue;
                            if (state.hoistable_symbols == null) {
                                state.hoistable_symbols = try getAllocator().create(std.AutoHashMapUnmanaged(SymbolRef, bool));
                                state.hoistable_symbols.?.* = .{};
                            }
                            var m = state.hoistable_symbols.?;

                            var pre_iter = NodeIterator.init(self.nodes, stmts_head);
                            while (pre_iter.nextRef()) |stmt_ref| {
                                const stmt = self.nodes.at(stmt_ref);
                                const is_static = stmt.hasFlag(NodeFlags.static);
                                if (!is_static) {
                                    // we can still sometimes hoist non-static declarations 
                                    // though this is only worth it for fns passed to components
                                    // which would change observable behavior if the callee is not analyzed
                                }
                                if (stmt.kind == .variable_statement) {
                                    const decl_head = maybeUnwrapRef(stmt) orelse continue;
                                    var di = NodeIterator.init(self.nodes, decl_head);
                                    while (di.nextRef()) |decl_ref| {
                                        const sym_ref = self.file.binder.getSymbol(decl_ref) orelse continue;
                                        if (!is_static) {
                                            try m.put(getAllocator(), sym_ref, false);
                                            continue;
                                        }
                                        const decl = self.nodes.at(decl_ref);
                                        const init_ref = getPackedData(decl).right;
                                        const can_hoist = init_ref == 0 or self.inlineCanHoistExpr(init_ref, m);
                                        try m.put(getAllocator(), sym_ref, can_hoist);
                                    }
                                } else if (stmt.kind == .function_declaration) {
                                    const sym_ref = self.file.binder.getSymbol(stmt_ref) orelse continue;
                                    // TODO: we don't need to be adding to the map ?
                                    try m.put(getAllocator(), sym_ref, is_static);
                                } else if (stmt.kind == .class_declaration) {
                                    const sym_ref = self.file.binder.getSymbol(stmt_ref) orelse continue;
                                    if (!is_static) {
                                        try m.put(getAllocator(), sym_ref, false);
                                        continue;
                                    }
                                    
                                    var can_hoist = true;
                                    var members_iter = NodeIterator.init(self.nodes, maybeUnwrapRef(stmt) orelse 0);
                                    while (members_iter.nextRef()) |member_ref| {
                                        const member = self.nodes.at(member_ref);
                                        if (!member.hasFlag(.static) and member.kind != .class_static_block_declaration) continue;
                                        if (member.kind != .class_static_block_declaration and member.kind != .property_declaration) continue;
                                        if (self.dependsOnEffects(member_ref, member)) {
                                            can_hoist = false;
                                            break;
                                        }
                                    }
                                    try m.put(getAllocator(), sym_ref, can_hoist);
                                }
                            }

                            // collect static const 
                            var nonnull_candidates = std.AutoHashMapUnmanaged(SymbolRef, ?bool){};
                            defer nonnull_candidates.deinit(getAllocator());
                            var cand_iter = NodeIterator.init(self.nodes, stmts_head);
                            while (cand_iter.nextRef()) |stmt_ref| {
                                const stmt = self.nodes.at(stmt_ref);
                                if (stmt.kind != .variable_statement) continue;
                                if (!stmt.hasFlag(NodeFlags.static) or !stmt.hasFlag(NodeFlags.@"const")) continue;
                                const decl_head = maybeUnwrapRef(stmt) orelse continue;
                                var di = NodeIterator.init(self.nodes, decl_head);
                                while (di.nextRef()) |decl_ref| {
                                    const sym_ref = self.file.binder.getSymbol(decl_ref) orelse continue;
                                    try nonnull_candidates.put(getAllocator(), sym_ref, null);
                                }
                            }
                            if (nonnull_candidates.count() > 0) {
                                try self.inlineMarkNonNullCandidates(state, stmts_head, &nonnull_candidates);
                            }
                        },
                        .jsx_element, .jsx_self_closing_element => {
                            const o = if (n.kind == .jsx_element) self.nodes.at(unwrapRef(n)) else n;
                            if (!self.isIntrinsicTag(getPackedData(o).left)) continue;
                            const attributes_ref = getPackedData(o).right;
                            const attributes = self.nodes.at(attributes_ref);
                            const attr_start = maybeUnwrapRef(attributes) orelse 0;
                            var attr_iter = NodeIterator.init(self.nodes, attr_start);
                            while (attr_iter.nextRef()) |attr_ref| {
                                const attr = self.nodes.at(attr_ref);
                                if (attr.kind != .jsx_attribute) continue;
                                const ad = getPackedData(attr);
                                const key = getSlice(self.nodes.at(ad.left), u8);

                                if (strings.startsWith(key, "on:")) {
                                    if (ad.right != 0 and self.nodes.at(ad.right).kind == .jsx_expression) {
                                        const inner_ref = unwrapRef(self.nodes.at(ad.right));
                                        try self.inlineBridgeStaticAnonymousFn(state, inner_ref);
                                    }
                                }
                            }
                        },
                        else => {},
                    }
                }

                // now we recurse to handle nested components
                iter = NodeIterator.init(self.nodes, children_start);
                while (iter.nextRef()) |ref| {
                    const n = self.nodes.at(ref);
                    switch (n.kind) {
                        .jsx_component => {
                            try self.inlineBridgeNestedCompDecl(state, ref);
                            try self._inlineBridgeStaticAnonymousFns(state, getPackedData(n).right);
                        },
                        .jsx_if_directive, .jsx_else_directive, .jsx_fragment => {
                            try self._inlineBridgeStaticAnonymousFns(state, getPackedData(n).right);
                        },
                        .jsx_element => {
                            try self._inlineBridgeStaticAnonymousFns(state, unwrapRef(n));
                        },
                        else => {},
                    }
                }
            }

            fn inlineBridgeStaticAnonymousFns(
                self: *@This(),
                state: *InlineEmitState,
                children_start: NodeRef,
            ) !void {
                if (state.did_prepass_for_bridges) return;
                state.did_prepass_for_bridges = true;
                try self._inlineBridgeStaticAnonymousFns(state, children_start);
                if (state.tree_classification != null) return;
                const tc = try getAllocator().create(TreeClassification);
                tc.* = .{};
                try self.classifyTreeSymbols(children_start, tc);
                state.tree_classification = tc;
                // tc.debug_print(self.nodes, self.file.binder);
            }

            fn inlineBridgeStaticAnonymousFnVisitor(
                self: *@This(),
                state: *InlineEmitState,
                bridged_symbols: *std.AutoHashMapUnmanaged(SymbolRef, NodeRef),
                exp_ref: NodeRef,
                deopt: *bool,
            ) !void {
                const sym_id = self.file.binder.getSymbol(exp_ref) orelse return;
                if (self.run_directive_symbols.get(sym_id) == null) return;
                const sym = self.file.binder.symbols.at(sym_id);
                if (sym.declaration == 0) return;

                const decl = self.nodes.at(sym.declaration);
                if (decl.kind == .variable_declaration) {
                    if (!sym.hasFlag(.@"const")) {
                        deopt.* = true;
                        return;
                    }
                }

                if (state.bridged_declarations) |m| {
                    if (m.contains(sym_id)) return;
                }

                const entry = try bridged_symbols.getOrPut(getAllocator(), sym_id);
                if (!entry.found_existing) {
                    const bridge_name = try state.nextName();
                    entry.value_ptr.* = try self.factory.createIdentifierAllocated(bridge_name);
                }
            }

            fn forEachChildInlineBridgeComp(
                self: *@This(),
                state: *InlineEmitState,
                bridged_symbols: *std.AutoHashMapUnmanaged(SymbolRef, NodeRef),
                start_ref: NodeRef
            ) !void {
                if (start_ref == 0) return;
                const Self = *@This();
                const V = struct {
                    s: Self,
                    state: *InlineEmitState,
                    bridged_symbols: *std.AutoHashMapUnmanaged(SymbolRef, NodeRef),
                    pub fn visit(v: *@This(), n: *const AstNode, ref: NodeRef) anyerror!void {
                        switch (n.kind) {
                            .identifier => {
                                const sym_id = v.s.file.binder.getSymbol(ref) orelse return;
                                const sym = v.s.file.binder.symbols.at(sym_id);
                                if (sym.declaration == 0) return;

                                if (v.state.bridged_declarations) |m| {
                                    if (m.contains(sym_id)) return;
                                }

                                if (!v.s.run_directive_symbols.contains(sym_id)) return;

                                const entry = try v.bridged_symbols.getOrPut(getAllocator(), sym_id);
                                if (!entry.found_existing) {
                                    const bridge_name = try v.state.nextName();
                                    entry.value_ptr.* = try v.s.factory.createIdentifierAllocated(bridge_name);
                                }
                            },
                            .parameter => {
                                const init_ref = getPackedData(n).right;
                                if (init_ref != 0) {
                                    try parser.forEachChild(v.s.nodes, v.s.nodes.at(init_ref), v);
                                }
                            },
                            else => {
                                try parser.forEachChild(v.s.nodes, n, v);
                            }
                        }
                    }
                };

                var v = V{
                    .s = self,
                    .state = state,
                    .bridged_symbols = bridged_symbols,
                };
                try parser.forEachChild(self.nodes, self.nodes.at(start_ref), &v);
            }

            fn forEachChildDetectCaptures(
                self: *@This(),
                start_ref: NodeRef,
                captured: *std.AutoHashMapUnmanaged(SymbolRef, void),
            ) !void {
                if (start_ref == 0) return;
                const Self = *@This();
                const V = struct {
                    s: Self,
                    is_capturing: bool,
                    captured: *std.AutoHashMapUnmanaged(SymbolRef, void),
                    excluded: std.AutoHashMapUnmanaged(SymbolRef, void),

                    fn markDeclared(v: *@This(), sym_ref: SymbolRef) !void {
                        try v.excluded.put(getAllocator(), sym_ref, {});
                        _ = v.captured.remove(sym_ref);
                    }

                    fn maybeMarkDeclared(v: *@This(), node_ref: NodeRef) anyerror!void {
                        if (node_ref == 0) return;
                        const n = v.s.nodes.at(node_ref);
                        switch (n.kind) {
                            .array_binding_pattern, .object_binding_pattern => {
                                var iter = NodeIterator.init(this.nodes, maybeUnwrapRef(n) orelse 0);
                                while (iter.nextRef()) |r| {
                                    try v.maybeMarkDeclared(r);
                                }
                                return;
                            },
                            .binding_element => {
                                return try v.maybeMarkDeclared(getPackedData(n).left);
                            },
                            else => {},
                        }

                        if (v.s.file.binder.getSymbol(node_ref)) |sym_ref| {
                            try v.markDeclared(sym_ref);
                        }
                    }

                    pub fn visit(v: *@This(), n: *const AstNode, ref: NodeRef) anyerror!void {
                        switch (n.kind) {
                            .identifier => {
                                if (!v.is_capturing) return;
                                const sym_ref = v.s.file.binder.getSymbol(ref) orelse return;
                                if (v.excluded.contains(sym_ref)) return;
                                try v.captured.put(getAllocator(), sym_ref, {});
                            },
                            .variable_declaration => {
                                try v.maybeMarkDeclared(ref);
                                const init_ref = getPackedData(n).right;
                                if (init_ref != 0) {
                                    try parser.forEachChild(v.s.nodes, v.s.nodes.at(init_ref), v);
                                }
                            },
                            .function_declaration, .class_declaration => {
                                try v.maybeMarkDeclared(ref);
                                const saved = v.is_capturing;
                                defer v.is_capturing = saved;
                                v.is_capturing = true;
                                try parser.forEachChild(v.s.nodes, n, v);
                            },
                            .function_expression, .arrow_function => {
                                if (n.kind == .function_expression) {
                                    try v.maybeMarkDeclared(getPackedData(n).left);
                                }
                                const saved = v.is_capturing;
                                defer v.is_capturing = saved;
                                v.is_capturing = true;
                                try parser.forEachChild(v.s.nodes, n, v);
                            },
                            .method_declaration, .get_accessor, .set_accessor => {
                                const saved = v.is_capturing;
                                defer v.is_capturing = saved;
                                v.is_capturing = true;
                                try parser.forEachChild(v.s.nodes, n, v);
                            },
                            .call_expression => {
                                if (v.is_capturing) {
                                    return try parser.forEachChild(v.s.nodes, n, v);
                                }
                                const d = getPackedData(n);
                                if (v.s.nodes.at(d.left).kind == .parenthesized_expression) {
                                    const inner = unwrapRef(v.s.nodes.at(d.left));
                                    if (v.s.nodes.at(inner).kind == .arrow_function or v.s.nodes.at(inner).kind == .function_expression) {
                                        try parser.forEachChild(v.s.nodes, v.s.nodes.at(inner), v);
                                        var args_iter = NodeIterator.init(v.s.nodes, d.right);
                                        while (args_iter.nextRef()) |r| {
                                            try v.visit(v.s.nodes.at(r), r);
                                        }
                                        return;
                                    }
                                }
                                try parser.forEachChild(v.s.nodes, n, v);
                            },
                            .jsx_element, .jsx_self_closing_element => {
                                const opening = if (n.kind == .jsx_element) unwrapRef(n) else ref;
                                try v.maybeMarkDeclared(v.s.nodes.at(opening).extra_data);
                                try parser.forEachChild(v.s.nodes, n, v);
                            },
                            .parameter => {
                                try v.maybeMarkDeclared(ref);
                                const init_ref = getPackedData(n).right;
                                if (init_ref != 0) {
                                    try parser.forEachChild(v.s.nodes, v.s.nodes.at(init_ref), v);
                                }
                            },
                            else => {
                                try parser.forEachChild(v.s.nodes, n, v);
                            },
                        }
                    }
                };

                var v = V{
                    .s = self,
                    .is_capturing = false,
                    .captured = captured,
                    .excluded = .{},
                };
                defer v.excluded.deinit(getAllocator());
                try parser.forEachChild(self.nodes, self.nodes.at(start_ref), &v);
            }

            fn inlineBridgeNestedCompDecl(
                self: *@This(),
                state: *InlineEmitState,
                decl_ref: NodeRef,
            ) !void {
                const decl = self.nodes.at(decl_ref);
                std.debug.assert(decl.kind == .jsx_component);

                var bridged_symbols = std.AutoHashMapUnmanaged(SymbolRef, NodeRef){};
                defer bridged_symbols.deinit(getAllocator());

                try self.forEachChildInlineBridgeComp(state, &bridged_symbols, decl_ref);

                if (bridged_symbols.count() == 0) return;

                if (state.bridged_declarations == null) {
                    const q = try getAllocator().create(std.AutoHashMapUnmanaged(SymbolRef, NodeRef));
                    q.* = .{};
                    state.bridged_declarations = q;
                }

                var iter = bridged_symbols.iterator();
                while (iter.next()) |entry| {
                    try state.bridged_declarations.?.put(getAllocator(), entry.key_ptr.*, entry.value_ptr.*);
                }
            }

            fn inlineBridgeStaticAnonymousFn(
                self: *@This(),
                state: *InlineEmitState,
                exp_ref: NodeRef,
            ) !void {
                const exp = self.nodes.at(exp_ref);
                switch (exp.kind) {
                    .arrow_function, .function_expression => {},
                    else => return,
                }

                var deopt = false;

                var bridged_symbols = std.AutoHashMapUnmanaged(SymbolRef, NodeRef){};
                defer bridged_symbols.deinit(getAllocator());

                const params_start = if (exp.kind == .arrow_function) getPackedData(exp).left else getPackedData(exp).right;
                var params_iter = NodeIterator.init(self.nodes, params_start);
                while (params_iter.nextRef()) |x| {
                    try self.forEachChildInlineBridge(state, &bridged_symbols, &deopt, x);
                    if (deopt) return;
                }

                const body_ref = if (exp.kind == .arrow_function) getPackedData(exp).right else exp.len;
                try self.forEachChildInlineBridge(state, &bridged_symbols, &deopt, body_ref);
                if (deopt) return;

                if (state.hoistables == null) {
                    const q = try getAllocator().create(std.AutoHashMapUnmanaged(NodeRef, void));
                    q.* = .{};
                    state.hoistables = q;
                }
                try state.hoistables.?.put(getAllocator(), exp_ref, {});
                if (state.bridged_declarations == null) {
                    const q = try getAllocator().create(std.AutoHashMapUnmanaged(SymbolRef, NodeRef));
                    q.* = .{};
                    state.bridged_declarations = q;
                }
                var iter = bridged_symbols.iterator();
                while (iter.next()) |entry| {
                    try state.bridged_declarations.?.put(getAllocator(), entry.key_ptr.*, entry.value_ptr.*);
                }
            }

            const ScopedSymbolReplacer = struct {
                const MapPtr = *std.AutoHashMapUnmanaged(SymbolRef, NodeRef);
                target: MapPtr, 
                old_replacements: std.AutoArrayHashMapUnmanaged(SymbolRef, ?NodeRef) = .{},

                pub fn init(target: MapPtr, source: MapPtr) !@This() {
                    var s = @This(){ .target = target };
                    var iter = source.iterator();
                    while (iter.next()) |entry| {
                        const old = s.target.get(entry.key_ptr.*);
                        try s.old_replacements.put(getAllocator(), entry.key_ptr.*, old);
                        try s.target.put(getAllocator(), entry.key_ptr.*, entry.value_ptr.*);
                    }
                    return s;
                }

                pub fn deinit(s: @This()) void {
                    defer {
                        var m = s.old_replacements;
                        m.deinit(getAllocator());
                    }
                    var iter = s.old_replacements.iterator();
                    while (iter.next()) |entry| {
                        if (entry.value_ptr.* == null) {
                            _ = s.target.remove(entry.key_ptr.*);
                        } else {
                            s.target.putAssumeCapacity(entry.key_ptr.*, entry.value_ptr.*.?);
                        }
                    }
                }
            };

            fn inlineEmitOnPseudoAttribute(
                self: *@This(),
                state: *InlineEmitState,
                upd_body: *std.ArrayList(NodeRef),
                el_name: []const u8,
                tag: []const u8,
                attr: *const AstNode,    
            ) !void {
                const ad = getPackedData(attr);
                const key = getSlice(self.nodes.at(ad.left), u8);
                if (ad.right != 0 and self.nodes.at(ad.right).kind == .jsx_expression) {
                    const inner_ref = unwrapRef(self.nodes.at(ad.right));
                    const can_hoist = if (state.hoistables) |m| m.contains(inner_ref) else false;
                    const symbol_replacer = if (can_hoist and state.bridged_declarations != null) 
                        try ScopedSymbolReplacer.init(&self.symbol_replacements, state.bridged_declarations.?)
                        else null;
                    defer if (symbol_replacer) |r| r.deinit();
                    var old_replacements = std.AutoArrayHashMapUnmanaged(SymbolRef, ?NodeRef){};
                    defer old_replacements.deinit(getAllocator());

                    try self.visit(self.nodes.at(inner_ref), inner_ref);
                    if (can_hoist) {
                        try state.addStmt(try self.inlineSetAttrStmt(state.ctx, el_name, tag, key, inner_ref));
                    } else {
                        const tmp_name = try state.nextName();
                        const tmp = try self.factory.createIdentifier(tmp_name);
                        try state.addStmt(try self.factory.createLetVariable(tmp, 0));

                        const set_fn = try self.factory.createPropertyAccessExpression(
                        try self.factory.createIdentifier(el_name), try self.factory.createIdentifier("removeEventListener"));
                        const key_str = try self.factory.createStringLiteral(key[3..]);
                        try upd_body.append(
                            try self.factory.createIfStatement(
                                tmp,
                                try self.factory.createCallExpression(set_fn, &.{ key_str, tmp }),
                                0,
                            )
                        );
                        const assign = try self.factory.createBinaryExpression(tmp, SyntaxKind.equals_token, inner_ref);
                        try upd_body.append(try self.inlineSetAttrStmt(state.ctx, el_name, tag, key, assign));
                    }
                }
            }

            // collect symbols declared in #run directives so `dependsOnEffects` treats them as dynamic
            fn inlineCollectDynamicRunSymbols(self: *@This(), children_start_ref: NodeRef) !void {
                var iter = NodeIterator.init(self.nodes, children_start_ref);
                while (iter.next()) |child| {
                    if (child.kind != .jsx_run_directive) continue;
                    const stmts_head = getPackedData(child).right;
                    var si = NodeIterator.init(self.nodes, stmts_head);
                    while (si.next()) |stmt| {
                        if (stmt.hasFlag(.static)) continue;
                        switch (stmt.kind) {
                            .class_declaration, .function_declaration => {
                                if (self.file.binder.getSymbol(getPackedData(stmt).left)) |sym_ref| {
                                    try self.run_directive_symbols.put(getAllocator(), sym_ref, {});
                                }
                            },
                            .variable_statement => {
                                var di = NodeIterator.init(self.nodes, unwrapRef(stmt));
                                while (di.next()) |decl| {
                                    std.debug.assert(decl.kind == .variable_declaration);
                                    // FIXME: destructuring!
                                    const name_ref = getPackedData(decl).left;
                                    if (self.file.binder.getSymbol(name_ref)) |sym_ref| {
                                        try self.run_directive_symbols.put(getAllocator(), sym_ref, {});
                                    }
                                }
                            },
                            else => {},
                        }
                    }
                }
            }

            fn emitJsxMethodAttribute(
                self: *@This(),
                state: *InlineEmitState,
                el_name: []const u8,
                node_ref: NodeRef,
                can_emit_arrow: bool,
            ) !NodeRef {
                const n = self.nodes.at(node_ref);
                std.debug.assert(n.kind == .jsx_method_attribute);
                const d = getPackedData(n);

                const name = if (!can_emit_arrow) try state.nextName() else null;
                const decl = if (can_emit_arrow)
                    try self.factory.createArrowFunction(d.right, n.len, n.flags)
                else
                    try self.factory.createFunctionDeclaration(try self.factory.createIdentifier(name.?), d.right, n.len);
                self.nodes.at(decl).flags |= n.flags;

                if (!can_emit_arrow) try state.addStmt(decl);

                var body = std.ArrayList(NodeRef).init(getAllocator());
                defer body.deinit();

                const replacer = try ScopedTreeBindingReplacer.init(self, state, n, &body);
                defer if (replacer) |x| x.deinit();

                var params_iter = NodeIterator.init(self.nodes, d.right);
                while (params_iter.nextRef()) |r| {
                    try self.visit(self.nodes.at(r), r);
                }
                {
                    // XXX: gross!
                    const z = state.current_node_ref;
                    const ident = try self.factory.createIdentifier(el_name);
                    const save = self.replacements.get(z);
                    if (z != 0) try self.replacements.put(z, ident);
                    try self.visit(self.nodes.at(n.len), n.len);
                    if (save) |x| {
                        try self.replacements.put(z, x);
                    }
                }

                if (body.items.len > 0) {
                    const block_ref = n.len;
                    const block_start = maybeUnwrapRef(self.nodes.at(block_ref)) orelse 0;
                    self.nodes.at(block_ref).data = @ptrFromInt(body.items[0]);
                    var x: NodeRef = 0;
                    for (body.items) |u| {
                        if (x != 0) self.nodes.at(x).next = u;
                        x = u;
                    }
                    self.nodes.at(x).next = block_start;
                }

                if (can_emit_arrow) return decl;

                return try self.factory.createIdentifier(name.?);
            }

            fn inlineProcessAttrs(
                self: *@This(),
                state: *InlineEmitState,
                upd_body: *std.ArrayList(NodeRef),
                el_name: []const u8,
                tag: []const u8,
                attrs_ref: NodeRef,
            ) !void {
                if (state.skip_attributes) return;

                if (attrs_ref == 0) return;
                const attrs = self.nodes.at(attrs_ref);
                if (attrs.kind != .jsx_attributes) return;

                const has_spread = self.hasSpreadAttr(attrs);
                var iter = NodeIterator.init(self.nodes, unwrapRef(attrs));

                // slow path for spreads
                if (has_spread) {
                    var obj_props = std.ArrayList(NodeRef).init(getAllocator());
                    defer obj_props.deinit();

                    while (iter.nextRef()) |ref| {
                        const attr = self.nodes.at(ref);
                        if (attr.kind == .jsx_class_attribute or attr.kind == .jsx_class_list) {
                            if (state.ctx == .component) continue;
                            if (attr.kind == .jsx_class_list) {
                                const list_ref = maybeUnwrapRef(attr) orelse continue;
                                var li = NodeIterator.init(self.nodes, list_ref);
                                while (li.next()) |ca| {
                                    if (ca.kind != .jsx_class_attribute) continue;
                                    try self.inlineEmitClassToggle(state, upd_body, el_name, ca);
                                }
                            } else {
                                try self.inlineEmitClassToggle(state, upd_body, el_name, attr);
                            }
                            continue;
                        }

                        if (attr.kind == .jsx_spread_attribute) {
                            const inner_ref = unwrapRef(attr);
                            try self.visit(self.nodes.at(inner_ref), inner_ref);
                            try obj_props.append(try self.factory.createSpreadAssignment(inner_ref));
                            continue;
                        }

                        std.debug.assert(attr.kind == .jsx_attribute);
                        const ad = getPackedData(attr);
                        const key = getSlice(self.nodes.at(ad.left), u8);

                        if (strings.startsWith(key, "on:")) {
                            if (ad.right != 0 and self.nodes.at(ad.right).kind == .jsx_expression) {
                                const inner_ref = unwrapRef(self.nodes.at(ad.right));
                                try self.visit(self.nodes.at(inner_ref), inner_ref);
                                try state.addStmt(try self.inlineSetAttrStmt(state.ctx, el_name, tag, key, inner_ref));
                            }
                            continue;
                        }

                        const key_id = try self.factory.createIdentifier(key);
                        if (ad.right == 0) {
                            try obj_props.append(try self.factory.createPropertyAssignment(key_id, try self.factory.createTrue()));
                            continue;
                        }
                        const val = self.nodes.at(ad.right);
                        if (val.kind != .jsx_expression) {
                            try obj_props.append(try self.factory.createPropertyAssignment(key_id, ad.right));
                        } else {
                            const inner_ref = unwrapRef(val);
                            try self.visit(self.nodes.at(inner_ref), inner_ref);
                            try obj_props.append(try self.factory.createPropertyAssignment(key_id, inner_ref));
                        }
                    }

                    const obj = try self.factory.createObjectLiteralExpression(obj_props.items);
                    const cache_id = try self.factory.createIdentifier(try state.nextName());
                    try self.inlineAddHoistedVar(state, cache_id, 0, @intFromEnum(NodeFlags.let));
                    const set_fn = try self.factory.createIdentifier(self.requireHelper(.spread_attributes));
                    const el_id = try self.factory.createIdentifier(el_name);
                    const call = try self.factory.createCallExpression(set_fn, &.{ el_id, obj, cache_id });
                    try upd_body.append(try self.factory.createAssignmentStatement(cache_id, call));
                    return;
                }

                while (iter.nextRef()) |attr_ref| {
                    const attr = self.nodes.at(attr_ref);
                    if (attr.kind == .jsx_class_attribute or attr.kind == .jsx_class_list) {
                        if (state.ctx == .component) continue;
                        if (attr.kind == .jsx_class_list) {
                            if (attr.data == null) continue;
                            const list_ref: NodeRef = @truncate(@intFromPtr(attr.data.?));
                            var li = NodeIterator.init(self.nodes, list_ref);
                            while (li.next()) |ca| {
                                if (ca.kind != .jsx_class_attribute) continue;
                                try self.inlineEmitClassToggle(state, upd_body, el_name, ca);
                            }
                        } else {
                            try self.inlineEmitClassToggle(state, upd_body, el_name, attr);
                        }
                        continue;
                    }

                    if (attr.kind == .jsx_method_attribute) {
                        const ad = getPackedData(attr);
                        const key = getSlice(self.nodes.at(ad.left), u8);
                        const is_dom_ev_handler = strings.startsWith(key, "on:") and isHtmlIntrinsic(tag);
                        const decl_ident = try self.emitJsxMethodAttribute(state, el_name, attr_ref, is_dom_ev_handler);
                        const s = try self.inlineSetAttrStmt(state.ctx, el_name, tag, key, decl_ident);
                        if (is_dom_ev_handler) {
                            try state.addStmt(s);
                        } else {
                            try upd_body.append(s);
                        }
                        continue;
                    }

                    std.debug.assert(attr.kind == .jsx_attribute);
                    const ad = getPackedData(attr);
                    const key = getSlice(self.nodes.at(ad.left), u8);
                    if (ad.right == 0) {
                        if (state.ctx != .templated) {
                            const true_val = try self.factory.createTrue();
                            try state.addStmt(try self.inlineSetAttrStmt(state.ctx, el_name, tag, key, true_val));
                        }
                        continue;
                    }
                    if (strings.startsWith(key, "on:") and isHtmlIntrinsic(tag)) {
                        try self.inlineEmitOnPseudoAttribute(state, upd_body, el_name, tag, attr);
                        continue;
                    }

                    const val = self.nodes.at(ad.right);
                    if (val.kind != .jsx_expression) {
                        if (isCamelCase(key) and tag.len > 0 and isHtmlIntrinsic(tag) and state.ctx != .component) {
                            try state.addStmt(try self.inlineSetAttrStmt(state.ctx, el_name, tag, key, ad.right));
                            continue;
                        }
                        if (state.ctx != .templated) {
                            try state.addStmt(try self.inlineSetAttrStmt(state.ctx, el_name, tag, key, ad.right));
                        }
                        continue;
                    }
                    const inner_ref = unwrapRef(val);
                    try self.visit(self.nodes.at(inner_ref), inner_ref);

                    const s = try self.inlineSetAttrStmt(state.ctx, el_name, tag, key, inner_ref);
                    if (self._dependsOnEffects(inner_ref)) {
                        try upd_body.append(s);
                    } else {
                        try state.addStmt(s);
                    }
                }
            }

            fn inlineAttrsHasDynamic(self: *const @This(), attrs_ref: NodeRef) bool {
                if (attrs_ref == 0) return false;
                const attrs = self.nodes.at(attrs_ref);
                if (attrs.kind != .jsx_attributes) return false;
                var iter = NodeIterator.init(self.nodes, unwrapRef(attrs));
                while (iter.next()) |attr| {
                    if (attr.kind == .jsx_class_attribute) {
                        const ad = getPackedData(attr);
                        if (ad.right != 0) return true;
                        continue;
                    }
                    if (attr.kind == .jsx_class_list) {
                        const s = maybeUnwrapRef(attr) orelse continue;
                        var iter2 =  NodeIterator.init(self.nodes, s);
                        while (iter2.next()) |a| {
                            // TODO: define what node to use for `{...exp}` inside of the class list
                            if (a.kind == .jsx_spread_attribute or a.kind == .jsx_expression) return true;
                            if (a.kind != .jsx_class_attribute) continue;
                            const ad = getPackedData(a);
                            if (ad.right != 0) return true;
                            continue;
                        } 
                    }
                    if (attr.kind == .jsx_method_attribute) return true;
                    if (attr.kind != .jsx_attribute) continue;
                    const ad = getPackedData(attr);
                    if (ad.right == 0) continue;
                    if (self.nodes.at(ad.right).kind == .jsx_expression) return true;
                }
                return false;
            }

            fn inlineNodeHasDynamic(self: *@This(), node: *const AstNode) bool {
                switch (node.kind) {
                    .jsx_self_closing_element => {
                        return self.inlineAttrsHasDynamic(getPackedData(node).right);
                    },
                    .jsx_element => {
                        const opening_ref = maybeUnwrapRef(node) orelse return false;
                        const opening = self.nodes.at(opening_ref);
                        if (self.inlineAttrsHasDynamic(getPackedData(opening).right)) return true;
                        var iter = NodeIterator.init(self.nodes, opening_ref);
                        while (iter.next()) |child| {
                            switch (child.kind) {
                                .jsx_expression => return true,
                                .jsx_element, .jsx_self_closing_element => {
                                    const ct = self.getJsxTagRef(child);
                                    if (!self.isIntrinsicTag(ct)) return true;
                                    if (self.inlineNodeHasDynamic(child)) return true;
                                },
                                .jsx_if_directive => return true,
                                .jsx_run_directive => {
                                    if (getPackedData(child).right != 0) return true;
                                },
                                .jsx_fragment => {
                                    if (self.inlineNodeHasDynamic(child)) return true;
                                },
                                else => {},
                            }
                        }
                        return false;
                    },
                    .jsx_if_directive, .jsx_else_directive, .jsx_fragment => {
                        // check if an update impl is needed for the fragment
                        var iter = NodeIterator.init(self.nodes, getPackedData(node).right);
                        while (iter.next()) |c| {
                            switch (c.kind) {
                                .jsx_expression,
                                .jsx_run_directive,
                                .jsx_if_directive,
                                .jsx_else_directive => return true, 
                                else => {},
                            }
                            if (self.inlineNodeHasDynamic(c)) return true;
                        }
                        return false;
                    },
                    else => return false,
                }
            }

            fn isStaticJsxExp(self: *@This(), node_ref: NodeRef) bool {
                if (node_ref == 0) return false;
                const n = self.nodes.at(node_ref);
                switch (n.kind) {
                    .numeric_literal, .string_literal, .true_keyword, .false_keyword => return true,
                    .jsx_expression => {
                        if (n.hasFlag(.static)) return true;
                        const inner_ref = maybeUnwrapRef(n) orelse return false;
                        if (self._dependsOnEffects(inner_ref)) return false;
                        return true;
                    },
                    else => {},
                }
                return false;
            }

            fn jsxNodeCanUseEphemeralNav(self: *@This(), node: *const AstNode) bool {
                if (self.inlineMaybeGetElementBinding(node) != null) return false;
                var attrs_ref: NodeRef = 0;
                switch (node.kind) {
                    .jsx_text => return true,
                    .jsx_self_closing_element => {
                        attrs_ref = getPackedData(node).right;
                    },
                    .jsx_element => {
                        const start_ref = unwrapRef(node);
                        attrs_ref = getPackedData(self.nodes.at(start_ref)).right;
                        var iter = NodeIterator.init(self.nodes, start_ref);
                        while (iter.next()) |child| {
                            switch (child.kind) {
                                .jsx_if_directive, .jsx_else_directive => return false,
                                .jsx_fragment => return false, // TODO: this isn't always the case
                                .jsx_element, .jsx_self_closing_element => {
                                    if (self.inlineNodeHasDynamic(child)) return false;
                                },
                                // TODO: static expressions could be elided if reordering does not change behavior
                                // also, we currently setup all of the navs before walking children. it _might_ be
                                // better to setup navs as we walk each
                                .jsx_expression => return false,
                                else => {},
                            }
                        }
                    },
                    else => return false,
                }
                if (attrs_ref != 0) {
                    var iter = NodeIterator.init(self.nodes, maybeUnwrapRef(self.nodes.at(attrs_ref)) orelse 0);
                    while (iter.nextRef()) |r| {
                        const attr = self.nodes.at(r);
                        switch (attr.kind) {
                            .jsx_spread_attribute, .jsx_method_attribute => return false,
                            .jsx_attribute, .jsx_class_attribute => {
                                if (!self.isStaticJsxExp(getPackedData(attr).right)) return false;
                            },
                            .jsx_class_list => {
                                var class_iter = NodeIterator.init(self.nodes, maybeUnwrapRef(attr) orelse 0);
                                while (class_iter.nextRef()) |c_ref| {
                                    const class_attr = self.nodes.at(c_ref);
                                    if (class_attr.kind != .jsx_class_attribute) return false;
                                    if (!self.isStaticJsxExp(getPackedData(class_attr).right)) return false;
                                }
                            },
                            else => {},
                        }
                    }
                }
                return true;
            }

            // keep in sync with `templateWriteHtmlAttrs`
            fn attrsAnyStatic(self: *@This(), attrs_ref: NodeRef) bool {
                if (attrs_ref == 0) return false;
                const attrs = self.nodes.at(attrs_ref);
                if (attrs.kind != .jsx_attributes) return false;

                var has_static = false;
                var iter = NodeIterator.init(self.nodes, maybeUnwrapRef(attrs) orelse 0);
                while (iter.next()) |attr| {
                    // spread attributes _always_ strip the template
                    // we can only early return false in this loop because of this
                    if (attr.kind == .jsx_spread_attribute) return false;
                    if (attr.kind == .jsx_class_list) {
                        var iter2 = NodeIterator.init(self.nodes, maybeUnwrapRef(attr) orelse 0);
                        while (iter2.next()) |a2| {
                            const ad = getPackedData(a2);
                            if (ad.right == 0 or self.nodes.at(ad.right).kind != .jsx_expression) {
                                has_static = true;
                            }
                        }
                        continue;
                    }
                    if (attr.kind != .jsx_attribute and attr.kind != .jsx_class_attribute) continue;

                    const ad = getPackedData(attr);
                    const name = self.nodes.at(ad.right);
                    if (strings.startsWith(getSlice(name, u8), "on:")) continue;
                    if (ad.right == 0 or self.nodes.at(ad.right).kind != .jsx_expression) {
                        has_static = true;
                    }
                }
                return has_static;
            }

            // a "simple static template" contains only 1 tag and no attributes e.g. `<div></div>`
            // these can be emitted using `document.createElement` directly
            fn simpleStaticTemplate(self: *@This(), n: *const AstNode) ?[]const u8 {
                if (self.style_visitor.node_ptr_to_scope_map.get(n) != null) return null;
                switch (n.kind) {
                    .jsx_self_closing_element => {
                        const d = getPackedData(n);
                        if (self.attrsAnyStatic(d.right)) return null;
                        return getSlice(self.nodes.at(d.left), u8);
                    },
                    .jsx_element => {
                        const opening_ref = maybeUnwrapRef(n) orelse return null;
                        const opening = self.nodes.at(opening_ref);
                        const od = getPackedData(opening);
                        if (self.attrsAnyStatic(od.right)) return null;
                        var iter = NodeIterator.init(self.nodes, opening_ref);
                        var has_computed = false;
                        while (iter.next()) |child| {
                            switch (child.kind) {
                                .jsx_run_directive, .jsx_component,
                                .jsx_opening_element, .jsx_closing_element, .jsx_text_all_white_spaces => {},
                                .jsx_text => { if (!self.isJsxTextAllWhitespace(child)) return null; },
                                .jsx_expression => {
                                    if (has_computed) return null;
                                    const inner = maybeUnwrapRef(child) orelse continue;
                                    if (self.nodes.at(inner).kind != .spread_element) return null;
                                    has_computed = true;
                                },
                                else => return null,
                            }
                        }
                        return getSlice(self.nodes.at(od.left), u8);
                    },
                    else => return null,
                }
            }

            fn isEmptyTemplateForFragmentLike(self: *@This(), n: *const AstNode) bool {
                if (!self.isFragmentLike(n)) return false;
                var iter = NodeIterator.init(self.nodes, getPackedData(n).right);
                while (iter.next()) |c| {
                    switch (c.kind) {
                        .jsx_text => {
                            if (!self.isJsxTextAllWhitespace(c)) return false;
                        },
                        .jsx_expression => {},
                        .jsx_component, .jsx_run_directive, .jsx_style_directive => {},
                        else => return false,
                    }
                }
                return true;
            }

            fn pruneTrailingEndTags(html: []const u8) []const u8 {
                var end = html.len;
                while (end > 0 and html[end-1] == '>') {
                    var i = end - 1;
                    while (i > 0 and html[i] != '<' and !std.ascii.isWhitespace(html[i])) i -= 1;
                    if (html[i] != '<' or i + 1 >= end or html[i+1] != '/') break;
                    end = i;
                }
                return html[0..end];
            }

            fn createHtmlTemplate(self: *@This(), ref: NodeRef) !NodeRef {
                const n = self.nodes.at(ref);

                var for_component: bool = false;
                switch (n.kind) {
                    .jsx_element, .jsx_self_closing_element => {
                        if (!self.isIntrinsicTag(self.getJsxTagRef(n))) {
                            for_component = true;
                        }
                    },
                    .jsx_if_directive, .jsx_else_directive => {
                        if (self.jsx_emit_state) |s| {
                            for_component = s.containing_element_is_fragment_like;
                        }
                    },
                    .jsx_fragment => {
                        for_component = true;
                    },
                    .jsx_component => {
                        for_component = n.hasFlag(.generator);
                    },
                    else => {},
                }

                // XXX: optimization hack
                if (self.isEmptyTemplateForFragmentLike(n) and for_component) {
                    return 0;
                }

                if (self.simpleStaticTemplate(n)) |tag| {
                    const document_id = try self.factory.createIdentifier("document");
                    const create_el = try self.factory.createPropertyAccessExpression(document_id, "createElement");
                    return self.factory.createCallExpression(create_el, try self.factory.createStringLiteral(tag));
                }

                var html = std.ArrayList(u8).init(getAllocator());
                defer html.deinit();
                if (!for_component) {
                    try self.templateWriteHtml(ref, &html, false);
                } else {
                    try self.templateWriteHtml(ref, &html, true);
                }

                // empty -> new Comment()
                // TODO: fallback to document.createComment("") if `Comment` is shadowed
                if (html.items.len == 0 or strings.eqlComptime(html.items, "<!>")) {
                    if (n.kind == .jsx_component) {
                        return 0;
                    }
                    return self.factory.createNewExpression(try self.factory.createIdentifier("Comment"), 0);
                }

                // FIXME: we do not need to allocate again here, we can just shrink to fit...
                const html_duped = try getAllocator().dupe(u8, pruneTrailingEndTags(html.items));
                const html_ref = try self.factory.createNoSubstitutionTemplateLiteralAllocated(html_duped);
                if (self.isFragmentLike(n) and self.jsxNodeHasManyChildren(n) and !(for_component and !self.willHaveManyNodes(self.getChildrenStartRef(n).?, for_component))) {
                    const t_fn = try self.factory.createIdentifier(self.requireHelper(.template));
                    return try self.factory.createCallExpression(t_fn, &.{html_ref, try self.factory.createNumericLiteral(@as(i64, 1))});
                }
                if (html_duped[0] != '<') {
                    // FIXME: this is broken if the text includes entities
                    return self.factory.createNewExpression(try self.factory.createIdentifier("Text"), &.{
                        try self.factory.createNoSubstitutionTemplateLiteralAllocated(html_duped)
                    });
                }
                const t_fn = try self.factory.createIdentifier(self.requireHelper(.template));
                return try self.factory.createCallExpression(t_fn, html_ref);
            }

            const TreeNodeInfoNav = struct {
                use_previous_sibling: bool = false,
                can_release_name: bool = false,
                is_comment_node: bool = false,
                is_two_nodes: bool = false,
                amount: u24 = 1, // 0 means direct assign
                prior_nav_node: ?*TreeNodeInfo,
            };

            const TreeNodeKind = enum { text_static, expression, intrinsic_static, intrinsic_dynamic, component_instance, if_directive, labeled_fragment, run_directive, style_directive, component_directive };
            const TreeNodeInfo = struct {
                kind: TreeNodeKind,
                node_ref: NodeRef,
                node_ptr: *const AstNode, // do not use this >:( 
                inner_ref: NodeRef = 0, // the interior expression w/o modifiers like spread
                depends_on_effects: bool = false,
                is_spread: bool = false, // can be on jsx_element (+ self-closing)
                needs_nav: bool = false,
                nav_name: []const u8 = &.{}, // TODO: rename to "dom node name"
                ph_name: []const u8 = &.{}, // the placement node
                state_name: []const u8 = &.{},
                parent_ref: NodeRef = 0, // logical/synthetic, not specific to the AST
                visited_for_transform: bool = false,

                nav_info: ?TreeNodeInfoNav = null,

                scope: ?*TreeScope = null,

                template_exp: NodeRef = 0,

                len_var: NodeRef = 0, // state var
                static_pos: u16 = 0, // array pos
                is_last_spread: bool = false,
                static_pos_counter: u16 = 0, // ONLY USED BY A PARENT
                needs_len_var: bool = false,

                children: std.ArrayListUnmanaged(*TreeNodeInfo) = .{},
            };
            
            fn getChildrenStartRef(_: *const @This(), node: *const AstNode) ?NodeRef {
                switch (node.kind) {
                    .jsx_element, .jsx_fragment => return maybeUnwrapRef(node),
                    .jsx_if_directive, .jsx_else_directive, .jsx_labeled_fragment,
                    .jsx_component, .jsx_run_directive => {
                        const d = getPackedData(node).right;
                        return if (d != 0) d else null;
                    },
                    else => return null,
                }
            }

            fn populateChildrenTreeNodeInfo(self: *@This(), state: *InlineEmitState, parent_info: *TreeNodeInfo, start_ref: NodeRef) anyerror!void {
                try self.inlineCollectDynamicRunSymbols(start_ref); // XXX

                var iter = NodeIterator.init(self.nodes, start_ref);

                while (iter.nextRef()) |r| {
                    const child = self.nodes.at(r);
                    switch (child.kind) {
                        .jsx_opening_element, .jsx_closing_element, 
                        .jsx_text_all_white_spaces => continue,
                        .jsx_text => {
                            if (self.isJsxTextAllWhitespace(child)) continue;
                        },
                        .jsx_run_directive => {
                            if (getPackedData(child).right == 0) continue;
                        },
                        .jsx_fragment => {
                            try self.populateChildrenTreeNodeInfo(state, parent_info, maybeUnwrapRef(child) orelse continue);
                            continue;
                        },
                        else => {},
                    }

                    const child_info = try self.getTreeNodeInfo(state, r);
                    try parent_info.children.append(getAllocator(), child_info);
                    child_info.static_pos = parent_info.static_pos_counter;
                    child_info.parent_ref = parent_info.node_ref;
                    switch (child.kind) {
                        .jsx_text => {
                            parent_info.static_pos_counter += 1;
                        },
                        .jsx_expression => {
                            var is_spread = false;
                            var inner_ref = unwrapRef(child);
                            if (self.nodes.at(inner_ref).kind == .spread_element) {
                                is_spread = true;
                                inner_ref = unwrapRef(self.nodes.at(inner_ref));
                            } else if (self.nodes.at(inner_ref).hasFlag(.generator)) {
                                is_spread = true;
                            }
                            try self.visit(self.nodes.at(inner_ref), inner_ref); // XXX: make sure to transform JSX expressions
                            child_info.visited_for_transform = true;
                            child_info.is_spread = is_spread;
                            child_info.depends_on_effects = self.dependsOnEffects(inner_ref, self.nodes.at(inner_ref));
                            if (!is_spread) {
                                parent_info.static_pos_counter += 1;
                            }
                            if (is_spread and state.containing_element_is_fragment_like) {
                                child_info.needs_len_var = true;
                            }
                        },
                        .jsx_element, .jsx_self_closing_element => {
                            if (!child_info.is_spread) {
                                parent_info.static_pos_counter += 1;
                            } else if (state.containing_element_is_fragment_like) {
                                child_info.needs_len_var = true;
                            }
                        },
                        .jsx_if_directive, .jsx_else_directive => {
                            child_info.needs_len_var = state.containing_element_is_fragment_like;
                        },
                        .jsx_style_directive, .jsx_component => {},
                        .jsx_labeled_fragment => {
                            parent_info.static_pos_counter += 1;
                        },
                        else => unreachable,
                    }
                }
            }

            fn navigateTreeChildren(self: *@This(), state: *InlineEmitState, node_info: *TreeNodeInfo) !void {
                const n = self.nodes.at(node_info.node_ref);
                const scope = node_info.scope orelse unreachable;

                var prev_nav: []const u8 = node_info.nav_name;
                var use_first_child = true;
                for (node_info.children.items) |child_info| {
                    if (!child_info.needs_nav) continue;
                    const nav_info = child_info.nav_info orelse continue;
                    const direct_assign = nav_info.amount == 0;

                    const binding_ref: ?u32 = if (!nav_info.is_comment_node) 
                        self.inlineMaybeGetElementBinding(child_info.node_ptr) else null;

                    if (binding_ref == null and n.kind == .jsx_component and direct_assign) {
                        const nav_name = prev_nav;
                        prev_nav = nav_name;
                        use_first_child = false;
                        child_info.nav_name = nav_name;
                        continue;        
                    }

                    var did_allocate = binding_ref != null;
                    const nav_name = if (binding_ref) |br|
                        getSlice(self.nodes.at(br), u8)
                    else
                        state.maybeReuseName() orelse blk: {
                            did_allocate = true;
                            break :blk try state.nextName();
                        };

                    // >:(
                    if (binding_ref != null and strings.eql(nav_name, node_info.nav_name) and use_first_child) {
                        prev_nav = nav_name;
                        use_first_child = false;
                        child_info.nav_name = nav_name;
                        continue;
                    }

                    const should_release = binding_ref == null and self.jsxNodeCanUseEphemeralNav(child_info.node_ptr);

                    const prev_id = try self.factory.createIdentifier(prev_nav);
                    const nav_prop = if (direct_assign)
                            prev_id
                        else try self.factory.createPropertyAccessExpression(
                            prev_id, if (use_first_child) "firstChild" else "nextSibling");

                    if (did_allocate) {
                        const nav_decl = try self.factory.createVariableDeclarationSimple(
                            try self.factory.createIdentifier(nav_name), nav_prop);
                        // TODO: emit all of these as a single statement, use let
                        const decl_flags = if (should_release or (child_info.kind == .expression and child_info.depends_on_effects) or child_info.kind == .component_instance)
                            @intFromEnum(NodeFlags.let)
                        else
                            @intFromEnum(NodeFlags.@"const");
                        try scope.appendStaticStatement(
                            try self.factory.createVariableStatement(nav_decl, decl_flags)
                        );
                    } else {
                        try scope.appendStaticStatement(
                            try self.factory.createAssignmentStatement(try self.factory.createIdentifier(nav_name), nav_prop)
                        );
                    }

                    if (should_release) {
                        try state.releaseName(nav_name);
                    }

                    prev_nav = nav_name;
                    use_first_child = false;
                    child_info.nav_name = nav_name;

                    if (nav_info.is_two_nodes) {
                        const ph_name = try state.nextName();
                        child_info.ph_name = ph_name;
                        const access = try self.factory.createPropertyAccessExpression(try self.factory.createIdentifier(prev_nav), "nextSibling");
                        try scope.appendStaticStatement(
                            try self.factory.createLetVariable(try self.factory.createIdentifier(ph_name), access)
                        );
                        prev_nav = ph_name;
                    }
                }
            }

            fn emitHtmlTemplateFragment(self: *@This(), state: *InlineEmitState, node_info: *TreeNodeInfo) !void {
                std.debug.assert(node_info.template_exp == 0);
                std.debug.assert(node_info.nav_name.len > 0);
                
                const save_state = self.jsx_emit_state;
                defer self.jsx_emit_state = save_state;
                self.jsx_emit_state = state;

                const save_current = state.current_node_ref;
                defer state.current_node_ref = save_current;
                state.current_node_ref = node_info.node_ref;

                const save_current_decl = state.current_component_decl;
                defer state.current_component_decl = save_current_decl;
                state.current_component_decl = if (node_info.kind == .component_directive) node_info.node_ref else save_current_decl;

                const save_fragment_like = state.containing_element_is_fragment_like;
                defer state.containing_element_is_fragment_like = save_fragment_like;
                state.containing_element_is_fragment_like = switch (node_info.kind) {
                    .component_instance => true,
                    .intrinsic_static, .intrinsic_dynamic => false,
                    .if_directive => if (node_info.parent_ref == 0) true else save_fragment_like,
                    else => save_fragment_like,
                };

                const needs_template = node_info.template_exp == 0 and switch (node_info.kind) {
                    .if_directive, .component_instance, .component_directive => true,
                    else => node_info.parent_ref == 0,
                };

                const save_scope = state.tree_scope;
                defer state.tree_scope = save_scope;
                state.tree_scope = node_info.scope orelse state.tree_scope;

                if (needs_template) {
                    node_info.template_exp = try self.createHtmlTemplate(node_info.node_ref);
                }

                try self.navigateTreeChildren(state, node_info);
            }

            fn getTreeNodeInfo(self: *@This(), state: *InlineEmitState, ref: NodeRef) anyerror!*TreeNodeInfo {
                const n = self.nodes.at(ref);
                const entry = try state.getOrPutTreeNodeInfo(getAllocator(), ref, n);
                if (entry.found) return entry.info;

                const save_scope = state.tree_scope;
                defer state.tree_scope = save_scope;
                state.tree_scope = blk: {
                    if (entry.info.parent_ref == 0) break :blk try TreeScope.initStaticScope(state);
                    if (save_scope != null and (entry.info.kind == .if_directive or entry.info.kind == .component_directive)) {
                        const static = save_scope.?.initStaticScope(state);
                        break :blk static.initUpdateScope(state);
                    }
                    if (save_scope != null and self.inlineMaybeGetElementBinding(n) != null) {
                        break :blk save_scope.?.initUpdateScope(state);
                    }
                    break :blk save_scope;
                };

                entry.info = state.tree_scope;

                // refine info `kind`
                switch (n.kind) {
                    .jsx_element, .jsx_self_closing_element => {
                        if (!self.isIntrinsicTag(self.getJsxTagRef(n))) {
                            entry.info.kind = .component_instance;
                        } else if (self.inlineNodeHasDynamic(n)) {
                            entry.info.kind = .intrinsic_dynamic;
                        }
                    },
                    else => {},
                }

                const save_fragment_like = state.containing_element_is_fragment_like;
                defer state.containing_element_is_fragment_like = save_fragment_like;
                state.containing_element_is_fragment_like = switch (entry.info.kind) {
                    .component_instance => true,
                    .intrinsic_static, .intrinsic_dynamic => false,
                    .if_directive => if (entry.info.parent_ref == 0) true else save_fragment_like,
                    else => save_fragment_like,
                };

                const start_ref = self.getChildrenStartRef(n) orelse return entry.info;
                try self.inlineBridgeStaticAnonymousFns(state, start_ref);
                try self.populateChildrenTreeNodeInfo(state, entry.info, start_ref);

                return entry.info;
            }

            fn gatherChildInfo(self: *@This(), start_ref: NodeRef) anyerror!std.ArrayList(TreeNodeInfo) {
                var children = std.ArrayList(TreeNodeInfo).init(getAllocator());

                // FIXME: delete this
                try self.inlineCollectDynamicRunSymbols(start_ref);

                var static_pos: u16 = 0;
                var iter = NodeIterator.init(self.nodes, start_ref);
                while (iter.nextRef()) |r| {
                    const child = self.nodes.at(r);
                    const saved_static_pos = static_pos;
                    switch (child.kind) {
                        .jsx_opening_element, .jsx_closing_element, 
                        .jsx_text_all_white_spaces, .jsx_else_directive => continue,
                        .jsx_text => {
                            if (self.isJsxTextAllWhitespace(child)) continue;
                            try children.append(.{ .kind = .text_static, .node_ptr = child, .node_ref = r });
                            static_pos += 1;
                        },
                        .jsx_expression => {
                            var is_spread = false;
                            var inner_ref = unwrapRef(child);
                            if (self.nodes.at(inner_ref).kind == .spread_element) {
                                is_spread = true;
                                inner_ref = unwrapRef(self.nodes.at(inner_ref));
                            }
                            try self.visit(self.nodes.at(inner_ref), inner_ref); // XXX: make sure to transform JSX expressions
                            try children.append(.{ 
                                .kind = .expression, 
                                .node_ptr = child, 
                                .node_ref = r,
                                .inner_ref = inner_ref, 
                                .depends_on_effects = self.dependsOnEffects(inner_ref, self.nodes.at(inner_ref)), 
                                .is_spread = is_spread 
                            });
                            if (!is_spread) {
                                static_pos += 1;
                            }
                        },
                        .jsx_element, .jsx_self_closing_element => {
                            const ct = self.getJsxTagRef(child);
                            if (self.isIntrinsicTag(ct)) {
                                const kind: TreeNodeKind = if (self.inlineNodeHasDynamic(child)) .intrinsic_dynamic else .intrinsic_static;
                                try children.append(.{ .kind = kind, .node_ptr = child, .node_ref = r });
                            } else {
                                try children.append(.{ .kind = .component_instance, .node_ptr = child, .node_ref = r, .is_spread = child.hasFlag(.generator) });
                            }
                            if (!child.hasFlag(.generator)) {
                                static_pos += 1;
                            }
                        },
                        .jsx_if_directive => {
                            try children.append(.{ .kind = .if_directive, .node_ptr = child, .node_ref = r });
                        },
                        .jsx_labeled_fragment => {
                            try children.append(.{ .kind = .labeled_fragment, .node_ptr = child, .node_ref = r });
                            static_pos += 1;
                        },
                        .jsx_run_directive => {
                            if (getPackedData(child).right == 0) continue;
                            try children.append(.{ .kind = .run_directive, .node_ptr = child, .node_ref = r });
                        },
                        .jsx_style_directive => {
                            try children.append(.{ .kind = .style_directive, .node_ptr = child, .node_ref = r });
                        },
                        .jsx_component => {
                            try children.append(.{ .kind = .component_directive, .node_ptr = child, .node_ref = r });
                        },
                        .jsx_fragment => {
                            const nested = try self.gatherChildInfo(maybeUnwrapRef(child) orelse 0);
                            defer nested.deinit();
                            for (nested.items) |*info| {
                                switch (info.kind) {
                                    .text_static, .intrinsic_static, .intrinsic_dynamic => {
                                        static_pos += 1;
                                    },
                                    .expression, .component_instance => {
                                        if (!info.is_spread) {
                                            static_pos += 1;
                                        }
                                    },
                                    else => {},
                                }
                                info.static_pos += saved_static_pos;
                                try children.append(info.*);
                            }
                            continue;
                        },
                        else => unreachable,
                    }
                    if (children.items.len > 0) {
                        children.items[children.items.len-1].static_pos = saved_static_pos;
                    }
                }

                var i: usize = children.items.len;
                while (i > 0) {
                    i -= 1;
                    if (children.items[i].is_spread or children.items[i].kind == .if_directive) {
                        children.items[i].is_last_spread = true;
                        break;
                    }
                }

                return children;
            }
            
            fn createJsxExpressionToDomSlot(self: *@This(), state: *InlineEmitState, child_info: *TreeNodeInfo) !NodeRef {
                std.debug.assert(child_info.nav_name.len > 0);
                std.debug.assert(child_info.kind == .expression);

                if (child_info.is_spread) {
                    std.debug.assert(child_info.ph_name.len > 0);
                    const set_slot_call = try self.factory.createCallExpression(
                        try self.factory.createIdentifier(self.requireHelper(.set_slot_spread)), &.{
                            try self.factory.createIdentifier(child_info.nav_name),
                            try self.factory.createIdentifier(child_info.ph_name),
                            try self.cloneIfNeeded(child_info.inner_ref),
                        });
                    return self.factory.createExpressionStatement(set_slot_call);
                }

                const prev_name = blk: {
                    if (child_info.state_name.len > 0) {
                        break :blk child_info.state_name;
                    }
                    const n = try state.nextName();
                    const prev_decl = try self.factory.createVariableDeclarationSimple(
                        try self.factory.createIdentifier(n),0);
                    try state.addStmt(try self.factory.createVariableStatement(
                        prev_decl, @intFromEnum(NodeFlags.let)));
                    child_info.state_name = n;
                    break :blk n;
                };

                const set_slot_call = try self.factory.createCallExpression(
                    try self.factory.createIdentifier(self.requireHelper(.set_slot)), &.{
                    try self.factory.createIdentifier(child_info.nav_name),
                    try self.factory.createIdentifier(prev_name),
                    try self.cloneIfNeeded(child_info.inner_ref),
                });
                const assign = try self.factory.createBinaryExpression(
                    try self.factory.createIdentifier(prev_name), .equals_token, set_slot_call);
                return assign;
            }

            fn inlineAddHoistedVar(self: *@This(), state: *InlineEmitState, ident: NodeRef, initializer: NodeRef, flags: u22) !void {
                try state.addStmt(try self.factory.createVariableStatement(
                    try self.factory.createVariableDeclarationSimple(ident, initializer), flags));
            }

            fn willHaveManyNodes(self: *@This(), children_start: NodeRef, fragment_like: bool) bool {
                if (!fragment_like) {
                    return self.jsxHasManyChildren(children_start);
                }
                var child_count: u32 = 0;
                var has_preceding_text = false;
                var iter = NodeIterator.init(self.nodes, children_start);
                while (iter.next()) |child| {
                    switch (child.kind) {
                        .jsx_text => {
                            if (has_preceding_text) continue;
                            if (self.isJsxTextAllWhitespace(child)) continue;
                            child_count += 1;
                            has_preceding_text = true;
                            if (child_count > 1) return false;
                        },
                        .jsx_element, .jsx_self_closing_element => {
                            const child_tag_ref = self.getJsxTagRef(child);
                            if (!self.isIntrinsicTag(child_tag_ref)) continue;
                            has_preceding_text = false;
                            child_count += 1;
                            if (child_count > 1) return false;
                        },
                        else => {},
                    }
                }
                return child_count > 1;
            }

            // returns ident_ref
            fn inlineInternalArrayChildren(
                self: *@This(),
                state: *InlineEmitState,
                node_ref: NodeRef,
                children_start: NodeRef,
                body: *std.ArrayList(NodeRef),
                had_update_fn: *bool,
            ) !NodeRef {
                const children = try self.gatherChildInfo(children_start);
                defer children.deinit();

                var init_body = std.ArrayList(NodeRef).init(getAllocator());
                defer init_body.deinit();

                var updates = std.ArrayList(NodeRef).init(getAllocator());
                defer updates.deinit();

                const el_name = try state.nextName();
                const ident = try self.factory.createIdentifier(el_name);
                // const decl_init = try self.factory.createArrayLiteralExpression(0);
                try state.addStmt(try self.factory.createLetVariable(ident, 0));


                const parent_init_stmts = state.stmts;
                defer state.stmts = parent_init_stmts;
                state.stmts = init_body;

                const save_static_gate = state.static_gate;
                defer state.static_gate = save_static_gate;
                state.static_gate = null;
                
                const save_internal_fragment = state.emit_internal_fragment;
                defer state.emit_internal_fragment = save_internal_fragment;
                state.emit_internal_fragment = blk: {
                    if (state.current_node_ref == 0) break :blk true;
                    const cur = self.nodes.at(state.current_node_ref);
                    break :blk switch (cur.kind) {
                        .jsx_element, .jsx_self_closing_element => self.isIntrinsicTag(self.getJsxTagRef(cur)),
                        else => state.emit_internal_fragment,
                    };
                };
                
                const many_elements = self.willHaveManyNodes(children_start, state.containing_element_is_fragment_like);
                const snapshot_name = try state.nextName();
                // TODO: can only be released to the next element up
                // defer state.releaseName(snapshot_name) catch unreachable;
                {
                    const save_children_exp = state.children_exp;
                    defer state.children_exp = save_children_exp;
                    state.children_exp = 0;

                    const save_children_init_ref = state.children_init_ref;
                    defer state.children_init_ref = save_children_init_ref;
                    state.children_init_ref = 0;

                    const tmpl =  try self.createHtmlTemplate(node_ref);
                    if (!many_elements and tmpl != 0) {
                        state.children_exp = try self.factory.createIdentifier(snapshot_name);
                        try state.addStmt(
                            try self.factory.createConstVariable(
                                try self.factory.createIdentifier(snapshot_name), 
                                try self.factory.createArrayLiteralExpression(&.{
                                    unwrapRef(self.nodes.at(try self.factory.createAssignmentStatement(ident, tmpl)))
                                })
                            )
                        );
                    } else if (tmpl != 0) {
                        state.children_exp = try self.factory.createIdentifier(snapshot_name);
                        try state.addStmt(try self.factory.createConstVariable(try self.factory.createIdentifier(snapshot_name), try self.factory.createArrayLiteralExpression(0)));
                        try state.addStmt(try self.factory.createAssignmentStatement(ident, tmpl));
                        try state.addStmt(try self.factory.createExpressionStatement(try self.factory.createCallExpression(
                            try self.factory.createPropertyAccessExpression(try self.factory.createIdentifier(snapshot_name), "push"),
                            &.{
                                if (many_elements)
                                    try self.factory.createSpreadElement(try self.factory.createPropertyAccessExpression(ident, "childNodes")) // DOM API: Node.childNodes (Symbol.iterator)
                                else ident,
                            }
                        )));
                    } else {
                        state.children_init_ref = try self.factory.createArrayLiteralExpression(0);
                        try state.addStmt(try self.factory.createAssignmentStatement(ident, state.children_init_ref));
                    }
                    _ = try self.inlineProcessElement2(state, el_name, node_ref, &updates);
                    if (state.stmts.items.len == 1 and tmpl != 0) {
                        _ = state.stmts.pop();
                        try state.stmts.append(try self.factory.createAssignmentStatement(ident, try self.factory.createArrayLiteralExpression(&.{tmpl})));
                    } else if (tmpl != 0) {
                        try state.addStmt(try self.factory.createAssignmentStatement(ident, try self.factory.createIdentifier(snapshot_name)));
                    }
                    try self.emitStaticGateInit(state);
                }
                
                init_body = state.stmts;

                const lhs = try self.accessUpdateSymbol(ident);

                if (updates.items.len > 0) {
                    had_update_fn.* = true;
                    const upd_block = try self.factory.createBlock(updates.items);
                    try self.coalesceVariableStatements(self.nodes.at(upd_block));
                    try init_body.append(try self.factory.createExpressionStatement(
                        try self.factory.createBinaryExpression(lhs, .equals_token,
                            try self.factory.createArrowFunction(0, upd_block, 0))));
                }

                const init_block = try self.factory.createBlock(init_body.items);
                try self.coalesceVariableStatements(self.nodes.at(init_block));
                try body.append(try self.factory.createIfStatement(
                    try self.factory.createPrefixUnaryExpression(.exclamation_token, ident),
                    init_block,
                    0,
                ));

                return ident;
            }

            fn inlineArrayChildren(
                self: *@This(),
                state: *InlineEmitState,
                children: []TreeNodeInfo,
                upd_body: *std.ArrayList(NodeRef),
                children_exp: NodeRef,
            ) anyerror!void {
                const save_children = state.children_exp;
                defer state.children_exp = save_children;
                state.children_exp = children_exp;

                const save_offset_name = state.offset_counter_name;
                defer state.offset_counter_name = save_offset_name;

                var needs_spread_unwind = std.ArrayList(*TreeNodeInfo).init(upd_body.allocator);
                defer needs_spread_unwind.deinit();
                for (children) |*child_info| {
                    if (child_info.is_spread or child_info.kind == .if_directive) {
                        try needs_spread_unwind.append(child_info);
                    }
                }

                var offset_counter_name: NodeRef = 0;
                if (needs_spread_unwind.items.len > 0) {
                    if (needs_spread_unwind.items.len > 1) {
                        offset_counter_name = try self.factory.createIdentifier(try state.nextName());
                        state.offset_counter_name = offset_counter_name;
                        try self.inlineAddHoistedVar(state,
                            offset_counter_name,
                            try self.factory.createNumericLiteral(@as(i64, 0)),
                            @intFromEnum(NodeFlags.let));

                        try upd_body.append(
                            try self.factory.createAssignmentStatement(offset_counter_name, try self.factory.createNumericLiteral(@as(i64, 0)))
                        );
                    }
                    while (needs_spread_unwind.popOrNull()) |x| {
                        const len_name = try self.factory.createIdentifier(try state.nextName());
                        x.len_var = len_name;
                        
                        try self.inlineAddHoistedVar(state,
                            len_name,
                            try self.factory.createNumericLiteral(@as(i64, 0)),
                            @intFromEnum(NodeFlags.let));
                    }
                }

                for (children) |*child_info| {
                    var element_init: NodeRef = 0;

                    switch (child_info.kind) {
                        .text_static => {
                            if (child_info.nav_name.len > 0) {
                                element_init = try self.factory.createIdentifier(child_info.nav_name);
                            } else {
                                element_init = try self.factory.createNewExpression(
                                    try self.factory.createIdentifier("Text"),
                                    &.{(try self.jsxTextToString(child_info.node_ptr)).?}
                                );
                            }
                        },
                        .intrinsic_static => {
                            if (child_info.nav_name.len > 0) {
                                element_init = try self.factory.createIdentifier(child_info.nav_name);
                            } else {
                                element_init = try self.transformJsxNode(child_info.node_ref);
                            }
                        },
                        .expression => blk: {
                            const inner_ref = child_info.inner_ref;
                            if (!child_info.depends_on_effects and !child_info.is_spread) {
                                element_init = inner_ref;
                                break :blk;
                            }

                            if (!child_info.is_spread) {
                                // might not be needed for correctness, though it avoids shape transitions (holey)
                                // element_init = try self.factory.createNull();
                                const lhs = try self.factory.createElementAccessExpression(children_exp, child_info.static_pos);
                                const assign = try self.factory.createAssignmentStatement(lhs, inner_ref);
                                try upd_body.append(assign);
                                continue;
                                // break :blk;
                            }

                            try upd_body.append(try self.createSpliceAtStatement(
                                offset_counter_name,
                                child_info.len_var,
                                children_exp,
                                inner_ref,
                                child_info.static_pos,
                            ));
                        },
                        .intrinsic_dynamic, .component_instance => blk: {
                            if (child_info.nav_name.len > 0) {
                                const ident = try self.factory.createIdentifier(child_info.nav_name);
                                const save_ctx = state.ctx;
                                const save_children_exp = state.children_exp;
                                const save_counter = state.offset_counter_name;
                                defer {
                                    state.ctx = save_ctx;
                                    state.children_exp = save_children_exp;
                                    state.offset_counter_name = save_counter;
                                }
                                if (child_info.kind == .component_instance) {
                                    state.ctx = .component;
                                    element_init = try self.factory.createPropertyAccessExpression(ident, "root");
                                } else {
                                    state.ctx = .templated;
                                    element_init = ident;
                                }
                                const has_binding = self.inlineMaybeGetElementBinding(child_info.node_ptr) != null;
                                const had_update = try self.inlineProcessElement2(state, child_info.nav_name, child_info.node_ref, if (has_binding) null else upd_body);
                                if (has_binding and had_update) try upd_body.append(try self.inlineCallSymbolUpdate(child_info.nav_name));
                                if (child_info.is_spread) {
                                    try upd_body.append(try self.createSpliceAtStatement(
                                        offset_counter_name,
                                        child_info.len_var,
                                        children_exp,
                                        element_init,
                                        child_info.static_pos,
                                    ));
                                }
                                break :blk;
                            }
                            if (child_info.kind == .component_instance and comptime callee_creates_comp_instance) {
                                try self.emitCallerCompProtocol(state, child_info, upd_body);
                                element_init = try self.factory.createPropertyAccessExpression(try self.factory.createIdentifier(child_info.ph_name), "root");
                                break :blk;
                            }
                            const nav_name = try state.nextName();
                            const ident = try self.factory.createIdentifier(nav_name);
                            var child_state = InlineEmitState{
                                .counter = state.counter,
                                .stmts = std.ArrayList(NodeRef).init(getAllocator()),
                            };
                            defer child_state.stmts.deinit();
                            if (child_info.kind == .component_instance) child_state.ctx = .component;
                            const element_expr = try self.createHtmlTemplate(child_info.node_ref);
                            const had_update = try self.inlineProcessElement2(&child_state, nav_name, child_info.node_ref, null);
                            if (had_update) try upd_body.append(try self.inlineCallSymbolUpdate(nav_name));

                            state.counter = child_state.counter;
                            try self.inlineAddHoistedVar(state, ident, element_expr, @intFromEnum(NodeFlags.@"const"));
                            if (child_state.ctx == .component) try self.maybeEmitCompAttr(state, nav_name, child_info.node_ptr);
                            try state.stmts.appendSlice(child_state.stmts.items);

                            if (child_state.ctx != .component) {
                                element_init = ident;
                                break :blk;
                            }

                            element_init = try self.factory.createPropertyAccessExpression(ident, "root");
                            if (child_info.is_spread) {
                                try upd_body.append(try self.createSpliceAtStatement(
                                    offset_counter_name,
                                    child_info.len_var,
                                    children_exp,
                                    element_init,
                                    child_info.static_pos,
                                ));
                            }
                        },
                        .if_directive => {
                            try self.emitIfDirective(state, child_info, upd_body);
                        },
                        .run_directive => {
                            try self.inlineProcessRunDirective(state, child_info.node_ptr, upd_body);
                            continue;
                        },
                        .style_directive => {
                            try self.inlineProcessStyleDirective(state, child_info.node_ptr);
                            continue;
                        },
                        .component_directive => {
                            const fn_decl = try self.visitJsxCompDeclaration(state, child_info);
                            try state.addStmt(fn_decl);
                            continue;
                        },
                        .labeled_fragment => unreachable,
                    }

                    if (child_info.is_spread or child_info.kind == .if_directive) {
                        continue;
                    }

                    std.debug.assert(element_init != 0);

                    if (state.containing_element_is_fragment_like and state.current_node_ref != 0) {
                        if (!self.willHaveManyNodes(self.getChildrenStartRef(self.nodes.at(state.current_node_ref)).?, true) and child_info.nav_name.len > 0) {
                            continue;
                        }
                    }

                    const is_static = child_info.kind == .text_static or (child_info.kind != .component_instance and !(state.ctx == .component and comptime callee_creates_comp_instance));
                    if (state.children_init_ref != 0) {
                        const arr_exp = self.nodes.at(state.children_init_ref);
                        var tail: NodeRef = 0;
                        var iter = NodeIterator.init(self.nodes, maybeUnwrapRef(arr_exp) orelse 0);
                        while (iter.nextRef()) |x| {
                            tail = x;
                            if (self.nodes.at(x).next == 0) break;
                        }
                        const val = if (is_static) try self.cloneIfNeeded(element_init) else try self.factory.createNull();
                        self.nodes.at(val).next = 0;
                        if (tail == 0) {
                            arr_exp.data = @ptrFromInt(val);
                        } else {
                            self.nodes.at(tail).next = try self.factory.createNull();
                        }
                        if (is_static) continue;
                    }
                    const lhs = try self.factory.createElementAccessExpression(children_exp, try self.factory.createNumericLiteral(child_info.static_pos));
                    const assign = try self.factory.createAssignmentStatement(lhs, element_init);
                    if (!is_static) {
                        try upd_body.append(assign);
                    } else {
                        try state.addStmt(assign);
                    }

                    switch (child_info.kind) {
                        .text_static => try self.factory.attachDebugComment(assign, "#text"),
                        else => {},
                    }
                }
            }

            fn inlineProcessStyleDirective(
                self: *@This(),
                state: *InlineEmitState,
                node: *const AstNode,
            ) !void {
                const stmt = try self.transformJsxStyleDirective(node);
                if (stmt == 0) return;
                try state.addStmt(stmt);
            }

            fn inlineCanHoistExpr(
                self: *const @This(),
                inner: NodeRef,
                rlk: *const std.AutoHashMapUnmanaged(u32, bool),
            ) bool {
                if (inner == 0) return true;
                const n = self.nodes.at(inner);
                switch (n.kind) {
                    .identifier => {
                        if (self.file.binder.getSymbol(inner)) |sym_ref| {
                            if (rlk.get(sym_ref)) |is_hoisted| {
                                return is_hoisted;
                            }
                        }
                        return true;
                    },
                    .call_expression, .new_expression => return false,
                    .binary_expression => {
                        const d = getPackedData(n);
                        switch (@as(SyntaxKind, @enumFromInt(n.len))) {
                            .equals_token,
                            .plus_equals_token, .minus_equals_token,
                            .asterisk_equals_token, .slash_equals_token, .percent_equals_token,
                            .asterisk_asterisk_equals_token,
                            .bar_equals_token, .ampersand_equals_token, .caret_equals_token,
                            .question_question_equals_token,
                            .bar_bar_equals_token, .ampersand_ampersand_equals_token => return false,
                            else => return self.inlineCanHoistExpr(d.left, rlk) and self.inlineCanHoistExpr(d.right, rlk),
                        }
                    },
                    .prefix_unary_expression => {
                        const d = getPackedData(n);
                        return switch (@as(SyntaxKind, @enumFromInt(d.left))) {
                            .plus_plus_token, .minus_minus_token => false,
                            else => self.inlineCanHoistExpr(d.right, rlk),
                        };
                    },
                    .postfix_unary_expression => return false,
                    .conditional_expression => {
                        const d = getPackedData(n);
                        return self.inlineCanHoistExpr(d.left, rlk)
                            and self.inlineCanHoistExpr(d.right, rlk)
                            and self.inlineCanHoistExpr(n.len, rlk);
                    },
                    .parenthesized_expression,
                    .typeof_expression,
                    .void_expression => return self.inlineCanHoistExpr(unwrapRef(n), rlk),
                    .property_access_expression => return self.inlineCanHoistExpr(getPackedData(n).left, rlk),
                    .element_access_expression => {
                        const d = getPackedData(n);
                        return self.inlineCanHoistExpr(d.left, rlk) and self.inlineCanHoistExpr(d.right, rlk);
                    },
                    // it is invalid to capture non-static tree locals
                    // FIXME: we need to check static members for the class exp case
                    .jsx_component, .jsx_element, .jsx_self_closing_element,
                    .function_expression, .arrow_function, .class_expression => {
                        return true;
                    },
                    .object_literal_expression,
                    .array_literal_expression => {
                        var iter = NodeIterator.init(self.nodes, maybeUnwrapRef(n) orelse 0);
                        while (iter.nextRef()) |r| {
                            if (!self.inlineCanHoistExpr(r, rlk)) return false;
                        }
                        return true;
                    },
                    .property_assignment => {
                        return self.inlineCanHoistExpr(getPackedData(n).right, rlk);
                    },
                    .numeric_literal, .string_literal, .no_substitution_template_literal,
                    .true_keyword, .false_keyword, .null_keyword, .undefined_keyword => return true,
                    else => return false,
                }
            }

            const ProducerInfo = struct {
                containing_node: NodeRef = 0,
                is_read: bool = false,
                is_written: bool = false,
                is_captured: bool = false,
                any_consumer_read: bool = false,
                any_consumer_written: bool = false,
                any_consumer_captured: bool = false,
            };

            const SymbolInfo = struct {
                producer: ?*ProducerInfo = null,
                is_read: bool = false,
                is_written: bool = false,
                is_captured: bool = false,
            };

            const TreeClassification = struct {
                node_maps: std.AutoHashMapUnmanaged(
                    NodeRef,
                    std.AutoHashMapUnmanaged(SymbolRef, SymbolInfo),
                ) = .{},
                producers: std.AutoHashMapUnmanaged(SymbolRef, *ProducerInfo) = .{},
                node_ptr_to_ref: std.AutoHashMapUnmanaged(*const AstNode, NodeRef) = .{},

                fn deinit(tc: *@This()) void {
                    tc.node_ptr_to_ref.deinit(getAllocator());
                    {
                        var iter = tc.producers.valueIterator();
                        while (iter.next()) |p| getAllocator().destroy(p.*);
                    }
                    tc.producers.deinit(getAllocator());
                    {
                        var iter = tc.node_maps.iterator();
                        while (iter.next()) |entry| entry.value_ptr.deinit(getAllocator());
                    }
                    tc.node_maps.deinit(getAllocator());
                }

                fn ensureNodeMap(
                    tc: *@This(),
                    node_ref: NodeRef,
                ) !*std.AutoHashMapUnmanaged(SymbolRef, SymbolInfo) {
                    const entry = try tc.node_maps.getOrPut(getAllocator(), node_ref);
                    if (!entry.found_existing) entry.value_ptr.* = .{};
                    return entry.value_ptr;
                }

                fn debug_print(tc: *const @This(), nodes: *const BumpAllocator(AstNode), binder: *const Binder) void {
                    std.debug.print("=== classifyTreeSymbols ===\n", .{});
                    var iter = tc.node_maps.iterator();
                    while (iter.next()) |node_entry| {
                        const node_ref = node_entry.key_ptr.*;
                        std.debug.print("  node #{d} [{?}]:\n", .{node_ref, nodes.at(node_ref).kind});
                        var sym_iter = node_entry.value_ptr.iterator();
                        while (sym_iter.next()) |sym_entry| {
                            const sym_ref = sym_entry.key_ptr.*;
                            const info = sym_entry.value_ptr.*;
                            const sym = binder.symbols.at(sym_ref);
                            const name = if (sym.declaration != 0)
                                getSlice(nodes.at(getPackedData(nodes.at(sym.declaration)).left), u8)
                            else
                                "<unknown>";
                            std.debug.print("    sym #{d} ({s}): read={} write={} capture={}", .{
                                sym_ref, name, info.is_read, info.is_written, info.is_captured,
                            });
                            if (info.producer) |p| {
                                std.debug.print(" | producer: read={} write={} capture={} | any_consumer: read={} write={} capture={}", .{
                                    p.is_read, p.is_written, p.is_captured,
                                    p.any_consumer_read, p.any_consumer_written, p.any_consumer_captured,
                                });
                            }
                            std.debug.print("\n", .{});
                        }
                    }
                    std.debug.print("===========================\n", .{});
                }
            };

            fn classifyTreeSymbols(
                self: *@This(),
                children_head: NodeRef,
                result: *TreeClassification,
            ) !void {
                if (children_head == 0) return;
                const Self = *@This();

                const W = struct {
                    s: Self,
                    result: *TreeClassification,
                    producers: std.AutoHashMapUnmanaged(SymbolRef, *ProducerInfo) = .{},
                    current_node: NodeRef = 0, // zero inside of an anonymous root
                    in_run: bool = false,
                    is_capturing: bool = false,
                    suppress_element_maps: bool = false,

                    fn deinit(w: *@This()) void {
                        w.producers.deinit(getAllocator());
                    }

                    fn ensureProducer(w: *@This(), sym_ref: SymbolRef) !*ProducerInfo {
                        const entry = try w.producers.getOrPut(getAllocator(), sym_ref);
                        if (!entry.found_existing) {
                            const p = try getAllocator().create(ProducerInfo);
                            p.* = .{};
                            p.*.containing_node = w.current_node;
                            entry.value_ptr.* = p;
                            try w.result.producers.put(getAllocator(), sym_ref, p);
                        }
                        return entry.value_ptr.*;
                    }

                    fn record(w: *@This(), sym_ref: SymbolRef, comptime is_write: bool) !void {
                        if (!w.s.run_directive_symbols.contains(sym_ref)) return;
                        if (w.current_node == 0) {
                            const p = w.producers.get(sym_ref) orelse return;
                            if (is_write) p.is_written = true
                            else p.is_read = true;
                            if (w.is_capturing) p.is_captured = true;
                        } else {
                            const p = w.producers.get(sym_ref);
                            const m = try w.result.ensureNodeMap(w.current_node);
                            const entry = try m.getOrPut(getAllocator(), sym_ref);
                            if (!entry.found_existing) {
                                entry.value_ptr.* = .{ .producer = p };
                            }
                            if (is_write) {
                                entry.value_ptr.is_written = true;
                                if (p) |pp| pp.any_consumer_written = true;
                            } else {
                                entry.value_ptr.is_read = true;
                                if (p) |pp| pp.any_consumer_read = true;
                            }
                            if (w.is_capturing) {
                                entry.value_ptr.is_captured = true;
                                if (p) |pp| pp.any_consumer_captured = true;
                            }
                        }
                    }

                    fn declareProducer(w: *@This(), name_ref: NodeRef) !void {
                        const sym_ref = w.s.file.binder.getSymbol(name_ref) orelse return;
                        if (!w.s.run_directive_symbols.contains(sym_ref)) return;
                        _ = try w.ensureProducer(sym_ref);
                    }

                    fn visitChildren(w: *@This(), n: *const AstNode) anyerror!void {
                        try parser.forEachChild(w.s.nodes, n, w);
                    }

                    fn hoistRuns(w: *@This(), list_head: NodeRef) !void {
                        var ci = NodeIterator.init(w.s.nodes, list_head);
                        while (ci.nextRef()) |cref| {
                            const child = w.s.nodes.at(cref);
                            if (child.kind != .jsx_run_directive) continue;
                            const stmts_head = getPackedData(child).right;
                            if (stmts_head == 0) continue;
                            var si = NodeIterator.init(w.s.nodes, stmts_head);
                            while (si.nextRef()) |stmt_ref| {
                                const stmt = w.s.nodes.at(stmt_ref);
                                switch (stmt.kind) {
                                    .variable_statement => {
                                        const decl_head = maybeUnwrapRef(stmt) orelse continue;
                                        var di = NodeIterator.init(w.s.nodes, decl_head);
                                        while (di.nextRef()) |decl_ref| {
                                            try w.declareProducer(getPackedData(w.s.nodes.at(decl_ref)).left);
                                        }
                                    },
                                    .function_declaration, .class_declaration => {
                                        try w.declareProducer(stmt_ref);
                                    },
                                    else => {},
                                }
                            }
                        }
                    }

                    pub fn visit(w: *@This(), n: *const AstNode, ref: NodeRef) anyerror!void {
                        switch (n.kind) {
                            .identifier => {
                                if (n.flags & (1 << 19) != 0) return; // type node ident
                                if (ref >= w.s.file.binder.nodes.count()) return; // XXX: synthetic nodes
                                const sym_ref = w.s.file.binder.getSymbol(ref) orelse return;
                                try w.record(sym_ref, false);
                            },

                            .jsx_run_directive => {
                                const stmts_head = getPackedData(n).right;
                                if (stmts_head == 0) return;
                                const saved_run = w.in_run;
                                const saved_sem = w.suppress_element_maps;
                                w.in_run = true;
                                w.suppress_element_maps = true;
                                defer w.in_run = saved_run;
                                defer w.suppress_element_maps = saved_sem;
                                var iter = NodeIterator.init(w.s.nodes, stmts_head);
                                while (iter.nextRef()) |stmt_ref| {
                                    try w.visitStmt(stmt_ref);
                                }
                            },

                            .jsx_component => {
                                const saved_node = w.current_node;
                                const saved_ic = w.suppress_element_maps;
                                w.current_node = ref;
                                w.suppress_element_maps = true;
                                defer w.current_node = saved_node;
                                defer w.suppress_element_maps = saved_ic;
                                try w.result.node_ptr_to_ref.put(getAllocator(), n, ref);
                                try w.visitChildren(n);
                            },

                            .jsx_element, .jsx_self_closing_element => {
                                const binding = w.s.inlineMaybeGetElementBinding(n);
                                if (binding != null and !w.suppress_element_maps) {
                                    const saved = w.current_node;
                                    w.current_node = ref;
                                    defer w.current_node = saved;
                                    try w.result.node_ptr_to_ref.put(getAllocator(), n, ref);
                                    if (n.kind == .jsx_element) try w.hoistRuns(unwrapRef(n));
                                    try w.visitChildren(n);
                                } else {
                                    if (n.kind == .jsx_element) try w.hoistRuns(unwrapRef(n));
                                    try w.visitChildren(n);
                                }
                            },

                            .function_expression, .arrow_function,
                            .function_declaration, .class_declaration,
                            .method_declaration, .get_accessor, .set_accessor => {
                                const saved = w.is_capturing;
                                w.is_capturing = true;
                                defer w.is_capturing = saved;
                                try w.visitChildren(n);
                            },

                            .binary_expression => {
                                const d = getPackedData(n);
                                const op: SyntaxKind = @enumFromInt(n.len);
                                const is_assign = switch (op) {
                                    .equals_token,
                                    .plus_equals_token, .minus_equals_token,
                                    .asterisk_equals_token, .slash_equals_token,
                                    .percent_equals_token, .asterisk_asterisk_equals_token,
                                    .bar_equals_token, .ampersand_equals_token,
                                    .caret_equals_token, .question_question_equals_token,
                                    .bar_bar_equals_token, .ampersand_ampersand_equals_token => true,
                                    else => false,
                                };
                                if (is_assign and w.s.nodes.at(d.left).kind == .identifier) {
                                    if (w.s.file.binder.getSymbol(d.left)) |sym_ref| {
                                        try w.record(sym_ref, true);
                                        if (op != .equals_token) try w.record(sym_ref, false);
                                    }
                                } else {
                                    try w.visit(w.s.nodes.at(d.left), d.left);
                                }
                                try w.visit(w.s.nodes.at(d.right), d.right);
                            },

                            .prefix_unary_expression => {
                                const d = getPackedData(n);
                                const is_mutating = switch (@as(SyntaxKind, @enumFromInt(d.left))) {
                                    .plus_plus_token, .minus_minus_token => true,
                                    else => false,
                                };
                                if (is_mutating and w.s.nodes.at(d.right).kind == .identifier) {
                                    if (w.s.file.binder.getSymbol(d.right)) |sym_ref| {
                                        try w.record(sym_ref, true);
                                        try w.record(sym_ref, false);
                                    }
                                } else {
                                    try w.visitChildren(n);
                                }
                            },

                            .postfix_unary_expression => {
                                const d = getPackedData(n);
                                if (w.s.nodes.at(d.left).kind == .identifier) {
                                    if (w.s.file.binder.getSymbol(d.right)) |sym_ref| {
                                        try w.record(sym_ref, true);
                                        try w.record(sym_ref, false);
                                    }
                                } else {
                                    try w.visitChildren(n);
                                }
                            },

                            .jsx_expression => {
                                const saved = w.suppress_element_maps;
                                w.suppress_element_maps = true;
                                defer w.suppress_element_maps = saved;
                                try w.visitChildren(n);
                            },

                            .jsx_attributes => {
                                var attr_iter = NodeIterator.init(w.s.nodes, maybeUnwrapRef(n) orelse 0);
                                while (attr_iter.nextRef()) |r| {
                                    const attr = w.s.nodes.at(r);
                                    if (attr.kind != .jsx_method_attribute) {
                                        try w.visitChildren(attr);
                                        continue;
                                    }
                                    // jsx method attr do not "capture" anything on their own
                                    const saved_node = w.current_node;
                                    defer w.current_node = saved_node;
                                    w.current_node = r;
                                    try w.result.node_ptr_to_ref.put(getAllocator(), attr, r);
                                    try w.visitChildren(attr);
                                }
                            },

                            else => try w.visitChildren(n),
                        }
                    }

                    fn visitStmt(w: *@This(), stmt_ref: NodeRef) anyerror!void {
                        const stmt = w.s.nodes.at(stmt_ref);
                        switch (stmt.kind) {
                            .variable_statement => {
                                if (stmt.hasFlag(.static)) {
                                    return try w.visit(stmt, stmt_ref);
                                }
                                const decl_head = maybeUnwrapRef(stmt) orelse return;
                                var di = NodeIterator.init(w.s.nodes, decl_head);
                                while (di.nextRef()) |decl_ref| {
                                    const decl = w.s.nodes.at(decl_ref);
                                    std.debug.assert(decl.kind == .variable_declaration);
                                    const name_ref = getPackedData(decl).left;
                                    try w.declareProducer(name_ref);
                                    const init_ref = getPackedData(decl).right;
                                    if (init_ref != 0) try w.visit(w.s.nodes.at(init_ref), init_ref);
                                }
                            },
                            .function_declaration, .class_declaration => {
                                if (stmt.hasFlag(.static)) {
                                    return try w.visit(stmt, stmt_ref);
                                }
                                try w.declareProducer(stmt_ref);
                                const saved = w.is_capturing;
                                w.is_capturing = true;
                                defer w.is_capturing = saved;
                                try w.visitChildren(stmt);
                            },
                            else => try w.visit(stmt, stmt_ref),
                        }
                    }
                };

                var w = W{ .s = self, .result = result, .current_node = 0 };
                defer w.deinit();

                try w.hoistRuns(children_head);

                var iter = NodeIterator.init(self.nodes, children_head);
                while (iter.nextRef()) |ref| {
                    try w.visit(self.nodes.at(ref), ref);
                }
            }

            fn inlineFlushStaticCoalesce(
                self: *@This(),
                state: *InlineEmitState,
                coalesce_inits: *std.ArrayList(NodeRef),
                coalesce_post: *std.ArrayList(NodeRef),
                upd_body: *std.ArrayList(NodeRef),
            ) !void {
                if (coalesce_inits.items.len == 0) {
                    if (coalesce_post.items.len > 0) {
                        try upd_body.appendSlice(coalesce_post.items);
                        coalesce_post.clearRetainingCapacity();
                    }
                    return; 
                }
                try upd_body.append(try self.emitStaticStatements(state, coalesce_inits.items));
                try upd_body.appendSlice(coalesce_post.items);
                coalesce_inits.clearRetainingCapacity();
                coalesce_post.clearRetainingCapacity();
            }

            fn inlineProcessRunDirective(
                self: *@This(),
                state: *InlineEmitState,
                node: *const AstNode,
                upd_body: *std.ArrayList(NodeRef),
            ) anyerror!void {
                const save_emit_state = self.jsx_emit_state;
                self.jsx_emit_state = state;
                defer self.jsx_emit_state = save_emit_state;

                const stmts_head = getPackedData(node).right;

                var coalesce_inits = std.ArrayList(NodeRef).init(upd_body.allocator);
                defer coalesce_inits.deinit();
                var coalesce_post = std.ArrayList(NodeRef).init(upd_body.allocator);
                defer coalesce_post.deinit();

                var stmt_iter = NodeIterator.init(self.nodes, stmts_head);
                while (stmt_iter.nextRef()) |stmt_ref| {
                    const stmt = self.nodes.at(stmt_ref);
                    try self.visit(stmt, stmt_ref);

                    const is_static = stmt.hasFlag(NodeFlags.static);

                    if (stmt.kind == .variable_statement and is_static) {
                        const actual_stmt_ref = self.replacements.get(stmt_ref) orelse stmt_ref;
                        const is_const = stmt.hasFlag(NodeFlags.@"const");
                        const decl_head = unwrapRef(stmt);
                        var decl_iter = NodeIterator.init(self.nodes, decl_head);
                        while (decl_iter.nextRef()) |decl_ref| {
                            const decl = self.nodes.at(decl_ref);
                            std.debug.assert(decl.kind == .variable_declaration);
                            const dd = getPackedData(decl);
                            const name_ref = dd.left;
                            const init_ref = dd.right;
                            const name_text = getSlice(self.nodes.at(name_ref), u8);
                            const sym_ref = self.file.binder.getSymbol(decl_ref);
                            const can_hoist = if (sym_ref) |sr| (if (state.hoistable_symbols) |m| m.get(sr) orelse false else false) else false;
                            if (can_hoist) {
                                try self.inlineFlushStaticCoalesce(state, &coalesce_inits, &coalesce_post, upd_body);
                                const var_flags: u22 = if (is_const) @intFromEnum(NodeFlags.@"const") else @intFromEnum(NodeFlags.let);
                                try state.addStmt(try self.factory.createVariableStatement(
                                    try self.factory.createVariableDeclarationSimple(
                                        try self.factory.createIdentifier(name_text), init_ref),
                                    var_flags));
                                try self.copySyntheticsFrom(stmt_ref, &state.stmts);
                            } else {
                                var emit_compound_assign = false;
                                if (coalesce_inits.items.len == 0 and init_ref != 0) {
                                    const nonnull_per_update = if (state.static_nonnull) |m| m.contains(sym_ref orelse 0) else false;
                                    if (nonnull_per_update) {
                                        emit_compound_assign = true;
                                    }
                                }

                                const val_name: []const u8 = if (is_const) blk: {
                                    const vn = try state.nextName();
                                    try state.addStmt(try self.factory.createVariableStatement(
                                        try self.factory.createVariableDeclarationSimple(
                                            try self.factory.createIdentifier(vn), 0),
                                        @intFromEnum(NodeFlags.let)));
                                    break :blk vn;
                                } else blk: {
                                    try state.addStmt(try self.factory.createVariableStatement(
                                        try self.factory.createVariableDeclarationSimple(
                                            try self.factory.createIdentifier(name_text), 0),
                                        @intFromEnum(NodeFlags.let)));
                                    break :blk name_text;
                                };

                                if (init_ref != 0) {
                                    var actual_init = self.replacements.get(init_ref) orelse init_ref;
                                    const decl_next = self.nodes.at(actual_stmt_ref).next;
                                    if (decl_next != 0 and self.nodes.at(decl_next).kind == .block and decl_next != stmt.next) {
                                        const ret_name = try self.factory.createIdentifier(name_text);
                                        var iife_body = std.ArrayList(NodeRef).init(upd_body.allocator);
                                        defer iife_body.deinit();
                                        try iife_body.append(try self.factory.createConstVariable(ret_name, actual_init));
                                        try iife_body.append(decl_next);
                                        try iife_body.append(try self.factory.createReturnStatement(
                                            try self.factory.createIdentifier(name_text)));
                                        const arrow = try self.factory.createArrowFunction(
                                            0, try self.factory.createBlock(iife_body.items), 0);
                                        actual_init = try self.factory.createCallExpression(
                                            try self.factory.createParenthesizedExpression(arrow), &.{});
                                    }
                                    try coalesce_inits.append(try self.factory.createExpressionStatement(
                                        try self.factory.createBinaryExpression(
                                            try self.factory.createIdentifier(val_name),
                                            .equals_token,
                                            actual_init)));
                                }

                                if (is_const) {
                                    if (emit_compound_assign) {
                                        try upd_body.append(try self.factory.createVariableStatement(
                                            try self.factory.createVariableDeclarationSimple(
                                                try self.factory.createIdentifier(name_text),
                                                try self.factory.createParenthesizedExpression(
                                                    try self.factory.createBinaryExpression(try self.factory.createIdentifier(val_name), .question_question_equals_token, init_ref)
                                                )),
                                            @intFromEnum(NodeFlags.@"const")));
                                    } else {
                                        try coalesce_post.append(try self.factory.createVariableStatement(
                                            try self.factory.createVariableDeclarationSimple(
                                                try self.factory.createIdentifier(name_text),
                                                try self.factory.createIdentifier(val_name)),
                                            @intFromEnum(NodeFlags.@"const")));
                                    }
                                }
                                if (sym_ref) |r| {
                                    const bridged_name = if (state.bridged_declarations) |m| m.get(r) else null;
                                    if (bridged_name) |name| {
                                        try state.addStmt(
                                            try self.factory.createLetVariable(name, 0)
                                        );
                                        try coalesce_post.append(try self.factory.createAssignmentStatement(
                                            name,
                                            try self.factory.createIdentifier(name_text),
                                        ));
                                    }
                                }
                            }
                        }
                        continue;
                    } else if (is_static and stmt.kind == .block) {
                        const block_start = maybeUnwrapRef(stmt) orelse continue;
                        var iter = NodeIterator.init(self.nodes, block_start);
                        while (iter.nextRef()) |r| try coalesce_inits.append(r);
                        continue;
                    }

                    // any other statement breaks the coalesce group
                    try self.inlineFlushStaticCoalesce(state, &coalesce_inits, &coalesce_post, upd_body);

                    if ((stmt.kind == .function_declaration or stmt.kind == .class_declaration) and is_static) {
                        const actual = self.replacements.get(stmt_ref) orelse stmt_ref;
                        const fn_node = self.nodes.at(actual);
                        const fn_name_ref = getPackedData(fn_node).left;
                        const fn_name_text = getSlice(self.nodes.at(fn_name_ref), u8);
                        const sym_ref = self.file.binder.getSymbol(stmt_ref);
                        const can_hoist = if (sym_ref) |sr| (if (state.hoistable_symbols) |m| m.get(sr) orelse false else false) else false;

                        if (can_hoist) {
                            const hoisted = try self.copySyntheticStatements(stmt_ref, &state.stmts);
                            self.nodes.at(hoisted).flags &= ~@as(u22, @intFromEnum(NodeFlags.static));
                        } else {
                            const cache_name = try state.nextName();
                            try state.addStmt(try self.factory.createVariableStatement(
                                try self.factory.createVariableDeclarationSimple(
                                    try self.factory.createIdentifier(cache_name), 0),
                                @intFromEnum(NodeFlags.let)));

                            const fn_expr = try self.factory.cloneNodeRef(actual);
                            self.nodes.at(fn_expr).kind = if (stmt.kind == .function_declaration)
                                .function_expression
                            else
                                .class_expression;
                            self.nodes.at(fn_expr).flags &= ~@as(u22, @intFromEnum(NodeFlags.static));
                            self.nodes.at(fn_expr).next = 0;

                            try upd_body.append(try self.factory.createExpressionStatement(
                                try self.factory.createBinaryExpression(
                                    try self.factory.createIdentifier(cache_name),
                                    .question_question_equals_token,
                                    fn_expr)));
                            try upd_body.append(try self.factory.createVariableStatement(
                                try self.factory.createVariableDeclarationSimple(
                                    try self.factory.createIdentifier(fn_name_text),
                                    try self.factory.createIdentifier(cache_name)),
                                @intFromEnum(NodeFlags.@"const")));
                        }
                    } else blk: {
                        if (stmt.kind == .variable_statement) {
                            var decl_iter = NodeIterator.init(self.nodes, unwrapRef(stmt));
                            while (decl_iter.nextRef()) |decl_ref| {
                                const binding_ref = getPackedData(self.nodes.at(decl_ref)).left;
                                if (self.nodes.at(binding_ref).kind != .identifier) continue; // TODO
                                if (self.file.binder.getSymbol(binding_ref)) |r| {
                                    const bridged_name = if (state.bridged_declarations) |m| m.get(r) else null;
                                    if (bridged_name) |name| {
                                        try state.addStmt(
                                            try self.factory.createLetVariable(name, 0)
                                        );
                                        try coalesce_post.append(try self.factory.createAssignmentStatement(
                                            name,
                                            try self.cloneIfNeeded(binding_ref),
                                        ));
                                    }
                                }
                            }
                        }

                        if (stmt.kind == .variable_statement and !stmt.hasFlag(NodeFlags.@"const")) {
                            if (state.tree_classification) |tc| {
                                var di = NodeIterator.init(self.nodes, unwrapRef(stmt));
                                while (di.nextRef()) |decl_ref| {
                                    const binding_ref = getPackedData(self.nodes.at(decl_ref)).left;
                                    if (self.nodes.at(binding_ref).kind != .identifier) continue;
                                    const sym_ref = self.file.binder.getSymbol(binding_ref) orelse continue;
                                    const p = tc.producers.get(sym_ref) orelse continue;
                                    if (!p.is_written and !p.any_consumer_written) continue;
                                    // we break on multiple var decls in one statement!
                                    if (!p.is_captured and !p.any_consumer_captured) {
                                        // hoisted
                                        // FIXME: this should copy over any generated .next nodes too!
                                        const init_ref = getPackedData(self.nodes.at(decl_ref)).right;
                                        try state.addStmt(try self.factory.createLetVariable(try self.cloneIfNeeded(binding_ref), 0));
                                        try upd_body.append(try self.factory.createAssignmentStatement(try self.cloneIfNeeded(binding_ref), init_ref));
                                        break :blk;
                                    }
                                }
                            }
                        }

                        _ = try self.copySyntheticStatements(stmt_ref, upd_body);

                        if (stmt.kind == .variable_statement and !stmt.hasFlag(NodeFlags.@"const")) {
                            if (state.tree_classification) |tc| {
                                var di = NodeIterator.init(self.nodes, unwrapRef(stmt));
                                while (di.nextRef()) |decl_ref| {
                                    const binding_ref = getPackedData(self.nodes.at(decl_ref)).left;
                                    if (self.nodes.at(binding_ref).kind != .identifier) continue;
                                    const sym_ref = self.file.binder.getSymbol(binding_ref) orelse continue;
                                    const p = tc.producers.get(sym_ref) orelse continue;
                                    if (!p.is_written and !p.any_consumer_written) continue;
                                    if (!p.is_captured and !p.any_consumer_captured) continue;
                                    const var_name = getSlice(self.nodes.at(binding_ref), u8);

                                    const getter_name = name: {
                                        if (state.consumer_getters.get(sym_ref)) |exp| {
                                            break :name getSlice(self.nodes.at(getPackedData(self.nodes.at(exp)).left), u8);
                                        }
                                        break :name try state.nextName();
                                    };
                                    try state.addStmt(try self.factory.createLetVariable(
                                        try self.factory.createIdentifier(getter_name), 0));
                                    const setter_name = name: {
                                        if (state.consumer_setters.get(sym_ref)) |exp| {
                                            break :name getSlice(self.nodes.at(exp), u8);
                                        }
                                        break :name try state.nextName();
                                    };
                                    try state.addStmt(try self.factory.createLetVariable(
                                        try self.factory.createIdentifier(setter_name), 0));

                                    const getter_arrow = try self.factory.createArrowFunction(
                                        0, try self.factory.createIdentifier(var_name), 0);
                                    try upd_body.append(try self.factory.createExpressionStatement(
                                        try self.factory.createBinaryExpression(
                                            try self.factory.createIdentifier(getter_name),
                                            .equals_token, getter_arrow)));

                                    const param_v = try self.factory.createParameter(
                                        try self.factory.createIdentifier("v"), 0);
                                    const setter_body = try self.factory.createBinaryExpression(
                                        try self.factory.createIdentifier(var_name),
                                        .equals_token,
                                        try self.factory.createIdentifier("v"));
                                    const setter_arrow = try self.factory.createSingleParamArrowFunction(
                                        param_v, setter_body, 0);
                                    try upd_body.append(try self.factory.createExpressionStatement(
                                        try self.factory.createBinaryExpression(
                                            try self.factory.createIdentifier(setter_name),
                                            .equals_token, setter_arrow)));

                                    const getter_call = try self.factory.createCallExpression(
                                        try self.factory.createIdentifier(getter_name), &.{});
                                    const setter_ident = try self.factory.createIdentifier(setter_name);
                                    try state.consumer_getters.put(getAllocator(), sym_ref, getter_call);
                                    try state.consumer_setters.put(getAllocator(), sym_ref, setter_ident);
                                }
                            }
                        }
                    }
                }

                try self.inlineFlushStaticCoalesce(state, &coalesce_inits, &coalesce_post, upd_body);
            }

            fn copySyntheticStatements(self: *@This(), stmt_ref: NodeRef, dest: *std.ArrayList(NodeRef)) !NodeRef {
                const actual = self.replacements.get(stmt_ref) orelse stmt_ref;
                const clone = try self.factory.cloneNodeRef(actual);
                self.nodes.at(clone).next = 0;
                try dest.append(clone);
                try self.copySyntheticsFrom(stmt_ref, dest);
                return clone;
            }

            fn copySyntheticsFrom(self: *@This(), stmt_ref: NodeRef, dest: *std.ArrayList(NodeRef)) !void {
                const actual = self.replacements.get(stmt_ref) orelse stmt_ref;
                if (actual == stmt_ref or actual == 0) return;

                const real_next = self.nodes.at(stmt_ref).next;
                var n = self.nodes.at(actual).next;
                while (n != real_next and n != 0) {
                    try dest.append(n);
                    n = self.nodes.at(n).next;
                }
            }

            fn inlineFragmentObjectChildren(
                self: *@This(),
                state: *InlineEmitState,
                children: []const TreeNodeInfo,
                children_exp: NodeRef,
            ) anyerror!void {
                for (children) |child_info| {
                    if (child_info.kind != .labeled_fragment) continue;
                    const slot = child_info.node_ptr;
                    const sd = getPackedData(slot);
                    const name_ref = sd.left;
                    const params_head = sd.right;
                    const children_head = slot.len;
                    const is_parameterized = (slot.flags & @intFromEnum(NodeFlags.protected)) != 0;

                    if (children_head != 0) {
                        var it = NodeIterator.init(self.nodes, children_head);
                        while (it.nextRef()) |cr| try self.visit(self.nodes.at(cr), cr);
                    }

                    const body: NodeRef = if (children_head == 0)
                        try self.factory.createIdentifier("undefined")
                    else if (self.nodes.at(children_head).next == 0)
                        children_head
                    else blk: {
                        var cr = children_head;
                        while (cr != 0) {
                            const next_cr = self.nodes.at(cr).next;
                            if (next_cr != 0) {
                                const repl = self.replacements.get(cr) orelse cr;
                                var tail = repl;
                                while (self.nodes.at(tail).next != 0) tail = self.nodes.at(tail).next;
                                self.nodes.at(tail).next = next_cr;
                            }
                            cr = self.nodes.at(cr).next;
                        }
                        break :blk try self.nodes.push(.{
                            .kind = .array_literal_expression,
                            .data = @ptrFromInt(children_head),
                        });
                    };

                    const name_text = getSlice(self.nodes.at(name_ref), u8);
                    const lhs = try self.factory.createPropertyAccessExpression(children_exp, name_text);

                    if (!is_parameterized) {
                        const assign = try self.factory.createBinaryExpression(lhs, .equals_token, body);
                        try state.addStmt(try self.factory.createExpressionStatement(assign));
                        continue;
                    }

                    var block_stmts = std.ArrayList(NodeRef).init(getAllocator());
                    defer block_stmts.deinit();

                    var new_params_head: NodeRef = 0;
                    var new_params_tail: NodeRef = 0;
                    var assign_stmts_head: NodeRef = 0;
                    var assign_stmts_tail: NodeRef = 0;

                    var param_iter = NodeIterator.init(self.nodes, params_head);
                    while (param_iter.nextRef()) |param_ref| {
                        const param_node = self.nodes.at(param_ref);
                        const param_name_ref = getPackedData(param_node).left;
                        const param_name_text = getSlice(self.nodes.at(param_name_ref), u8);

                        const let_decl = try self.factory.createVariableDeclarationSimple(
                            try self.factory.createIdentifier(param_name_text), 0);
                        try block_stmts.append(try self.factory.createVariableStatement(
                            let_decl, @intFromEnum(NodeFlags.let)));

                        const prefixed = try std.fmt.allocPrint(getAllocator(), "_{s}", .{param_name_text});
                        const new_param = try self.factory.createParameter(
                            try self.factory.createIdentifier(prefixed), 0);
                        self.nodes.at(new_param).next = 0;
                        if (new_params_tail != 0) {
                            self.nodes.at(new_params_tail).next = new_param;
                        } else {
                            new_params_head = new_param;
                        }
                        new_params_tail = new_param;

                        const update_assign = try self.factory.createExpressionStatement(
                            try self.factory.createBinaryExpression(
                                try self.factory.createIdentifier(param_name_text),
                                .equals_token,
                                try self.factory.createIdentifier(prefixed)));
                        self.nodes.at(update_assign).next = 0;
                        if (assign_stmts_tail != 0) {
                            self.nodes.at(assign_stmts_tail).next = update_assign;
                        } else {
                            assign_stmts_head = update_assign;
                        }
                        assign_stmts_tail = update_assign;
                    }

                    const cache_name = try state.nextName();
                    const cache_decl = try self.factory.createVariableDeclarationSimple(
                        try self.factory.createIdentifier(cache_name), 0);
                    try block_stmts.append(try self.factory.createVariableStatement(
                        cache_decl, @intFromEnum(NodeFlags.let)));

                    const condition = try self.factory.createPrefixUnaryExpression(
                        .exclamation_token,
                        try self.factory.createIdentifier(cache_name));
                    const then_stmt = try self.factory.createExpressionStatement(
                        try self.factory.createBinaryExpression(
                            try self.factory.createIdentifier(cache_name),
                            .equals_token,
                            body));
                    const else_stmt = try self.inlineCallSymbolUpdate(cache_name);
                    const if_stmt = try self.factory.createIfStatement(condition, then_stmt, else_stmt);

                    const return_stmt = try self.factory.createReturnStatement(
                        try self.factory.createIdentifier(cache_name));

                    if (assign_stmts_tail != 0) {
                        self.nodes.at(assign_stmts_tail).next = if_stmt;
                    }
                    self.nodes.at(if_stmt).next = return_stmt;
                    const body_head = if (assign_stmts_head != 0) assign_stmts_head else if_stmt;

                    const arrow_block = try self.factory.createBlock(body_head);
                    const slot_value = try self.factory.createArrowFunction(new_params_head, arrow_block, 0);

                    const slot_assign = try self.factory.createBinaryExpression(lhs, .equals_token, slot_value);
                    try block_stmts.append(try self.factory.createExpressionStatement(slot_assign));

                    try state.addStmt(try self.factory.createBlock(block_stmts.items));
                }
            }

            fn inlineMaybeGetElementBinding(self: *@This(), node: *const AstNode) ?NodeRef {
                switch (node.kind) {
                    .jsx_self_closing_element => return if (node.extra_data == 0) null else node.extra_data,
                    .jsx_element => {
                        const or2 = maybeUnwrapRef(node) orelse return null;
                        const ref = self.nodes.at(or2).extra_data;
                        return if (ref == 0) null else ref;
                    },
                    else => return null,
                }
            }

            fn inlineEmitSpreadCompFn(
                self: *@This(),
                state: *InlineEmitState,
                el_name: []const u8,
                children: []const TreeNodeInfo,
            ) !void {
                const Tag = enum(u4) {
                    static_root,
                    dynamic_root,
                    spread_exp,
                    spread_comp,
                };
                const SlotInfo = struct { tag: Tag, static_pos: u32, dyn_idx: u32, len_var: NodeRef, nav_name: []const u8 };
                var slots = std.ArrayList(SlotInfo).init(getAllocator());
                defer slots.deinit();
                var has_dynamic = false;
                var dyn_counter: u32 = 0;
                for (children) |ci| {
                    const tag: Tag = switch (ci.kind) {
                        .run_directive, .style_directive, .component_directive, .labeled_fragment => continue,
                        .text_static, .intrinsic_static, .intrinsic_dynamic => .static_root,
                        .component_instance => if (ci.is_spread) .spread_comp else .static_root,
                        .expression => if (ci.is_spread) .spread_exp else .dynamic_root,
                        .if_directive => .spread_exp,
                    };
                    const dyn_idx = if (tag != .static_root) blk: { const d = dyn_counter; dyn_counter += 1; break :blk d; } else 0;
                    try slots.append(.{
                        .tag = tag,
                        .static_pos = ci.static_pos,
                        .dyn_idx = dyn_idx,
                        .len_var = ci.len_var,
                        .nav_name = ci.nav_name,
                    });
                    if (tag != .static_root) has_dynamic = true;
                }

                const a_id = try self.factory.createIdentifier("a");
                const rm_anchor = try self.factory.createExpressionStatement(
                    try self.factory.createCallExpression(
                        try self.factory.createPropertyAccessExpression(
                            try self.cloneIfNeeded(a_id), "remove"), 0));

                if (!has_dynamic) {
                    const a_d = try self.factory.createPropertyAccessExpression(a_id, "_d");
                    const not_d = try self.factory.createPrefixUnaryExpression(.exclamation_token, a_d);
                    const init_blk = try self.factory.createIfStatement(not_d, try self.factory.createBlock(&.{
                        try self.factory.createAssignmentStatement(a_d, try self.factory.createNumericLiteral(@as(i64,1))),
                        try self.factory.createExpressionStatement(
                            try self.factory.createCallExpression(
                                try self.factory.createPropertyAccessExpression(
                                    try self.cloneIfNeeded(a_id), "after"),
                                &.{try self.factory.createSpreadElement(state.children_exp)})
                        ),
                        rm_anchor,
                    }), 0);
                    const fn_body = try self.factory.createBlock(&.{init_blk});
                    const param = try self.cloneIfNeeded(a_id);
                    const arrow = try self.factory.createSingleParamArrowFunction(param, fn_body, 0);

                    const sc_lhs = try self.factory.createPropertyAccessExpression(
                        try self.factory.createIdentifier(el_name), "_sc");
                    try state.addStmt(try self.factory.createAssignmentStatement(sc_lhs, arrow));

                    return;
                }

                // opt
                if (slots.items.len == 1) {
                    var fn_body: ?NodeRef = null;
                    const s = slots.items[0];
                    if (s.tag == .dynamic_root) {
                        const n = try state.nextName();
                        try state.addStmt(try self.factory.createLetVariable(try self.factory.createIdentifier(n), 0));
                        fn_body = try self.factory.createBlock(&.{
                            try self.factory.createAssignmentStatement(
                                try self.factory.createIdentifier(n),
                                try self.factory.createCallExpression(
                                try self.factory.createIdentifier(self.requireHelper(.set_slot)), &.{
                                    try self.cloneIfNeeded(a_id),
                                    try self.factory.createElementAccessExpression(try self.cloneIfNeeded(state.children_exp), s.static_pos),
                                    try self.factory.createIdentifier(n)
                                })
                            )
                        });
                    }
                    if (fn_body) |b| {
                        const param = try self.cloneIfNeeded(a_id);
                        const arrow = try self.factory.createSingleParamArrowFunction(param, b, 0);
                        const sc_lhs = try self.factory.createPropertyAccessExpression(
                            try self.factory.createIdentifier(el_name), "_sc");
                        try state.addStmt(try self.factory.createAssignmentStatement(sc_lhs, arrow));
                        return;
                    }
                }

                const total_dyn = dyn_counter;
                const d_id = try self.factory.createIdentifier("d");

                var init_stmts = std.ArrayList(NodeRef).init(getAllocator());
                defer init_stmts.deinit();

                var d_props = NodeList.init(self.nodes);
                for (0..total_dyn) |i| {
                    const key = try std.fmt.allocPrint(getAllocator(), "c{d}", .{i});
                    const key_id = try self.factory.createIdentifier(key);
                    const new_cmt = try self.factory.createNewExpression(
                        try self.factory.createIdentifier("Comment"), &.{});
                    d_props.appendRef(try self.factory.createPropertyAssignment(key_id, new_cmt));
                }
                const a_d = try self.factory.createPropertyAccessExpression(
                    try self.factory.cloneNodeRef(a_id), "_d");
                const obj_lit = try self.factory.createObjectLiteralExpression(d_props.head);
                try init_stmts.append(try self.factory.createExpressionStatement(
                    try self.factory.createBinaryExpression(
                        try self.factory.cloneNodeRef(d_id), .equals_token,
                        try self.factory.createBinaryExpression(
                            a_d, .equals_token, obj_lit))));

                var after_args = NodeList.init(self.nodes);
                for (slots.items) |s| {
                    if (s.tag == .static_root) {
                        after_args.appendRef(try self.factory.createElementAccessExpression(
                            try self.cloneIfNeeded(state.children_exp), s.static_pos));
                    } else {
                        const key: []const u8 = try std.fmt.allocPrint(getAllocator(), "c{d}", .{s.dyn_idx});
                        after_args.appendRef(try self.factory.createPropertyAccessExpression(
                            try self.factory.cloneNodeRef(d_id), key));
                    }
                }
                try init_stmts.append(try self.factory.createExpressionStatement(
                    try self.factory.createCallExpression(
                        try self.factory.createPropertyAccessExpression(
                            try self.cloneIfNeeded(a_id), "after"),
                        after_args.head)));

                // for (slots.items) |s| {
                //     if (s.tag == .spread_comp) {
                //         const sc_fn = try self.factory.createPropertyAccessExpression(
                //             try self.factory.createPropertyAccessExpression(try self.factory.createIdentifier(s.nav_name), "root"), "_sc");
                //         const key: []const u8 = try std.fmt.allocPrint(getAllocator(), "c{d}", .{s.dyn_idx});
                //         const cn_init = try self.factory.createPropertyAccessExpression(
                //             try self.factory.cloneNodeRef(d_id), key);
                //         try init_stmts.append(try self.factory.createExpressionStatement(
                //             try self.factory.createCallExpression(sc_fn, &.{cn_init})));
                //     }
                // }

                try init_stmts.append(rm_anchor);

                var upd_stmts = std.ArrayList(NodeRef).init(getAllocator());
                defer upd_stmts.deinit();

                const has_spreads = state.offset_counter_name != 0;
                const acc_id = if (has_spreads) blk: {
                    const acc_name = try state.nextName();
                    const id = try self.factory.createIdentifier(acc_name);
                    try upd_stmts.append(try self.factory.createVariableStatement(
                        try self.factory.createVariableDeclarationSimple(
                            try self.cloneIfNeeded(id),
                            try self.cloneIfNeeded(state.offset_counter_name)),
                        @intFromEnum(NodeFlags.let)));
                    break :blk id;
                } else @as(NodeRef, 0);

                var i: usize = slots.items.len;
                while (i > 0) {
                    i -= 1;
                    const s = slots.items[i];
                    if (s.tag == .static_root) continue;

                    const key: []const u8 = try std.fmt.allocPrint(getAllocator(), "c{d}", .{s.dyn_idx});
                    const cn = try self.factory.createPropertyAccessExpression(
                        try self.factory.cloneNodeRef(d_id), key);

                    if (s.tag == .dynamic_root) {
                        const idx_exp = if (!has_spreads)
                            try self.factory.createNumericLiteral(s.static_pos)
                        else if (s.static_pos == 0)
                            try self.cloneIfNeeded(acc_id)
                        else
                            try self.factory.createBinaryExpression(
                                try self.factory.createNumericLiteral(s.static_pos),
                                .plus_token,
                                try self.cloneIfNeeded(acc_id));
                        const val = try self.factory.createElementAccessExpression(
                            try self.cloneIfNeeded(state.children_exp), idx_exp);
                        const cn_s = try self.factory.createPropertyAccessExpression(cn, "s");
                        const cn_s2 = try self.factory.createPropertyAccessExpression(
                            try self.factory.createPropertyAccessExpression(
                                try self.factory.cloneNodeRef(d_id), key), "s");
                        const set_slot = try self.factory.createCallExpression(
                            try self.factory.createIdentifier(self.requireHelper(.set_slot)),
                            &.{cn, val, cn_s2});
                        try upd_stmts.append(try self.factory.createExpressionStatement(
                            try self.factory.createBinaryExpression(
                                cn_s, .equals_token, set_slot)));
                    } else if (s.tag == .spread_exp) {
                        // slice(acc -= len, acc + len)
                        const dec_exp = try self.factory.createBinaryExpression(
                            try self.cloneIfNeeded(acc_id), .minus_equals_token,
                            try self.cloneIfNeeded(s.len_var));
                        const start_exp = if (s.static_pos == 0)
                            dec_exp
                        else
                            try self.factory.createBinaryExpression(
                                try self.factory.createNumericLiteral(s.static_pos),
                                .plus_token,
                                try self.factory.createParenthesizedExpression(dec_exp));
                        const end_exp = if (s.static_pos == 0)
                            try self.factory.createBinaryExpression(
                                try self.cloneIfNeeded(acc_id), .plus_token,
                                try self.cloneIfNeeded(s.len_var))
                        else
                            try self.factory.createBinaryExpression(
                                try self.factory.createBinaryExpression(
                                    try self.factory.createNumericLiteral(s.static_pos),
                                    .plus_token,
                                    try self.cloneIfNeeded(acc_id)),
                                .plus_token,
                                try self.cloneIfNeeded(s.len_var));
                        const slice_call = try self.factory.createCallExpression(
                            try self.factory.createPropertyAccessExpression(
                                try self.cloneIfNeeded(state.children_exp), "slice"),
                            &.{start_exp, end_exp});
                        const cn_s = try self.factory.createPropertyAccessExpression(cn, "s");
                        const cn_s2 = try self.factory.createPropertyAccessExpression(
                            try self.factory.createPropertyAccessExpression(
                                try self.factory.cloneNodeRef(d_id), key), "s");
                        const set_spread = try self.factory.createCallExpression(
                            try self.factory.createIdentifier(self.requireHelper(.set_slot_spread)),
                            &.{cn, slice_call, cn_s2});
                        try upd_stmts.append(try self.factory.createExpressionStatement(
                            try self.factory.createBinaryExpression(
                                cn_s, .equals_token, set_spread)));
                    } else if (s.tag == .spread_comp) {
                        const sc_fn = try self.factory.createPropertyAccessExpression(
                            try self.factory.createPropertyAccessExpression(try self.factory.createIdentifier(s.nav_name), "root"), "_sc");
                        try upd_stmts.append(try self.factory.createExpressionStatement(
                            try self.factory.createCallExpression(sc_fn, &.{cn})));
                        try upd_stmts.append(try self.factory.createExpressionStatement(
                            try self.factory.createBinaryExpression(
                                try self.cloneIfNeeded(acc_id),
                                .minus_equals_token,
                                try self.cloneIfNeeded(s.len_var))));
                    }
                }

                var fn_body_stmts = std.ArrayList(NodeRef).init(getAllocator());
                defer fn_body_stmts.deinit();

                try fn_body_stmts.append(try self.factory.createVariableStatement(
                    try self.factory.createVariableDeclarationSimple(
                        try self.factory.cloneNodeRef(d_id),
                        try self.factory.createPropertyAccessExpression(
                            try self.factory.cloneNodeRef(a_id), "_d")),
                    @intFromEnum(NodeFlags.let)));

                const not_d = try self.factory.createPrefixUnaryExpression(
                    .exclamation_token,
                    try self.factory.cloneNodeRef(d_id));
                try fn_body_stmts.append(try self.factory.createIfStatement(
                    not_d, try self.factory.createBlock(init_stmts.items), 0));
                try fn_body_stmts.appendSlice(upd_stmts.items);

                const fn_body = try self.factory.createBlock(fn_body_stmts.items);
                const param = try self.factory.createIdentifier("a");
                const arrow = try self.factory.createSingleParamArrowFunction(param, fn_body, 0);

                const sc_lhs = try self.factory.createPropertyAccessExpression(
                    try self.factory.createIdentifier(el_name), "_sc");
                try state.addStmt(try self.factory.createExpressionStatement(
                    try self.factory.createBinaryExpression(sc_lhs, .equals_token, arrow)));
            }

            const _Visitor = @This();
            const ScopedTreeBindingReplacer = struct {
                proxy_getter_replacer: ?ScopedSymbolReplacer = null,
                proxy_setter_replacer: ?ScopedSymbolReplacer = null,
                getter_snapshots: ?ScopedSymbolReplacer = null,
                setter_snapshots: ?ScopedSymbolReplacer = null,
                bridged_replacer: ?ScopedSymbolReplacer = null,

                pub fn init(v: *_Visitor, s: *InlineEmitState, node: *const AstNode, upd_body: *std.ArrayList(NodeRef)) !?@This() {
                    const tc = s.tree_classification orelse return null;
                    const node_ref = blk: {
                        if (s.stmts.items.len == 0 and s.current_component_decl != 0) {
                            if (!tc.node_ptr_to_ref.contains(node) or tc.node_maps.get(tc.node_ptr_to_ref.get(node).?) == null) {
                                break :blk s.current_component_decl;
                            }
                        }
                        break :blk tc.node_ptr_to_ref.get(node) orelse return null;
                    };
                    const m = tc.node_maps.get(node_ref) orelse return null;

                    var self = @This(){};

                    var getter_replacements: std.AutoHashMapUnmanaged(SymbolRef, NodeRef) = .{};
                    defer getter_replacements.deinit(getAllocator());
                    var setter_replacements: std.AutoHashMapUnmanaged(SymbolRef, NodeRef) = .{};
                    defer setter_replacements.deinit(getAllocator());

                    var bridges: std.AutoHashMapUnmanaged(SymbolRef, NodeRef) = .{};
                    defer bridges.deinit(getAllocator());

                    var iter = m.iterator();
                    while (iter.next()) |sym_entry| {
                        const sym_ref = sym_entry.key_ptr.*;
                        const info = sym_entry.value_ptr.*;
                        var any_captured = false;
                        var bridged = false;
                        if (info.producer) |p| {
                            if (p.containing_node == node_ref) continue;

                            if ((p.is_captured or p.any_consumer_captured) and (p.is_written or p.any_consumer_written)) {
                                if (p.any_consumer_written and !s.consumer_setters.contains(sym_ref)) {
                                    const r = try s.nextName();
                                    const ident = try v.factory.createIdentifier(r);
                                    try s.consumer_setters.put(getAllocator(), sym_ref, ident);

                                    // const r = try s.getStaticScopedName();
                                    // const ident = try v.factory.createIdentifier(r.name);
                                    // try s.consumer_setters.put(getAllocator(), sym_ref, ident);
                                    // try s.stmts.append(try v.factory.createLetVariable(ident, 0));
                                }
                                if (p.any_consumer_read and !s.consumer_getters.contains(sym_ref)) {
                                    const r = try s.nextName();
                                    const ident = try v.factory.createIdentifier(r);
                                    try s.consumer_getters.put(getAllocator(), sym_ref, try v.factory.createCallExpression(ident, 0));

                                    // const r = try s.getStaticScopedName();
                                    // const ident = try v.factory.createIdentifier(r.name);
                                    // try s.consumer_getters.put(getAllocator(), sym_ref, ident);
                                    // try s.stmts.append(try v.factory.createLetVariable(ident, 0));
                                }
                            }

                            any_captured = p.any_consumer_captured;
                            if (p.is_captured) bridged = true;
                        }
                        // TODO: a symbol across a nested #component boundary, if inside the template, 
                        // should still be treated as "captured" if we cannot prove synchronized updates
                        if (!any_captured) {
                            if (bridged) {
                                if (s.bridged_declarations) |m2| {
                                    if (m2.get(sym_ref)) |x| {
                                        try bridges.put(getAllocator(), sym_ref, x);
                                    }
                                }
                            }
                            continue;
                        }

                        if (info.is_read) {
                            if (s.consumer_getters.get(sym_ref)) |r| {
                                const n = try s.nextName();
                                const is_call = v.nodes.at(r).kind == .call_expression;
                                const ident = if (is_call) getPackedData(v.nodes.at(r)).left else r;
                                try upd_body.append(try v.factory.createConstVariable(
                                    try v.factory.createIdentifier(n),
                                    ident
                                ));
                                const u = try v.factory.createIdentifier(n);
                                const q = if (is_call) try v.factory.createCallExpression(u, getPackedData(v.nodes.at(r)).right) else u;
                                try getter_replacements.put(getAllocator(), sym_ref, q);
                            }
                        }

                        if (info.is_written) {
                            if (s.consumer_setters.get(sym_ref)) |r| {
                                const n = try s.nextName();
                                try upd_body.append(try v.factory.createConstVariable(
                                    try v.factory.createIdentifier(n),
                                    r
                                ));
                                try setter_replacements.put(getAllocator(), sym_ref, try v.factory.createIdentifier(n));
                            }
                        }
                    }

                    if (bridges.count() > 0) {
                        self.bridged_replacer =  try ScopedSymbolReplacer.init(&v.symbol_replacements, &bridges);
                    }

                    // These two replacers churn the same memory, we should only need to setup based on `m`
                    if (s.consumer_getters.count() > 0) {
                        self.proxy_getter_replacer = try ScopedSymbolReplacer.init(&v.symbol_replacements, &s.consumer_getters);
                    }

                    if (s.consumer_setters.count() > 0) {
                        self.proxy_setter_replacer = try ScopedSymbolReplacer.init(&v.proxied_symbol_replacements, &s.consumer_setters);
                    }
                    
                    if (getter_replacements.count() > 0) {
                        self.getter_snapshots = try ScopedSymbolReplacer.init(&v.symbol_replacements, &getter_replacements);
                    }

                    if (setter_replacements.count() > 0) {
                        self.setter_snapshots = try ScopedSymbolReplacer.init(&v.proxied_symbol_replacements, &setter_replacements);
                    }

                    return self;
                }

                pub fn deinit(self: @This()) void {
                    if (self.getter_snapshots) |r| r.deinit();
                    if (self.setter_snapshots) |r| r.deinit();
                    if (self.proxy_getter_replacer) |r| r.deinit();
                    if (self.proxy_setter_replacer) |r| r.deinit();
                    if (self.bridged_replacer) |r| r.deinit();
                }
            };

            fn inlineProcessElement2(
                self: *@This(),
                state: *InlineEmitState,
                el_name: []const u8,
                node_ref: NodeRef,
                merge_into: ?*std.ArrayList(NodeRef),
            ) anyerror!bool {
                const save_ref = state.current_node_ref;
                defer state.current_node_ref = save_ref;
                state.current_node_ref = node_ref;

                const save_fragment_like = state.containing_element_is_fragment_like;
                defer state.containing_element_is_fragment_like = save_fragment_like;
                state.containing_element_is_fragment_like = switch (self.nodes.at(node_ref).kind) {
                    .jsx_element => !self.isIntrinsicElement(node_ref),
                    .jsx_component => self.nodes.at(node_ref).hasFlag(.generator),
                    else => save_fragment_like,
                };
                
                if (self.isIntrinsicElement(node_ref)) {
                    state.skip_attributes = false;
                }

                return self.inlineProcessElement(state, el_name, self.nodes.at(node_ref), merge_into);
            }

            fn inlineProcessElement(
                self: *@This(),
                state: *InlineEmitState,
                el_name: []const u8,
                node: *const AstNode,
                merge_into: ?*std.ArrayList(NodeRef),
            ) anyerror!bool {
                var upd_body = std.ArrayList(NodeRef).init(getAllocator());
                defer upd_body.deinit();

                const tree_binding_replacer = try ScopedTreeBindingReplacer.init(self, state, node, &upd_body);
                defer if (tree_binding_replacer) |r| r.deinit();

                const children_start: NodeRef = switch (node.kind) {
                    .jsx_self_closing_element => {
                        const d = getPackedData(node);
                        const tag_ref = d.left;
                        const tag_name: []const u8 = if (self.isIntrinsicTag(tag_ref)) getSlice(self.nodes.at(tag_ref), u8) else "";
                        try self.inlineProcessAttrs(state, &upd_body, el_name, tag_name, d.right);
                        if (self.inlineMaybeGetElementBinding(node)) |binding_ref| {
                            const binding_text = getSlice(self.nodes.at(binding_ref), u8);
                            std.debug.assert(std.mem.eql(u8, binding_text, el_name));
                        }
                        if (merge_into) |pb| { try pb.appendSlice(upd_body.items); return false; }
                        return try self.inlineEmitSymbolUpdateFull(state, el_name, upd_body.items);
                    },
                    .jsx_element => blk: {
                        const opening_ref = maybeUnwrapRef(node) orelse return error.InvalidJsx;
                        const od = getPackedData(self.nodes.at(opening_ref));
                        const tag_ref = od.left;
                        const tag_name: []const u8 = if (self.isIntrinsicTag(tag_ref)) getSlice(self.nodes.at(tag_ref), u8) else "";
                        try self.inlineProcessAttrs(state, &upd_body, el_name, tag_name, od.right);
                        break :blk opening_ref;
                    },
                    .jsx_fragment => maybeUnwrapRef(node) orelse return false,
                    .jsx_if_directive, .jsx_else_directive,
                    .jsx_component => blk: {
                        const d = getPackedData(node);
                        break :blk d.right;
                    },
                    else => {
                        if (comptime is_debug) std.debug.print("Invalid Jsx: {?}\n",.{node.kind});
                        return error.InvalidJsx;
                    },
                };

                const is_fragment_like = self.isFragmentLike(node);

                const children = try self.gatherChildInfo(children_start);
                defer children.deinit();
                for (children.items) |*info| {
                    info.parent_ref = state.current_node_ref;
                }

                try self.inlineBridgeStaticAnonymousFns(state, children_start);

                var component_children_template: ?[]const u8 = null;
                if (state.ctx == .component and self.jsxRealChildCount(children_start, true, true) > 0) {
                    component_children_template = try state.nextName();
                    const tmpl = try self.createHtmlTemplate(state.current_node_ref);
                    const tmpl_decl = try self.factory.createConstVariable(try self.factory.createIdentifier(component_children_template.?), tmpl);
                    try state.addStmt(tmpl_decl);
                }

                if (state.ctx != .component or component_children_template != null) {
                    var has_nav_after = false;
                    var ci = children.items.len;
                    while (ci > 0) {
                        ci -= 1;
                        var info = &children.items[ci];
                        if (info.kind == .run_directive or info.kind == .style_directive or info.kind == .component_directive) continue;
                        if (component_children_template != null) {
                            info.needs_nav = info.kind == .intrinsic_static or info.kind == .intrinsic_dynamic;
                        }
                        if (state.containing_element_is_fragment_like and info.kind == .if_directive) continue;
                        if (is_fragment_like) {
                            if (info.kind == .text_static and !has_nav_after) {
                                if (state.containing_element_is_fragment_like) {
                                    var ci2 = ci;
                                    var should_skip = false;
                                    while (ci2 > 0) {
                                        ci2 -= 1;
                                        const info2 = children.items[ci];
                                        switch (info2.kind) {
                                            .run_directive, .style_directive, .component_directive => {},
                                            .expression, .component_instance, .if_directive => {},
                                            .text_static => {
                                                should_skip = true;
                                                break;
                                            },
                                            else => break,
                                        }
                                    }
                                    if (should_skip) continue;
                                }
                            }
                            if (info.kind != .expression or !state.containing_element_is_fragment_like) {
                                info.needs_nav = true;
                            }
                            if (has_nav_after) {
                                info.needs_nav = true;
                            }
                            has_nav_after = has_nav_after or info.needs_nav;
                            continue;
                        }
                        if (state.ctx != .templated and info.kind != .intrinsic_static and info.kind != .intrinsic_dynamic) continue;
                        const k = info.kind;
                        const is_dyn = k != .intrinsic_static and k != .text_static;
                        const has_binding = self.inlineMaybeGetElementBinding(info.node_ptr) != null;
                        info.needs_nav = info.needs_nav or is_dyn or has_binding or has_nav_after;
                        has_nav_after = has_nav_after or info.needs_nav;
                    }

                    var prev_nav: []const u8 = if (component_children_template) |x| x else el_name;
                    var use_first_child = true;
                    for (children.items) |*child_info| {
                        if (!child_info.needs_nav) continue;

                        const direct_assign = (is_fragment_like and use_first_child and !self.jsxHasManyChildren(children_start)) or (use_first_child and state.containing_element_is_fragment_like and !self.willHaveManyNodes(children_start, true));
                        // use the binding name directly if one exists, otherwise generate
                        // component instances do not get bound here, only intrinsics
                        const binding_ref: ?u32 = if (child_info.kind != .component_instance) 
                            self.inlineMaybeGetElementBinding(child_info.node_ptr) else null;

                        if (direct_assign and (node.kind == .jsx_if_directive or node.kind == .jsx_else_directive) and binding_ref == null) {
                            const nav_name = prev_nav;
                            prev_nav = nav_name;
                            use_first_child = false;
                            child_info.nav_name = nav_name;
                            continue;
                        }

                        if (comptime callee_creates_comp_instance) {
                            if (binding_ref == null and node.kind == .jsx_component and direct_assign) {
                                const nav_name = prev_nav;
                                prev_nav = nav_name;
                                use_first_child = false;
                                child_info.nav_name = nav_name;
                                continue;        
                            }
                        }

                        var did_allocate = binding_ref != null;
                        const nav_name = if (binding_ref) |br|
                            getSlice(self.nodes.at(br), u8)
                        else
                            state.maybeReuseName() orelse blk: {
                                did_allocate = true;
                                break :blk try state.nextName();
                            };


                        if (comptime callee_creates_comp_instance) {
                            // >:(
                            if (binding_ref != null and strings.eql(nav_name, el_name) and use_first_child) {
                                prev_nav = nav_name;
                                use_first_child = false;
                                child_info.nav_name = nav_name;
                                continue;
                            }
                        }

                        const should_release = binding_ref == null and self.jsxNodeCanUseEphemeralNav(child_info.node_ptr);

                        const prev_id = try self.factory.createIdentifier(prev_nav);
                        const nav_prop = if (direct_assign)
                                prev_id
                            else try self.factory.createPropertyAccessExpression(
                                prev_id, if (use_first_child) "firstChild" else "nextSibling");

                        if (did_allocate) {
                            const nav_decl = try self.factory.createVariableDeclarationSimple(
                                try self.factory.createIdentifier(nav_name), nav_prop);
                            // TODO: emit all of these as a single statement, use let
                            const decl_flags = if (should_release or (child_info.kind == .expression and child_info.depends_on_effects) or child_info.kind == .component_instance)
                                @intFromEnum(NodeFlags.let)
                            else
                                @intFromEnum(NodeFlags.@"const");
                            try state.addStmt(try self.factory.createVariableStatement(nav_decl, decl_flags));
                        } else {
                            try state.addStmt(try self.factory.createAssignmentStatement(try self.factory.createIdentifier(nav_name), nav_prop));
                        }

                        if (should_release) {
                            try state.releaseName(nav_name);
                        }

                        prev_nav = nav_name;
                        use_first_child = false;
                        child_info.nav_name = nav_name;

                        if (child_info.kind == .if_directive or (child_info.kind == .expression and child_info.is_spread)) {
                            try self.factory.attachDebugComment(state.stmts.getLast(), if (child_info.kind == .if_directive) "<!> - #if" else "<!> - {...}");
                            const ph_name = try state.nextName();
                            child_info.ph_name = ph_name;
                            const access = try self.factory.createPropertyAccessExpression(try self.factory.createIdentifier(prev_nav), "nextSibling");
                            try state.addStmt(try self.factory.createLetVariable(try self.factory.createIdentifier(ph_name), access));
                            prev_nav = ph_name;
                            try self.factory.attachDebugComment(state.stmts.getLast(), if (child_info.kind == .if_directive) "#if - <!>" else "{...} - <!>");
                        } else {
                            // debug info
                            if (binding_ref == null) {
                                if (child_info.node_ptr.kind == .jsx_element or child_info.node_ptr.kind == .jsx_self_closing_element) {
                                    const tag_ref = self.getJsxTagRef(child_info.node_ptr);
                                    if (self.nodes.at(tag_ref).kind == .identifier) {
                                        try self.factory.attachDebugComment(state.stmts.getLast(), getSlice(self.nodes.at(tag_ref), u8));
                                    }
                                }
                                if (child_info.node_ptr.kind == .jsx_expression) {
                                    try self.factory.attachDebugComment(state.stmts.getLast(), "<!> - {}");
                                }
                                if (child_info.node_ptr.kind == .jsx_text) {
                                    // const text = std.fmt.allocPrint(getAllocator(), "#text - {s}")// LEAKS
                                    try self.factory.attachDebugComment(state.stmts.getLast(), "#text");
                                }
                            }
                        }
                    }
                }

                if (state.ctx == .component or (is_fragment_like and !state.emit_internal_fragment) or (node.kind == .jsx_element and !self.isIntrinsicTag(self.getJsxTagRef(node)))) {
                    var has_spread = false;
                    for (children.items) |child_info| {
                        if (child_info.is_spread) has_spread = true;
                    }
                    const is_single_root = node.kind == .jsx_component and !has_spread and !node.hasFlag(.generator) and self.jsxRealChildCount(children_start, false, false) == 1;
                    if (is_single_root) {
                        var snapshot_exp: NodeRef = 0;
                        // XXX: we are bypassing the normal "emit as array" flow
                        for (children.items) |*child_info| {
                            if (child_info.kind == .run_directive) {
                                if (comptime callee_creates_comp_instance) {
                                    try self.inlineProcessRunDirective(state, child_info.node_ptr, &upd_body);
                                    continue;
                                }
                                var gated_upd_body = std.ArrayList(NodeRef).init(getAllocator());
                                defer gated_upd_body.deinit();
                                try self.inlineProcessRunDirective(state, child_info.node_ptr, &gated_upd_body);
                                if (gated_upd_body.items.len == 0) continue;
                                const stmt = if (gated_upd_body.items.len == 1) gated_upd_body.items[0] else try self.factory.createBlock(gated_upd_body.items);
                                try upd_body.append(try self.factory.createIfStatement(try self.factory.createIdentifier("__p"), stmt, 0));
                            } else if (child_info.kind == .style_directive) {
                                try self.inlineProcessStyleDirective(state, child_info.node_ptr);
                            } else if (child_info.kind == .component_directive) {
                                const fn_decl = try self.visitJsxCompDeclaration(state, child_info);
                                try state.addStmt(fn_decl);
                            }
                            if (!child_info.needs_nav) continue;
                            const nav_name = child_info.nav_name;
                            switch (child_info.kind) {
                                .intrinsic_static => {},
                                .intrinsic_dynamic => {
                                    if (self.inlineMaybeGetElementBinding(child_info.node_ptr) != null) {
                                        const had_update = try self.inlineProcessElement2(state, nav_name, child_info.node_ref, null);
                                        if (had_update) {
                                            if (comptime callee_creates_comp_instance) {
                                                try upd_body.append(try self.inlineCallSymbolUpdate(nav_name));
                                            } else {
                                                const snapshot_name = try state.nextName();
                                                snapshot_exp = try self.factory.createIdentifier(snapshot_name);
                                                try state.addStmt(try self.factory.createConstVariable(snapshot_exp, try self.accessUpdateSymbol(try self.factory.createIdentifier(nav_name))));
                                                try upd_body.append(try self.factory.createCallExpression(snapshot_exp, &.{}));
                                            }
                                        }
                                    } else {
                                        _ = try self.inlineProcessElement2(state, nav_name, child_info.node_ref, &upd_body);
                                    }
                                },
                                .component_instance => blk: {
                                    std.debug.assert(!child_info.is_spread);
                                    const save_ctx = state.ctx;
                                    defer state.ctx = save_ctx;
                                    state.ctx = .component;

                                    try self.emitCallerCompProtocol(state, child_info, &upd_body);
                                    break :blk;
                                },
                                else => unreachable,
                            }
                            if (strings.eql(el_name, nav_name)) continue;
                            try state.addStmt(try self.factory.createAssignmentStatement(
                            try self.factory.createIdentifier(el_name), try self.factory.createIdentifier(nav_name)));
                        }
                        if (merge_into) |pb| { try pb.appendSlice(upd_body.items); return false; }
                        if (upd_body.items.len == 0) return false;
                        const body_block = try self.factory.createBlock(upd_body.items);
                        const arrow = try self.factory.createSingleParamArrowFunction(try self.factory.createParameter(try self.factory.createIdentifier("__p"), 0), body_block, 0);
                        const assign = try self.factory.createBinaryExpression(try self.accessUpdateSymbol(try self.factory.createIdentifier(el_name)), .equals_token, arrow);
                        try state.addStmt(try self.factory.createExpressionStatement(assign));
                        return true;
                    }
                    // only self-closing elements elide `children`
                    const has_slots = for (children.items) |c| {
                        if (c.kind == .labeled_fragment) break true;
                    } else false;

                    const empty_init = if (has_slots)
                        try self.factory.createObjectLiteralExpression(0)
                    else
                        try self.factory.createArrayLiteralExpression(&.{});

                    var children_binding: NodeRef = undefined;
                    if (is_fragment_like) {
                        if (state.children_exp != 0 and state.current_node_ref != 0 and (self.nodes.at(state.current_node_ref).kind == .jsx_if_directive or self.nodes.at(state.current_node_ref).kind == .jsx_else_directive)) {
                            children_binding = state.children_exp;
                        } else if (state.containing_element_is_fragment_like) {
                            children_binding = try self.factory.createIdentifier(el_name);
                        } else {
                            try state.addStmt(try self.factory.createAssignmentStatement(
                                try self.factory.createIdentifier(el_name), empty_init));
                            children_binding = try self.factory.createIdentifier(el_name);
                        }
                    } else {
                        const props_ref = if (comptime callee_creates_comp_instance)
                            try self.factory.createIdentifier(el_name)
                        else
                            try self.factory.createPropertyAccessExpression(
                                try self.factory.createIdentifier(el_name),
                                "_p"
                            );
                        const ch =  try self.factory.createPropertyAccessExpression(props_ref, "children");

                        // optimization, we want to pass spread expressions directly into children
                        if (!is_fragment_like and node.kind == .jsx_element and children.items.len == 1) {
                            var single_exp: ?TreeNodeInfo = null;
                            for (children.items) |c| {
                                switch (c.kind) {
                                    .expression => {
                                        if (!c.is_spread) break;
                                        if (self.nodes.at(c.inner_ref).kind != .identifier) break;
                                        if (single_exp != null) {
                                            single_exp = null; // bail
                                            break;
                                        }
                                        single_exp = c;
                                    },
                                    else => {},
                                }
                            }
                            if (single_exp) |c| {
                                // TODO: if the symbol points to `children` param in #component (or if we can prove an array), we can skip the array check
                                const mc_check = try self.factory.createPropertyAccessExpression(
                                    try self.factory.createPropertyAccessExpression(try self.factory.createIdentifier(el_name), "root"),
                                    "_mc"
                                );
                                const copy_branch = try self.factory.createArrayLiteralExpression(&.{
                                    try self.factory.createSpreadElement(try self.cloneIfNeeded(c.inner_ref))
                                });
                                const is_not_array = try self.factory.createPrefixUnaryExpression(
                                    .exclamation_token,
                                    try self.factory.createCallExpression(try self.factory.createPropertyAccessExpression(try self.factory.createIdentifier("Array"), "isArray"), &.{try self.cloneIfNeeded(c.inner_ref)})
                                );
                                const check = try self.factory.createBinaryExpression(mc_check, .bar_bar_token, is_not_array);
                                try upd_body.append(try self.factory.createAssignmentStatement(
                                    ch,
                                    try self.factory.createConditionalExpression(check, copy_branch,  try self.cloneIfNeeded(c.inner_ref))
                                ));
                                if (merge_into) |pb| { try pb.appendSlice(upd_body.items); return false; }
                                return try self.inlineEmitSymbolUpdateFull(state, el_name, upd_body.items);
                            }
                        }

                        if (comptime callee_creates_comp_instance) {
                            children_binding = props_ref; // ch;
                        } else {
                            const assign = try self.factory.createBinaryExpression(
                                ch, .equals_token, empty_init);
                            children_binding = try self.factory.createIdentifier(try state.nextName());
                            const decl = try self.factory.createVariableDeclarationSimple(children_binding, assign);
                            try state.addStmt(try self.factory.createVariableStatement(decl, @intFromEnum(NodeFlags.@"const")));
                        }
                    }

                    if (has_slots) {
                        try self.inlineFragmentObjectChildren(state, children.items, try self.cloneIfNeeded(children_binding));
                    } else {
                        try self.inlineArrayChildren(state, children.items, &upd_body, try self.cloneIfNeeded(children_binding));
                        if (node.kind == .jsx_component) {
                            try self.inlineEmitSpreadCompFn(state, el_name, children.items);
                        }
                    }

                    if (merge_into) |pb| { try pb.appendSlice(upd_body.items); return false; }
                    return try self.inlineEmitSymbolUpdateFull(state, el_name, upd_body.items);
                }

                // const has_many = self.jsxHasManyChildren(children_start);

                for (children.items) |*child_info| {
                    if (child_info.kind == .run_directive) {
                        try self.inlineProcessRunDirective(state, child_info.node_ptr, &upd_body);
                    } else if (child_info.kind == .style_directive) {
                        try self.inlineProcessStyleDirective(state, child_info.node_ptr);
                    } else if (child_info.kind == .component_directive) {
                        const fn_decl = try self.visitJsxCompDeclaration(state, child_info);
                        try state.addStmt(fn_decl);
                    }
                    if (!child_info.needs_nav) continue;

                    const nav_name = child_info.nav_name;

                    switch (child_info.kind) {
                        .run_directive, .style_directive, .component_directive,
                        .text_static, .intrinsic_static => {},
                        .expression => {
                            try upd_body.append(
                                try self.createJsxExpressionToDomSlot(state, child_info)
                            );
                        },
                        .intrinsic_dynamic => {
                            if (self.inlineMaybeGetElementBinding(child_info.node_ptr) != null) {
                                const had_update = try self.inlineProcessElement2(state, nav_name, child_info.node_ref, null);
                                if (had_update) {
                                    try upd_body.append(try self.inlineCallSymbolUpdate(nav_name));
                                }
                            } else {
                                _ = try self.inlineProcessElement2(state, nav_name, child_info.node_ref, &upd_body);
                            }
                        },
                        .component_instance => {
                            try self.emitCallerCompProtocol(state, child_info, &upd_body);
                        },
                        .if_directive => {
                            try self.emitIfDirective(state, child_info, &upd_body);
                        },
                        .labeled_fragment => {},
                    }
                }

                if (merge_into) |pb| { try pb.appendSlice(upd_body.items); return false; }
                return try self.inlineEmitSymbolUpdateFull(state, el_name, upd_body.items);
            }

            fn emitIfDirective(self: *@This(), state: *InlineEmitState, child_info: *TreeNodeInfo, upd_body: *std.ArrayList(NodeRef)) !void {
                if (self.nodes.at(child_info.node_ref).kind == .jsx_else_directive) return;

                // a general lowering is roughly of the form:
                // <>
                //   <#run>
                //     static let fragment
                //     const cond = ...
                //     if (cond) defer { update fragment }  
                //     if (cond && !fragment) fragment = <>...</>
                //   </>
                //   {...(cond ? fragment : [])}
                // </>
                //
                // the spread should be gated based on the transition rather than called constantly
                // likewise, the fragment is not a normal array fragment, it contains all of the static nodes
                // so that slots are inserted as their bare anchors
                // the deferred update then finalizes the update
                //
                // multiple branches would share a single {...} slot (and thus the same #run as well)

                const if_children_start = getPackedData(child_info.node_ptr).right;
                const if_cond = getPackedData(child_info.node_ptr).left;
                try self.visit(self.nodes.at(if_cond), if_cond);

                var else_children_start: NodeRef = 0;
                if (child_info.node_ptr.next != 0) {
                    const maybe_else = self.nodes.at(child_info.node_ptr.next);
                    if (maybe_else.kind == .jsx_else_directive) {
                        else_children_start = getPackedData(maybe_else).right;
                    }
                }

                var if_body = std.ArrayList(NodeRef).init(getAllocator());
                defer if_body.deinit();
                var else_body = std.ArrayList(NodeRef).init(getAllocator());
                defer else_body.deinit();

                var if_had_update = false;
                var else_had_update = false;

                const if_exp = try self.inlineInternalArrayChildren(state, child_info.node_ref, if_children_start, &if_body, &if_had_update);

                const else_exp = if (else_children_start != 0)
                    try self.inlineInternalArrayChildren(state, child_info.node_ptr.next, else_children_start, &else_body, &else_had_update)
                else
                    try self.factory.createArrayLiteralExpression(0);

                const cond_var_name = try state.nextName();
                try upd_body.append(try self.factory.createConstVariable(
                    try self.factory.createIdentifier(cond_var_name), try self.normalizeExpToBoolean(if_cond)));

                const then_block = try self.factory.createBlock(if_body.items);
                const else_block = if (else_body.items.len > 0) try self.factory.createBlock(else_body.items) else 0;

                try self.coalesceVariableStatements(self.nodes.at(then_block));
                if (else_block != 0) try self.coalesceVariableStatements(self.nodes.at(else_block));

                try upd_body.append(try self.factory.createIfStatement(
                    try self.factory.createIdentifier(cond_var_name),
                    then_block,
                    else_block,
                ));

                const res = try self.factory.createConditionalExpression(
                try self.factory.createIdentifier(cond_var_name),
                if_exp,
                else_exp);

                var res_exp: NodeRef = res;
                if (if_had_update and else_had_update) {
                    const res_name = state.maybeReuseName() orelse try state.nextName();
                    try upd_body.append(try self.factory.createConstVariable(try self.factory.createIdentifier(res_name), res));
                    res_exp = try self.factory.createIdentifier(res_name);
                }

                var final_upd_call: NodeRef = 0;
                if (if_had_update and else_had_update) {
                    final_upd_call = try self.factory.createExpressionStatement(
                        try self.factory.createCallExpression(
                            try self.accessUpdateSymbolDirect(res_exp), &.{})
                    );
                    // self.nodes.at(final_upd_call).flags |= @intFromEnum(NodeFlags.optional);
                } else if (if_had_update) {
                    const u = try self.factory.createExpressionStatement(
                        try self.factory.createCallExpression(try self.accessUpdateSymbolDirect(if_exp), &.{}));
                    final_upd_call = try self.factory.createIfStatement(
                        try self.factory.createIdentifier(cond_var_name), u, 0);
                } else if (else_had_update) {
                    const u = try self.factory.createExpressionStatement(
                        try self.factory.createCallExpression(try self.accessUpdateSymbolDirect(else_exp), &.{}));
                    final_upd_call = try self.factory.createIfStatement(
                        try self.factory.createPrefixUnaryExpression(.exclamation_token, try self.factory.createIdentifier(cond_var_name)), u, 0);
                }

                if (child_info.len_var != 0) {
                    if (final_upd_call != 0) try upd_body.append(final_upd_call);
                }

                const if_branch_count = if (child_info.len_var != 0) self.jsxStableArrayLength(if_children_start) else null;
                const else_branch_count = if (if_branch_count != null and else_children_start != 0) self.jsxStableArrayLength(else_children_start) else null;
                const can_emit_direct_assign = if_branch_count != null and else_branch_count != null and if_branch_count.? == else_branch_count.?;
                const can_emit_splice_assign = if_branch_count != null and (else_branch_count != null or else_children_start == 0);

                const set_slot_call = blk: {
                    if (child_info.len_var != 0) {
                        if (can_emit_direct_assign) break :blk 0;
                        break :blk try self.createSpliceAtStatement(
                            state.offset_counter_name, 
                            child_info.len_var, 
                            state.children_exp, 
                            res_exp, 
                            child_info.static_pos
                        );
                    } else {
                        const fn_name = self.requireHelper(.swap_tree);
                        const set_slot_args = &.{
                            try self.factory.createIdentifier(child_info.nav_name),
                            try self.factory.createIdentifier(child_info.ph_name),
                            res_exp,
                            try self.factory.createConditionalExpression(
                                try self.factory.createIdentifier(cond_var_name),
                                else_exp,
                                if_exp)
                        };
                        const c = try self.factory.createCallExpression(
                            try self.factory.createIdentifier(fn_name), set_slot_args);
                        break :blk try self.factory.createExpressionStatement(c);

                        // const fn_name = self.requireHelper(.set_slot_spread);
                        // const set_slot_args = &.{
                        //     try self.factory.createIdentifier(child_info.nav_name),
                        //     try self.factory.createIdentifier(child_info.ph_name),
                        //     res_exp,
                        // };
                        // const c = try self.factory.createCallExpression(
                        //     try self.factory.createIdentifier(fn_name), set_slot_args);
                        // break :blk try self.factory.createExpressionStatement(c);
                    }
                };

                if (can_emit_splice_assign and !can_emit_direct_assign) {
                    const delta: i64 = @as(i64, if_branch_count.?) - (else_branch_count orelse 0);
                    const min = @min(if_branch_count.?, else_branch_count orelse 0);
                    if (min != 0) {
                        if (self.nodes.at(res_exp).kind != .identifier) {
                            const res_name = state.maybeReuseName() orelse try state.nextName();
                            try upd_body.append(try self.factory.createConstVariable(try self.factory.createIdentifier(res_name), res));
                            res_exp = try self.factory.createIdentifier(res_name);
                        }
                        if (min == 1) {
                            const access = try self.factory.createElementAccessExpression(res_exp, try self.factory.createNumericLiteral(@as(i64, 0)));
                            const assign = try self.factory.createAssignmentStatement(
                                try self.factory.createElementAccessExpression(state.children_exp, 
                                try self.factory.createNumericLiteral(child_info.static_pos)
                                ),
                                access
                            );
                            try upd_body.append(assign);
                        } else {
                            const inc_name = try state.nextName();
                            try upd_body.append(try self.factory.createLetVariable(try self.factory.createIdentifier(inc_name), try self.factory.createNumericLiteral(@as(i64, -1)))); 
                            const end = try self.factory.createNumericLiteral(@as(i64, min));
                            const cmp = try self.factory.createBinaryExpression(
                                try self.factory.createPrefixUnaryExpression(.plus_plus_token, try self.factory.createIdentifier(inc_name)), .less_than_token, end);
                            const access = try self.factory.createElementAccessExpression(res_exp, try self.factory.createIdentifier(inc_name));
                            const assign = try self.factory.createAssignmentStatement(
                                try self.factory.createElementAccessExpression(state.children_exp, 
                                    if (child_info.static_pos == 0)
                                        try self.factory.createIdentifier(inc_name)
                                    else 
                                        try self.factory.createBinaryExpression(
                                            try self.factory.createNumericLiteral(child_info.static_pos),
                                            .plus_token,
                                            try self.factory.createIdentifier(inc_name)
                                        )
                                ),
                                access
                            );
                            try upd_body.append(try self.factory.createWhileStatement(
                                cmp,
                                assign,
                            ));
                        }
                    }
                    const state_var_name = try state.nextName();
                    const state_ident = try self.factory.createIdentifier(state_var_name);
                    try state.addStmt(try self.factory.createLetVariable(state_ident, 0));
                    if (else_branch_count != null) {
                        var args = std.ArrayList(NodeRef).init(getAllocator());
                        defer args.deinit();
                        try args.append(try self.factory.createNumericLiteral(min+child_info.static_pos));
                        if (delta > 0) {
                            try args.append(try self.factory.createNumericLiteral(delta));
                        } else {
                            try args.append(try self.factory.createNumericLiteral(@as(i64, 0)));
                            var i: i64 = 0;
                            while (i < -delta) {
                                try args.append(try self.factory.createElementAccessExpression(
                                    else_exp,
                                    try self.factory.createNumericLiteral(min+i),
                                ));
                                i += 1;
                            }
                        }
                        try upd_body.append(
                            try self.factory.createIfStatement(
                                try self.factory.createBinaryExpression(
                                    try self.factory.createBinaryExpression(state_ident, .equals_equals_equals_token, try self.factory.createTrue()),
                                    .ampersand_ampersand_token,
                                    try self.factory.createPrefixUnaryExpression(.exclamation_token, try self.factory.createIdentifier(cond_var_name))
                                ),
                              try self.factory.createExpressionStatement(
                                try self.factory.createCallExpression(
                                    try self.factory.createPropertyAccessExpression(
                                        state.children_exp, "splice"),
                                    try self.factory.createList(args.items),
                                ), 
                              ), 0
                            )
                        );
                    }
                    {
                        var args = std.ArrayList(NodeRef).init(getAllocator());
                        defer args.deinit();
                        try args.append(try self.factory.createNumericLiteral(min+child_info.static_pos));
                        if (delta < 0) {
                            try args.append(try self.factory.createNumericLiteral(-delta));
                        } else {
                            try args.append(try self.factory.createNumericLiteral(@as(i64, 0)));
                            var i: i64 = 0;
                            while (i < delta) {
                                try args.append(try self.factory.createElementAccessExpression(
                                    if_exp,
                                    try self.factory.createNumericLiteral(min+i),
                                ));
                                i += 1;
                            }
                        }
                        try upd_body.append(
                            try self.factory.createIfStatement(
                                try self.factory.createBinaryExpression(
                                    try self.factory.createBinaryExpression(state_ident, .equals_equals_equals_token, try self.factory.createFalse()),
                                    .ampersand_ampersand_token,
                                    try self.factory.createIdentifier(cond_var_name),
                                ),
                              try self.factory.createExpressionStatement(
                                try self.factory.createCallExpression(
                                    try self.factory.createPropertyAccessExpression(
                                        state.children_exp, "splice"),
                                    try self.factory.createList(args.items),
                                )
                              ), 0
                            )
                        );
                    }
                    try upd_body.append(try self.factory.createAssignmentStatement(state_ident, try self.factory.createIdentifier(cond_var_name)));
                    return;
                }

                if (can_emit_direct_assign) {
                    if (if_branch_count.? == 1) {
                        const access = try self.factory.createElementAccessExpression(
                            try self.factory.createParenthesizedExpression(res_exp),
                                try self.factory.createNumericLiteral(@as(i64, 0))
                        );
                        const assign = try self.factory.createAssignmentStatement(
                            try self.factory.createElementAccessExpression(state.children_exp, 
                                try self.factory.createNumericLiteral(child_info.static_pos)
                            ),
                            access
                        );
                        try upd_body.append(assign);
                        return;
                    }
                    if (if_branch_count.? == 0) return;
                    if (self.nodes.at(res_exp).kind != .identifier) {
                        const res_name = state.maybeReuseName() orelse try state.nextName();
                        try upd_body.append(try self.factory.createConstVariable(try self.factory.createIdentifier(res_name), res));
                        res_exp = try self.factory.createIdentifier(res_name);
                    }
                    const inc_name = try state.nextName();
                    try upd_body.append(try self.factory.createLetVariable(try self.factory.createIdentifier(inc_name), try self.factory.createNumericLiteral(@as(i64, -1)))); 
                    const end = try self.factory.createNumericLiteral(@as(i64, if_branch_count.?));
                    const cmp = try self.factory.createBinaryExpression(
                        try self.factory.createPrefixUnaryExpression(.plus_plus_token, try self.factory.createIdentifier(inc_name)), .less_than_token, end);
                    const access = try self.factory.createElementAccessExpression(res_exp, try self.factory.createIdentifier(inc_name));
                    const assign = try self.factory.createAssignmentStatement(
                        try self.factory.createElementAccessExpression(state.children_exp, 
                            if (child_info.static_pos == 0)
                                try self.factory.createIdentifier(inc_name)
                            else 
                                try self.factory.createBinaryExpression(
                                    try self.factory.createNumericLiteral(child_info.static_pos),
                                    .plus_token,
                                    try self.factory.createIdentifier(inc_name)
                                )
                        ),
                        access
                    );
                    try upd_body.append(try self.factory.createWhileStatement(
                        cmp,
                        assign,
                    ));

                    return;
                }

                if (child_info.len_var == 0) {
                    const state_var_name = try state.nextName();
                    const state_ident = try self.factory.createIdentifier(state_var_name);
                    try state.addStmt(try self.factory.createLetVariable(state_ident, 0));

                    try upd_body.append(try self.factory.createIfStatement(
                        try self.factory.createBinaryExpression(try self.factory.createIdentifier(cond_var_name), .exclamation_equals_equals_token, state_ident), 
                        set_slot_call, 0));
                    try upd_body.append(try self.factory.createAssignmentStatement(state_ident, try self.factory.createIdentifier(cond_var_name)));
                    if (final_upd_call != 0) try upd_body.append(final_upd_call);
                } else {
                    try upd_body.append(set_slot_call);
                }
            }

            fn emitCallerCompProtocol(
                self: *@This(), 
                state: *InlineEmitState, 
                info: *TreeNodeInfo,
                upd_body: ?*std.ArrayList(NodeRef),
            ) !void {
                const n = self.nodes.at(info.node_ref);
                std.debug.assert(n.kind == .jsx_element or n.kind == .jsx_self_closing_element);
                const tag_ref = self.getJsxTagRef(n);
                std.debug.assert(!self.isIntrinsicTag(tag_ref));
                const opening_ref = if (n.kind == .jsx_element) unwrapRef(n) else info.node_ref;
                const opening = self.nodes.at(opening_ref);
                const attrs = getPackedData(opening).right;
                var static_props_members = std.ArrayList(NodeRef).init(getAllocator());
                defer static_props_members.deinit();
                var has_children_like = false;
                var has_update_code = false;
                const can_inline_children = blk: {
                    if (n.kind != .jsx_element) break :blk false;
                    var dynamic = false;
                    var iter = NodeIterator.init(self.nodes, opening_ref);
                    while (iter.nextRef()) |r| {
                        const c = self.nodes.at(r);
                        switch (c.kind) {
                            .jsx_element, .jsx_self_closing_element => {
                                if (dynamic) continue;
                                has_children_like = true;
                                // for simplicity, we won't inline if any code exists as a child
                                if (!self.isIntrinsicTag(self.getJsxTagRef(c))) dynamic = true
                                else if (self.inlineNodeHasDynamic(c)) dynamic = true;
                            },
                            .jsx_expression => {
                                dynamic = true;
                                has_children_like = true;  
                            },
                            .jsx_text => {
                                if (!self.isJsxTextAllWhitespace(c)) {
                                    has_children_like = true;
                                }
                            },
                            .jsx_if_directive, .jsx_fragment => {
                                // just assume in these cases (come back to this later for opt)
                                dynamic = true;
                                has_children_like = true;  
                            },
                            .jsx_run_directive => {
                                has_update_code = true;
                            },
                            else => {},
                        }
                    }
                    break :blk !dynamic;
                };
                const can_inline_attrs = blk: {
                    if (attrs == 0) break :blk true;
                    var iter = NodeIterator.init(self.nodes, maybeUnwrapRef(self.nodes.at(attrs)) orelse 0);
                    while (iter.nextRef()) |r| {
                        const a = self.nodes.at(r);
                        if (a.kind != .jsx_attribute) break;
                        const d = getPackedData(a);
                        const name_ref = d.left; // quotes?
                        var val: NodeRef = undefined;
                        if (d.right == 0) {
                            val = try self.factory.createTrue();
                        } else {
                            const v = self.nodes.at(d.right);
                            if (v.kind == .jsx_expression) {
                                const inner = unwrapRef(v);
                                if (v.hasFlag(.static) or !self._dependsOnEffects(inner)) {
                                    val = inner;
                                } else {
                                    break :blk false;
                                }
                            } else {
                                val = d.right;
                            }
                        }
                        try static_props_members.append(
                            try self.factory.createPropertyAssignment(
                            name_ref,
                            val,
                        ));
                    }
                    break :blk true;
                };

                // the general form is roughly as follows, with the top level being static:
                // 
                // const _v0 = {} // set any static attributes here if possible (we must preserve order)
                // const _v3 = [] // set any static children here if possible, same as above
                // let el, _v1 
                // function _v2() {
                //   // ...update attributes via _v0
                //   if (!el) {
                //     el = Comp(_v0, _v3)
                //     _v1 = el[Symbol.update]
                //     el[Symbol.update] = _v2
                //   }
                //   // ...update children via _v3
                //   _v1?.()
                //   if (ph) ph = void ph.replaceWith(el.root)
                //   // TODO `ph` can be released to upd at this point but subsequent usages need to always end w/ falsy value and release
                // }
                //
                // we do emit `_v2` if the comp instance cannot be directly updated
                // the logic is emitted inline into upd_body instead
                //
                // the main difference between variants is the "ph" line
                // only comps with DOM insertions use ph
                // comps apart of fragments would use something like `_v4[index] = el.root`
                // and spread comps with DOM would use `el.root._sc?.(ph) ?? __slot_s(ph, el.root, ph2)`

                // `nav_name` is really `ph_name` here :(
                // so `ph_name` is `el_name`
                if (info.ph_name.len == 0) {
                    if (self.inlineMaybeGetElementBinding(n)) |x| {
                        info.ph_name = getSlice(self.nodes.at(x), u8);
                    } else {
                        info.ph_name = try state.nextName(); // LEAK
                    }
                    try state.addStmt(try self.factory.createLetVariable(try self.factory.createIdentifier(info.ph_name), 0));
                }
                const el_name = info.ph_name;
                const ph_name = info.nav_name;

                var props_name: ?[]const u8 = null;
                if (!can_inline_attrs) {
                    props_name = try state.nextName();
                    try state.addStmt(try self.factory.createConstVariable(try self.factory.createIdentifier(props_name.?), try self.factory.createObjectLiteralExpression(0)));
                }

                var children_name: ?[]const u8 = null;
                var children_init_ref: NodeRef = 0;
                if (n.kind == .jsx_element and has_children_like and !can_inline_children) {
                    children_name = try state.nextName();
                    children_init_ref = try self.factory.createArrayLiteralExpression(0);
                    try state.addStmt(try self.factory.createConstVariable(try self.factory.createIdentifier(children_name.?), children_init_ref));
                }

                const props_exp = if (props_name) |p| try self.factory.createIdentifier(p) else blk: {
                    // this is only for the direct call case!
                    if (static_props_members.items.len == 0) {
                        if (has_children_like) {
                            break :blk try self.factory.createVoidZero();
                        }
                        break :blk 0;
                    }
                    break :blk try self.factory.createObjectLiteralExpression(static_props_members.items);
                };

                const children_exp = if (children_name) |t| try self.factory.createIdentifier(t) else blk: {
                    if (!has_children_like) break :blk null;
                    children_init_ref = try self.factory.createArrayLiteralExpression(0);
                    break :blk children_init_ref;
                };

                var fn_ident: NodeRef = 0;
                var snapshot_ident: NodeRef = 0;
                var fn_upd_body = std.ArrayList(NodeRef).init(getAllocator());
                defer fn_upd_body.deinit();
                var upd_dest: *std.ArrayList(NodeRef) = if (upd_body) |x| x else &fn_upd_body;

                const should_decorate = !can_inline_attrs;
                // emit a decorator instead of inline
                // TODO: unlike intrinsics, a named comp instance can be proven to not need a decorator via escape analysis
                if ((info.parent_ref == 0 and should_decorate and state.current_component_decl == 0) or self.inlineMaybeGetElementBinding(n) != null) {
                    snapshot_ident = try self.factory.createIdentifier(try state.nextName());
                    try state.addStmt(try self.factory.createLetVariable(snapshot_ident, 0));
                    fn_ident = try self.factory.createIdentifier(try state.nextName());
                    upd_dest = &fn_upd_body;
                }

                if (props_name) |x| {
                    const t = self.nodes.at(tag_ref);
                    const tag = if (t.kind == .identifier) getSlice(t, u8) else ""; // TODO: namespaced tags
                    try self.inlineProcessAttrs(state, upd_dest, x, tag, attrs);
                }

                const el_ident = try self.factory.createIdentifier(el_name);
                const comp_call = blk: {
                    if (children_exp) |ch| {
                        std.debug.assert(props_exp != 0);
                        break :blk try self.factory.createCallExpression(tag_ref, &.{props_exp, ch});
                    }
                    if (props_exp != 0) {
                        break :blk try self.factory.createCallExpression(tag_ref, &.{props_exp});
                    } else {
                        break :blk try self.factory.createCallExpression(tag_ref, &.{});
                    }
                };

                if (snapshot_ident == 0) {
                    const op: SyntaxKind = if (upd_body == null and fn_ident == 0) .equals_token else .question_question_equals_token;
                    try upd_dest.append(try self.factory.createExpressionStatement(
                        try self.factory.createBinaryExpression(el_ident, op, comp_call)
                    ));
                } else {
                    var body = std.ArrayList(NodeRef).init(getAllocator());
                    defer body.deinit();
                    try body.append(try self.factory.createAssignmentStatement(el_ident, comp_call));
                    if (snapshot_ident != 0) {
                        std.debug.assert(fn_ident != 0);
                        try body.append(try self.factory.createAssignmentStatement(snapshot_ident, try self.accessUpdateSymbolDirect(el_ident)));
                        try body.append(try self.factory.createAssignmentStatement(try self.accessUpdateSymbolDirect(el_ident), fn_ident));  
                    }

                    const cond = try self.factory.createPrefixUnaryExpression(.exclamation_token, el_ident);
                    try upd_dest.append(try self.factory.createIfStatement(cond, try self.factory.createBlock(body.items), 0));
                }

                if (children_name) |x| {
                    const save_skip_attributes = state.skip_attributes;
                    defer state.skip_attributes = save_skip_attributes;
                    state.skip_attributes = true;
                    const save_children_ref = state.children_init_ref;
                    defer state.children_init_ref = save_children_ref;
                    state.children_init_ref = children_init_ref;
                    _ = try self.inlineProcessElement2(state, x, info.node_ref, upd_dest);
                }

                if (snapshot_ident != 0) {
                    const call_exp = try self.factory.createCallExpression(snapshot_ident, &.{});
                    self.nodes.at(call_exp).flags |= @intFromEnum(NodeFlags.optional);
                    try upd_dest.append(try self.factory.createExpressionStatement(call_exp));
                }

                var insertion_statement: NodeRef = 0;
                const inside_component_decl = info.parent_ref != 0 and self.nodes.at(info.parent_ref).kind == .jsx_component;
                const is_dom_insertion = !inside_component_decl;
                if (ph_name.len != 0 and is_dom_insertion) {
                    const p = try self.factory.createIdentifier(ph_name);
                    insertion_statement = try self.factory.createIfStatement(
                        p,
                        try self.factory.createAssignmentStatement(p, try self.factory.nodes.push(.{
                            .kind = .void_expression,
                            .data = @ptrFromInt(try self.factory.createCallExpression(try self.factory.createPropertyAccessExpression(p, "replaceWith"), &.{try self.factory.createPropertyAccessExpression(el_ident, "root")}))
                        })),
                        0);
                } else if (inside_component_decl and !self.nodes.at(info.parent_ref).hasFlag(.generator)) {
                    insertion_statement = try self.factory.createExpressionStatement(try self.factory.createBinaryExpression(
                        try self.factory.createPropertyAccessExpression(try self.factory.createIdentifier("__ret"), "root"),
                        .question_question_equals_token,
                       try self.factory.createPropertyAccessExpression(el_ident, "root"),
                    ));
                }

                if (fn_ident != 0) {
                    if (insertion_statement != 0) try upd_dest.append(insertion_statement);
                    const decl = try self.factory.createFunctionDeclaration(fn_ident, 0, try self.factory.createBlock(upd_dest.items));
                    try state.addStmt(decl);
                    const call_stmt = try self.factory.createExpressionStatement(
                        try self.factory.createCallExpression(fn_ident, &.{})
                    );
                    if (upd_body) |m| {
                        try m.append(call_stmt);
                    } else {
                        try state.addStmt(call_stmt);
                    }
                } else {
                    const call_stmt = try self.factory.createExpressionStatement(
                        try self.factory.createCallExpression(try self.accessUpdateSymbolDirect(el_ident), &.{})
                    );
                    try upd_dest.append(call_stmt);
                    if (insertion_statement != 0) try upd_dest.append(insertion_statement);
                }

                if (upd_body == null and fn_ident == 0) {
                    try state.stmts.appendSlice(fn_upd_body.items);
                }
            }

            fn inlineSetupJsxRoot(self: *@This(), state: *InlineEmitState, ref: NodeRef, binding_name: []const u8) !NodeRef {
                const save_emit_state = self.jsx_emit_state;
                self.jsx_emit_state = state;
                defer self.jsx_emit_state = save_emit_state;
                
                const n = self.nodes.at(ref);
                const is_fragment_like = self.isFragmentLike(n);
                if (is_fragment_like) state.ctx = .templated
                else if (!self.isIntrinsicTag(self.getJsxTagRef(n))) state.ctx = .component;
                if (comptime callee_creates_comp_instance) {
                    if (n.kind != .jsx_component and !self.isIntrinsicTag(self.getJsxTagRef(n))) {
                        var info = TreeNodeInfo{
                            .kind = .component_instance,
                            .node_ptr = n,
                            .node_ref = ref,
                            .ph_name = binding_name,
                        };
                        try self.emitCallerCompProtocol(state, &info, null);
                        try self.emitStaticGateInit(state);
                        return 0;
                    }
                }
                const element_expr = try self.createHtmlTemplate(ref);
                if (state.ctx == .component) try self.maybeEmitCompAttr(state, binding_name, n);
                if (comptime callee_creates_comp_instance) {
                    if (n.kind == .jsx_component) {
                        var upd_body = std.ArrayList(NodeRef).init(getAllocator());
                        defer upd_body.deinit();
                        var public_idents = std.ArrayList(struct {NodeRef, ?NodeRef}).init(getAllocator());
                        defer public_idents.deinit();
                        const block = self.nodes.at(getPackedData(n).left).len;
                        const body_start = maybeUnwrapRef(self.nodes.at(block)) orelse 0;
                        var body_iter = NodeIterator.init(self.nodes, body_start);
                        while (body_iter.nextRef()) |r| {
                            const s = self.nodes.at(r);
                            if (s.hasFlag(.declare)) continue;
                            if (s.hasFlag(.public)) {
                                switch (s.kind) {
                                    .function_declaration, .class_declaration => {
                                        try public_idents.append(.{getPackedData(s).left, null});
                                    },
                                    .public_declaration => {
                                        var iter = NodeIterator.init(self.nodes, maybeUnwrapRef(s) orelse 0);
                                        while (iter.nextRef()) |b| {
                                            const spec = self.nodes.at(b);
                                            if (spec.hasFlag(.declare)) continue;
                                            const z = getPackedData(spec);
                                            try public_idents.append(.{z.left, if (z.right == 0) null else z.right});
                                        }
                                    },
                                    else => {},
                                }
                            }
                        }
                        const root_expr = blk: {
                            const r = try self.getSingleRootFromCompDecl(n);
                            if (self.isIntrinsicTag(self.getJsxTagRef(self.nodes.at(r)))) break :blk try self.factory.createIdentifier(binding_name);
                            break :blk 0;
                        };
                        _ = try self.inlineProcessElement2(state, binding_name, ref, &upd_body);
                        try state.addStmt(try self.factory.createAssignmentStatement(
                            try self.factory.createIdentifier(binding_name),
                            try self.createComponentInstanceObject(root_expr, upd_body.items, public_idents.items),
                        ));
                        try self.emitStaticGateInit(state);
                        return element_expr;
                    }
                }
                const had_update = try self.inlineProcessElement(state, binding_name, n, null);
                if (had_update and state.stmts.items.len > 0) {
                    // creates an IIFE from the trailing Symbol.update assignment
                    const last_ref = state.stmts.getLast();
                    const last = self.nodes.at(last_ref);
                    const inner_ref = unwrapRef(last);
                    const inner = self.nodes.at(inner_ref);
                    if (last.kind == .expression_statement and
                        inner.kind == .binary_expression and
                        inner.len == @intFromEnum(SyntaxKind.equals_token) and
                        self.nodes.at(getPackedData(inner).left).kind == .element_access_expression)
                    {
                        const call = try self.factory.createCallExpression(
                            try self.factory.createParenthesizedExpression(inner_ref), &.{});
                        state.stmts.items[state.stmts.items.len - 1] =
                            try self.factory.createExpressionStatement(call);
                    } else {
                        try state.addStmt(try self.inlineCallSymbolUpdate(binding_name));
                    }
                }
                try self.emitStaticGateInit(state);
                return element_expr;
            }

            fn createInlineJsx(self: *@This(), ref: NodeRef) !NodeRef {
                const n = self.nodes.at(ref);
                var state = InlineEmitState{
                    .counter = 0,
                    .stmts = std.ArrayList(NodeRef).init(getAllocator()),
                };
                defer state.deinit();

                const root_name = if (self.inlineMaybeGetElementBinding(n)) |x|
                    getSlice(self.nodes.at(x), u8)
                else try state.nextName();
                const element_expr = try self.inlineSetupJsxRoot(&state, ref, root_name);

                if (state.stmts.items.len == 0) {
                    if (n.next != 0 and element_expr != 0) {
                        self.nodes.at(element_expr).next = n.next;
                    }
                    return element_expr;
                }

                var body_stmts = std.ArrayList(NodeRef).init(getAllocator());
                defer body_stmts.deinit();
                if (self.isFragmentLike(n) or (callee_creates_comp_instance and !self.isIntrinsicTag(self.getJsxTagRef(n)))) {
                    // we use `let` so we can change the binding after nav
                    try body_stmts.append(try self.factory.createLetVariable(
                        try self.factory.createIdentifier(root_name), element_expr));
                } else {
                    try body_stmts.append(try self.factory.createConstVariable(
                        try self.factory.createIdentifier(root_name), element_expr));
                }
                try body_stmts.appendSlice(state.stmts.items);
                try body_stmts.append(try self.factory.createReturnStatement(
                    try self.factory.createIdentifier(root_name)));

                const body = try self.factory.createBlock(body_stmts.items);
                try self.coalesceVariableStatements(self.nodes.at(body));
                const arrow = try self.factory.createArrowFunction(0, body, 0);
                const res = try self.factory.createCallExpression(
                    try self.factory.createParenthesizedExpression(arrow), &.{});
                if (n.next != 0) {
                    self.nodes.at(res).next = n.next;
                }
                return res;
            }

            fn createComponentInstanceObject(
                self: *@This(),
                root_expr: NodeRef,
                upd_stmts: []const NodeRef,
                public_idents: []const struct {NodeRef, ?NodeRef},
            ) !NodeRef {
                var props = std.ArrayList(NodeRef).init(getAllocator());
                defer props.deinit();

                const root_val = if (root_expr != 0) root_expr else try self.factory.createNull();
                if (self.nodes.at(root_val).kind == .identifier and strings.eqlComptime(getSlice(self.nodes.at(root_val), u8), "root")) {
                    try props.append(try self.factory.createShorthandPropertyAssignment(root_val));
                } else {
                    const root_prop = try self.factory.createPropertyAssignment(
                        try self.factory.createIdentifier("root"),
                        root_val);
                    try props.append(root_prop);
                }

                const sym_name = try self.factory.createIdentifier(self.requireHelper(.update_symbol));
                const computed_key = try self.factory.nodes.push(.{
                    .kind = .computed_property_name,
                    .data = @ptrFromInt(sym_name),
                });
                const upd_body = try self.factory.createBlock(upd_stmts);
                try self.coalesceVariableStatements(self.nodes.at(upd_body));
                const upd = try self.factory.createArrowFunction(0, upd_body, 0);
                try props.append(try self.factory.createPropertyAssignment(computed_key, upd));

                for (public_idents) |pair| {
                    if (pair[1]) |alias| {
                        try props.append(try self.factory.createPropertyAssignment(alias, pair[0]));
                    } else {
                        try props.append(try self.factory.createShorthandPropertyAssignment(pair[0]));
                    }
                }

                return self.factory.createObjectLiteralExpression(props.items);
            }

            fn createInlineJsxBlock(
                self: *@This(),
                ref: NodeRef,
                binding_name: []const u8,
            ) !struct { element_expr: NodeRef, setup_block: NodeRef } {
                const n = self.nodes.at(ref);
                var state = InlineEmitState{
                    .counter = 0,
                    .stmts = std.ArrayList(NodeRef).init(getAllocator()),
                };
                state.current_node_ref = ref; // XXX
                defer state.deinit();

                var should_set_counter = false;
                defer if (should_set_counter) {
                    if (self.jsx_emit_state) |s| s.counter = state.counter;
                };

                const symbol_replacer = if (self.jsx_emit_state != null and self.jsx_emit_state.?.bridged_declarations != null)
                    try ScopedSymbolReplacer.init(&self.symbol_replacements, self.jsx_emit_state.?.bridged_declarations.?)
                else null;
                defer if (symbol_replacer) |r| r.deinit();

                // we want to propagate forward a bit of shared state when recursing into nested components
                if (self.jsx_emit_state) |s| {
                    state.counter = s.counter;
                    if (s.bridged_declarations == null) {
                        s.bridged_declarations = try getAllocator().create(std.AutoHashMapUnmanaged(SymbolRef, NodeRef));
                        s.bridged_declarations.?.* = .{};
                    }
                    state.borrowed_bridged_declarations = true;
                    state.bridged_declarations = s.bridged_declarations;
                    should_set_counter = true;
                    state.consumer_getters = try s.consumer_getters.clone(getAllocator());
                    state.consumer_setters = try s.consumer_setters.clone(getAllocator());
                    state.current_component_decl = s.current_component_decl;
                    state.tree_classification = s.tree_classification;
                }

                if (state.current_component_decl == 0 and n.kind == .jsx_component) {
                    state.current_component_decl = ref;
                }

                const element_expr = try self.inlineSetupJsxRoot(&state, ref, binding_name);

                const setup_block: NodeRef = if (state.stmts.items.len > 0)
                    try self.factory.createBlock(state.stmts.items)
                else
                    0;
                if (setup_block != 0) {
                    try self.coalesceVariableStatements(self.nodes.at(setup_block));
                }
                return .{ .element_expr = element_expr, .setup_block = setup_block };
            }

            const callee_creates_comp_instance = true; // FIXME: remove

            fn getSingleRootFromCompDecl(self: *@This(), n: *const AstNode) !NodeRef {
                var root_ref: NodeRef = 0;
                var iter = NodeIterator.init(self.nodes, getPackedData(n).right);
                while (iter.nextRef()) |r| {
                    const c = self.nodes.at(r);
                    switch (c.kind) {
                        .jsx_element, .jsx_self_closing_element => {
                            if (root_ref != 0) {
                                // FIXME: emit diagnostic!
                                return error.StandardCompWithMultipleRoots;
                            }
                            if (c.hasFlag(.generator)) {
                                // same as before!
                                return error.StandardCompWithoutStableRoot;
                            }
                            root_ref = r;
                        },
                        else => {},
                    }
                }
                if (root_ref == 0) {
                    // FIXME: emit diagnostic...
                    return error.StandardCompWithNoRoot;
                }
                return root_ref;
            }

            fn visitJsxCompDeclaration(self: *@This(), state: *InlineEmitState, info: *TreeNodeInfo) !NodeRef {
                const save_emit_state = self.jsx_emit_state;
                self.jsx_emit_state = state;
                defer self.jsx_emit_state = save_emit_state;
                const save_comp_ref = state.current_component_decl;
                defer state.current_component_decl = save_comp_ref;
                state.current_component_decl = info.node_ref;
                return try self.transformJsxComponent(info.node_ref);
            }

            fn transformJsxComponent(self: *@This(), ref: NodeRef) !NodeRef {
                const n = self.nodes.at(ref);
                const d = getPackedData(n);
                const fn_exp = self.nodes.at(d.left);
                const fn_d = getPackedData(fn_exp);

                const fn_name = fn_d.left;
                const params_head = fn_d.right;
                const original_body = fn_exp.len;
                const children_head = d.right;

                const is_spreadable_comp = n.hasFlag(.generator);

                var param_count: u32 = 0;
                var children_param_ref: NodeRef = 0;
                {
                    var it = NodeIterator.init(self.nodes, params_head);
                    while (it.nextRef()) |pr| {
                        param_count += 1;
                        // FIXME: ??? what is this nonsense. also: destructuring
                        const param = self.nodes.at(pr);
                        const param_name_ref = getPackedData(param).left;
                        const param_name_text = getSlice(self.nodes.at(param_name_ref), u8);
                        if (std.mem.eql(u8, param_name_text, "children")) {
                            children_param_ref = pr;
                            continue;
                        }
                        const props_access = try self.factory.createPropertyAccessExpression(
                            try self.factory.createIdentifier("attrs"), param_name_text);
                        if (self.file.binder.getSymbol(param_name_ref)) |sym_ref| {
                            try self.symbol_replacements.put(getAllocator(), sym_ref, props_access);
                        }
                    }
                }
                defer {
                    var it = NodeIterator.init(self.nodes, params_head);
                    while (it.nextRef()) |pr| {
                        const param = self.nodes.at(pr);
                        const param_name_ref = getPackedData(param).left;
                        if (self.file.binder.getSymbol(param_name_ref)) |sym_ref| {
                            _ = self.symbol_replacements.remove(sym_ref);
                        }
                    }
                }

                // FIXME: this should be inverted, mark when the comp _doesn't_ mutate/escape children
                // sets `_mc = 1`
                const children_mutates_or_escapes: bool = mc: {
                    var it = NodeIterator.init(self.nodes, params_head);
                    while (it.nextRef()) |pr| {
                        const param_name_ref = getPackedData(self.nodes.at(pr)).left;
                        const name_text = getSlice(self.nodes.at(param_name_ref), u8);
                        if (std.mem.eql(u8, name_text, "children")) {
                            var mutates = try self.childrenParamMutatesOrEscapes(param_name_ref, original_body);
                            if (!mutates) {
                                var iter = NodeIterator.init(self.nodes, children_head);
                                while (iter.nextRef()) |c| {
                                    mutates = try self.childrenParamMutatesOrEscapes(param_name_ref, c);
                                    if (mutates) break;
                                }
                            }
                            break :mc mutates;
                        }
                    }
                    break :mc false;
                };

                const orig_stmts_head = if (original_body != 0)
                    maybeUnwrapRef(self.nodes.at(original_body)) orelse 0
                else 0;
                if (orig_stmts_head != 0) {
                    var iter = NodeIterator.init(self.nodes, orig_stmts_head);
                    while (iter.nextRef()) |r| {
                        const s = self.nodes.at(r);
                        try self.visit(s, r);
                        if (comptime callee_creates_comp_instance) continue;

                        // "exports" public functions into the comp instance
                        if (s.kind == .function_declaration and s.hasFlag(.public)) {
                            const clone = try self.factory.cloneNode(s);
                            self.nodes.at(clone).flags &= ~@intFromEnum(NodeFlags.public);
                            const assign = try self.factory.createAssignmentStatement(
                                try self.factory.createPropertyAccessExpression(
                                    try self.factory.nodes.push(.{ .kind = .this_keyword }),
                                    getPackedData(s).left,
                                ),
                                getPackedData(s).left
                            );
                            self.nodes.at(assign).next = self.nodes.at(clone).next;
                            self.nodes.at(clone).next = assign;
                            try self.replacements.put(r, clone);
                        }
                    }
                }

                const children_res = blk: {
                    if (children_head == 0) {
                        break :blk try self.factory.createReturnStatement(try self.nodes.push(.{
                            .kind = .array_literal_expression,
                            .data = null,
                        }));
                    }
                    var root_ref: NodeRef = 0;
                    if (!is_spreadable_comp) {
                        root_ref = try self.getSingleRootFromCompDecl(n);
                    }
                    const children_head_node = self.nodes.at(children_head);
                    const is_single_element = !callee_creates_comp_instance and children_head_node.next == 0 and
                        (children_head_node.kind == .jsx_element or children_head_node.kind == .jsx_self_closing_element);
                    const target = if (is_single_element) children_head else ref;
                    var binding_name: []const u8 = "__ret";
                    var can_be_const = false;
                    if (!is_spreadable_comp) {
                        if (self.inlineMaybeGetElementBinding(self.nodes.at(root_ref))) |x| {
                            binding_name = getSlice(self.nodes.at(x), u8);
                        }
                        if (self.isIntrinsicTag(self.getJsxTagRef(self.nodes.at(root_ref)))) {
                            can_be_const = true;
                        }
                    }
                    const name = try self.factory.createIdentifier(binding_name);
                    const setup = try self.createInlineJsxBlock(target, binding_name);
                    const decl = if (can_be_const) 
                        try self.factory.createConstVariable(name, setup.element_expr)
                    else 
                        try self.factory.createLetVariable(name, setup.element_expr);
                    var ret: NodeRef = 0;
                    if (comptime callee_creates_comp_instance) {
                        // bleh
                        var t = unwrapRef(self.nodes.at(setup.setup_block));
                        var l = t;
                        while (true) {
                            const s = self.nodes.at(t);
                            if (s.next == 0) break;
                            l = t;
                            t = s.next;
                        }
                        self.nodes.at(l).next = 0;
                        // we expect a binary exp statement
                        if (can_be_const) {
                            const inner = self.nodes.at(unwrapRef(self.nodes.at(t)));
                            ret = try self.factory.createReturnStatement(getPackedData(inner).right);
                        } else {
                            ret = try self.factory.createReturnStatement(t);
                        }
                    } else {
                        ret = try self.factory.createReturnStatement(name);
                    }
                    const tail = if (children_mutates_or_escapes) t: {
                        if (!is_spreadable_comp) break :t ret;
                        const lhs = try self.factory.createPropertyAccessExpression(
                            try self.factory.createIdentifier(binding_name), "_mc");
                        const mc_stmt = try self.factory.createExpressionStatement(
                            try self.factory.createBinaryExpression(lhs, .equals_token, try self.factory.createNumericLiteral(@as(i64, 1))));
                        self.nodes.at(mc_stmt).next = ret;
                        break :t mc_stmt;
                    } else ret;
                    if (setup.setup_block != 0) {
                        var block_tail: NodeRef = 0;
                        var iter = NodeIterator.init(self.nodes, maybeUnwrapRef(self.nodes.at(setup.setup_block)) orelse 0);
                        const block_head = iter.ref;
                        while (iter.nextRef()) |r| block_tail = r;
                        self.nodes.at(block_tail).next = tail;
                        self.nodes.at(decl).next = block_head;
                    } else {
                        self.nodes.at(decl).next = tail;
                    }
                    break :blk decl;
                };

                var header = std.ArrayList(NodeRef).init(getAllocator());
                defer header.deinit();
                {
                    var params_iter = NodeIterator.init(self.nodes, params_head);
                    while (params_iter.nextRef()) |r| {
                        if (r == children_param_ref) continue;
                        const p = self.nodes.at(r);
                        if (p.hasFlag(.generator)) continue; // spread attr
                        const q = getPackedData(p);
                        const p_init = q.right;
                        if (p_init == 0) continue;
                        const l = self.nodes.at(q.left);
                        if (l.kind != .identifier) continue;
                        const attrs_access = try self.factory.createPropertyAccessExpression(
                            try self.factory.createIdentifier("attrs"), q.left);
                        const check = try self.factory.createPrefixUnaryExpression(
                            .exclamation_token, try self.factory.createParenthesizedExpression(try self.factory.createBinaryExpression(
                                try self.factory.createStringLiteralAllocated(getSlice(l, u8)), .in_keyword, try self.factory.createIdentifier("attrs"))));
                        // TODO: optimizing based on declared types seems reasonable here
                        // the current behavior is _technically_ inconsistent with how fn args are dealt with (`undefined` uses the default init)
                        try header.append(
                            try self.factory.createIfStatement(check, try self.factory.createAssignmentStatement(attrs_access, p_init), 0)
                        );
                        const len = header.items.len;
                        if (len > 1) {
                            self.nodes.at(header.items[len-2]).next = header.items[len-1];
                        }
                        self.nodes.at(header.getLast()).next = orig_stmts_head;
                    }
                }

                var body_head = header.getLastOrNull() orelse orig_stmts_head;
 
                var body_tail: NodeRef = 0;
                if (orig_stmts_head != 0) {
                    var it = NodeIterator.init(self.nodes, orig_stmts_head);
                    while (it.nextRef()) |sr| body_tail = sr;
                    if (body_tail != 0) {
                        var cur = self.replacements.get(body_tail) orelse body_tail;
                        while (self.nodes.at(cur).next != 0) cur = self.nodes.at(cur).next;
                        body_tail = cur;
                    }
                }
                if (body_tail != 0) { self.nodes.at(body_tail).next = children_res; } else { body_head = children_res; }

                const body_block = try self.nodes.push(.{
                    .kind = .block,
                    .data = if (body_head != 0) @ptrFromInt(body_head) else null,
                });
                const props_param: NodeRef = if (params_head == 0) 0 else blk: {
                    if (param_count == 1 and children_param_ref != 0) {
                        // TODO: avoid shadowing
                        break :blk try self.factory.createParameter(try self.factory.createIdentifier("_attrs"), 0);
                    }

                    // emit `attrs = {}` if every param is optional or has an initializer
                    const all_optional = opt: {
                        var it = NodeIterator.init(self.nodes, params_head);
                        while (it.nextRef()) |pr| {
                            if (pr == children_param_ref) continue;
                            const param = self.nodes.at(pr);
                            const has_init = getPackedData(param).right != 0;
                            const is_optional = param.hasFlag(NodeFlags.optional);
                            if (!has_init and !is_optional) break :opt false;
                        }
                        break :opt true;
                    };
                    const default_init = if (all_optional) try self.factory.createObjectLiteralExpression(0) else @as(NodeRef, 0);
                    break :blk try self.factory.createParameter(
                        try self.factory.createIdentifier("attrs"), default_init);
                };
                if (children_param_ref != 0) {
                    const p = self.nodes.at(children_param_ref);
                    const default_init = if (getPackedData(p).right != 0) getPackedData(p).right else try self.factory.createArrayLiteralExpression(0);
                    self.nodes.at(props_param).next = try self.factory.createParameter(
                        try self.factory.createIdentifier("children"), default_init);     
                }
                try self.coalesceVariableStatements(self.nodes.at(body_block));
                var flags: u22 = 0;
                if (n.hasFlag(.@"export")) {
                    flags |= @intFromEnum(NodeFlags.@"export");
                }
                return self.nodes.push(.{
                    .kind = .function_declaration,
                    .data = toBinaryDataPtrRefs(fn_name, props_param),
                    .len = body_block,
                    .next = n.next,
                    .flags = flags,
                });
            }

            fn transformJsxNode(self: *@This(), ref: NodeRef) anyerror!NodeRef {
                switch (self.nodes.at(ref).kind) {
                    .jsx_self_closing_element, .jsx_element, .jsx_fragment => {
                        return self.createInlineJsx(ref);
                    },
                    else => return error.InvalidJsx,
                }
            }

            fn transformJsxStyleDirective(self: *@This(), n: *const AstNode) !NodeRef {
                const s = self.style_visitor.node_ptr_to_scope_map.get(n) orelse return 0;
                if (s.did_emit) return 0;
                s.did_emit = true;
                const html_lit = try self.factory.createNoSubstitutionTemplateLiteralAllocated(s.merged_css);
                const call = try self.factory.createCallExpression(
                    try self.factory.createIdentifier(self.requireHelper(.style)), html_lit);
                return try self.factory.createExpressionStatement(call);
            }
            
            // note: this can coalesce element access assignments too !!!
            // which can be rather confusing when debugging the emitter >:)
            fn coalesceVariableStatements(self: *@This(), block: *const AstNode) !void {
                var iter = NodeIterator.init(self.nodes, maybeUnwrapRef(block) orelse 0);
                while (iter.nextRef()) |r| {
                    const s = self.nodes.at(r);
                    switch (s.kind) {
                        .if_statement => {
                            // turns gated assignments into ??=
                            if (s.len != 0) continue;
                            const cond = self.nodes.at(getPackedData(s).left);
                            if (cond.kind != .prefix_unary_expression or getPackedData(cond).left != @intFromEnum(SyntaxKind.exclamation_token)) continue;
                            const inner = self.nodes.at(getPackedData(cond).right);
                            if (inner.kind != .identifier or inner.extra_data != 0) continue;
                            const then = self.nodes.at(getPackedData(s).right);
                            if (then.kind != .block) continue;
                            const u = self.nodes.at(maybeUnwrapRef(then) orelse continue);
                            if (u.next != 0) continue;
                            if (u.kind != .expression_statement) continue;
                            const inner_exp = self.nodes.at(unwrapRef(u));
                            if (inner_exp.kind != .binary_expression or inner_exp.len != @intFromEnum(SyntaxKind.equals_token)) continue;
                            const right = self.nodes.at(getPackedData(inner_exp).right);
                            if (right.kind != .array_literal_expression and right.kind != .object_literal_expression) continue;
                            const left = self.nodes.at(getPackedData(inner_exp).left);
                            if (left.kind != .identifier) continue;
                            if (strings.eql(getSlice(inner, u8), getSlice(left, u8))) {
                                s.kind = .expression_statement;
                                const copy = try self.factory.cloneNode(inner_exp);
                                self.nodes.at(copy).len = @intFromEnum(SyntaxKind.question_question_equals_token);
                                s.data = @ptrFromInt(copy);
                            }
                        },
                        .variable_statement => {
                            // ignores var
                            const decl = self.nodes.at(unwrapRef(s));
                            const right = getPackedData(decl).right;
                            if (right == 0 and s.next != 0 and self.nodes.at(s.next).kind == .expression_statement and decl.next == 0) {
                                // combines decl with its assignment
                                const ns = self.nodes.at(unwrapRef(self.nodes.at(s.next)));
                                if (ns.kind == .binary_expression and self.nodes.at(getPackedData(ns).left).kind == .identifier and ns.len == @intFromEnum(SyntaxKind.equals_token)) {
                                    const ident = self.nodes.at(getPackedData(ns).left);
                                    if (strings.eql(getSlice(ident, u8), getSlice(self.nodes.at(getPackedData(decl).left), u8))) {
                                        const next = self.nodes.at(s.next).next;
                                        s.next = next;
                                        decl.data = toBinaryDataPtrRefs(getPackedData(decl).left, getPackedData(ns).right);
                                        continue;
                                    }
                                }
                            }
                            if (right != 0) {
                                // consolidates simple array initializers
                                const l = self.nodes.at(getPackedData(decl).left);
                                if (l.kind != .identifier) continue;
                                const ident = getSlice(l, u8);
                                const ini = self.nodes.at(right);
                                const rhs_ref = blk: {
                                    if (ini.kind == .binary_expression and ini.len == @intFromEnum(SyntaxKind.equals_token)) {
                                        break :blk getPackedData(ini).right;
                                    }
                                    break :blk right;
                                };
                                const val = self.nodes.at(rhs_ref);
                                if (val.kind != .array_literal_expression or maybeUnwrapRef(val) != null) continue;
                                var exps = std.ArrayListUnmanaged(NodeRef){};
                                defer exps.deinit(getAllocator());
                                var q = s.next;
                                var ind: f64 = 0;
                                while (q != 0) {
                                    const s2 = self.nodes.at(q);
                                    if (s2.kind != .expression_statement) break;
                                    const exp = self.nodes.at(unwrapRef(s2));
                                    if (exp.kind != .binary_expression or exp.len != @intFromEnum(SyntaxKind.equals_token)) break;
                                    const lhs = self.nodes.at(getPackedData(exp).left);
                                    if (lhs.kind != .element_access_expression) break;
                                    const subject = self.nodes.at(getPackedData(lhs).left);
                                    if (subject.kind != .identifier) break;
                                    if (!std.mem.eql(u8, ident, getSlice(subject, u8))) break;
                                    const arg = self.nodes.at(getPackedData(lhs).right);
                                    if (arg.kind != .numeric_literal) break;
                                    if (getNumber(arg) != ind) break;
                                    q = s2.next;
                                    ind += 1;
                                    try exps.append(getAllocator(), getPackedData(exp).right);
                                }
                                if (exps.items.len != 0) {
                                    try self.replacements.put(getPackedData(ini).right, try self.factory.createArrayLiteralExpression(exps.items));
                                    const new_statement = try self.factory.cloneNodeRef(r);
                                    self.nodes.at(new_statement).next = q;
                                    try self.replacements.put(r, new_statement);
                                    iter.ref = q;
                                }
                                continue;
                            }
                            if (decl.next != 0 or (right != 0 and self.nodes.at(right).kind != .numeric_literal)) continue;
                            var decls = std.ArrayListUnmanaged(NodeRef){};
                            defer decls.deinit(getAllocator());
                            try decls.append(getAllocator(), unwrapRef(s));
                            var q = s.next;
                            while (q != 0) {
                                const s2 = self.nodes.at(q);
                                if (s2.kind != .variable_statement) break;
                                if (s2.flags != s.flags) break;
                                const d2 = self.nodes.at(unwrapRef(s2));
                                if (d2.next != 0) break;
                                const right2 = getPackedData(d2).right;
                                if (right2 != 0 and self.nodes.at(right2).kind != .numeric_literal) break;
                                try decls.append(getAllocator(), unwrapRef(s2));
                                q = s2.next;
                            }
                            if (decls.items.len == 1) continue;
                            var l = NodeList.init(self.nodes);
                            for (decls.items) |d| {
                                l.appendRef(try self.factory.cloneNodeRef(d));
                            }
                            const new_statement = try self.factory.createVariableStatement(l.head, s.flags);
                            self.nodes.at(new_statement).next = q;
                            try self.replacements.put(r, new_statement);
                            iter.ref = q;
                        },
                        else => {},
                    }
                }
            }

            // attempts to emit more optimal/natural expression transformations inside statement contexts
            fn maybeInlineExpTransform(self: *@This(), statement: *const AstNode) !?NodeRef {
                var inner_exp: NodeRef = undefined;
                var binding_name: NodeRef = undefined;
                var binding_statement: ?NodeRef = null;
                switch (statement.kind) {
                    .variable_statement => {
                        const decl_start = maybeUnwrapRef(statement) orelse return null;
                        const first_decl = self.nodes.at(decl_start);
                        if (first_decl.kind != .variable_declaration or first_decl.next != 0) return null;
                        const fd = getPackedData(first_decl);
                        const binding_node = self.nodes.at(fd.left);
                        if (binding_node.kind != .identifier) return null;
                        inner_exp = fd.right;
                        binding_name = fd.left;
                    },
                    .return_statement => {
                        inner_exp = maybeUnwrapRef(statement) orelse return null;
                        const el_name = if (self.inlineMaybeGetElementBinding(self.nodes.at(inner_exp))) |x| 
                            getSlice(self.nodes.at(x), u8) else "__ret";
                        binding_name = try self.factory.createIdentifier(el_name);
                        binding_statement = try self.factory.createConstVariable(binding_name, inner_exp);
                        const clone = try self.factory.cloneNode(statement);
                        self.nodes.at(clone).data = @ptrFromInt(binding_name); // return __ret
                        self.nodes.at(binding_statement.?).next = clone;
                    },
                    else => return null,
                }

                // TODO: we can also optimize patterns like `(try foo()).x`
                // call expression args can be optimized as well but we need to be careful with ordering

                if (self.nodes.at(inner_exp).kind == .parenthesized_expression) {
                    inner_exp = unwrapRef(self.nodes.at(inner_exp));
                }

                var can_inline_block: bool = false;
                var inline_block_head: NodeRef = 0;
                var inline_block_tail: NodeRef = 0;

                var extra_statement: NodeRef = undefined;
                const init_node = self.nodes.at(inner_exp);
                switch (init_node.kind) {
                    .keyword_unary_expression => {
                        if (init_node.len != @intFromEnum(SyntaxKind.try_keyword)) return null;
                        
                        const inner = unwrapRef(init_node);
                        try self.visit(self.nodes.at(inner), inner);

                        // ensures `try` is elided during final emit
                        try self.replacements.put(inner_exp, inner);

                        // FIXME: use `Error.isError`
                        const cond = try self.factory.createBinaryExpression(
                            binding_name,
                            .instanceof_keyword,
                            try self.factory.createIdentifier("Error")
                        );
                        extra_statement = try self.factory.createIfStatement(cond, try self.factory.createThrowStatement(binding_name), 0);
                    },
                    .jsx_element, .jsx_self_closing_element => {
                        var element_exp: NodeRef = undefined;
                        var setup_block: NodeRef = undefined;
                        if (!self.isIntrinsicTag(self.getJsxTagRef(init_node)) and callee_creates_comp_instance) {
                            var state = InlineEmitState{
                                .stmts = std.ArrayList(NodeRef).init(getAllocator()),
                                .ctx = .component,
                            };
                            defer state.deinit();
                            var info = TreeNodeInfo{
                                .kind = .component_instance,
                                .node_ptr = init_node,
                                .node_ref = inner_exp,
                                .ph_name = getSlice(self.nodes.at(binding_name), u8), // XXX
                            };
                            try self.emitCallerCompProtocol(&state, &info, null);
                            if (state.stmts.items.len <= 2) {
                                std.debug.assert(state.stmts.items.len == 2); // XXX
                                const z = self.nodes.at(state.stmts.items[0]);
                                std.debug.assert(z.kind == .expression_statement);
                                const binary_exp = self.nodes.at(unwrapRef(z));
                                setup_block = try self.factory.createBlock(&.{state.stmts.items[1]});
                                element_exp = getPackedData(binary_exp).right;
                            } else {
                                setup_block = try self.factory.createBlock(state.stmts.items);
                                element_exp = try self.factory.nodes.push(.{
                                    .kind = .void_expression,
                                    .data = @ptrFromInt(try self.factory.createNumericLiteral(@as(i64,0)))
                                });
                                // XXX: const binding would be difficult here
                                var s = if (binding_statement) |x| self.nodes.at(x) else @constCast(statement);
                                s.flags |= @intFromEnum(NodeFlags.let);
                                s.flags &= ~@intFromEnum(NodeFlags.@"const");
                            }
                            if (setup_block != 0) 
                                try self.coalesceVariableStatements(self.nodes.at(setup_block));
                        } else {
                            const expanded = try self.createInlineJsxBlock(inner_exp, getSlice(self.nodes.at(binding_name), u8));
                            element_exp = expanded.element_expr;
                            setup_block = expanded.setup_block;
                        }
                        
                        try self.replacements.put(inner_exp, element_exp);
                        if (setup_block == 0) {
                            return try self.factory.cloneNode(statement);
                        }
                        extra_statement = setup_block;

                        // does NOT check .replacements, but probably should
                        can_inline_block = true;
                        inline_block_head = unwrapRef(self.nodes.at(extra_statement));
                        var iter = NodeIterator.init(self.nodes, inline_block_head);
                        l: while (iter.nextRef()) |x| {
                            inline_block_tail = x;
                            const n = self.nodes.at(x);
                            switch (n.kind) {
                                .variable_statement, .function_declaration, .class_declaration => {
                                    can_inline_block = false;
                                    break :l;
                                },
                                else => {},
                            }
                        }
                    },
                    else => return null,
                }

                // binding_statement means we inserted a decl already, so we add new statement after it
                if (binding_statement) |x| {
                    if (can_inline_block) {
                        self.factory.insertListAfter(x, inline_block_head, inline_block_tail);
                    } else {
                        self.factory.insertAfter(x, extra_statement);
                    }
                    return x;
                }

                const clone = try self.factory.cloneNode(statement);

                if (can_inline_block) {
                    self.factory.insertListAfter(clone, inline_block_head, inline_block_tail);
                } else {
                    self.factory.insertAfter(clone, extra_statement);
                }

                return clone;
            }

            pub fn visit(self: *@This(), n: *const AstNode, ref: NodeRef) anyerror!void {
                switch (n.kind) {
                    .class_declaration, .class_expression, .get_accessor, .set_accessor, .parameter => {
                        const is_async = self.is_async_ctx;
                        defer self.is_async_ctx = is_async;
                        self.is_async_ctx = false;

                        try parser.forEachChild(self.nodes, n, self);
                    },
                    .function_declaration, .function_expression, .method_declaration, .arrow_function => {
                        const is_async = self.is_async_ctx;
                        defer self.is_async_ctx = is_async;
                        self.is_async_ctx = n.hasFlag(.@"async");

                        try parser.forEachChild(self.nodes, n, self);
                    },
                    .for_of_statement => {
                        const r = getPackedData(n).right;
                        const ty = try self.analyzer.evaluateType(try self.analyzer.getType(self.file, r), 1 << 0 | 1 << 30);
                        var emit_entries = false;
                        if (self.analyzer.getKindOfRef(ty) == .empty_object) {
                            emit_entries = true;
                        }
                        if (self.analyzer.getKindOfRef(ty) == .object_literal) {
                            emit_entries = true;
                            if (try self.analyzer.getKnownSymbolType("iterator")) |iter_sym_ty| {
                                const u = self.analyzer.types.at(ty);
                                const o = Analyzer.getSlice2(u, Analyzer.ObjectLiteralMember);
                                for (o) |*m| {
                                    if (m.name == iter_sym_ty) {
                                        emit_entries = false;
                                        break;
                                    }
                                }
                                if (u.slot3 != 0) {
                                    const impl = try self.analyzer.accessType(u.slot3, iter_sym_ty);
                                    if (impl != @intFromEnum(Kind.never)) {
                                        emit_entries = false;
                                    }
                                }
                            }
                        }

                        if (emit_entries) {
                            const clone = try self.factory.cloneNode(n);
                            const entries_access = try self.factory.createPropertyAccessExpression(
                                try self.factory.createIdentifier("Object"),
                                "entries"
                            );
                            const e = try self.factory.createCallExpression(entries_access, r);
                            self.nodes.at(clone).data = toBinaryDataPtrRefs(getPackedData(n).left, e);
                            try self.replacements.put(ref, clone);
                        }

                        try parser.forEachChild(self.nodes, n, self);
                    },
                    .as_expression => {
                        const d = getPackedData(n);

                        // TODO: just do a direct visit here after unwrapping parens
                        self.as_type_node = self.nodes.at(d.right);

                        try self.visit(self.nodes.at(d.left), d.left);
                    },
                    .throw_statement => {
                        const inner_ref = unwrapRef(n);
                        const inner = self.nodes.at(inner_ref);
                        if (inner.kind != .string_literal and inner.kind != .template_expression and inner.kind != .no_substitution_template_literal) {
                            return try parser.forEachChild(self.nodes, n, self);
                        }

                        const ident = try self.factory.createIdentifier("Error");
                        const n2 = try self.factory.createNewExpression(ident, inner_ref);

                        const n3 = try self.nodes.push(n.*);
                        self.nodes.at(n3).data = @ptrFromInt(n2);

                        try self.replacements.put(ref, n3);
                    },
                    .return_statement => {
                        if (try self.maybeInlineExpTransform(n)) |new_ref| {
                            try self.replacements.put(ref, new_ref);
                        } else {
                            try parser.forEachChild(self.nodes, n, self);
                        }
                    },
                    .catch_clause => {
                        const d = getPackedData(n);
                        const var_decl_ref = d.left;
                        const block_ref = d.right;

                        if (var_decl_ref == 0) {
                            return try parser.forEachChild(self.nodes, n, self);
                        }

                        const var_decl = self.nodes.at(var_decl_ref);
                        const var_name_ref = getPackedData(var_decl).left;
                        const type_annotation_ref = var_decl.len;

                        const Mode = enum { coerce, passthrough, guard };
                        var mode: Mode = .coerce; //no annotation = coerce

                        if (type_annotation_ref != 0) {
                            const ty = try self.analyzer.getType(self.file, type_annotation_ref);
                            if (ty == @intFromEnum(Kind.unknown) or ty == @intFromEnum(Kind.any)) {
                                mode = .passthrough;
                            } else {
                                mode = .guard;
                            }
                        }

                        if (mode == .passthrough) {
                            return try parser.forEachChild(self.nodes, n, self);
                        }

                        const orig_block = self.nodes.at(block_ref);
                        const orig_stmts_head = maybeUnwrapRef(orig_block) orelse 0;

                        const var_name = getSlice(self.nodes.at(var_name_ref), u8);

                        const guard_stmt = if (mode == .coerce) blk: {
                            const var_ident = try self.factory.createIdentifier(var_name);
                            const error_ident = try self.factory.createIdentifier("Error");

                            const instanceof_check = try self.factory.createBinaryExpression(var_ident, .instanceof_keyword, error_ident);

                            // !(e instanceof Error)
                            const not_instanceof = try self.factory.createPrefixUnaryExpression(.exclamation_token, try self.factory.createParenthesizedExpression(instanceof_check));

                            // e = new Error(e)
                            const error_ident2 = try self.factory.createIdentifier("Error");
                            const var_ident2 = try self.factory.createIdentifier(var_name);
                            const new_error = try self.factory.createNewExpression(error_ident2, var_ident2);

                            const var_ident3 = try self.factory.createIdentifier(var_name);
                            const assignment = try self.factory.createBinaryExpression(var_ident3, .equals_token, new_error);
                            const assign_stmt = try self.factory.createExpressionStatement(assignment);

                            // if (!(e instanceof Error)) e = new Error(e)
                            break :blk try self.factory.createIfStatement(not_instanceof, assign_stmt, 0);
                        } else blk: {
                            const ty = try self.analyzer.getType(self.file, type_annotation_ref);
                            const var_ident = try self.factory.createIdentifier(var_name);

                            const is_check = try self.generateIsExpression(var_ident, ty);

                            const not_is = try self.factory.createPrefixUnaryExpression(.exclamation_token, try self.factory.createParenthesizedExpression(is_check));

                            const var_ident2 = try self.factory.createIdentifier(var_name);
                            const throw_stmt = try self.factory.createThrowStatement(var_ident2);

                            // if (!(e is T)) throw e
                            break :blk try self.factory.createIfStatement(not_is, throw_stmt, 0);
                        };

                        self.nodes.at(guard_stmt).next = orig_stmts_head;

                        const new_block = try self.factory.createBlock(guard_stmt);

                        const new_var_decl = try self.factory.createVariableDeclarationSimple(var_name_ref, 0);

                        const new_catch = try self.factory.createCatchClause(new_var_decl, new_block);
                        try self.addReplacement(ref, new_catch);

                        try parser.forEachChild(self.nodes, n, self);
                    },
                    .is_expression => {
                        const d = getPackedData(n);
                        const l = try self.analyzer.getType(self.file, d.left);
                        if (l == @intFromEnum(Kind.any) or l == @intFromEnum(Kind.unknown)) {
                            const r = try self.analyzer.getType(self.file, d.right);
                            const sub = self.unwrapSubject(d.left);

                            const n2 = try self.generateIsExpression(sub, r);
                            try self.replacements.put(ref, try self.factory.createParenthesizedExpression(n2));
                            return;
                        }

                        const r = try self.analyzer.getType(self.file, d.right);
                        if (l == r) {
                            try self.replacements.put(ref, try self.factory.createTrue());
                            return;
                        }

                        const sub = self.unwrapSubject(d.left);
                        const result = try self.generateNarrowedIsExpression(sub, r, l);
                        try self.addReplacement(ref, result);
                        return;
                    },
                    .binary_expression => {
                        const operator = n.len;
                        switch (@as(SyntaxKind, @enumFromInt(operator))) {
                            .equals_token,
                            .plus_equals_token, .minus_equals_token,
                            .asterisk_equals_token, .slash_equals_token, .percent_equals_token,
                            .asterisk_asterisk_equals_token,
                            .bar_equals_token, .ampersand_equals_token, .caret_equals_token,
                            .question_question_equals_token,
                            .bar_bar_equals_token, .ampersand_ampersand_equals_token => {
                                // TODO: handle all left hand side ref expressions, parens is OK and should be unwrapped
                                const d = getPackedData(n);
                                if (self.nodes.at(d.left).kind == .identifier) {
                                    const sym_id = self.nodes.at(d.left).extra_data;
                                    if (self.proxied_symbol_replacements.get(sym_id)) |x| {
                                        try self.visit(self.nodes.at(d.right), d.right);

                                        if (operator == @intFromEnum(SyntaxKind.equals_token)) {
                                            const c = try self.factory.createCallExpression(x, .{d.right});
                                            self.nodes.at(c).next = n.next;
                                            try self.replacements.put(ref, c);
                                        } else {
                                            const op: SyntaxKind = switch (@as(SyntaxKind, @enumFromInt(operator))) {
                                                .plus_equals_token => .plus_token, 
                                                .minus_equals_token => .minus_token,
                                                .asterisk_equals_token => .asterisk_token, 
                                                .slash_equals_token => .slash_token, 
                                                .percent_equals_token => .percent_token,
                                                .asterisk_asterisk_equals_token => .asterisk_asterisk_token,
                                                .bar_equals_token => .bar_token,
                                                .ampersand_equals_token => .ampersand_token,
                                                .caret_equals_token => .caret_token,
                                                .question_question_equals_token => .question_question_token,
                                                .bar_bar_equals_token => .bar_bar_token, 
                                                .ampersand_ampersand_equals_token => .ampersand_ampersand_token,
                                                else => unreachable,
                                            };
                                            const getter = self.symbol_replacements.get(sym_id) orelse unreachable;
                                            const clone = try self.nodes.push(n.*);
                                            self.nodes.at(clone).data = toBinaryDataPtrRefs(getter, d.right);
                                            self.nodes.at(clone).len = @intFromEnum(op);
                                            const c = try self.factory.createCallExpression(x, .{clone});
                                            self.nodes.at(c).next = n.next;
                                            try self.replacements.put(ref, c);
                                        }

                                        return;
                                    }
                                }
                            },
                            else => {},
                        }
                        if (operator == @intFromEnum(SyntaxKind.equals_equals_token) or operator == @intFromEnum(SyntaxKind.exclamation_equals_token)) {
                            const nt = if (operator == @intFromEnum(SyntaxKind.equals_equals_token)) 
                                @intFromEnum(SyntaxKind.equals_equals_equals_token) 
                            else 
                                @intFromEnum(SyntaxKind.exclamation_equals_equals_token); 
                            
                            const clone = try self.nodes.push(n.*);
                            self.nodes.at(clone).len = nt;
                            try self.replacements.put(ref, clone);

                            return try parser.forEachChild(self.nodes, n, self);
                        }
                        return try parser.forEachChild(self.nodes, n, self);
                    },
                    .call_expression => {
                        if (!self.is_async_ctx) {
                            self.as_type_node = null;
                            return try parser.forEachChild(self.nodes, n, self);
                        }

                        const as_node = self.as_type_node;
                        self.as_type_node = null;

                        if (as_node) |c| {
                            if (c.kind == .async_keyword) {
                                const d = getPackedData(n);
                                {
                                    self.as_type_node = c;
                                    defer self.as_type_node = null;
                                    try self.visit(self.nodes.at(d.left), d.left);
                                }
                                var arg_iter = NodeIterator.init(self.nodes, d.right);
                                while (arg_iter.nextRef()) |arg_ref| {
                                    try self.visit(self.nodes.at(arg_ref), arg_ref);
                                }
                                return;
                            }

                            // TODO: as Promise...
                        }

                        const t = try self.analyzer.getType(self.file, ref);
                        const u = try self.analyzer.maybeUnwrapPromise(t);
                        if (u != null and t != u.?) {
                            const copy = try self.factory.cloneNode(n);
                            const n2 = try self.factory.createAwaitExpression(copy);
                            try self.replacements.put(ref, n2);
                        }

                        return try parser.forEachChild(self.nodes, n, self);
                    },
                    .switch_statement => {
                        const d = getPackedData(n);
                        const expr_ref = d.left;
                        const clauses_head = d.right;

                        var lifted_stmt: ?NodeRef = null;
                        var switch_subject_ref = expr_ref;

                        const expr_node = self.nodes.at(expr_ref);
                        if (expr_node.kind == .variable_statement) {
                            // TODO: handle name collisions
                            lifted_stmt = expr_ref;

                            const decl_head = unwrapRef(expr_node);
                            const decl = self.nodes.at(decl_head);
                            const decl_name = getPackedData(decl).left;
                            switch_subject_ref = decl_name;
                        }

                        var has_case_is = false;
                        {
                            var check_iter = NodeIterator.init(self.nodes, clauses_head);
                            while (check_iter.next()) |clause| {
                                if (clause.kind == .case_clause and clause.hasFlag(.declare)) {
                                    has_case_is = true;
                                    break;
                                }
                            }
                        }

                        var switch_init_stmt: ?NodeRef = null;
                        var new_expr_ref = switch_subject_ref;

                        if (has_case_is) {
                            var case_index: u32 = 0;
                            var default_index: ?u32 = null;

                            {
                                var count_iter = NodeIterator.init(self.nodes, clauses_head);
                                while (count_iter.next()) |clause| {
                                    if (clause.kind == .default_clause) {
                                        default_index = case_index;
                                    }
                                    case_index += 1;
                                }
                            }

                            var cond_expr = if (default_index) |idx|
                                try self.factory.createNumericLiteral(idx)
                            else
                                try self.factory.createNumericLiteral(@as(i64, -1));

                            var case_idx: i32 = @intCast(case_index);
                            case_idx -= 1;

                            var clause_refs: [64]NodeRef = undefined; // TODO: dynamic allocation
                            var clause_count: usize = 0;
                            {
                                var collect_iter = NodeIterator.init(self.nodes, clauses_head);
                                while (collect_iter.nextRef()) |cref| {
                                    clause_refs[clause_count] = cref;
                                    clause_count += 1;
                                }
                            }

                            while (case_idx >= 0) : (case_idx -= 1) {
                                const idx: usize = @intCast(case_idx);
                                const clause = self.nodes.at(clause_refs[idx]);

                                if (clause.kind == .default_clause) continue;

                                const case_num = try self.factory.createNumericLiteral(idx);

                                const condition = if (clause.hasFlag(.declare)) blk: {
                                    const type_ref = unwrapRef(clause);
                                    const ty = try self.analyzer.getType(self.file, type_ref);
                                    break :blk try self.generateIsExpression(switch_subject_ref, ty);
                                } else blk: {
                                    const case_expr = unwrapRef(clause);
                                    break :blk try self.factory.createBinaryExpression(switch_subject_ref, .equals_equals_equals_token, case_expr);
                                };

                                cond_expr = try self.factory.createConditionalExpression(condition, case_num, cond_expr);
                            }

                            const switch_ident = try self.factory.createIdentifier("__switch");
                            const switch_decl = try self.factory.createVariableDeclarationSimple(switch_ident, cond_expr);
                            switch_init_stmt = try self.factory.createVariableStatement(switch_decl, @intFromEnum(NodeFlags.@"const"));

                            new_expr_ref = try self.factory.createIdentifier("__switch");
                        }

                        var new_clauses_head: NodeRef = 0;
                        var new_clauses_tail: NodeRef = 0;
                        var case_index: u32 = 0;

                        var clause_iter = NodeIterator.init(self.nodes, clauses_head);
                        while (clause_iter.nextRef()) |clause_ref| {
                            const clause = self.nodes.at(clause_ref);
                            const stmts_head = clause.len;

                            const is_empty = stmts_head == 0;
                            const has_next_clause = clause.next != 0;

                            var new_clause_ref: NodeRef = undefined;

                            if (is_empty and has_next_clause) {
                                if (has_case_is and clause.kind == .case_clause) {
                                    new_clause_ref = try self.factory.createCaseClause(try self.factory.createNumericLiteral(case_index), 0);
                                } else {
                                    new_clause_ref = try self.factory.cloneNode(clause);
                                }
                            } else {
                                const block_ref = try self.transformCaseBody(stmts_head);

                                if (clause.kind == .default_clause) {
                                    new_clause_ref = try self.factory.createDefaultClause(block_ref);
                                } else if (has_case_is) {
                                    new_clause_ref = try self.factory.createCaseClause(try self.factory.createNumericLiteral(case_index), block_ref);
                                } else {
                                    const case_expr = unwrapRef(clause);
                                    new_clause_ref = try self.factory.createCaseClause(case_expr, block_ref);
                                }
                            }

                            case_index += 1;

                            if (new_clauses_head == 0) {
                                new_clauses_head = new_clause_ref;
                            } else {
                                self.nodes.at(new_clauses_tail).next = new_clause_ref;
                            }
                            new_clauses_tail = new_clause_ref;
                        }

                        const new_switch = try self.factory.createSwitchStatement(new_expr_ref, new_clauses_head);
                        self.nodes.at(new_switch).next = n.next;

                        var result_head = new_switch;

                        if (switch_init_stmt) |init_stmt| {
                            self.nodes.at(init_stmt).next = new_switch;
                            result_head = init_stmt;
                        }

                        if (lifted_stmt) |stmt_ref| {
                            const cloned_stmt = try self.factory.cloneNode(self.nodes.at(stmt_ref));
                            self.nodes.at(cloned_stmt).next = result_head;
                            result_head = cloned_stmt;
                        }

                        try self.replacements.put(ref, result_head);

                        try parser.forEachChild(self.nodes, n, self);
                    },
                    .variable_statement => {
                        if (try self.maybeInlineExpTransform(n)) |new_ref| {
                            try self.replacements.put(ref, new_ref);
                        } else {
                            try parser.forEachChild(self.nodes, n, self);
                        }
                    },
                    .update_statement => {
                        const d = getPackedData(n);
                        const operands_head = d.left;
                        const block_ref = d.right;

                        try parser.forEachChild(self.nodes, n, self);

                        var block_tail: NodeRef = 0;
                        const can_elide_block = blk: {
                            if (block_ref == 0) break :blk false;
                            const block_start = maybeUnwrapRef(self.nodes.at(block_ref)) orelse break :blk false;
                            var block_iter = NodeIterator.init(self.nodes, block_start);
                            while (block_iter.nextRef()) |r| {
                                block_tail = r;
                                switch (self.nodes.at(r).kind) {
                                    .variable_statement, .function_declaration, 
                                    .class_declaration, .defer_statement, 
                                    .jsx_component, .jsx_element, 
                                    .jsx_self_closing_element, 
                                    .jsx_style_directive => {
                                        break :blk false;
                                    },
                                    else => {},
                                }
                            }
                            break :blk true;
                        };

                        var call_head: NodeRef = 0;
                        var call_tail: NodeRef = 0;
                        var op_iter = NodeIterator.init(self.nodes, operands_head);
                        while (op_iter.nextRef()) |op_ref| {
                            const op = self.replacements.get(op_ref) orelse op_ref;
                            const call_lhs = try self.accessUpdateSymbolDirect(op);
                            const call_exp = try self.factory.createCallExpression(call_lhs, &.{});
                            // self.nodes.at(call_exp).flags |= @intFromEnum(NodeFlags.optional);
                            const call_stmt = try self.factory.createExpressionStatement(call_exp);
                            if (call_tail != 0) {
                                self.nodes.at(call_tail).next = call_stmt;
                            } else {
                                call_head = call_stmt;
                            }
                            call_tail = call_stmt;
                        }

                        if (can_elide_block) {
                            var t = block_tail;
                            while (true) {
                                const z = self.replacements.get(t) orelse t;
                                if (z == 0) break;
                                const q = self.nodes.at(z).next;
                                if (q == 0) break;
                                t = q;
                            }
                            if (call_tail != 0) {
                                self.nodes.at(call_tail).next = n.next;
                                self.nodes.at(t).next = call_head;
                            }
                            const s = unwrapRef(self.nodes.at(block_ref));
                            try self.replacements.put(ref, self.replacements.get(s) orelse s);
                        } else if (block_ref == 0) {
                            try self.replacements.put(ref, call_head);
                        } else {
                            if (call_tail != 0) {
                                self.nodes.at(call_tail).next = n.next;
                                self.nodes.at(block_ref).next = call_head;
                            }
                            try self.replacements.put(ref, block_ref);
                        }
                    },
                    .jsx_component => {
                        const replacement = try self.transformJsxComponent(ref);
                        try self.replacements.put(ref, replacement);
                    },
                    .jsx_element, .jsx_self_closing_element, .jsx_fragment => {
                        const replacement = try self.transformJsxNode(ref);
                        try self.replacements.put(ref, replacement);
                    },
                    .jsx_style_directive => {
                        // assumes the node is being used like a statement/decl
                        var replacement = try self.transformJsxStyleDirective(n);
                        if (replacement != 0) {
                            self.nodes.at(replacement).next = n.next;
                        } else {
                            replacement = n.next;
                        }
                        try self.replacements.put(ref, replacement);
                    },
                    .public_declaration => {
                        try self.replacements.put(ref, try self.factory.nodes.push(.{
                            .kind = .empty_statement,
                            .next = n.next,
                        }));
                    },
                    .keyword_unary_expression => {
                        if (n.len == @intFromEnum(SyntaxKind.update_keyword)) {
                            const inner = unwrapRef(n);
                            const call_lhs = try self.accessUpdateSymbolDirect(inner);
                            const call_exp = try self.factory.createCallExpression(call_lhs, &.{});
                            // self.nodes.at(call_exp).flags |= @intFromEnum(NodeFlags.optional);
                            try self.replacements.put(ref, call_exp);
                        } else if (n.len == @intFromEnum(SyntaxKind.try_keyword)) {
                            const inner = unwrapRef(n);
                            try self.visit(self.nodes.at(inner), inner);
                            const ident = try self.factory.createIdentifier("v");
                            // FIXME: use `Error.isError`
                            const cond = try self.factory.createBinaryExpression(
                                ident,
                                .instanceof_keyword,
                                try self.factory.createIdentifier("Error")
                            );
                            const body = try self.factory.createBlock(&.{
                                try self.factory.createIfStatement(cond, try self.factory.createThrowStatement(ident), 0),
                                try self.factory.createReturnStatement(ident),
                            });
                            const arrow = try self.factory.createSingleParamArrowFunction(try self.factory.createParameter(ident, 0), body, 0);
                            const call_exp = try self.factory.createCallExpression(
                                try self.factory.createParenthesizedExpression(arrow), 
                                &.{inner}
                            );
                            try self.replacements.put(ref, call_exp);
                        } else {
                            try parser.forEachChild(self.nodes, n, self);
                        }
                    },
                    .this_keyword => {
                        // super hacky and indirect, we use the symbol decl node as the replacement target
                        const symbol_id = n.extra_data;
                        if (symbol_id == 0) return;
                        const sym = self.file.binder.symbols.at(symbol_id);
                        if (sym.declaration == 0) return;
                        const target = self.nodes.at(sym.declaration);
                        if (target.kind != .jsx_element and target.kind != .jsx_self_closing_element) return;
                        if (self.replacements.get(sym.declaration)) |t| {
                            const c = try self.factory.cloneNodeRef(t);
                            self.nodes.at(c).next = n.next;
                            try self.replacements.put(ref, c);
                        }
                    },
                    .identifier => {
                        const symbol_id = n.extra_data;
                        if (symbol_id != 0) {
                            if (self.symbol_replacements.get(symbol_id)) |t| {
                                if (n.next != 0) {
                                    const c = try self.factory.cloneNodeRef(t);
                                    self.nodes.at(c).next = n.next;
                                    try self.replacements.put(ref, c);
                                    return;
                                }
                                try self.replacements.put(ref, t);
                                return;
                            }
                        }
                    },
                    else => {
                        try parser.forEachChild(self.nodes, n, self);
                    },
                }
            }
        };

        // our transform allocates nodes, we need to copy the node allocator 
        // so we don't clobber the page ptr array in the binder
        const nodes = try f.ast.nodes.clone();
        f.ast.nodes = nodes;
        var r = std.AutoArrayHashMap(NodeRef, NodeRef).init(getAllocator());
        var factory = parser.Factory{ .nodes = &f.ast.nodes };
        const a = try this.getAnalyzer();
        var v = Visitor{ 
            .analyzer = a, 
            .file = f, 
            .nodes = &f.ast.nodes,
            .factory = &factory,
            .replacements = &r,
        };

        v.style_visitor.nodes = &f.ast.nodes;
        try v.style_visitor.visit(f.ast.nodes.at(start), start);

        try v.visit(f.ast.nodes.at(start), start);

        if (v.helpers.count() > 0) {
            const source = f.ast.nodes.at(start);
            const first_stmt_ref: NodeRef = @truncate(@intFromPtr(source.data orelse return r));
            var first_emit = r.get(first_stmt_ref) orelse first_stmt_ref;
            while (r.get(first_emit)) |next| first_emit = next;

            var helper_tail: NodeRef = 0;
            var helper_head: NodeRef = 0;
            const pushHelper = struct {
                fn run(bump: *BumpAllocator(AstNode), code: []const u8, head: *NodeRef, tail: *NodeRef) !void {
                    const vnode = try bump.push(.{
                        .kind = .verbatim_node,
                        .data = @ptrCast(code.ptr),
                        .len = @intCast(code.len),
                        .extra_data = 1,
                    });
                    if (tail.* != 0) {
                        bump.at(tail.*).next = vnode;
                    } else {
                        head.* = vnode;
                    }
                    tail.* = vnode;
                }
            };
            if (v.helpers.contains(.template)) {
                try pushHelper.run(&f.ast.nodes, Visitor.helper_code.template, &helper_head, &helper_tail);
            }
            if (v.helpers.contains(.style)) {
                try pushHelper.run(&f.ast.nodes, Visitor.helper_code.style, &helper_head, &helper_tail);
            }
            if (v.helpers.contains(.set_attribute)) {
                try pushHelper.run(&f.ast.nodes, Visitor.helper_code.set_attribute, &helper_head, &helper_tail);
            }
            if (v.helpers.contains(.spread_attributes)) {
                try pushHelper.run(&f.ast.nodes, Visitor.helper_code.spread_attributes, &helper_head, &helper_tail);
            }
            if (v.helpers.contains(.update_symbol)) {
                try pushHelper.run(&f.ast.nodes, Visitor.helper_code.update_symbol, &helper_head, &helper_tail);
            }
            if (v.helpers.contains(.spread_comp)) {
                try pushHelper.run(&f.ast.nodes, Visitor.helper_code.spread_comp, &helper_head, &helper_tail);
            }
            if (v.helpers.contains(.splice_at)) {
                try pushHelper.run(&f.ast.nodes, Visitor.helper_code.splice_at, &helper_head, &helper_tail);
            }
            if (v.helpers.contains(.set_slot_spread)) {
                try pushHelper.run(&f.ast.nodes, Visitor.helper_code.set_slot_spread, &helper_head, &helper_tail);
            }
            if (v.helpers.contains(.set_slot)) {
                try pushHelper.run(&f.ast.nodes, Visitor.helper_code.set_slot, &helper_head, &helper_tail);
            }
            if (v.helpers.contains(.swap_tree)) {
                try pushHelper.run(&f.ast.nodes, Visitor.helper_code.swap_tree, &helper_head, &helper_tail);
            }
            if (helper_tail != 0) {
                if (first_emit == first_stmt_ref) {
                    // need copy to avoid loop
                    first_emit = try factory.cloneNodeRef(first_stmt_ref);
                }
                f.ast.nodes.at(helper_tail).next = first_emit;
                try r.put(first_stmt_ref, helper_head);
            }
        }

        return r;
    }

    // TODO:
    // const a = 1
    // export default { a }
    // ---
    // declare const _default: {
    //     a: number;
    // };
    // export default _default;

    pub fn printDeclarationText(this: *@This(), file_id: u32, start: NodeRef) ![]const u8 {
        const f = this.getFileData(file_id);
        std.debug.assert(f.ast.nodes.at(start).kind == .source_file);

        try this.bindModule(f);

        const analyzer = try this.getAnalyzer();
        const printer = try analyzer.getPrinter();
        const first_statement = maybeUnwrapRef(f.ast.nodes.at(start)) orelse 0;

        try this.doTopLevelCfa(f, start);

        printer.imported_symbols = .{};

        const Converter = struct {
            file: *ParsedFileData,
            analyzer: *Analyzer,
            printer: *Analyzer.TypePrinter,

            pub fn tryTransformExternalAlias(self: *const @This(), abs_ref: u64) !bool {
                const f_id: u32 = @intCast(abs_ref >> 32);

                const f2 = self.analyzer.program.getFileData(f_id);

                const sym_ref: SymbolRef = @truncate(abs_ref);
                const external_sym = f2.binder.symbols.at(sym_ref);

                if (external_sym.hasFlag(.late_bound)) {
                    if (comptime is_debug) {
                        std.debug.print(" skipped converting late bound symbol: ", .{});
                        printSymbol(f2, sym_ref);
                    }
                    return true;
                }

                const ident = getIdentFromSymbol(f2.binder, sym_ref) orelse unreachable;
                const hash = getHashFromNode(ident);

                if (f2.binder.exports.type_symbols.get(hash) != null) {
                    const imported_path = f2.file_name orelse "";
                    const origin = self.file.file_name orelse "";
                    // LEAK
                    const spec = try std.fs.path.relativePosix(self.analyzer.allocator(), std.fs.path.dirname(origin) orelse "", imported_path);
                    const spec2 = try std.mem.concat(self.analyzer.allocator(), u8, &.{"./",std.mem.trimRight(u8, spec, ".ts")});

                    try self.printer.imported_symbols.?.put(self.printer.allocator, abs_ref, spec2); // FIXME: use module spec :/
                    return true;
                }

                // the symbol might be imported by this external module
                if (external_sym.hasFlag(.imported)) {
                    if (external_sym.hasFlag(.namespace)) {
                        return error.TODO_transitive_imported_namespace;
                    }

                    const f3 = self.analyzer.program.getFileData(external_sym.getOrdinal());
                    const external_sym2 = f3.binder.symbols.at(external_sym.declaration);
                    // XXX: search for the symbol
                    if (try self.searchAmbientModules(f3, external_sym2, ident.extra_data2, external_sym.declaration, abs_ref)) |r| {
                        return r;
                    }

                    const imported_path = f3.file_name orelse "";
                    const origin = self.file.file_name orelse "";
                    // LEAK
                    const spec = try std.fs.path.relativePosix(self.analyzer.allocator(), std.fs.path.dirname(origin) orelse "", imported_path);
                    const spec2 = try std.mem.concat(self.analyzer.allocator(), u8, &.{"./",std.mem.trimRight(u8, spec, ".ts")});

                    try self.printer.imported_symbols.?.put(self.printer.allocator, abs_ref, spec2); // FIXME: use module spec :/
                    return true;
                }

                // XXX: search for the symbol
                if (try self.searchAmbientModules(f2, external_sym, ident.extra_data2,sym_ref, abs_ref)) |r| {
                    return r;
                }

                return false;
            }

            fn searchAmbientModules(self: *const @This(), f2: *ParsedFileData, external_sym: *const parser.Symbol, sym_hash: u32, sym_ref: u32, abs_ref: u64) !?bool {
                var module_iter = f2.binder.ambient_modules.iterator();
                while (module_iter.next()) |module_entry| {
                    const sym = f2.binder.symbols.at(module_entry.value_ptr.*);
                    std.debug.assert(sym.hasFlag(.namespace));
                    const ns = f2.binder.namespaces.items[sym.binding];
                    const exports = ns.exports orelse continue;
                    _ = exports;

                    const sym_table = if (external_sym.hasFlag(.type)) ns.type_symbols else ns.symbols;
                    if (sym_table.get(sym_hash)) |s| {
                        if (s == sym_ref) {
                            if (self.analyzer.program.associated_directives.get(@intCast(abs_ref >> 32))) |d| {
                                var did_find = false;

                                for (self.printer.triple_slash_directives.items) |d2| {
                                    if (d2.kind == d.kind and strings.eql(d.value, d2.value)) {
                                        did_find = true;
                                        break;
                                    }
                                }

                                if (!did_find) {
                                    try self.printer.triple_slash_directives.append(self.printer.allocator, d.*);
                                }
                            }
                            try self.printer.imported_symbols.?.put(self.printer.allocator, abs_ref, ns.module_specifier.?);
                            return true;
                        }
                    }
                }

                return null;
            }

            fn _classLike(self: *const @This(), node: *const AstNode, t: Analyzer.TypeRef, exported: bool) !NodeRef {
                const d = getPackedData(node);
                const synthed_ref = try self.printer.toTypeNode(t);
                const synthed = self.printer.synthetic_nodes.at(synthed_ref);
                const copy = try self.printer.copyNodeFromRef(d.left, self.file.id);
                synthed.data = toBinaryDataPtrRefs(copy, getPackedData(synthed).right);
                synthed.flags |= @intFromEnum(NodeFlags.declare);
                if (exported) synthed.flags |= @intFromEnum(NodeFlags.@"export");

                return synthed_ref;
            }

            pub fn classLike(self: *const @This(), node: *const AstNode, ref: NodeRef) !NodeRef {
                const t = try self.analyzer.getType(self.file, ref);
                return self._classLike(node, t, false);
            }

            pub fn classLikeFromType(self: *const @This(), node: *const AstNode, t: Analyzer.TypeRef) !NodeRef {
                return self._classLike(node, t, true);
            }

            pub fn functionLikeFromType(self: *const @This(), node: *const AstNode, type_ref: Analyzer.TypeRef) !NodeRef {
                const synthed_ref = try self.printer.toTypeNode(type_ref);
                const synthed = self.printer.synthetic_nodes.at(synthed_ref);
                const copy = try self.printer.copyNodeFromRef(getPackedData(node).left, self.file.id);

                var flags: u22 = @intFromEnum(NodeFlags.declare);
                if (node.hasFlag(.@"export")) flags |= @intFromEnum(NodeFlags.@"export");

                var return_type = (getPackedData(synthed)).right;

                const t = self.analyzer.types.at(type_ref);
                std.debug.assert(t.getKind() == .function_literal or t.getKind() == .parameterized);
                if (t.getKind() == .function_literal) {
                    const followed = try self.analyzer.followInnerScopeAliases(t.slot3);
                    if (followed != t.slot3) {
                        return_type = try self.printer.toTypeNode(followed);
                    }
                } else if (t.getKind() == .parameterized) {
                    std.debug.assert(t.slot3 < @intFromEnum(Analyzer.Kind.false));
                    const inner = self.analyzer.types.at(t.slot3);
                    std.debug.assert(inner.getKind() == .function_literal); // TODO: could be recursive
                    const followed = try self.analyzer.followInnerScopeAliases(inner.slot3);
                    if (followed != inner.slot3) {
                        const parameterized = try self.analyzer.createParameterizedType(Analyzer.getSlice2(t, Analyzer.TypeRef), followed);
                        return_type = try self.printer.toTypeNode(parameterized);
                    }
                }

                return self.printer.synthetic_nodes.push(.{
                    .kind = .function_declaration,
                    .flags = flags,
                    .data = toBinaryDataPtrRefs(copy, (getPackedData(synthed)).left),
                    .extra_data = synthed.len, // type params
                    .extra_data2 = return_type,
                });
            }
        };

        const converter = Converter{
            .file = f,
            .analyzer = analyzer,
            .printer = printer,
        };

        // TODO
        // export type RegExp = 'ok'
        // export const y = /aaa/

        // export type RegExp = 'ok';
        // export declare const y: globalThis.RegExp;

        var to_keep = std.AutoArrayHashMap(u64, bool).init(this.allocator);
        defer to_keep.deinit();

        var external_set = std.AutoArrayHashMap(u64, bool).init(this.allocator);
        defer external_set.deinit();

        // file nodes -> synthetic nodes
        var replacements = std.AutoArrayHashMap(NodeRef, NodeRef).init(this.allocator);
        defer replacements.deinit();

        var named_imports = std.ArrayList(struct { NodeRef, NodeRef }).init(this.allocator);
        defer named_imports.deinit();

        var nodes_to_keep = std.AutoArrayHashMap(NodeRef, bool).init(this.allocator);
        defer nodes_to_keep.deinit();


        // TODO: don't iterate over all statements on the first pass
        // Re-use the results from binding instead
        //
        // var imports_iter = f.binder.imports.iterator();
        // while (imports_iter.next()) |entry| {
        // }

        var exported_syms = f.binder.exports.symbols.iterator();
        while (exported_syms.next()) |entry| {
            const s = f.binder.symbols.at(entry.value_ptr.*);
            if (s.declaration == 0) return error.MissingExportedDecl;

            const n = f.ast.nodes.at(s.declaration);
            if (n.kind != .function_declaration) continue; // TODO

            const d = getPackedData(n);
            if (d.left == 0) return error.TODO_default_export;

            try to_keep.put((@as(u64, file_id) << 32) | f.ast.nodes.at(d.left).extra_data, true);

            const type_ref = try analyzer.getTypeOfSymbol(f, entry.value_ptr.*);
            try analyzer.gatherReferencedSymbols2(&to_keep, type_ref, f.id, &external_set);

            // var iter2 = to_keep.iterator();
            // while (iter2.next()) |entry2| {
            //     printSymbol(f, @truncate(entry2.key_ptr.* & 0xFFFFFFFF));
            // }

            defer external_set.clearAndFree();

            var external_set_iter = external_set.iterator();
            while (external_set_iter.next()) |external_entry| {
                _ = try converter.tryTransformExternalAlias(external_entry.key_ptr.*);
            }

            const t = analyzer.types.at(type_ref);
            switch (t.getKind()) {
                .function_literal, .parameterized => {
                    try replacements.put(s.declaration, try converter.functionLikeFromType(n, type_ref));
                },
                .object_literal => {
                    var list = NodeList.init(&printer.synthetic_nodes);
                    for (Analyzer.getSlice2(t, Analyzer.ObjectLiteralMember)) |*el| {
                        if (el.kind != .call_signature) continue;

                        list.appendRef(try converter.functionLikeFromType(n, try el.getType(analyzer)));
                    }

                    std.debug.assert(list.head != 0);
                    try replacements.put(s.declaration, list.head);
                },
                else => return error.UnknownTypeKind,
            }
        }

        var exported_types = f.binder.exports.type_symbols.iterator();
        while (exported_types.next()) |entry| {
            const sym_ref = entry.value_ptr.*;
            const s = f.binder.symbols.at(sym_ref);
            if (s.declaration == 0) return error.MissingExportedDecl;

            const n = f.ast.nodes.at(s.declaration);
            if (n.kind == .class_declaration) continue; // TODO

           // const d = getPackedData(n);
           // try to_keep.put((@as(u64, file_id) << 32) | f.ast.nodes.at(d.left).extra_data, true);

            // const t = try analyzer.getTypeOfSymbol(f, sym_ref);
            try analyzer.gatherReferencedSymbolsFromAst(&to_keep, f, s.declaration);

            // if (n.kind == .type_alias_declaration and d.right == 0) {
            //     const ident = try printer.copyNodeFromRef(d.left, @intCast(f.id));
            //     var copy = n.*;
            //     copy.len = try printer.toTypeNode(t);
            //     copy.data = toBinaryDataPtrRefs(ident, 0);
            //     const n2 = try printer.synthetic_nodes.push(copy);
            //     try replacements.put(s.declaration, n2);
            // }
        }

        var iter = NodeIterator.init(&f.ast.nodes, first_statement);
        while (iter.nextPair()) |p| {
            const n: *const AstNode = p[0];
            const ref = p[1];

            // TODO: always include ambient modifications
            if (!n.hasFlag(.@"export")) {
                if (n.kind == .import_declaration) {
                    const d = getPackedData(n);
                    const clause = f.ast.nodes.at(d.left);
                    const clause_data = getPackedData(clause);
                    if (clause_data.right == 0) continue;

                    const namespace_or_named_imports = f.ast.nodes.at(clause_data.right);
                    if (namespace_or_named_imports.kind == .named_imports) {
                        try named_imports.append(.{ ref, clause_data.right });
                    }
                } else if (n.kind == .export_declaration) {
                    try nodes_to_keep.put(ref, true);
                }
                continue;
            }

            switch (n.kind) {
                .type_alias_declaration, .interface_declaration => {
                    // const d = getPackedData(n);
                    // try to_keep.put((@as(u64, file_id) << 32) | f.ast.nodes.at(d.left).extra_data, true);
                    // const t = try analyzer.getType(f, ref);
                    // try analyzer.gatherReferencedSymbols(&to_keep, t, f.id);
                },
                .variable_statement => {
                    var decls_iter = NodeIterator.init(&f.ast.nodes, unwrapRef(n));
                    var l = NodeList.init(&printer.synthetic_nodes);
                    while (decls_iter.nextPair()) |pair| {
                        const d = getPackedData(pair[0]);
                        const binding = f.ast.nodes.at(d.left);

                        // tsc "unrolls" the binding pattern
                        //
                        // example: `export declare const { z, z2 }: { z: number, z2: boolean }`
                        // -------> `export declare const z: number, z2: boolean;`
                        if (binding.kind != .identifier) {

                            return error.TODO_exported_variable_binding;
                        }

                        try to_keep.put((@as(u64, file_id) << 32) | binding.extra_data, true);

                        var t = try analyzer.getType(f, d.left);
                        if (pair[0].len == 0) {
                            // inferred, try to simplify
                            t = try analyzer.maybeSimplifyType(t);
                        }
                        try analyzer.gatherReferencedSymbols2(&to_keep, t, f.id, &external_set);

                        defer external_set.clearAndFree();

                        var external_set_iter = external_set.iterator();
                        while (external_set_iter.next()) |external_entry| {
                            const did_convert = try converter.tryTransformExternalAlias(external_entry.key_ptr.*);
                            if (!did_convert) {
                                t = try analyzer.maybeResolveAlias(t);
                            } else {
                                printer.removeCacheEntry(t);
                            }
                        }

                        const synthed_ref = try printer.toTypeNode(t);
                        const copy = try printer.copyNodeFromRef(d.left, @intCast(f.id));

                        try l.append(.{
                            .kind = .variable_declaration,
                            .data = toBinaryDataPtrRefs(copy, 0),
                            .len = synthed_ref,
                        });
                    }
                    const n2 = try printer.synthetic_nodes.push(.{
                        .kind = .variable_statement,
                        .flags = @intFromEnum(NodeFlags.declare) | n.flags,
                        .data = @ptrFromInt(l.head),
                    });
                    try replacements.put(ref, n2);
                },
                // .function_declaration => {
                //     const d = getPackedData(n);
                //     if (d.left == 0) return error.TODO_default_export;

                //     try to_keep.put((@as(u64, file_id) << 32) | f.ast.nodes.at(d.left).extra_data, true);

                //     const t = try analyzer.getType(f, ref);
                //     try analyzer.gatherReferencedSymbols(&to_keep, t, f.id);

                //     const synthed_ref = try printer.toTypeNode(t);
                //     const synthed = printer.synthetic_nodes.at(synthed_ref);
                //     const copy = try printer.copyNodeFromRef(d.left, @intCast(f.id));

                //     const n2 = try printer.synthetic_nodes.push(.{
                //         .kind = .function_declaration,
                //         .flags = @intFromEnum(NodeFlags.declare) | @intFromEnum(NodeFlags.@"export"),
                //         .data = toBinaryDataPtrRefs(copy, (getPackedData(synthed)).left),
                //         .extra_data = synthed.len, // type params
                //         .extra_data2 = (getPackedData(synthed)).right, // return type
                //     });

                //     try replacements.put(ref, n2);
                // },
                .class_declaration => {
                    const d = getPackedData(n);
                    if (d.left == 0) return error.TODO_default_export;

                    try to_keep.put((@as(u64, file_id) << 32) | f.ast.nodes.at(d.left).extra_data, true);

                    const t = try analyzer.getType(f, ref);
                    try analyzer.gatherReferencedSymbols(&to_keep, t, f.id);

                    try replacements.put(ref, try converter.classLikeFromType(n, t));
                },
                else => {},
            }
        }

        var to_keep_iter = to_keep.iterator();
        while (to_keep_iter.next()) |entry| {
            const f_id: u32 = @intCast(entry.key_ptr.* >> 32);
            if (f_id != file_id) continue;

            const sym_ref: SymbolRef = @truncate(entry.key_ptr.*);
            const sym = f.binder.symbols.at(sym_ref);
            if (hasSymbolFlag(sym, .late_bound)) continue;

            if (hasSymbolFlag(sym, .imported)) {
                const ident = getIdentFromSymbol(f.binder, sym_ref) orelse unreachable;
                // std.debug.print("IMPORT {s} -> {}\n", .{ getSlice(ident, u8), ident.next });
                try nodes_to_keep.put(ident.next, true);
            } else if (sym.declaration != 0) {
                try nodes_to_keep.put(sym.declaration, true);

                // don't add overloads, they're already handled
                if (f.ast.nodes.at(sym.declaration).kind == .function_declaration) continue;

                var next = sym.next;
                while (next != 0) {
                    const s = f.binder.symbols.at(next);
                    if (s.declaration != 0) try nodes_to_keep.put(s.declaration, true);
                    next = s.next;
                }
            }
        }

        // Prune import decls
        // TODO: prune decls w/ both default import and named/namespace imports
        for (named_imports.items) |pair| {
            if (!(nodes_to_keep.get(pair[0]) orelse false)) continue;

            const r = f.ast.nodes.at(pair[1]);
            var l = NodeList.init(&printer.synthetic_nodes);
            var did_change = false;

            //const count = printer.synthetic_nodes.count;
            const local_count = printer.synthetic_nodes.local_count;

            defer {
                if (!did_change) {
                //    printer.synthetic_nodes.count = count;
                    printer.synthetic_nodes.local_count = local_count;
                }
            }

            var iter2 = NodeIterator.init(&f.ast.nodes, maybeUnwrapRef(r) orelse 0);

            while (iter2.nextPair()) |p| {
                const d = getPackedData(p[0]);
                const binding = if (d.right != 0) d.right else d.left;
                const ident = f.ast.nodes.at(binding);
                if (to_keep.get((@as(u64, f.id) << 32) | ident.extra_data) orelse false) {
                    try l.append(.{
                        .kind = .external_node,
                        .data = &f.ast,
                        .len = p[1],
                    });
                } else {
                    did_change = true;
                }
            }

            if (!did_change) continue;

            const decl = f.ast.nodes.at(pair[0]);
            const d = getPackedData(decl);
            const right = try printer.synthetic_nodes.push(.{
                .kind = .external_node,
                .data = &f.ast,
                .len = d.right,
            });

            const imports = try printer.synthetic_nodes.push(.{
                .kind = .named_imports,
                .data = @ptrFromInt(l.head),
            });

            const clause = try printer.synthetic_nodes.push(.{
                .kind = .import_clause,
                .data = toBinaryDataPtrRefs(0, imports), // FIXME: this removes default import
            });

            const replacement = try printer.synthetic_nodes.push(.{
                .kind = .import_declaration,
                .flags = decl.flags,
                .data = toBinaryDataPtrRefs(clause, right),
            });

            try replacements.put(pair[0], replacement);
        }

        var statements = NodeList.init(&printer.synthetic_nodes);
        var iter2 = NodeIterator.init(&f.ast.nodes, first_statement);
        while (iter2.nextPair()) |p| {
            const should_keep = nodes_to_keep.get(p[1]) orelse false;
            if (!should_keep) {
                // XXX: check for variable statment
                if (p[0].kind != .variable_statement) continue;
                if (!(nodes_to_keep.get(unwrapRef(p[0])) orelse false)) continue; // FIXME: handle multiple decls
            }

            if (replacements.get(p[1])) |r| {
                var next = r;
                while (next != 0) {
                    statements.appendRef(next);
                    next = printer.synthetic_nodes.at(next).next;
                }
            } else {
                if (p[0].kind == .class_declaration) {
                    statements.appendRef(try converter.classLike(p[0], p[1]));
                    continue;
                }

                try statements.append(.{
                    .kind = .external_node,
                    .data = &f.ast,
                    .len = p[1],
                });
            }
        }

        // const start_print_time = std.time.microTimestamp();

        const s = try parser.printInMemoryWithTypes(.{
            .source_name = f.file_name,
            .nodes = printer.synthetic_nodes,
            .decorators = f.ast.decorators,
            .source = f.ast.source,
            .positions = f.ast.positions,
            .triple_slash_directives = printer.triple_slash_directives.items,
        }, .{
            .kind = .source_file,
            .data = @ptrFromInt(statements.head),
        });

        // std.debug.print("  print time: {d:.3}\n", .{std.time.microTimestamp() - start_print_time});

        return s;
    }
};

const ModuleList = packed struct {
    const ListType = std.ArrayListUnmanaged(FileRef);
    const max_inline_elements = 7;

    buf: [max_inline_elements]FileRef = undefined,
    count: u31 = 0,
    is_allocated: bool = false,

    comptime {
        if (@sizeOf(ModuleList) != 32) {
            @compileError("Expected 32 bytes");
        }
    }

    pub fn deinit(this: *@This(), allocator: std.mem.Allocator) void {
        if (!this.is_allocated) return;

        return allocator.free(this.getAllocatedSlice());
    }

    fn appendAllocated(this: *@This(), allocator: std.mem.Allocator, value: FileRef) !void {
        std.debug.assert(this.is_allocated);

        var list = ListType{
            .items = this.getAllocatedSlice(),
            .capacity = this.buf[2],
        };

        if (list.capacity > list.items.len) {
            this.count += 1;
            return list.appendAssumeCapacity(value);
        }

        try list.append(allocator, value);
        const items_ptr: *u64 = @alignCast(@ptrCast(&this.buf));
        items_ptr.* = @intFromPtr(list.items.ptr);
        this.buf[2] = @intCast(list.capacity);
        this.count += 1;
    }

    inline fn getAllocatedSlice(this: *const @This()) []FileRef {
        const ptr: *u64 = @constCast(@alignCast(@ptrCast(&this.buf)));
        return @as([*]FileRef, @ptrFromInt(ptr.*))[0..this.count];
    }

    pub fn getSlice(this: *const @This()) []const FileRef {
        if (this.count == 0) return &.{};

        if (this.is_allocated) {
            return this.getAllocatedSlice();
        }

        return this.buf[0..this.count];
    }

    fn allocate(this: *@This(), allocator: std.mem.Allocator, capacity: u32) ![]FileRef {
        std.debug.assert(!this.is_allocated);

        this.is_allocated = true;
        const buf = try allocator.alloc(FileRef, capacity);
        @memcpy(buf, this.buf[0..this.count]);

        return buf;
    }

    pub fn append(this: *@This(), allocator: std.mem.Allocator, ref: FileRef) !void {
        if (this.count < max_inline_elements) {
            this.buf[this.count] = ref;
            this.count += 1;
            return;
        }

        if (this.count == max_inline_elements) {
            const capacity: u32 = 16;
            const buf = try this.allocate(allocator, capacity);
            const items_ptr: *u64 = @alignCast(@ptrCast(&this.buf));
            items_ptr.* = @intFromPtr(buf.ptr);
            this.buf[2] = capacity;
        }

        return this.appendAllocated(allocator, ref);
    }
};

const FileRef = u32;
const ParsedPair = struct { *parser.ParsedFile, FileRef };

const ModuleLinkage = struct {
    // aliasing to make moving to later zig versions a bit easier
    const ImportMap = std.AutoArrayHashMapUnmanaged(u64, FileRef); // spec hash -> module id
    const InverseImportMap = std.AutoArrayHashMapUnmanaged(FileRef, []const u8);

    const PendingDependents = std.ArrayListUnmanaged(FileRef);
    const CachedExports = std.AutoArrayHashMapUnmanaged(NodeSymbolHash, AbsoluteSymbolRef);

    import_map: ImportMap = ImportMap{},
    inverse_import_map: InverseImportMap = InverseImportMap{},

    pub fn addImport(this: *@This(), allocator: std.mem.Allocator, spec: []const u8, module_id: FileRef) !void {
        try this.import_map.put(allocator, getHash(spec), module_id);
        try this.inverse_import_map.put(allocator, module_id, spec);
    }

};

pub const ParsedFileData = struct {
    const CachedSymbolTypes = std.AutoArrayHashMapUnmanaged(parser.SymbolRef, Analyzer.TypeRef);
    const CachedFlowTypes = std.AutoArrayHashMapUnmanaged(parser.SymbolRef, Analyzer.TypeRef);
    const Diagnostics = std.ArrayListUnmanaged(FileDiagnostic);

    id: FileRef = 0,
    file_name: ?[]const u8 = null,

    ast: parser.AstData,
    binder: *const parser.Binder,

    // Used by the analyzer
    // TODO (perf): maybe make symbols bigger and use a slot to cache
    cached_symbol_types: CachedSymbolTypes = .{},
    cached_flow_types: CachedFlowTypes = .{},

    is_lib: bool = false,
    is_declaration: bool = false,
    did_analyze: bool = false,
    did_top_level_cfa: bool = false,
    did_resolve_imports: bool = false,
    did_bind_imports: bool = false,
    did_bind_aliased_exports: bool = false,

    // Module data
    import_map: std.AutoArrayHashMap(u64, FileRef),
    unresolved_imports: std.ArrayList(u64),
    linkage: *ModuleLinkage,

    flow: ?*Analyzer.FlowTyper = null,
    declaration_flows: std.AutoArrayHashMapUnmanaged(NodeRef, *Analyzer.FlowTyper) = .{},

    diagnostics: Diagnostics = .{},

    pub fn init(_allocator: std.mem.Allocator, ast: parser.AstData, binder: *const parser.Binder, linkage: *ModuleLinkage) @This() {
        return .{
            .ast = ast,
            .binder = binder,
            .import_map = std.AutoArrayHashMap(u64, FileRef).init(_allocator),
            .unresolved_imports = std.ArrayList(u64).init(_allocator),
            .linkage = linkage,
        };
    }

    pub fn deinit(this: @This()) void {
        _ = this;
        @panic("todo");
    }

    pub fn initFromParsedFile(file: *parser.ParsedFile, linkage: *ModuleLinkage) @This() {
        var this = @This().init(getAllocator(), file.ast, &file.binder, linkage);
        this.file_name = file.source_name;
        this.is_lib = file.is_lib;
        this.did_top_level_cfa = file.is_lib;

        return this;
    }

    pub fn emitError(this: *@This(), node_ref: NodeRef, message: []const u8) !void {
        const s = try this.import_map.allocator.dupe(u8, message);
        try this.diagnostics.append(this.import_map.allocator, .{
            .node_ref = node_ref,
            .message = s,
        });
    }

    pub fn emitErrorFmt(this: *@This(), node_ref: NodeRef, comptime fmt: []const u8, args: anytype) !void {
        const message = try std.fmt.allocPrint(this.import_map.allocator, fmt, args);
        try this.emitError(node_ref, message);
    }

    pub fn printDiagnostics(this: *@This()) !void {
        const file_name = this.file_name orelse return error.MissingFileName;
        for (this.diagnostics.items) |d| {
            const loc = parser.getLoc(&this.ast.nodes, this.ast.nodes.at(d.node_ref)) orelse return error.MissingNodeLocation;
            std.debug.print("{s} at {s}:{}:{}\n", .{ d.message, file_name, loc.line + 1, loc.col + 1 });
        }
    }

    pub fn diagnosticsToBuf(this: *@This(), allocator: std.mem.Allocator) ![]u8 {
        const file_name = this.file_name orelse return error.MissingFileName;

        var list = std.ArrayList(u8).init(allocator);
        errdefer list.deinit();

        const writer = list.writer();

        for (this.diagnostics.items) |d| {
            const loc = parser.getLoc(
                &this.ast.nodes,
                this.ast.nodes.at(d.node_ref),
            ) orelse return error.MissingNodeLocation;

            try writer.print(
                "{s} at {s}:{}:{}\n",
                .{ d.message, file_name, loc.line + 1, loc.col + 1 },
            );
        }

        return list.toOwnedSlice();
    }
};

const AbsoluteSymbolRef = struct { file_id: FileRef, ref: parser.SymbolRef };

const Ambient = struct {
    const GlobalRef = u32;
    const Global = struct {
        type: Analyzer.TypeRef = 0,
        symbols: std.ArrayListUnmanaged(AbsoluteSymbolRef) = std.ArrayListUnmanaged(AbsoluteSymbolRef){},
    };

    modules: std.AutoArrayHashMap(u64, GlobalRef),
    // TODO: module patterns

    globals: std.AutoArrayHashMap(parser.NodeSymbolHash, GlobalRef),
    global_types: std.AutoArrayHashMap(parser.NodeSymbolHash, GlobalRef),

    globals_allocator: parser.BumpAllocator(Global),

    pub fn init(_allocator: std.mem.Allocator) @This() {
        var globals_allocator = parser.BumpAllocator(Global).init(_allocator, std.heap.page_allocator);
        globals_allocator.preAlloc() catch unreachable;

        return .{
            .globals_allocator = globals_allocator,
            .modules = std.AutoArrayHashMap(u64, GlobalRef).init(_allocator),
            .globals = std.AutoArrayHashMap(parser.NodeSymbolHash, GlobalRef).init(_allocator),
            .global_types = std.AutoArrayHashMap(parser.NodeSymbolHash, GlobalRef).init(_allocator),
        };
    }

    pub fn deinit(this: @This()) void {
        this.modules.deinit();
        this.globals.deinit();
        this.global_types.deinit();
    }

    pub fn getGlobalSymbol(this: *const @This(), comptime name: []const u8) ?*Global {
        const hashed: u32 = comptime @truncate(std.hash.Wyhash.hash(0, name));
        const index = this.globals.get(hashed) orelse return null;

        return this.globals_allocator.at(index);
    }

    pub fn getGlobalTypeSymbol(this: *const @This(), comptime name: []const u8) ?*Global {
        return this.globals_allocator.at(this.getGlobalTypeSymbolRef(name) orelse return null);
    }

    pub fn getGlobalTypeSymbolRef(this: *const @This(), comptime name: []const u8) ?GlobalRef {
        const hashed: u32 = comptime @truncate(std.hash.Wyhash.hash(0, name));
        const index = this.global_types.get(hashed) orelse return null;

        return index;
    }
};

const is_debug = @import("builtin").mode == .Debug;

pub const Analyzer = struct {
    const num_type_registers = 8;

    pub const Kind = enum(u32) {
        nil = 0, // placeholder/invalid type

        string_literal,
        template_literal,
        number_literal,
        object_literal,
        bigint_literal,
        function_literal,
        symbol_literal, // `unique symbol`

        class,
        array,

        type_parameter,

        tuple_element,

        @"union",
        intersection,
        tuple,
        mapped,
        indexed, // T[K]
        keyof,
        query,
        alias, // Used for better `.d.ts` emits

        // Conditional types are always reduced if possible
        conditional, // T extends ...
        parameterized,

        predicate,

        module_namespace, // Special case of an object literal

        // Intrinsics
        false = 1 << 31,
        true,
        null,
        undefined,
        number,
        string,
        bigint,
        object, // TODO: possibly add `null_or_object` for `object | null`, useful for `typeof`
        boolean, // Not technically intrinsic, this is equivalent to `true | false`
        function,
        symbol,

        // TODO: possibly remove empty_object/string/tuple
        empty_object,
        empty_string,
        empty_tuple,
        empty_element, // Similar to the "hole" in [1,,2]

        // XXX: `typeof globalThis` is just a really big object literal type
        // But the current impl. doesn't construct a map for object literals
        // So we'll do this for now
        global_this,

        void,

        this,

        any,
        error_any,
        never,
        unknown,
        infer_unknown,

        // User-accessible intrinsics (order matters for `isCallableIntrinsic`)
        string_uppercase,
        string_lowercase,
        string_capitalize,
        string_uncapitalize,
        no_infer,
        this_type_marker, // TODO: typescript doesn't use `intrinsic` to mark this decl

        // Lower bits reference the type parameter id, biased by 16
        // Under 16 uses ordinals = direct lookup into the register
        type_parameter_ref = 0b101 << 29,

        // 30 bit two's complement literals are treated as intrinsic
        // TODO: we could have this be 31 bit if we made `false` 0b01 << 30
        zero = 0b11 << 30,
    };

    pub const Flags = enum(u24) {
        has_alias = 1 << 0,

        has_infer = 1 << 1,
        parameter_decl = 1 << 2, // XXX: helper for getting types from constructor
        allocated_list = 1 << 3,

        class_alias = 1 << 4,
        instance_alias = 1 << 5,
        enum_alias = 1 << 14,

        abstract = 1 << 6,
        constructor = 1 << 7, // used for signatures and function literals
        spread = 1 << 8,
        infer_node = 1 << 9,

        parameterized = 1 << 10,
        has_this_type = 1 << 11,

        global = 1 << 12,

        lazy = 1 << 13,

        readonly = 1 << 16,
        optional = 1 << 17,
    };

    pub const QueryFlags = enum(u24) {
        return_type = 1 << 2, // equivalent to `ReturnType<typeof foo>`

        pub inline fn isReturnType(t: *const Type) bool {
            return (t.flags & @intFromEnum(@This().return_type)) == @intFromEnum(@This().return_type);
        }
    };

    // Goes into same slot as other type flags, be careful not to overlap
    const UnionFlags = enum(u24) {
        has_object_literal = 1 << 4,
        has_number_literal = 1 << 5,
        has_string_literal = 1 << 6,
        has_symbol_literal = 1 << 7,

        // shared with `Flags`
        parameterized = 1 << 10,

        // intrinsics
        has_undefined = 1 << 15,
        has_null_or_void = 1 << 18,
        has_object = 1 << 19,
        has_boolean = 1 << 20,
        has_string = 1 << 21,
        has_number = 1 << 22,
        has_symbol = 1 << 23,
    };

    const ObjectLiteralFlags = enum(u24) {
        overloaded_function = 1 << 4,

        // shared with `Flags`
        parameterized = 1 << 10,

        lazy = 1 << 13,

        has_call_signature = 1 << 21,
        has_index_signature = 1 << 22,
        // synthetic type produced by FlowTyper
        refined = 1 << 23,

        pub inline fn hasFlag(t: *const Type, comptime f: ObjectLiteralFlags) bool {
            return (t.flags & @intFromEnum(f)) == @intFromEnum(f);
        }

        pub inline fn isRefined(t: *const Type) bool {
            return ObjectLiteralFlags.hasFlag(t, .refined);
        }
    };

    pub const Type = packed struct {
        slot0: u32 = 0,
        slot1: u32 = 0,
        slot2: u32 = 0,
        slot3: u32 = 0,
        slot4: u32 = 0,
        slot5: u32 = 0,
        slot6: u32 = 0,

        // Placed below the data slots for easier alignment
        kind: u8,
        flags: u24 = 0,

        comptime {
            if (@sizeOf(Type) != 32) @compileError("Invalid type struct size");
        }

        pub inline fn init(comptime kind: Kind) @This() {
            if (comptime @intFromEnum(kind) >= @intFromEnum(Kind.false)) {
                @compileError("Cannot allocate type with kind >= `Kind.false`");
            }

            return .{ .kind = @intCast(@intFromEnum(kind)) };
        }

        pub inline fn getKind(this: *const @This()) Kind {
            return @enumFromInt(this.kind);
        }

        pub inline fn hasFlag(this: *const Type, flag: Flags) bool {
            return (this.flags & @intFromEnum(flag)) == @intFromEnum(flag);
        }

        pub const Class = struct {
            instance_type: TypeRef,
            static_type: TypeRef,
            constructor: TypeRef,
            base_class: TypeRef,

            pub inline fn fromType(t: *const Type) *align(@alignOf(Type)) const @This() {
                return @ptrCast(t);
            }
        };

        pub const Alias = struct {
            slot0: u32,
            slot1: u32,
            slot2: u32,
            file_id: u32,
            sym_ref: SymbolRef,
            next: u32,
            evaluated: u32,
            _: u32,

            pub inline fn getArgs(this: *const @This()) []TypeRef {
                return getSlice2(@ptrCast(this), TypeRef);
            }

            pub inline fn fromType(t: *const Type) *const @This() {
                return @ptrCast(t);
            }
        };
    };

    pub const TypeRef = u32;

    // All `.d.ts` files merge w/ ambient declarations but
    // only files loaded via directives expose changes.

    const Variance = enum {
        invariant,
        covariant,
        contravariant,

        pub fn invert(v: Variance) Variance {
            return switch (v) {
                .invariant => .invariant,
                .covariant => .contravariant,
                .contravariant => .covariant,
            };
        }
    };

    program: *Program,

    synthetic_strings: std.ArrayList([]const u8),

    types: parser.BumpAllocator(Type),
    interned_types: std.AutoArrayHashMap(u64, TypeRef),

    // key is (src << 32) | dst, inflight checks are assumed true
    assignable_cache: std.AutoArrayHashMapUnmanaged(u64, bool) = .{},

    type_args: std.AutoArrayHashMap(TypeRef, TypeRef),
    type_registers: [num_type_registers]TypeRef = [_]TypeRef{0} ** num_type_registers,
    contextual_this_type: TypeRef = 0, // Used to evaluate `this` in types (not expressions)

    inferred_type_params: ?std.AutoArrayHashMapUnmanaged(TypeRef, TypeRef) = null,
    inferrence_ctx: ?TypeRef = null, // points to a type to guide inferrence

    is_const_context: bool = false, // Forced `const` context e.g. `as const` or `const T`
    is_const_variable_context: bool = false, // Implicit `const` context e.g. `const x = 1`
    follow_parameterized_return_type: bool = false,

    // Used when analyzing parameterized types
    // We use this state to compute type parameter variance
    //
    // TODO: Type params used to constrain other type params take on the variance on the constrained type
    variance: Variance = .covariant,

    printer: ?*TypePrinter = null,

    // Used to detect recursion
    active_types: std.AutoArrayHashMapUnmanaged(u64, bool),

    current_node: if (is_debug) ?struct { *ParsedFileData, NodeRef } else void = if (is_debug) null else {},
   
    label_pool: std.heap.MemoryPool(FlowTyper.Label),


    pub fn init(program: *Program) !@This() {
        var types = BumpAllocator(Type).init(program.allocator, std.heap.page_allocator);
        try types.preAlloc();
        _ = try types.push(.{ .kind = @intFromEnum(Kind.nil) });

        return .{
            .program = program,
            .types = types,
            .interned_types = std.AutoArrayHashMap(u64, TypeRef).init(program.allocator),
            .synthetic_strings = std.ArrayList([]const u8).init(program.allocator),
            .type_args = std.AutoArrayHashMap(TypeRef, TypeRef).init(program.allocator),
            .active_types = std.AutoArrayHashMapUnmanaged(u64, bool){},
            .label_pool = std.heap.MemoryPool(FlowTyper.Label).init(program.allocator),
        };
    }

    pub fn getPrinter(this: *@This()) !*TypePrinter {
        if (this.printer) |p| return p;

        const p = try TypePrinter.init(this);
        this.printer = p;
        return p;
    }

    fn getAnalyzedFile(this: *@This(), id: u32) !*ParsedFileData {
        return this.program.getBoundFile(id);
    }

    const IntrinsicTypeAliases = ComptimeStringMap(Kind, .{
        .{ "NoInfer", .no_infer },
        .{ "Lowercase", .string_lowercase },
        .{ "Uppercase", .string_uppercase },
        .{ "Capitalize", .string_capitalize },
        .{ "Uncapitalize", .string_uncapitalize },
    });

    const TypeList = struct {
        buf: [4]TypeRef = undefined,
        count: u32 = 0,
        flags: u24 = 0,

        pub fn fromSlice(analyzer: *Analyzer, slice: []const TypeRef) !@This() {
            if (slice.len > 4) {
                var this = @This(){ .count = 0, .flags = @intFromEnum(Flags.allocated_list) };
                const buf = try this.allocate(analyzer.allocator(), @intCast(slice.len));
                @memcpy(buf, slice);
                this.setAllocatedSlice(buf);
                //this.recomputeStructuralFlags(analyzer);
                return this;
            }

            var this = @This(){ .count = @intCast(slice.len) };
            for (slice, 0..) |t, i| {
               //this.flags |= analyzer.getStructuralFlags(t);
                this.buf[i] = t;
            }

            return this;
        }

        pub fn fromAllocatedSlice(slice: []const TypeRef) @This() {
            var this = @This(){ 
                .count = @intCast(slice.len),
                .flags = @intFromEnum(Flags.allocated_list),
            };
            this.setAllocatedSlice(slice);
            return this;
        }

        pub fn deinit(this: *@This(), _allocator: std.mem.Allocator) void {
            if (!this.isAllocated()) return;

            return _allocator.free(this.getAllocatedSlice());
        }

        pub fn setCapacity(this: *@This(), _allocator: std.mem.Allocator, capacity: u32) !void {
            if (capacity <= 4) return;

            const buf = try this.allocate(_allocator, capacity);
            this.setAllocatedSlice(buf);
        }

        fn appendAllocated(this: *@This(), analyzer: *Analyzer, value: TypeRef) !void {
            std.debug.assert(this.isAllocated());

            var list = std.ArrayListUnmanaged(TypeRef){
                .items = this.getAllocatedSlice(),
                .capacity = this.buf[2],
            };

            if (list.capacity > list.items.len) {
                this.count += 1;
                return list.appendAssumeCapacity(value);
            }

            try list.append(analyzer.allocator(), value);
            this.setAllocatedSlice(list.items.ptr[0..list.capacity]);
            this.count += 1;
        }

        // TypeList becomes immutable after this
        fn shrinkToFit(this: *@This(), _allocator: std.mem.Allocator, slice: []TypeRef) []const TypeRef {
            std.debug.assert(this.isAllocated());

            var list = std.ArrayListUnmanaged(TypeRef){
                .items = this.getAllocatedSlice(),
                .capacity = this.buf[2],
            };

            list.shrinkAndFree(_allocator, slice.len);

            return list.items;
        }

        inline fn getAllocatedSlice(this: *const @This()) []TypeRef {
            // const ptr: *u64 = @constCast(@alignCast(@ptrCast(&this.buf)));
            // return @as([*]TypeRef, @ptrFromInt(ptr.*))[0..this.count];
            const ptr: [*]TypeRef = @ptrFromInt((@as(u64, this.buf[0]) << 32) | this.buf[1]);
            return ptr[0..this.count];
        }

        pub fn getSlice(this: *const @This()) []const TypeRef {
            if (this.count == 0) return &.{};

            if (this.isAllocated()) {
                return this.getAllocatedSlice();
            }

            return this.buf[0..this.count];
        }

        inline fn isAllocated(this: *const @This()) bool {
            return (this.flags & @intFromEnum(Flags.allocated_list)) == @intFromEnum(Flags.allocated_list);
        }

        fn allocate(this: *@This(), _allocator: std.mem.Allocator, capacity: u32) ![]TypeRef {
            std.debug.assert(!this.isAllocated());

            this.flags |= @intFromEnum(Flags.allocated_list);
            const buf = try _allocator.alloc(TypeRef, capacity);
            @memcpy(buf[0..this.count], this.buf[0..this.count]);

            return buf;
        }

        inline fn setAllocatedSlice(this: *@This(), slice: []const TypeRef) void {
            // const items_ptr: *u64 = @alignCast(@ptrCast(&this.buf));
            // items_ptr.* = @intFromPtr(slice.ptr);
            const p: u64 = @intFromPtr(slice.ptr);
            this.buf[0] = @truncate(p >> 32);
            this.buf[1] = @truncate(p);
            this.buf[2] = @intCast(slice.len);
        }

        pub fn append(this: *@This(), analyzer: *Analyzer, type_ref: TypeRef) !void {
            this.flags |= analyzer.getStructuralFlags(type_ref);

            if (this.count < 4) {
                this.buf[this.count] = type_ref;
                this.count += 1;
                return;
            }

            if (this.count == 4) {
                const buf = try this.allocate(analyzer.allocator(), 8);
                this.setAllocatedSlice(buf);
            }

            return this.appendAllocated(analyzer, type_ref);
        }

        // useful when you don't want to write to a type directly
        pub fn toAllocated(this: *@This(), _allocator: std.mem.Allocator) ![]TypeRef {
            if (this.isAllocated()) {
                return this.getAllocatedSlice();
            }

            const buf = try _allocator.alloc(TypeRef, this.count);
            @memcpy(buf, this.buf[0..this.count]);

            return buf;
        }

        pub fn getCount(this: *const @This()) u32 {
            return this.count;
        }

        pub fn swapRemove(this: *@This(), index: usize) TypeRef {
            std.debug.assert(this.count != 0);
            std.debug.assert(index < this.count);

            const slice = if (this.isAllocated()) this.getAllocatedSlice() else this.buf[0..this.count];
            const el = slice[index];
            this.count -= 1;
            if (index != this.count) {
                slice[index] = slice[this.count];
            }
            return el;
        }

        pub fn replace(this: *@This(), index: usize, val: TypeRef) TypeRef {
            const count = this.getCount();
            std.debug.assert(count != 0);
            std.debug.assert(index < count);

            const slice = if (this.isAllocated()) this.getAllocatedSlice() else this.buf[0..count];
            const el = slice[index];
            slice[index] = val;
            return el;
        }

        pub fn getSliceFromType(t: *const Type) []TypeRef {
            if (t.hasFlag(.allocated_list)) {
                if (t.slot0 == 0) return &.{};
                const ptr: [*]TypeRef = @ptrFromInt((@as(u64, t.slot2) << 32) | t.slot1);

                return ptr[0..t.slot0];
            }

            if (t.slot0 == 0) return &.{};

            const items_ptr: [*]TypeRef = @constCast(@ptrCast(&t.slot0));

            var len: u32 = 1;
            if (t.slot1 != 0) {
                if (t.slot2 != 0) {
                    len = 3;
                } else {
                    len = 2;
                }
            }

            return items_ptr[0..len];
        }

        pub fn recomputeStructuralFlags(this: *@This(), analyzer: *Analyzer) void {
            this.flags &= ~structural_flag_mask;
            const slice = if (this.isAllocated()) this.getAllocatedSlice() else this.buf[0..this.getCount()];
            for (slice) |t| {
                this.flags |= analyzer.getStructuralFlags(t);
            }
        }

        pub fn writeToType(this: *@This(), _allocator: std.mem.Allocator, t: *Type) !void {
            if (this.count <= 3) {
                if (this.count >= 1) {
                    t.slot0 = this.buf[0];
                }
                if (this.count >= 2) {
                    t.slot1 = this.buf[1];
                }
                if (this.count >= 3) {
                    t.slot2 = this.buf[2];
                }

                t.flags |= this.flags;

                return;
            }

            //const items_ptr: *u64 = @alignCast(@ptrCast(&t.slot1));

            if (this.count <= this.buf.len) {
                const slice = try this.allocate(_allocator, this.count);
                //items_ptr.* = @intFromPtr(slice.ptr);
                t.slot1 = @truncate(@intFromPtr(slice.ptr));
                t.slot2 = @truncate(@intFromPtr(slice.ptr) >> 32);
                t.slot0 = @intCast(slice.len);
                t.flags |= this.flags;
                return;
            }

            const slice = this.shrinkToFit(_allocator, this.getAllocatedSlice());
            // items_ptr.* = @intFromPtr(slice.ptr);
            t.slot1 = @truncate(@intFromPtr(slice.ptr));
            t.slot2 = @truncate(@intFromPtr(slice.ptr) >> 32);
            t.slot0 = @intCast(slice.len);
            t.flags |= this.flags;
        }

        const ReverseIterator = struct {
            types: *TypeList,
            pos: u32, // 1-indexed

            pub fn next(this: *@This()) ?TypeRef {
                if (this.pos == 0) return null;

                this.pos -= 1;
                return this.types.getSlice()[this.pos];
            }
        };

        pub fn reverseIterator(this: *@This()) ReverseIterator {
            return .{
                .types = this,
                .pos = this.getCount(),
            };
        }
    };

    inline fn isTypeParamRef(ref: TypeRef) bool {
        return (ref & (0b111 << 29)) == @intFromEnum(Kind.type_parameter_ref);
    }

    pub inline fn getKindOfRef(this: *const @This(), ref: TypeRef) Kind {
        if (ref >= @intFromEnum(Kind.false)) {
            if (isTypeParamRef(ref)) return .type_parameter_ref;
            if (ref >= @intFromEnum(Kind.zero)) return .number_literal;
            return @enumFromInt(ref);
        }

        return this.types.at(ref).getKind();
    }

    inline fn hasEvalFlag(state: u32, comptime flag: EvaluationFlags) bool {
        return (state & @intFromEnum(flag)) == @intFromEnum(flag);
    }

    inline fn followInnerScopeAliases(this: *@This(), type_ref: TypeRef) anyerror!TypeRef {
        return this.evaluateType(type_ref, @intFromEnum(EvaluationFlags.inner_scoped_aliases));
    }

    pub fn followAllAliases(this: *@This(), type_ref: TypeRef) !TypeRef {
        var res = type_ref;
        while (true) {
            const next = try this.maybeResolveAlias(res);
            if (next == res) return next;
            res = next;
        }
    }

    fn maybeResolveAlias(this: *@This(), type_ref: TypeRef) anyerror!TypeRef {
        if (type_ref >= @intFromEnum(Kind.false)) return type_ref;

        const t = this.types.at(type_ref);
        if (t.getKind() != .alias or t.hasFlag(.parameterized)) return type_ref;

        const key: u64 = (@as(u64, 1) << 63) | type_ref;
        if (this.active_types.contains(key)) return type_ref;

        try this.active_types.put(this.allocator(),key, true);
        defer _ = this.active_types.swapRemove(key);

        if (t.hasFlag(.class_alias)) {
            if (t.hasFlag(.global)) {
                // FIXME: we need to show the class w/ merged interfaces ?
                return this.getTypeOfGlobalSymbol(t.slot4);
            }
            return this.getTypeOfSymbol(try this.getAnalyzedFile(t.slot3), t.slot4);
        }

        const result = try this.followImmediateAlias(t, 0) orelse type_ref;

        return if (t.hasFlag(.instance_alias))
            this.getInstanceType(result, true)
        else
            result;
    }

    fn followImmediateAliasInner(this: *@This(), alias: *Type, flags: u32) anyerror!?TypeRef {
        const should_skip_inner = hasEvalFlag(flags, .inner_scoped_aliases);
        if (alias.hasFlag(.global)) {
            if (should_skip_inner) {
                return null;
            }
            if (hasEvalFlag(flags, .no_globals)) {
                return null;
            }

            if (alias.slot5 != 0) return alias.slot5;
            const r = try this.getTypeOfGlobalSymbol(alias.slot4);
            alias.slot5 = r;
            return r;
        }

        const f = try this.getAnalyzedFile(alias.slot3);
        if (should_skip_inner and f.binder.symbols.at(alias.slot4).hasFlag(.top_level)) {
            return null;
        }

        if (alias.slot5 != 0) return alias.slot5;
        const r= try this.getTypeOfSymbol(f, alias.slot4);
        alias.slot5 = r;
        return r;
    }

    fn followImmediateAlias(this: *@This(), alias: *Type, flags: u32) anyerror!?TypeRef {
        const inner = try this.followImmediateAliasInner(alias, flags) orelse return null;
        if (inner >= @intFromEnum(Kind.false) or this.types.at(inner).getKind() != .parameterized) {
            alias.slot6 = inner;
            return inner;
        }

        if (flags == @intFromEnum(EvaluationFlags.type_args)) {
            if (alias.slot6 != 0) return alias.slot6;
        }
 
        const inner_type = this.types.at(inner);
        const params = getSlice2(inner_type, TypeRef);
        const args = getSlice2(alias, TypeRef);

        var resolved = std.AutoArrayHashMap(TypeRef, TypeRef).init(this.type_args.allocator);
        defer resolved.deinit();

        try resolved.ensureTotalCapacity(params.len);

        for (params, 0..) |p, i| {
            const el = if (i < args.len) args[i] else this.getTypeParamDefault(p) 
                orelse this.getTypeParamConstraint(p)
                orelse @intFromEnum(Kind.infer_unknown);

            if ((flags & @intFromEnum(EvaluationFlags.type_args)) != @intFromEnum(EvaluationFlags.type_args)) {
                try resolved.put(p, el);
            } else {
                const v = try this.evaluateType(el, flags);
                try resolved.put(p, v);
            }
        }

        const result = try this.resolveWithTypeArgsInferred(inner_type, &resolved);
        if (flags == @intFromEnum(EvaluationFlags.type_args)) {
            alias.slot6 = result;
        }
        return result;
    }

    const EvaluationFlags = enum(u32) {
        type_args = 1 << 1,
        no_globals = 1 << 2,
        no_objects = 1 << 3,
        no_instance_aliases = 1 << 4,
        no_enum_aliases = 1 << 5,
        no_unions = 1 << 6,
        inner_scoped_aliases = 1 << 20,
        for_reify = 1 << 30,
    };

    pub fn evaluateType(this: *@This(), ref: TypeRef, flags: u32) anyerror!TypeRef {
        if (ref >= @intFromEnum(Kind.false)) {
            return ref;
        }

        const t = this.types.at(ref);
        const evaluated = try switch (this.getKindOfRef(ref)) {
            .conditional => try this.tryResolveConditionalType(t.slot0, t.slot1, t.slot2, t.slot3) orelse ref, // TODO: flags
            .query => this.evaluateQuery(t, flags),
            .keyof => this.evaluateKeyOfType(t.slot0), // TODO: flags
            .indexed => this.accessType(t.slot0, t.slot1),
            .alias => {
                if (t.hasFlag(.parameterized)) return ref;
                if (hasEvalFlag(flags, .no_instance_aliases) and t.hasFlag(.instance_alias)) return ref;
                if (hasEvalFlag(flags, .no_enum_aliases) and t.hasFlag(.enum_alias)) return ref;
                return try this.followImmediateAlias(t, @intFromEnum(EvaluationFlags.type_args) | flags) orelse ref;
            },
            .function_literal => {
                var did_change = false;
                var list = TypeList{};

                for (getSlice2(t, TypeRef)) |el| {
                    const v = try this.evaluateType(el, flags);
                    if (v != el) did_change = true;
                    try list.append(this, v);
                }

                const return_type = try this.evaluateType(t.slot3, flags);
                if (return_type != t.slot3) did_change = true;

                const this_type = try this.evaluateType(t.slot4, flags);
                if (this_type != t.slot4) did_change = true;

                if (!did_change) {
                    list.deinit(this.allocator());
                    return ref;
                }

                if (t.hasFlag(.constructor)) list.flags |= @intFromEnum(Flags.constructor);
                var params = Params{ .params = list, .this_type = this_type };

                return try this.createFunctionLiteral(&params, return_type);
            },
            .@"union" => {
                if (hasEvalFlag(flags, .no_unions)) return ref;

                var did_change = false;
                var tmp = TempUnion.init(this.allocator());
                defer if (!did_change) tmp.deinit();
                for (getSlice2(t, TypeRef)) |el| {
                    const v = try this.evaluateType(el, flags);
                    if (v != el) did_change = true;
                    // TODO: perf: don't add to the union right away
                    if (try this.addToUnion(&tmp, v)) |x| return x;
                }

                if (!did_change) return ref;

                return tmp.complete(this);
            },
            .intersection => {
                if (!hasEvalFlag(flags, .for_reify)) return ref;

                var tmp = std.ArrayList(ObjectLiteralMember).init(this.allocator());

                for (getSlice2(t, TypeRef)) |el| {
                    const v = try this.evaluateType(el, flags);
                    if (v >= @intFromEnum(Kind.false)) {
                        if (v == @intFromEnum(Kind.empty_object)) continue;
                        if (v == @intFromEnum(Kind.any) or v == @intFromEnum(Kind.never)) {
                            tmp.deinit();
                            return v;
                        }
                        this.printTypeInfo(v);
                        return error.TODO_primitive_intersection;
                    }
                    const t2 = this.types.at(v);
                    if (t2.getKind() != .object_literal) {
                        this.printTypeInfo(v);
                        return error.TODO_intersection_non_object;
                    }
                    const members = getSlice2(t2, ObjectLiteralMember);
                    for (members) |*m| {
                        if (m.kind != .property) continue;

                        const member_name_hash = try this.getMemberNameHash(m.name);
                        const member_type = try m.getType(this);
                        var found = false;
                        for (tmp.items) |*m2| {
                            if (member_name_hash != try this.getMemberNameHash(m2.name)) continue;

                            found = true;
                            if (m2.type != member_type) {
                                if (try this.isAssignableTo(m2.type, member_type)) {
                                    m2.type = member_type;
                                } else if (!try this.isAssignableTo(member_type, m2.type)) {
                                    m2.type = @intFromEnum(Kind.never);
                                }
                            }
                            break;
                        }
                        
                        if (!found) {
                            try tmp.append(.{
                                .name = m.name,
                                .type = member_type,
                            });
                        }
                    }
                }

                return this.createObjectLiteral(tmp.items, 0, 0);
            },
            .tuple => {
                const members = getSlice2(t, TypeRef);
                var did_change = false;
                var tmp = TypeList{};
                for (members) |el_type| {
                    if (el_type < @intFromEnum(Kind.false) and this.getKindOfRef(el_type) == .tuple_element) {
                        const m = this.types.at(el_type);
                        const inner = m.slot1;
                        const v = try this.evaluateType(inner, flags);
                        std.debug.assert(v != ref);
                        if (!m.hasFlag(.spread)) {
                            if (v == inner) {
                                try tmp.append(this, el_type);
                                continue;
                            }
                            did_change = true;
                            try tmp.append(this, v);
                            continue;
                        }

                        if (v == @intFromEnum(Kind.empty_tuple)) {
                            did_change = true;
                            continue;
                        }

                        if (this.isTuple(v)) {
                            did_change = true;
                            try this.reduceTupleElement(this.types.at(v), &tmp);
                            continue;
                        }

                        if (v == inner) {
                            try tmp.append(this, el_type);
                            continue;
                        }

                        const el_flags: u24 = @intFromEnum(Flags.spread) | this.getStructuralFlags(v);

                        did_change = true;
                        try tmp.append(this,try this.createUnnamedTupleElement(v, el_flags));

                        continue;
                    }

                    const v = try this.evaluateType(el_type, flags);
                    if (v != el_type) did_change = true;

                    try tmp.append(this, v);
                }

                if (!did_change) {
                    tmp.deinit(this.allocator());
                    return ref;
                }

                return this.createTupleType(&tmp);
            },
            .object_literal => {
                if (hasEvalFlag(flags, .no_objects)) return ref;

                const old_this_type = this.contextual_this_type;
                defer this.contextual_this_type = old_this_type;
                this.contextual_this_type = ref;

                const members = getSlice2(t, ObjectLiteralMember);
                var flags2: u24 = 0;
                var did_change = false;
                var tmp = try std.ArrayList(ObjectLiteralMember).initCapacity(this.allocator(), members.len);
                defer if (!did_change) tmp.deinit();
                for (members) |*el| {
                    const el_type = try el.getType(this);
                    const v = try this.evaluateType(el_type, flags);
                    if (v != el_type) did_change = true;
                    flags2 |= this.getStructuralFlags(v);
                    flags2 |= switch (el.kind) {
                        .index => @intFromEnum(ObjectLiteralFlags.has_index_signature),
                        .call_signature => @intFromEnum(ObjectLiteralFlags.has_call_signature),
                        else => 0,
                    };

                    tmp.appendAssumeCapacity(.{
                        .flags = el.flags,
                        .kind = el.kind,
                        .type = v,
                        .name = el.name,
                        .slot0 = el.slot0,
                    });
                }

                const proto = if (t.slot3 != 0) try this.evaluateType(t.slot3, flags) else 0;
                if (proto != t.slot3) did_change = true;

                if (!did_change) return ref;

                flags2 |= this.getStructuralFlags(proto);

                return this.createObjectLiteral(tmp.items, flags2, proto);
            },
            else => ref,
        };

        return if (evaluated != ref) this.evaluateType(evaluated, flags) else evaluated;
    }

    fn isSimpleType(this: *const @This(), ref: TypeRef) bool {
        if (ref >= @intFromEnum(Kind.false)) return true;

        const t = this.types.at(ref);

        return switch (t.getKind()) {
            .alias => true, // FIXME: check for simple args too
            .type_parameter => true,
            .string_literal, .number_literal => true,
            .tuple_element => this.isSimpleType(t.slot1),
            .tuple, .@"union", .intersection => {
                const elements = getSlice2(t, TypeRef);
                if (elements.len > 16) return false;

                for (elements) |u| {
                    if (!this.isSimpleType(u)) return false;
                }

                return true;
            },
            else => false,
        };
    }

    pub fn maybeSimplifyType(this: *@This(), ref: TypeRef) anyerror!TypeRef {
        if (ref >= @intFromEnum(Kind.false)) return ref;
        if (this.isParameterizedRef(ref)) return ref;

        const t = try this.evaluateType(ref, @intFromEnum(EvaluationFlags.no_globals) | @intFromEnum(EvaluationFlags.no_objects));
        if (t == ref) return ref;

        if (this.isSimpleType(t)) {
            if (this.getKindOfRef(t) == .tuple) {
                return this.maybeSimplifyType(t);
            }
            return t;
        }

        const u = this.types.at(ref);
        if (u.getKind() != .alias) return ref;
    
        const args = getSlice2(u, TypeRef);
        if (args.len == 0) return ref;

        var did_change = false;
        var tmp = TypeList{};
        defer if (!did_change) tmp.deinit(this.allocator());

        for (args) |a| {
            const v = try this.maybeSimplifyType(a);
            if (v != a) did_change = true;
            try tmp.append(this, v);
        }

        if (!did_change) return ref;

        return try this.createAlias(&tmp, u.slot3, u.slot4, u.flags);
    }

    // clobbers
    fn setTypeArg(this: *@This(), param: *const Type, param_ref: TypeRef, val: TypeRef) !void {
        if (param.slot3 < num_type_registers) {
            this.type_registers[param.slot3] = val;
        } else {
            try this.type_args.put(param_ref, val);
        }
    }

    fn setTypeArgFromTypeParamRef(this: *@This(), type_param_ref: TypeRef, val: TypeRef) !void {
        const register: u32 = type_param_ref & (~@intFromEnum(Kind.type_parameter_ref));
        if (register < num_type_registers) {
            this.type_registers[register] = val;
            return;
        }

        const param_ref = register - num_type_registers;
        if (val == 0) {
            _ = this.type_args.swapRemove(param_ref);
        } else {
            try this.type_args.put(param_ref, val);
        }
    }

    fn resolveTypeParam(this: *const @This(), ref: TypeRef) ?TypeRef {
        const register: u32 = ref & (~@intFromEnum(Kind.type_parameter_ref));
        if (register >= num_type_registers) {
            const param_ref = register - num_type_registers;
            return this.type_args.get(param_ref);
        }

        const v = this.type_registers[register];
        if (v == 0) return null;
        return v;
    }

    fn resolveUnionOrIntersection(this: *@This(), ref: TypeRef, comptime kind: Kind) !TypeRef {
        comptime switch (kind) {
            .@"union", .intersection => {},
            else => @compileError("Invalid kind"),
        };

        var did_change = false;
        var should_deinit = true;
        const elements = getSlice2(this.types.at(ref), TypeRef);
        var arr = try std.ArrayList(TypeRef).initCapacity(this.type_args.allocator, elements.len);
        defer if (should_deinit) arr.deinit();

        var flags: u24 = 0;

        for (elements) |el| {
            const resolved = try this.resolveParameterizedType(el) orelse el;
            if (resolved != el) did_change = true;
            flags |= this.getStructuralFlags(resolved);
            try arr.append(resolved);
        }

        if (!did_change) return ref;
        should_deinit = false;

        if (comptime kind == .@"union") {
            return this.toUnion(arr.items);
        }
        
        if (arr.items.len == 2) {
            should_deinit = true;
            if (arr.items[1] == @intFromEnum(Kind.empty_object)) {
                return this.nonNullable(arr.items[0]);
            }
            return this.intersectType(arr.items[0], arr.items[1]);
        }

        std.debug.print("FIXME INTERSECTION TYPES LEN > 2\n", .{});

        return createIntersectionType(this, arr.items, flags);
    }

    fn getTypeParamDefault(this: *@This(), param: TypeRef) ?TypeRef {
        std.debug.assert(param < @intFromEnum(Kind.false));
        const t = this.types.at(param);
        std.debug.assert(t.getKind() == .type_parameter);

        return if (t.slot2 == 0) null else t.slot2;
    }

    fn getTypeParamConstraint(this: *@This(), param: TypeRef) ?TypeRef {
        std.debug.assert(param < @intFromEnum(Kind.false));
        const t = this.types.at(param);
        std.debug.assert(t.getKind() == .type_parameter);

        return if (t.slot1 == 0) null else t.slot1;
    }

    // TODO: more than 3 elements = complex
    fn isComplexType(this: *@This(), ref: TypeRef) !bool {
        _ = this;
        _ = ref;
        return true;
    }

    inline fn isCallableIntrinsic(ref: TypeRef) bool {
        return ref >= @intFromEnum(Kind.string_uppercase) and ref <= @intFromEnum(Kind.string_uncapitalize);
    }

    fn getIntrinsicStringArg(this: *@This()) !TypeRef {
        const arg0 = this.type_registers[0];
        if (arg0 == 0) return error.MissingArg;

        if (arg0 >= @intFromEnum(Kind.false)) {
            return error.TODO_string_capitalize;
        }

        const t = this.types.at(arg0);
        if (t.getKind() != .string_literal) return error.NotAString;

        if ((t.slot3 & @intFromEnum(StringFlags.needs_decode)) == @intFromEnum(StringFlags.needs_decode)) {
            return error.TODO_non_ascii;
        }

        return arg0;
    }

    // TODO: use ` u_strToUpper` from ICU
    inline fn uppercaseAsciiChar(c: u8) u8 {
        if (c < 'a' or c > 'z') return c;
        return c - 32;
    }

    // TODO: use ` u_strToLower` from ICU
    inline fn lowercaseAsciiChar(c: u8) u8 {
        if (c < 'A' or c > 'Z') return c;
        return c + 32;
    }

    // Only works on ASCII strings currently
    fn capitlizeOrUncapitalize(this: *@This(), comptime capitalize: bool) !TypeRef {
        const arg0 = try this.getIntrinsicStringArg();
        const slice = this.getSliceFromLiteral(arg0);
        const u = if (comptime capitalize) uppercaseAsciiChar(slice[0]) else lowercaseAsciiChar(slice[0]);
        if (slice[0] == u) return arg0;

        // TODO: check if the same string literal exists first
        var buf = try this.allocator().alloc(u8, slice.len);
        @memcpy(buf, slice);
        buf[0] = u;
        return try this.createSyntheticStringLiteral(buf, true);
    }

    fn callIntrinsicType(this: *@This(), ref: TypeRef) !TypeRef {
        switch (@as(Kind, @enumFromInt(ref))) {
            .string_capitalize => return this.capitlizeOrUncapitalize(true),
            .string_uncapitalize => return this.capitlizeOrUncapitalize(false),
            .string_uppercase, .string_lowercase => return error.TODO_string_uppercase,
            else => unreachable,
        }
    }

    fn resolveParameterizedType(this: *@This(), ref: TypeRef) anyerror!?TypeRef {
        if (ref >= @intFromEnum(Kind.false)) {
            if (isCallableIntrinsic(ref)) {
                return try this.callIntrinsicType(ref);
            } else if (isTypeParamRef(ref)) {
                return this.resolveTypeParam(ref) orelse return null;
            }

            return ref;
