                if (!did_change) return ref;

                var resolved2 = std.ArrayList(TypeRef).init(this.allocator());
                try resolved2.ensureTotalCapacityPrecise(slice.len);

                resolved2.appendAssumeCapacity(slice[0]);
                for (resolved.items, 0..) |exp, j| {
